DEFAULT_PREFLIGHT_CLI_TIMEOUT_S = 30.0
PREFLIGHT_CLI_TIMING_SCHEMA = "pact.tac_preflight_cli_timing.v1"
_PREFLIGHT_CACHE_SCHEMA = "pact.preflight_cache.v1"
_PREFLIGHT_ALL_CLEAN_CACHE_VERSION = "preflight_all_clean.v3"
_PREFLIGHT_DEVELOPER_CLEAN_CACHE_VERSION = "preflight_developer_clean.v3"
_PUBLIC_PR_PRISTINE_CACHE_VERSION = "public_pr_intake_pristine.v1"
_NO_MPS_FALLBACK_CLEAN_CACHE_VERSION = "no_mps_fallback_default_clean.v2"


def _safe_resolve_path(path: Path) -> Path:
    try:
        return path.resolve()
    except OSError:
        return path.absolute()


def _preflight_cache_path(root: Path, name: str) -> Path:
    return Path(root).resolve() / ".omx" / "cache" / f"{name}.json"


def _load_preflight_cache(root: Path, name: str) -> dict[str, object]:
    path = _preflight_cache_path(root, name)
    try:
        payload = json.loads(path.read_text())
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(payload, dict):
        return {}
    if payload.get("schema") != _PREFLIGHT_CACHE_SCHEMA:
        return {}
    rows = payload.get("rows")
    return rows if isinstance(rows, dict) else {}


def _store_preflight_cache(root: Path, name: str, rows: dict[str, object]) -> None:
    path = _preflight_cache_path(root, name)
    payload = {"schema": _PREFLIGHT_CACHE_SCHEMA, "rows": rows}
    tmp = path.with_name(f".{path.name}.{os.getpid()}.tmp")
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp.write_text(json.dumps(payload, sort_keys=True))
        tmp.replace(path)
    except OSError:
        try:
            tmp.unlink(missing_ok=True)
        except OSError:
            pass


def _source_cache_row(path: Path, **extra: object) -> dict[str, object]:
    stat = path.stat()
    return {
        "path": str(path.resolve()),
        "size": stat.st_size,
        "mtime_ns": stat.st_mtime_ns,
        **extra,
    }


def _source_cache_row_matches(path: Path, row: object, **extra: object) -> bool:
    if not isinstance(row, dict):
        return False
    try:
        stat = path.stat()
    except OSError:
        return False
    return (
        row.get("path") == str(path.resolve())
        and row.get("size") == stat.st_size
        and row.get("mtime_ns") == stat.st_mtime_ns
        and all(row.get(key) == value for key, value in extra.items())
    )


def _fingerprint_paths(paths: tuple[Path, ...], root: Path, *, salt: str) -> str:
    digest = hashlib.sha256()
    digest.update(salt.encode())
    for path in sorted(paths, key=lambda item: item.as_posix()):
        try:
            stat = path.stat()
        except OSError:
            continue
        try:
            rel = path.resolve().relative_to(root).as_posix()
        except ValueError:
            rel = path.resolve().as_posix()
        digest.update(rel.encode())
        digest.update(b"\0")
        digest.update(str(stat.st_size).encode())
        digest.update(b":")
        digest.update(str(stat.st_mtime_ns).encode())
        digest.update(b"\n")
    return digest.hexdigest()


def _strong_fingerprint_paths(paths: tuple[Path, ...], root: Path, *, salt: str) -> str:
    digest = hashlib.sha256()
    digest.update(salt.encode())
    for path in sorted(paths, key=lambda item: item.as_posix()):
        try:
            stat_result = path.stat()
        except OSError:
            continue
        try:
            rel = path.resolve().relative_to(root).as_posix()
        except ValueError:
            rel = path.resolve().as_posix()
        digest.update(rel.encode())
        digest.update(b"\0")
        for value in (
            stat_result.st_size,
            stat_result.st_mtime_ns,
            stat_result.st_ctime_ns,
            stat_result.st_ino,
            stat_result.st_dev,
        ):
            digest.update(str(value).encode())
            digest.update(b":")
        digest.update(b"\n")
    return digest.hexdigest()


def _clean_check_cache_hit(
    root: Path,
    *,
    cache_name: str,
    version: str,
    paths: tuple[Path, ...],
) -> tuple[bool, str]:
    fingerprint = _strong_fingerprint_paths(paths, root, salt=version)
    rows = _load_preflight_cache(root, cache_name)
    row = rows.get("clean")
    hit = (
        isinstance(row, dict)
        and row.get("version") == version
        and row.get("fingerprint") == fingerprint
    )
    return hit, fingerprint


def _store_clean_check_cache(
    root: Path,
    *,
    cache_name: str,
    version: str,
    fingerprint: str,
) -> None:
    rows = _load_preflight_cache(root, cache_name)
    rows["clean"] = {
        "version": version,
        "fingerprint": fingerprint,
        "stored_at_utc": _dt.datetime.now(_dt.UTC).isoformat(),
    }
    _store_preflight_cache(root, cache_name, rows)


def _public_pr_intake_clone_roots(root: Path) -> tuple[Path, ...]:
    """Return public-PR intake clone roots with local git metadata.

    These clones live under ignored ``experiments/results`` custody trees, but
    Check 109 treats their pristine state as durable preflight input. Keep this
    discovery narrow so whole-preflight clean caches do not need to fingerprint
    arbitrary result payloads.
    """

    er = root / "experiments" / "results"
    if not er.is_dir():
        return ()
    candidates: list[Path] = []
    intake_dirs: list[Path] = []
    try:
        top_level = sorted(er.iterdir(), key=lambda item: item.name)
    except OSError:
        top_level = []
    for child in top_level:
        if not child.is_dir():
            continue
        if fnmatch.fnmatch(child.name, "public_pr*_intake_*"):
            intake_dirs.append(child)
        if child.name.startswith("public_pr"):
            try:
                nested = sorted(child.iterdir(), key=lambda item: item.name)
            except OSError:
                nested = []
            intake_dirs.extend(
                grandchild
                for grandchild in nested
                if grandchild.is_dir()
                and fnmatch.fnmatch(grandchild.name, "public_pr*_intake_*")
            )
    for child in intake_dirs:
        if not child.is_dir():
            continue
        for sub in ("source", "repo"):
            cand = child / sub
            if (cand / ".git").exists():
                candidates.append(cand)
        for pr_src in child.glob("pr*_src"):
            cand = pr_src / "repo"
            if (cand / ".git").exists():
                candidates.append(cand)
        if (child / ".git").exists():
            candidates.append(child)

    seen: set[Path] = set()
    out: list[Path] = []
    for candidate in candidates:
        resolved = _safe_resolve_path(candidate)
        if resolved in seen:
            continue
        seen.add(resolved)
        out.append(resolved)
    return tuple(sorted(out, key=lambda item: item.as_posix()))


def _public_pr_clone_fingerprint_paths(root: Path) -> tuple[Path, ...]:
    """Return lightweight metadata inputs for public-PR pristine cache hits."""

    paths: list[Path] = []
    for clone in _public_pr_intake_clone_roots(root):
        marker = clone / ".git"
        if marker.is_file():
            paths.append(marker)
        elif marker.is_dir():
            for name in ("HEAD", "index", "packed-refs"):
                p = marker / name
                if p.is_file():
                    paths.append(p)
            refs = marker / "refs"
            if refs.is_dir():
                for dirpath, dirnames, filenames in os.walk(refs):
                    dirnames.sort()
                    for filename in sorted(filenames):
                        p = Path(dirpath) / filename
                        if p.is_file():
                            paths.append(p)
        for dirpath, dirnames, filenames in os.walk(clone):
            dirnames[:] = sorted(name for name in dirnames if name != ".git")
            base = Path(dirpath)
            for filename in sorted(filenames):
                if filename == ".git":
                    continue
                p = base / filename
                if p.is_file() or p.is_symlink():
                    paths.append(p)
    return tuple(sorted(paths, key=lambda item: item.as_posix()))


def _preflight_all_fingerprint_paths(
    root: Path,
    *,
    include_result_artifacts: bool = True,
) -> tuple[Path, ...]:
    """Return files whose unchanged metadata can reuse a clean full preflight.

    This deliberately covers the repo source/control plane, not raw ignored
    experiment payloads. Raw provider logs and rebuildable result blobs are not
    durable codebase preflight inputs; promoted signal must be canonicalized
    into tracked source, docs, `.omx/research`, or small state manifests.
    """

    include_globs = (
        "*.py",
        "*.sh",
        "*.md",
        "*.json",
        "*.yaml",
        "*.yml",
        "*.toml",
        "*.txt",
    )
    exclude_globs = (
        ".venv/**",
        ".omx/cache/**",
        ".omx/research/artifacts/**",
        "__pycache__/**",
        "experiments/results/**",
        "reports/preflight*_timing*.json",
        "reports/raw/**",
        "reports/private/**",
    )
    paths = set(
        _rg_file_list(
            root,
            ["."],
            include_globs,
            exclude_globs=exclude_globs,
        )
        or ()
    )
    for pattern in (
        ".omx/research/*.md",
        ".omx/state/*.json",
        ".omx/state/*.yaml",
        ".omx/state/*.yml",
        "reports/latest.md",
        "reports/silent_defaults.md",
    ):
        paths.update(path for path in root.glob(pattern) if path.is_file())
    paths.update(_public_pr_clone_fingerprint_paths(root))
    results_dir = root / "experiments" / "results"
    if include_result_artifacts and results_dir.is_dir():
        for pattern in ("*status*.json", "*manifest*.json", "rebuild_command.txt"):
            for path in results_dir.rglob(pattern):
                if not path.is_file():
                    continue
                rel = path.relative_to(root).as_posix()
                if "/public_pr" in rel:
                    continue
                paths.add(path)
    return tuple(sorted(paths, key=lambda item: item.as_posix()))


def _preflight_codebase_clean_cache_hit(
    root: Path,
    *,
    cache_name: str,
    version: str,
    profile_name: str | None,
    tto_frames_path: str | Path | None,
    gt_poses_path: str | Path | None,
    masks_path: str | Path | None,
    renderer_path: str | Path | None,
    archive_path: str | Path | None,
) -> tuple[bool, str, tuple[Path, ...]]:
    """Return whether the current codebase has an unchanged strict-passing preflight."""

    paths = _preflight_all_fingerprint_paths(
        root,
        include_result_artifacts=cache_name == "preflight_all_clean",
    )
    fingerprint = _strong_fingerprint_paths(
        paths,
        root,
        salt=version,
    )
    key_payload = {
        "profile_name": profile_name,
        "tto_frames_path": str(tto_frames_path) if tto_frames_path else None,
        "gt_poses_path": str(gt_poses_path) if gt_poses_path else None,
        "masks_path": str(masks_path) if masks_path else None,
        "renderer_path": str(renderer_path) if renderer_path else None,
        "archive_path": str(archive_path) if archive_path else None,
    }
    cache_key = hashlib.sha256(
        json.dumps(key_payload, sort_keys=True).encode()
    ).hexdigest()
    cache_rows = _load_preflight_cache(root, cache_name)
    row = cache_rows.get(cache_key)
    hit = (
        isinstance(row, dict)
        and row.get("version") == version
        and row.get("fingerprint") == fingerprint
    )
    return hit, cache_key + ":" + fingerprint, paths


def _store_preflight_codebase_clean_cache(
    root: Path,
    *,
    cache_name: str,
    version: str,
    cache_token: str,
    paths: tuple[Path, ...],
    advisory_count: int = 0,
) -> None:
    """Record a strict-passing preflight for the current source/state fingerprint."""

    cache_key, fingerprint = cache_token.split(":", 1)
    rows = _load_preflight_cache(root, cache_name)
    rows[cache_key] = {
        "version": version,
        "fingerprint": fingerprint,
        "path_count": len(paths),
        "advisory_count": advisory_count,
        "stored_at_unix": int(time.time()),
    }
    _store_preflight_cache(root, cache_name, rows)


