def _rg_file_list(
    root: Path,
    dirs: Sequence[str | Path],
    include_globs: Sequence[str],
    *,
    exclude_globs: Sequence[str] = (),
    timeout_s: float = 5.0,
) -> tuple[Path, ...] | None:
    """Fast file discovery through ripgrep, with caller-managed fallback.

    `rg --files` uses a parallel directory walker and is materially faster
    than repeated Python rglob/os.walk scans on this repo. Returning None
    keeps portability: callers can fall back to the pure-Python walker when
    ripgrep is unavailable or fails unexpectedly.
    """

    existing_dirs: list[str] = []
    for item in dirs:
        path = Path(item)
        if path.is_absolute():
            if path.exists():
                existing_dirs.append(path.as_posix())
            continue
        if (root / path).exists():
            existing_dirs.append(path.as_posix())
    if not existing_dirs:
        return ()
    cmd = ["rg", "--files"]
    for glob in include_globs:
        cmd.extend(["-g", glob])
    for glob in exclude_globs:
        cmd.extend(["-g", f"!{glob}"])
    cmd.extend(existing_dirs)
    try:
        proc = subprocess.run(
            cmd,
            cwd=root,
            capture_output=True,
            text=True,
            timeout=timeout_s,
        )
    except (OSError, subprocess.TimeoutExpired):
        return None
    if proc.returncode not in (0, 1):
        return None
    paths: dict[str, Path] = {}
    for raw_line in proc.stdout.splitlines():
        if not raw_line:
            continue
        path = (root / raw_line).resolve()
        if not path.is_file():
            continue
        if _is_oss_export_mirror_path(path):
            continue
        paths[path.as_posix()] = path
    return tuple(paths[key] for key in sorted(paths))


def _rg_python_files_matching_regex(
    root: Path,
    dirs: Sequence[str | Path],
    regex: str,
    *,
    timeout_s: float = 5.0,
) -> tuple[Path, ...] | None:
    """Return Python files matching ``regex`` using one ripgrep pass."""

    existing_dirs: list[str] = []
    for item in dirs:
        path = Path(item)
        if path.is_absolute():
            if path.exists():
                existing_dirs.append(path.as_posix())
            continue
        if (root / path).exists():
            existing_dirs.append(path.as_posix())
    if not existing_dirs:
        return ()
    cmd = [
        "rg",
        "-l",
        regex,
        "-g",
        "*.py",
        "-g",
        "!experiments/results/**",
    ]
    cmd.extend(existing_dirs)
    try:
        proc = subprocess.run(
            cmd,
            cwd=root,
            capture_output=True,
            text=True,
            timeout=timeout_s,
        )
    except (OSError, subprocess.TimeoutExpired):
        return None
    if proc.returncode not in (0, 1):
        return None
    paths: dict[str, Path] = {}
    for raw_line in proc.stdout.splitlines():
        if not raw_line:
            continue
        path = (root / raw_line).resolve()
        if not path.is_file():
            continue
        if _is_oss_export_mirror_path(path):
            continue
        paths[path.as_posix()] = path
    return tuple(paths[key] for key in sorted(paths))


@functools.lru_cache(maxsize=4096)
def _cached_python_text(
    resolved_path: str,
    mtime_ns: int,
    size_bytes: int,
) -> str:
    """Return cached source text for repeated preflight scans."""
    del mtime_ns, size_bytes  # cache-key only
    return Path(resolved_path).read_text()


@functools.lru_cache(maxsize=4096)
def _cached_python_text_and_tree(
    resolved_path: str,
    mtime_ns: int,
    size_bytes: int,
) -> tuple[str, ast.Module]:
    """Return cached source text + AST for repeated preflight scans.

    Developer preflight intentionally runs several independent bug-class
    scanners over the same Python files. The files are immutable for the
    duration of one CLI run; keying by path, mtime, and size preserves
    correctness when a long-lived process edits a file and reruns checks.
    """
    text = _cached_python_text(resolved_path, mtime_ns, size_bytes)
    return text, ast.parse(text, filename=resolved_path)


def _read_python_text(
    path: Path,
) -> tuple[str | None, BaseException | None]:
    source_index = _current_source_index(REPO_ROOT)
    if source_index is not None:
        try:
            return source_index.read_text(path), None
        except (OSError, UnicodeDecodeError) as e:
            return None, e
    try:
        stat = path.stat()
        resolved = str(path.resolve())
    except OSError as e:
        return None, e
    try:
        text = _cached_python_text(
            resolved,
            stat.st_mtime_ns,
            stat.st_size,
        )
    except (OSError, UnicodeDecodeError) as e:
        return None, e
    return text, None


def _read_python_text_and_tree(
    path: Path,
) -> tuple[str | None, ast.Module | None, BaseException | None]:
    source_index = _current_source_index(REPO_ROOT)
    if source_index is not None:
        try:
            text = source_index.read_text(path)
            tree = source_index.python_ast(path)
            if isinstance(tree, ast.Module):
                return text, tree, None
            return text, tree, None
        except (OSError, SyntaxError, UnicodeDecodeError) as e:
            return None, None, e
    try:
        stat = path.stat()
        resolved = str(path.resolve())
    except OSError as e:
        return None, None, e
    try:
        text, tree = _cached_python_text_and_tree(
            resolved,
            stat.st_mtime_ns,
            stat.st_size,
        )
    except (OSError, SyntaxError, UnicodeDecodeError) as e:
        return None, None, e
    return text, tree, None


class PreflightError(Exception):
    """A preflight check failed - do NOT proceed."""
    pass


class PreflightTimeoutError(PreflightError):
    """The canonical preflight CLI exceeded its wall-clock budget."""
    pass


class _ParallelPreflightRunner:
    """Run independent preflight checks concurrently while preserving fail sites."""

    def __init__(
        self,
        *,
        enabled: bool,
        verbose: bool,
        max_workers: int | None = None,
    ) -> None:
        self.enabled = enabled
        self.verbose = verbose
        if max_workers is None:
            max_workers = _preflight_parallel_worker_count()
        self.max_workers = max_workers
        self._executor: ThreadPoolExecutor | None = (
            ThreadPoolExecutor(
                max_workers=self.max_workers,
                thread_name_prefix="preflight",
            )
            if self.enabled else None
        )
        self._futures: dict[str, Future[object]] = {}
        self.advisory_count = 0

    def __enter__(self) -> "_ParallelPreflightRunner":
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        if self._executor is not None:
            self._executor.shutdown(wait=True, cancel_futures=exc_type is not None)

    def submit(self, name: str, fn) -> None:
        if self._executor is None:
            return
        ctx = contextvars.copy_context()
        self._futures[name] = self._executor.submit(ctx.run, fn)

    def run(self, name: str, label: str, fn, *, strict: bool = True):
        future = self._futures.pop(name, None)
        if future is None:
            result = fn()
            self._record_result(result, strict=strict)
            if not self._futures:
                self.close(cancel=False)
            return result
        try:
            result = future.result()
        except BaseException:
            self.close(cancel=True)
            raise
        self._record_result(result, strict=strict)
        if self.verbose:
            if isinstance(result, list):
                if result:
                    mode = "violation(s)" if strict else "advisory finding(s)"
                    print(f"  {label} {len(result)} {mode}")
                    for item in result[:10]:
                        print(f"    - {str(item)[:240]}")
                    if len(result) > 10:
                        print(f"    ... and {len(result) - 10} more")
                else:
                    print(f"  {label} OK")
            else:
                print(f"  {label} OK")
        if not self._futures:
            self.close(cancel=False)
        return result

    def _record_result(self, result: object, *, strict: bool) -> None:
        if strict or not isinstance(result, list):
            return
        self.advisory_count += len(result)

    def close(self, *, cancel: bool) -> None:
        if self._executor is not None:
            self._executor.shutdown(wait=not cancel, cancel_futures=cancel)
            self._executor = None


def _preflight_parallel_enabled() -> bool:
    """Return true when independent preflight scanners should run in parallel."""

    # Keep the normal developer gate parallel by default. The GHA runner's
    # cold-cache sequential path exceeded the 30s DX budget on 2026-05-12;
    # per-file SourceIndex locks keep extraction coherent while wall-clock is
    # bounded by the slowest independent scanner instead of their sum.
    default = "1"
    value = os.environ.get("PACT_PREFLIGHT_ENABLE_PARALLEL", default).strip().lower()
    return value in {"1", "true", "yes", "on"}


def _preflight_parallel_worker_count() -> int:
    """Return the bounded worker budget for parallel developer checks.

    Broad preflight checks share a SourceIndex and several still parse or scan
    overlapping candidate files. Unbounded fan-out increases lock contention
    and I/O pressure, so the default is a fixed worker pool. Eight workers keeps
    local developer machines and GitHub-hosted runners responsive by starting
    slow full-tree policy scanners immediately instead of queueing them in long
    waves. Keep SourceIndex prewarm opt-in; the runner bottleneck is late scan
    start, not lack of a warm index.
    """

    raw = os.environ.get("PACT_PREFLIGHT_PARALLEL_WORKERS", "").strip()
    if raw:
        try:
            value = int(raw)
        except ValueError:
            value = 8
    else:
        value = 8
    return max(1, min(value, 16))


def _preflight_source_index_prewarm_enabled() -> bool:
    """Return true when source-index facts should be warmed before fan-out."""

    value = os.environ.get("PACT_PREFLIGHT_PREWARM_SOURCE_INDEX", "").strip().lower()
    return value in {"1", "true", "yes", "on"}


def _prewarm_preflight_source_index(root: Path) -> None:
    """Populate shared source-index fact groups before parallel checks fan out.

    The broad preflight checks are intentionally parallel, but many of them ask
    for overlapping ``*.py`` / ``*.sh`` / ``*.md`` source facts. Without this
    prewarm, concurrent cache misses can rebuild the same one-pass file facts
    several times. This keeps policy unchanged: precise checks still run their
    own validators over conservative candidate sets.
    """

    source_index = _current_source_index(root)
    if source_index is None:
        return
    groups = (
        # Exact developer-hot groups. These keys intentionally match the
        # downstream checks so SourceIndex can reuse one file/fact pass.
        (("scripts", "experiments", "src/tac/contrib", "src/tac/deploy", "src/tac/experiments"), ("*.py",)),
        (("experiments",), ("*.sh",)),
        (("src/tac", "tools"), ("*.py",)),
        (("src/tac", "tools", "scripts"), ("*.py",)),
        (("src/tac", "tools", "experiments"), ("*.py",)),
        (("src/tac", "tools", "experiments", "scripts"), ("*.py",)),
        (("src/tac", "experiments", "scripts"), ("*.py",)),
        (("scripts", "tools", "submissions/robust_current"), ("*.sh",)),
        (("experiments", "src/tac", "submissions/robust_current"), ("*.py", "*.sh")),
        (("src/tac", "experiments", "scripts", "submissions"), ("*.py",)),
        (("docs", "reports", "scripts", "src/tac", "experiments", "submissions"), ("*.py", "*.sh", "*.md")),
        (("src/tac/tests", "tests"), ("test_*.py",)),
    )
    for dirs, patterns in groups:
        if not any((root / d).exists() for d in dirs):
            continue
        try:
            if len(patterns) > 1:
                source_index.files_by_pattern(dirs, patterns=patterns)
            for pattern in patterns:
                source_index.facts_for_files(dirs, pattern=pattern)
        except OSError:
            # The owning check will report the real failure if the path matters.
            continue


@contextmanager
def _preflight_timeout_after(seconds: float | None) -> Iterator[None]:
    """Raise ``PreflightTimeoutError`` when the CLI exceeds ``seconds``.

    The timeout is intentionally CLI-scoped. Library callers can still profile
    individual checks or run release/custody sweeps under their own timeout
    policy, while the normal developer command fails fast instead of silently
    becoming a multi-minute velocity tax.
    """
    if seconds is None:
        yield
        return
    if seconds <= 0:
        raise ValueError("preflight timeout must be positive")
    if (
        threading.current_thread() is not threading.main_thread()
        or not hasattr(signal, "SIGALRM")
        or not hasattr(signal, "setitimer")
    ):
        yield
        return

    started = time.monotonic()

    def _handler(_signum: int, _frame: object) -> None:
        elapsed = time.monotonic() - started
        raise PreflightTimeoutError(
            f"preflight exceeded {seconds:g}s wall-clock budget "
            f"(elapsed {elapsed:.1f}s). This is a DX failure; profile with "
            "`tools/profile_preflight_latency.py` or run the explicit "
            "slow-release override only for custody/release sweeps."
        )

    old_handler = signal.getsignal(signal.SIGALRM)
    old_timer = signal.getitimer(signal.ITIMER_REAL)
    signal.signal(signal.SIGALRM, _handler)
    signal.setitimer(signal.ITIMER_REAL, seconds)
    try:
        yield
    finally:
        signal.setitimer(signal.ITIMER_REAL, 0.0)
        signal.signal(signal.SIGALRM, old_handler)
        if old_timer[0] > 0:
            signal.setitimer(signal.ITIMER_REAL, old_timer[0], old_timer[1])


def _preflight_cli_timeout_seconds(
    *,
    timeout_s: float,
    allow_slow_preflight: bool,
) -> float | None:
    if allow_slow_preflight:
        return None
    if timeout_s <= 0:
        raise ValueError("--timeout-s must be > 0")
    return timeout_s


def _called_preflight_cli_check_names(func) -> list[str]:
    """Return preflight/check function names called by a CLI scope runner."""

    try:
        source = inspect.getsource(func)
        tree = ast.parse(source)
    except (OSError, TypeError, SyntaxError):
        return []

    names: list[str] = []
    seen: set[str] = set()

    class Visitor(ast.NodeVisitor):
        def visit_Call(self, node: ast.Call) -> None:
            callee = node.func
            if isinstance(callee, ast.Name):
                name = callee.id
            elif isinstance(callee, ast.Attribute):
                name = callee.attr
            else:
                name = ""
            target = globals().get(name)
            if (
                name
                and name not in {func.__name__, "preflight_all", "preflight_developer"}
                and name not in seen
                and callable(target)
                and (name.startswith("check_") or name.startswith("preflight_"))
            ):
                seen.add(name)
                names.append(name)
            self.generic_visit(node)

    Visitor().visit(tree)
    return names


class _PreflightCliTimingRecorder:
    """Wrap scope-local checks and record wall-clock timing rows."""

    def __init__(self, *, scope: str, runner) -> None:
        self.scope = scope
        self.runner = runner
        self._originals: dict[str, object] = {}
        self._rows: list[dict[str, object]] = []
        self._active: dict[int, dict[str, object]] = {}
        self._lock = threading.Lock()
        self._started = 0.0
        self._sequence = 0

    def __enter__(self) -> "_PreflightCliTimingRecorder":
        self._started = time.perf_counter()
        for name in _called_preflight_cli_check_names(self.runner):
            func = globals().get(name)
            if not callable(func):
                continue
            self._originals[name] = func
            globals()[name] = self._wrap(name, func)
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        for name, func in self._originals.items():
            globals()[name] = func
        self._originals.clear()

    def _wrap(self, name: str, func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            row_started = time.perf_counter()
            with self._lock:
                self._sequence += 1
                sequence = self._sequence
                self._active[sequence] = {
                    "sequence": sequence,
                    "name": name,
                    "status": "running",
                    "elapsed_s": 0.0,
                    "started_offset_s": round(row_started - self._started, 6),
                    "finished_offset_s": None,
                    "thread": threading.current_thread().name,
                }
            status = "passed"
            detail = ""
            try:
                return func(*args, **kwargs)
            except BaseException as exc:
                status = "failed"
                detail = f"{type(exc).__name__}: {exc}"
                raise
            finally:
                row_finished = time.perf_counter()
                with self._lock:
                    row: dict[str, object] = {
                        "sequence": sequence,
                        "name": name,
                        "status": status,
                        "elapsed_s": round(row_finished - row_started, 6),
                        "started_offset_s": round(row_started - self._started, 6),
                        "finished_offset_s": round(row_finished - self._started, 6),
                        "thread": threading.current_thread().name,
                    }
                    if detail:
                        row["detail"] = detail
                    self._active.pop(sequence, None)
                    self._rows.append(row)

        return wrapper

    def rows(self) -> list[dict[str, object]]:
        with self._lock:
            rows = [dict(row) for row in self._rows]
            now = time.perf_counter()
            for row in self._active.values():
                active = dict(row)
                active["elapsed_s"] = round(
                    now - (self._started + float(active["started_offset_s"])),
                    6,
                )
                active["finished_offset_s"] = round(now - self._started, 6)
                rows.append(active)
            return rows


def _build_preflight_cli_timing_payload(
    *,
    scope: str,
    status: str,
    wall_elapsed_s: float,
    timeout_s: float | None,
    allow_slow_preflight: bool,
    check_codebase: bool,
    step_rows: list[dict[str, object]],
    error_type: str = "",
    error: str = "",
) -> dict[str, object]:
    hot_steps = sorted(
        step_rows,
        key=lambda row: (-float(row.get("elapsed_s", 0.0)), str(row.get("name", ""))),
    )
    serial_elapsed_s = sum(float(row.get("elapsed_s", 0.0)) for row in step_rows)
    payload: dict[str, object] = {
        "schema": PREFLIGHT_CLI_TIMING_SCHEMA,
        "generated_at": _dt.datetime.now(_dt.UTC).isoformat().replace("+00:00", "Z"),
        "repo_root": str(REPO_ROOT),
        "scope": scope,
        "status": status,
        "check_codebase": check_codebase,
        "timeout_s": 0 if timeout_s is None else timeout_s,
        "allow_slow_preflight": allow_slow_preflight,
        "wall_elapsed_s": round(wall_elapsed_s, 6),
        "serial_elapsed_s": round(serial_elapsed_s, 6),
        "step_count": len(step_rows),
        "failed_step_count": sum(1 for row in step_rows if row.get("status") != "passed"),
        "slow_step_threshold_s": 0.5,
        "slow_step_count": sum(
            1 for row in step_rows if float(row.get("elapsed_s", 0.0)) >= 0.5
        ),
        "steps": sorted(step_rows, key=lambda row: int(row.get("sequence", 0))),
        "hot_steps": hot_steps[:20],
    }
    if error_type:
        payload["error_type"] = error_type
    if error:
        payload["error"] = error
    return payload


def _write_preflight_cli_timing_json(path: Path, payload: dict[str, object]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n")


def _format_preflight_timing_summary(
    step_rows: list[dict[str, object]],
    *,
    max_steps: int = 5,
) -> str:
    """Return a concise hot-step summary for DX budget failures."""

    if not step_rows:
        return "No individual preflight check timings were recorded."
    hot_steps = sorted(
        step_rows,
        key=lambda row: (-float(row.get("elapsed_s", 0.0)), str(row.get("name", ""))),
    )[:max_steps]
    lines = ["Slowest preflight checks recorded before failure:"]
    for row in hot_steps:
        status = str(row.get("status", "unknown"))
        name = str(row.get("name", "<unknown>"))
        elapsed = float(row.get("elapsed_s", 0.0))
        thread_name = str(row.get("thread", ""))
        thread_suffix = f" [{thread_name}]" if thread_name else ""
        lines.append(f"  - {name}: {elapsed:.3f}s ({status}){thread_suffix}")
    return "\n".join(lines)


def _preflight_budget_error_message(
    *,
    scope: str,
    budget_s: float,
    elapsed_s: float,
    step_rows: list[dict[str, object]],
    cause: str = "",
) -> str:
    """Build an actionable timeout/over-budget error for normal preflight."""

    headline = (
        f"{scope} preflight exceeded {budget_s:g}s wall-clock DX budget "
        f"(elapsed {elapsed_s:.1f}s)."
    )
    details = _format_preflight_timing_summary(step_rows)
    action = (
        "Write a timing profile with `python -m tac.preflight --scope dev "
        "--timings-json reports/preflight_dev_timing.json`, then split, cache, "
        "or move the slow check out of the normal dev scope."
    )
    if cause:
        return f"{headline}\n{details}\nCause: {cause}\n{action}"
    return f"{headline}\n{details}\n{action}"


class PreflightWarning:
    """A preflight check raised a concern but is not fatal."""
    def __init__(self, msg: str):
        self.msg = msg


def preflight_check(
    renderer_path: str | Path | None = None,
    masks_path: str | Path | None = None,
    poses_path: str | Path | None = None,
    archive_path: str | Path | None = None,
    expected_n_frames: int = 1200,
    expected_n_pairs: int = 600,
    expected_seg_h: int = 384,
    expected_seg_w: int = 512,
    verbose: bool = True,
) -> list[PreflightWarning]:
    """Run all preflight checks. Raises PreflightError on fatal issues.

    Returns list of warnings (non-fatal concerns).
    """
    warnings: list[PreflightWarning] = []
    checks_passed = 0
    checks_total = 0

    def _pass(msg: str) -> None:
        nonlocal checks_passed, checks_total
        checks_total += 1
        checks_passed += 1
        if verbose:
            print(f"  [PASS] {msg}")

    def _fail(msg: str) -> None:
        nonlocal checks_total
        checks_total += 1
        if verbose:
            print(f"  [FAIL] {msg}")
        raise PreflightError(msg)

    def _warn(msg: str) -> None:
        nonlocal checks_total
        checks_total += 1
        warnings.append(PreflightWarning(msg))
        if verbose:
            print(f"  [WARN] {msg}")

    if verbose:
        print("=" * 60)
        print("PREFLIGHT CHECK")
        print("=" * 60)

    # ── Renderer checks ──────────────────────────────────────────
    if renderer_path:
        renderer_path = Path(renderer_path)
        if not renderer_path.exists():
            _fail(f"Renderer not found: {renderer_path}")

        raw = renderer_path.read_bytes()
        magic = raw[:4]

        runtime_renderer_magics = {
            b"DPSM": "DPSM runtime renderer",
            b"I4LZ": "INT4+LZMA2 runtime renderer",
            b"FP8H": "FP8H runtime renderer",
            b"CCh1": "Cool-Chic runtime renderer",
            b"C3R1": "C3 residual runtime renderer",
            b"SCv1": "Self-compressing runtime renderer",
            b"SZv1": "Szabolcs/SegMap runtime renderer",
            b"QFAI": "Q-FAITHFUL JointFrameGenerator runtime renderer",
            b"QZS3": "QZS3 JointFrameGenerator runtime renderer",
            b"MQZ1": "MQZ1 mixed/local QZS runtime renderer",
            b"BFJ1": "BFJ1 block-FP JointFrameGenerator runtime renderer",
            b"QH0": "PR85 QH0 JointFrameGenerator runtime renderer",
            b"QM0": "PR85 QM0 JointFrameGenerator runtime renderer",
            b"QH1": "PR85 QH1 lossless record-repack JointFrameGenerator runtime renderer",
            b"NWC1": "Neural weight codec runtime renderer",
            b"OWV2": "OWV2 runtime renderer",
            b"OWV3": "OWV3 runtime renderer",
            b"IMPS": "IMP sparse-CSR runtime renderer",
        }
        pytorch_pickle_magics = (b"PK\x03\x04", b"\x80\x02", b"\x80\x03", b"\x80\x04", b"\x80\x05")

        if magic == b"ASYM":
            header_len = struct.unpack("<I", raw[4:8])[0]
            import json
            header = json.loads(raw[8:8 + header_len])
            pose_dim = header.get("pose_dim", 0)
            base_ch = header.get("base_ch", "?")
            dsconv = header.get("use_dsconv", False)
            _pass(f"Renderer: ASYM, pose_dim={pose_dim}, base_ch={base_ch}, dsconv={dsconv}, {len(raw):,}B")

            if pose_dim == 0:
                _warn("Renderer has pose_dim=0 - FiLM conditioning disabled, poses will have no effect")
            if pose_dim > 0 and poses_path is None:
                _warn("Renderer has pose_dim>0 but no poses_path provided - will use zero poses")
        elif magic == b"FP4A":
            _pass(f"Renderer: FP4A, {len(raw):,}B")
            _warn("FP4 renderer - verify QAT was used during training (post-hoc QAT degrades 3-26x)")
        elif magic in runtime_renderer_magics:
            _pass(f"Renderer: {runtime_renderer_magics[magic]}, {len(raw):,}B")
        elif raw[:3] in runtime_renderer_magics:
            _pass(f"Renderer: {runtime_renderer_magics[raw[:3]]}, {len(raw):,}B")
        elif raw[:8] == b"NWCS1\0\0\0":
            _pass(f"Renderer: NWCS1 sensitivity-aware neural weight codec runtime renderer, {len(raw):,}B")
        elif raw.startswith(pytorch_pickle_magics):
            _warn(f"Renderer: PyTorch checkpoint payload, {len(raw):,}B")
        else:
            _fail(
                f"Renderer: unknown non-pickle binary format (magic={magic!r}). "
                "Refusing to assume PyTorch .pt because that reopens the "
                "renderer.bin torch.load bug class; add an explicit runtime "
                "loader/preflight branch for this wire format."
            )

    # ── Mask checks ──────────────────────────────────────────────
    if masks_path:
        masks_path = Path(masks_path)
        if not masks_path.exists():
            _fail(f"Masks not found: {masks_path}")

        if masks_path.suffix in (".mkv", ".mp4"):
            probe = subprocess.run(
                ["ffprobe", "-v", "quiet", "-select_streams", "v:0",
                 "-show_entries", "stream=width,height", "-of", "csv=p=0",
                 str(masks_path)],
                capture_output=True, text=True, timeout=10,
            )
            if probe.returncode == 0:
                parts = probe.stdout.strip().split(",")
                w, h = int(parts[0]), int(parts[1])
                size = masks_path.stat().st_size

                if h == expected_seg_h and w == expected_seg_w:
                    _pass(f"Masks: {w}x{h} (native resolution), {size:,}B")
                elif expected_seg_h % h == 0 and expected_seg_w % w == 0:
                    scale = expected_seg_h // h
                    _warn(f"Masks at 1/{scale} resolution ({w}x{h}), will upsample to {expected_seg_w}x{expected_seg_h}")
                else:
                    _fail(f"Masks resolution {w}x{h} is not a clean factor of {expected_seg_w}x{expected_seg_h}")
            else:
                _warn("Could not probe mask video with ffprobe")
        elif masks_path.suffix == ".pt":
            m = torch.load(str(masks_path), weights_only=True)
            if m.shape[1] != expected_seg_h or m.shape[2] != expected_seg_w:
                _warn(f"Masks shape {m.shape} - expected (N, {expected_seg_h}, {expected_seg_w})")
            else:
                _pass(f"Masks: {m.shape}, .pt format")

    # ── Pose checks ──────────────────────────────────────────────
    if poses_path:
        poses_path = Path(poses_path)
        if not poses_path.exists():
            _fail(f"Poses not found: {poses_path}")

        p = torch.load(str(poses_path), weights_only=True)
        if p.shape[0] != expected_n_pairs:
            _fail(f"Poses shape {p.shape} - expected ({expected_n_pairs}, 6). "
                  f"Wrong number of pairs.")
        if p.shape[1] != 6:
            _fail(f"Poses shape {p.shape} - expected (N, 6). Wrong pose dimension.")
        _pass(f"Poses: {p.shape}, dtype={p.dtype}")

        if p.abs().max() > 100:
            _warn(f"Poses max value {p.abs().max():.1f} - unusually large, may indicate wrong scale")
        if p.abs().mean() < 0.001:
            _warn(f"Poses mean abs {p.abs().mean():.6f} - near zero, may not have been optimized")

    # ── Pose-mask consistency ────────────────────────────────────
    # This is the #1 source of score regressions in this project.
    # Poses optimized against wrong masks caused 27x PoseNet degradation.
    if poses_path and masks_path:
        _warn("CRITICAL: Verify poses were optimized against THESE EXACT masks. "
              "Mismatched poses caused 27x PoseNet regression. "
              "optimize_poses.py now requires --masks to prevent this.")

    # ── Archive checks ───────────────────────────────────────────
    if archive_path:
        archive_path = Path(archive_path)
        if not archive_path.exists():
            _fail(f"Archive not found: {archive_path}")

        try:
            # R38 fix: use detect_pose_manifest to autopick the right
            # manifest based on which pose format the archive actually has.
            from tac.submission_archive import detect_pose_manifest, validate_archive
            manifest = detect_pose_manifest(archive_path)
            result = validate_archive(archive_path, manifest, strict=True)
            if result.valid and result.dispatch_ready:
                _pass(f"Archive: {result.archive_bytes:,}B, rate={result.rate_term:.4f}, valid")
            else:
                errors = result.errors or []
                if not result.dispatch_ready:
                    errors.extend(
                        f"archive dispatch blocker: {blocker}"
                        for blocker in result.dispatch_blockers
                    )
                if not errors:
                    errors = ["archive validation returned invalid"]
                _fail(f"Archive: {'; '.join(errors)}")
                for w in result.warnings:
                    _warn(f"Archive: {w}")
        except PreflightError:
            raise
        except Exception as e:
            _fail(f"Archive validation failed: {e}")

    # ── Summary ──────────────────────────────────────────────────
    if verbose:
        print(f"\n  {checks_passed}/{checks_total} checks passed, {len(warnings)} warnings")
        if warnings:
            print("  Warnings:")
            for w in warnings:
                print(f"    - {w.msg}")
        print("=" * 60)

    return warnings


# Note: __main__ block moved to the bottom of the module so all validator
# functions (preflight_all et al.) are defined before invocation. Was a
# misleading-CLI bug per R38 - operators running `python -m tac.preflight`
# only got artifact validation, silently skipping all 5 codebase layers.


def preflight_all(
    profile_name: str | None = None,
    profile_arch: dict | None = None,
    tto_frames_path: str | Path | None = None,
    gt_poses_path: str | Path | None = None,
    masks_path: str | Path | None = None,
    renderer_path: str | Path | None = None,
    archive_path: str | Path | None = None,
    check_codebase: bool = True,
    verbose: bool = True,
    use_fs_cache: bool = True,
    _fs_cache_wrapped: bool = False,
    wall_clock_budget_s: float | None = DEFAULT_PREFLIGHT_CLI_TIMEOUT_S,
    _timing_wrapped: bool = False,
) -> None:
    """Single entry point: run ALL preflight checks. Raises on any failure.

    This is what every deployment / pipeline / experiment should call FIRST.
    Combines:
      - preflight_check: artifact validation (renderer/masks/poses/archive shapes, magic bytes)
      - preflight_training_inputs: training-time data integrity (TTO range, profile arch, eval_roundtrip)
      - preflight_codebase: AST scan for forbidden ad-hoc patterns (no nohup, no launch_*.sh)

    Pass only the args relevant to your stage. e.g., training preflight needs
    profile_name + tto_frames_path + gt_poses_path + masks_path. Inflate-time
    preflight needs renderer_path + masks_path + archive_path.
    """
    if wall_clock_budget_s is not None and wall_clock_budget_s <= 0:
        raise ValueError("full preflight wall-clock budget must be positive")

    if wall_clock_budget_s is not None and not _timing_wrapped:
        started = time.perf_counter()
        recorder = _PreflightCliTimingRecorder(scope="all", runner=preflight_all)
        try:
            with recorder, _preflight_timeout_after(wall_clock_budget_s):
                preflight_all(
                    profile_name=profile_name,
                    profile_arch=profile_arch,
                    tto_frames_path=tto_frames_path,
                    gt_poses_path=gt_poses_path,
                    masks_path=masks_path,
                    renderer_path=renderer_path,
                    archive_path=archive_path,
                    check_codebase=check_codebase,
                    verbose=verbose,
                    use_fs_cache=use_fs_cache,
                    _fs_cache_wrapped=_fs_cache_wrapped,
                    wall_clock_budget_s=None,
                    _timing_wrapped=True,
                )
        except PreflightTimeoutError as exc:
            elapsed = time.perf_counter() - started
            raise PreflightTimeoutError(
                _preflight_budget_error_message(
                    scope="full",
                    budget_s=wall_clock_budget_s,
                    elapsed_s=elapsed,
                    step_rows=recorder.rows(),
                    cause=str(exc),
                )
            ) from exc
        elapsed = time.perf_counter() - started
        if elapsed > wall_clock_budget_s:
            raise PreflightTimeoutError(
                _preflight_budget_error_message(
                    scope="full",
                    budget_s=wall_clock_budget_s,
                    elapsed_s=elapsed,
                    step_rows=recorder.rows(),
                )
            )
        return

    codebase_cache_token: str | None = None
    codebase_cache_paths: tuple[Path, ...] = ()
    if (
        check_codebase
        and os.environ.get("PACT_PREFLIGHT_DISABLE_INCREMENTAL_CACHE") != "1"
        and not any(
            [
                profile_name,
                tto_frames_path,
                gt_poses_path,
                masks_path,
                renderer_path,
                archive_path,
            ]
        )
    ):
        cache_hit, codebase_cache_token, codebase_cache_paths = (
            _preflight_all_clean_cache_hit(
                REPO_ROOT,
                profile_name=profile_name,
                tto_frames_path=tto_frames_path,
                gt_poses_path=gt_poses_path,
                masks_path=masks_path,
                renderer_path=renderer_path,
                archive_path=archive_path,
            )
        )
        if cache_hit:
            if verbose:
                print(
                    "  [preflight-all-cache] OK: cached strict-passing full preflight "
                    f"({len(codebase_cache_paths)} fingerprinted file(s))"
                )
            check_codebase = False

    if check_codebase and use_fs_cache and not _fs_cache_wrapped:
        from tac.preflight_fs_cache import cached_filesystem
        from tac.source_index import source_index_context

        # Full codebase preflight repeatedly scans the same source files.
        # Apply the measured cache for library callers too, and provide a
        # normal shared source index for scanners that have been migrated away
        # from repeated per-check rglob/read/parse loops. Artifact-only callers
        # skip this path and still read their inputs live.
        with cached_filesystem(cache_reads=True), source_index_context(REPO_ROOT):
            if _preflight_source_index_prewarm_enabled():
                _prewarm_preflight_source_index(REPO_ROOT)
            preflight_all(
                profile_name=profile_name,
                profile_arch=profile_arch,
                tto_frames_path=tto_frames_path,
                gt_poses_path=gt_poses_path,
                masks_path=masks_path,
                renderer_path=renderer_path,
                archive_path=archive_path,
                check_codebase=check_codebase,
                verbose=verbose,
                use_fs_cache=use_fs_cache,
                _fs_cache_wrapped=True,
                wall_clock_budget_s=wall_clock_budget_s,
                _timing_wrapped=_timing_wrapped,
        )
        return

