def check_operator_approval_must_be_lane_scoped(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Operator-approval-leak gate (CODEX FINDING 2026-05-08).

    A globally-scoped ``selector_context_operator_approved_exact_cuda`` flag
    must NEVER override an explicit per-manifest
    ``manifest_operator_approved_exact_cuda: false``. This check scans every
    ``*_status.json`` under ``experiments/results/`` (and dated
    ``frontier_roadmap_status_*`` siblings) and refuses any
    ``operator_approval_state`` row where ``approved == True`` AND
    ``manifest_operator_approved_exact_cuda is False``. Such a row collapses
    candidate-specific operator authorization into a global flag that can
    unlock GPU dispatch on candidates the operator never approved.

    Forbidden pattern: "operator-approval-leak". See
    ``tools/build_field_meta_dispatch_selection.py::_operator_approval_state``
    for the producing logic; the fix lands in the same file with an explicit
    boundary assert.

    Reactivation criteria: the gate may be relaxed only if the build logic
    formally proves selector-wide flag is no longer persisted in committed
    output AND every approval row carries a per-candidate approval artifact
    path + SHA-256.
    """
    root = Path(repo_root or REPO_ROOT)
    results_dir = root / "experiments" / "results"
    if not results_dir.is_dir():
        if verbose:
            print("  [operator-approval-scope] OK (no experiments/results)")
        return []

    violations: list[str] = []
    scanned = 0
    for path in sorted(results_dir.rglob("*status*.json")):
        # Skip public_pr* intake clones (forensic inputs, owned by sister gate).
        rel = path.relative_to(root).as_posix()
        if "/public_pr" in rel:
            continue
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            continue
        scanned += 1
        # Walk every dict node looking for operator_approval_state shape.
        stack: list = [payload]
        while stack:
            node = stack.pop()
            if isinstance(node, dict):
                state = node.get("operator_approval_state")
                if isinstance(state, dict):
                    approved = state.get("approved")
                    manifest_flag = state.get("manifest_operator_approved_exact_cuda")
                    if approved is True and manifest_flag is False:
                        # Compute a stable row identifier from surrounding context.
                        row_id = (
                            node.get("candidate_id")
                            or node.get("packet_path")
                            or node.get("source")
                            or "unknown"
                        )
                        violations.append(
                            f"{rel}: operator-approval-leak - "
                            f"approved=True with manifest_operator_approved_exact_cuda=False "
                            f"(row_id={row_id!r}, source={state.get('source')!r})"
                        )
                stack.extend(node.values())
            elif isinstance(node, list):
                stack.extend(node)

    if violations and strict:
        raise MetaBugViolation(
            "OPERATOR-APPROVAL-LEAK VIOLATIONS:\n" + "\n".join(violations)
        )
    if verbose:
        if violations:
            print(
                f"  [operator-approval-scope] {len(violations)} violation(s) across {scanned} status file(s)"
            )
        else:
            print(f"  [operator-approval-scope] OK ({scanned} status file(s) scanned)")
    return violations


def _artifact_lifecycle_ref_exists(root: Path, ref: str) -> bool:
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--verify", "--quiet", ref],
            cwd=root,
            capture_output=True,
            text=True,
            timeout=10,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return False
    return result.returncode == 0


def _artifact_lifecycle_default_base_ref(root: Path) -> str | None:
    explicit = os.environ.get("ARTIFACT_LIFECYCLE_BASE_REF")
    if explicit:
        return explicit
    for ref in ("origin/main", "HEAD"):
        if _artifact_lifecycle_ref_exists(root, ref):
            return ref
    return None


def _artifact_lifecycle_changed_paths(root: Path, base_ref: str | None) -> set[str]:
    paths: set[str] = set()

    def collect(args: list[str]) -> None:
        try:
            result = subprocess.run(
                ["git", *args],
                cwd=root,
                capture_output=True,
                text=True,
                timeout=20,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
            return
        if result.returncode != 0:
            return
        paths.update(line.strip() for line in result.stdout.splitlines() if line.strip())

    if base_ref:
        collect(["diff", "--name-only", "--diff-filter=ACMRTUXB", f"{base_ref}..HEAD"])
    collect(["diff", "--name-only", "--diff-filter=ACMRTUXB", "--cached"])
    collect(["diff", "--name-only", "--diff-filter=ACMRTUXB"])
    if not paths:
        collect(["diff-tree", "--no-commit-id", "--name-only", "-r", "HEAD"])
    return paths


def check_artifact_lifecycle_compliance(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Meta gate - provenance-vs-state confusion class (CODEX 2026-05-08 META).

    Umbrella check that runs all four artifact-lifecycle guards
    (LIVE_STATE / HISTORICAL_PROVENANCE / LIVE_RECIPE / DERIVED_OUTPUT)
    against every committed artifact pattern in
    ``.omx/state/artifact_kind_registry.yaml``.

    This catches the META-CLASS that the per-finding sister gates catch
    one instance at a time:
    ``check_operator_approval_must_be_lane_scoped``,
    ``check_public_pr_intake_clones_pristine``,
    ``check_status_artifacts_no_stale_dirty_paths``,
    ``check_rebuild_commands_no_baked_runtime_state``,
    ``check_recovery_metadata_append_only``.

    Forbidden pattern: "transient/global/upstream state being frozen or
    mutated into committed/forensic artifacts in ways that destroy
    provenance or leak authorization." See CLAUDE.md catalog #113 +
    memory ``feedback_codex_findings_meta_pattern_artifact_lifecycle_FIXED_20260508.md``.

    Reactivation criteria: this gate may be relaxed only when EVERY
    long-lived artifact in the repo is explicitly classified in the
    registry AND each kind's guard has been hardened.
    """
    from tac.artifact_lifecycle import run_meta_lifecycle_audit

    root = Path(repo_root or REPO_ROOT)
    full_strict = os.environ.get("ARTIFACT_LIFECYCLE_FULL_STRICT") == "1"
    base_ref = _artifact_lifecycle_default_base_ref(root)
    path_filter = None
    changed_paths: set[str] | None = None
    if strict and not full_strict:
        changed_paths = _artifact_lifecycle_changed_paths(root, base_ref)
        path_filter = changed_paths
    # FIX-4 strict-flip 2026-05-08: enumerate UNKNOWN long-lived artifacts as
    # part of the META gate. Bug class: tracked artifacts under
    # LONG_LIVED_ARTIFACT_ROOTS that don't match any registry pattern slip
    # past the per-pattern guard loop entirely. Now ON unconditionally; legacy
    # baseline of 4016 was driven to 0 by the broad-sweep registry update at
    # commit landing this flip; new unregistered tracked artifacts must add
    # registry pattern OR allowlist entry.
    violations = run_meta_lifecycle_audit(
        repo_root=root,
        base_ref=base_ref,
        path_filter=path_filter,
        enumerate_unregistered=True,
    )
    if violations and strict:
        raise MetaBugViolation(
            "ARTIFACT-LIFECYCLE COMPLIANCE VIOLATIONS:\n"
            + "\n".join(violations)
        )
    if verbose:
        if violations:
            print(f"  [artifact-lifecycle] {len(violations)} violation(s)")
        else:
            scope = (
                f"changed-scope {len(changed_paths or set())} path(s)"
                if strict and not full_strict
                else "full-repo"
            )
            print(f"  [artifact-lifecycle] OK ({scope})")
    return violations


def check_reverse_engineering_tree_curation(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Keep reverse_engineering/ curated and force raw material into custody manifests."""
    root = Path(repo_root or REPO_ROOT)
    required = [
        root / "reverse_engineering" / "README.md",
        root / "reverse_engineering" / ".gitignore",
    ]
    missing = [path.relative_to(root).as_posix() for path in required if not path.is_file()]
    violations = [f"missing required reverse-engineering surface: {rel}" for rel in missing]
    try:
        from comma_lab.reverse_engineering import audit_reverse_engineering_tree, blocking_records
    except Exception as exc:  # pragma: no cover - import failure is environment-specific
        violations.append(f"cannot import comma_lab.reverse_engineering: {exc}")
        records = []
        blockers = []
    else:
        try:
            records = audit_reverse_engineering_tree(root)
            blockers = blocking_records(records)
        except Exception as exc:
            violations.append(f"reverse-engineering audit failed: {exc}")
            records = []
            blockers = []
        for record in blockers:
            violations.append(f"{record.relpath}: {record.disposition}: {record.reason}")
    if violations and strict:
        raise MetaBugViolation("REVERSE ENGINEERING TREE CURATION VIOLATIONS:\n" + "\n".join(violations))
    if verbose:
        if violations:
            print(f"  [reverse-engineering-curation] {len(violations)} violation(s)")
        else:
            print(f"  [reverse-engineering-curation] OK ({len(records)} file(s), {len(blockers)} blocker(s))")
    return violations


