def check_codex_inbox_open_questions_have_response_or_default_within_deadline(
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #333 - expired Codex inbox questions must be resolved.

    The Codex to Claude inbox is append-only; a question remains open until a
    later row answers it, withdraws it, or records that Codex invoked the
    declared operator default. This gate refuses stale unresolved questions so
    the persistent Codex loop cannot silently block on missing design judgment.
    """

    from tac.codex_to_claude_inbox import (
        EVENT_QUESTION,
        STATUS_OPEN,
        latest_status_by_event_id,
        load_inbox_strict,
    )

    root = Path(repo_root or REPO_ROOT)
    path = root / ".omx" / "state" / "codex_to_claude_inbox.jsonl"
    if not path.exists():
        if verbose:
            print("  [codex-inbox-deadlines] OK: inbox ledger absent")
        return []

    rows = load_inbox_strict(path)
    statuses = latest_status_by_event_id(path=path)
    now = _dt.datetime.now(_dt.UTC)
    violations: list[str] = []
    for row in rows:
        if row.get("event_type") != EVENT_QUESTION:
            continue
        event_id = str(row.get("event_id", ""))
        if statuses.get(event_id) != STATUS_OPEN:
            continue
        deadline_raw = row.get("response_deadline_utc")
        if not deadline_raw:
            continue
        text = str(deadline_raw)
        parse_text = text[:-1] + "+00:00" if text.endswith("Z") else text
        try:
            deadline = _dt.datetime.fromisoformat(parse_text)
        except ValueError as exc:
            violations.append(f"[Check 333] {event_id}: invalid response_deadline_utc={text!r}: {exc}")
            continue
        if deadline.tzinfo is None:
            deadline = deadline.replace(tzinfo=_dt.UTC)
        deadline = deadline.astimezone(_dt.UTC)
        if now >= deadline:
            task = row.get("blocking_task_id") or "<none>"
            violations.append(
                f"[Check 333] {event_id}: open Codex inbox question for blocking_task_id={task!r} "
                f"passed response_deadline_utc={text!r} without answer, withdrawal, or "
                "operator_default_invoked row"
            )

    if verbose:
        if violations:
            print(f"  [codex-inbox-deadlines] {len(violations)} expired open question(s)")
            for violation in violations[:5]:
                print(f"    - {violation[:240]}")
        else:
            print("  [codex-inbox-deadlines] OK: 0 expired open question(s)")

    if violations and strict:
        raise MetaBugViolation(
            "Codex inbox open questions past deadline:\n"
            + "\n".join(f"  - {v}" for v in violations[:5])
            + "\n\nFix: append a Claude answer, withdraw the question, or run "
            "`tools/codex_to_claude_inbox.py operator-default-invoked`."
        )
    return violations


# ── Catalog #343: CLAUDE.md frontier scores use canonical pointer ────────────
#
# Per CLAUDE.md "Frontier scores are pointer-only - NON-NEGOTIABLE" (added
# 2026-05-19): operator-facing surfaces MUST cite the canonical pointer file
# at ``.omx/state/canonical_frontier_pointer.json`` rather than embedding
# hardcoded score literals that drift over time.
#
# Bug class anchor: 2026-05-19 operator correction verbatim "your math and
# recollection is wrong regarding the leaderboard and frontier; we have a
# 0.19205 or something close to that but we havne't submitted a PR for it
# yet beause we thought we might be able to beat it". I had conflated
# ``0.19285`` (PR101 GOLD UPSTREAM baseline) with ``0.19205`` (our actual
# local frontier).
#
# The gate refuses NEW hardcoded score literals in CLAUDE.md that look like
# our-frontier / current-frontier / current-public-leaderboard scores.
# HISTORICAL-CONTEXT score literals (catalog row docstrings; postmortems;
# falsification verdicts; historical PR refs) are accepted via same-line
# ``# HISTORICAL_SCORE_LITERAL_OK:<rationale>`` waiver OR by an adjacent
# canonical pointer reference (see ``.omx/state/canonical_frontier_pointer
# .json`` OR per ``tools/refresh_canonical_frontier.py``) within ±5 lines.
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
# because CLAUDE.md carries dozens of historical anchors (PR102 / PR103 /
# PR101 / NSCS06 / etc.) that need backfill OR HISTORICAL-CONTEXT waivers;
# strict-flip planned after the backfill + waiver sweep.

_CHECK_343_FRONTIER_SCORE_RE = re.compile(
    r"\b0\.(?:19[0-9]{2,5}|20[0-9]{2,5})\b"
)
_CHECK_343_POINTER_REFERENCE_TOKENS: tuple[str, ...] = (
    "canonical_frontier_pointer.json",
    "tools/refresh_canonical_frontier.py",
    "tac.canonical_frontier_pointer",
    "CANONICAL_FRONTIER_POINTER_PATH",
)
_CHECK_343_LINE_WAIVER_MARKER = "FRONTIER_POINTER_LITERAL_OK"
_CHECK_343_HISTORICAL_WAIVER_MARKER = "HISTORICAL_SCORE_LITERAL_OK"
_CHECK_343_PLACEHOLDER_RATIONALES: frozenset[str] = frozenset({"<rationale>", "<reason>"})


def _check_343_waiver_has_real_rationale(line: str, marker: str) -> bool:
    """Return True if the line carries ``# <marker>:<rationale>`` with a real rationale.

    Placeholder ``<rationale>`` / ``<reason>`` literals are rejected so the
    gate's own docstring example cannot self-waive. Empty rationales after
    the colon are rejected too. Per Catalog #287 / #323 sister discipline.
    """

    marker_idx = line.find(marker + ":")
    if marker_idx < 0:
        return False
    after = line[marker_idx + len(marker) + 1 :].strip()
    if not after:
        return False
    # Strip trailing punctuation that might appear after a rationale.
    rationale = after.rstrip(" .,;-*/").strip()
    if not rationale or len(rationale) < 4:
        return False
    return rationale not in _CHECK_343_PLACEHOLDER_RATIONALES


def _check_343_pointer_reference_in_window(lines: list[str], index: int, window: int = 5) -> bool:
    """Return True if any pointer reference token appears within ±window lines."""

    start = max(0, index - window)
    end = min(len(lines), index + window + 1)
    for line in lines[start:end]:
        for token in _CHECK_343_POINTER_REFERENCE_TOKENS:
            if token in line:
                return True
    return False


def check_claude_md_frontier_score_uses_canonical_pointer_not_hardcoded(
    *,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #343 - CLAUDE.md must cite canonical pointer for frontier scores.

    Scans the repo's CLAUDE.md for score literals in the range our-frontier /
    current-public-leaderboard (``0.19xxx`` / ``0.20xxx``). Each literal must
    EITHER carry a same-line waiver (``# FRONTIER_POINTER_LITERAL_OK:<rationale>``
    or ``# HISTORICAL_SCORE_LITERAL_OK:<rationale>``) OR have a canonical
    pointer reference within ±5 lines.

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
    because legacy CLAUDE.md has dozens of historical score literals that
    need backfill (PR102 0.193 / PR103 0.195 / etc.).
    """

    root = Path(repo_root) if repo_root is not None else Path(".")
    claude_md = root / "CLAUDE.md"
    if not claude_md.is_file():
        if verbose:
            print("  [check-343] OK: CLAUDE.md absent")
        return []

    try:
        text = claude_md.read_text(encoding="utf-8")
    except OSError as exc:
        if verbose:
            print(f"  [check-343] WARN: read failure: {exc}")
        return []

    lines = text.splitlines()
    violations: list[str] = []
    for index, line in enumerate(lines):
        matches = list(_CHECK_343_FRONTIER_SCORE_RE.finditer(line))
        if not matches:
            continue
        # Acceptance cascade: same-line waiver?
        if _check_343_waiver_has_real_rationale(line, _CHECK_343_LINE_WAIVER_MARKER):
            continue
        if _check_343_waiver_has_real_rationale(line, _CHECK_343_HISTORICAL_WAIVER_MARKER):
            continue
        # Or: pointer reference within ±5 lines.
        if _check_343_pointer_reference_in_window(lines, index, window=5):
            continue
        # Otherwise: flag every score literal on this line.
        for match in matches:
            score = match.group(0)
            violations.append(
                f"[Check 343] CLAUDE.md:{index + 1}: hardcoded frontier score "
                f"{score!r} without canonical pointer reference or "
                "HISTORICAL_SCORE_LITERAL_OK waiver"
            )

    if verbose:
        if violations:
            print(
                f"  [check-343] {len(violations)} hardcoded frontier score literal(s) "
                "(warn-only at landing per Strict-flip atomicity rule)"
            )
            for violation in violations[:5]:
                print(f"    - {violation[:240]}")
        else:
            print("  [check-343] OK: no hardcoded frontier score literals without pointer")

    if violations and strict:
        raise PreflightError(
            "Catalog #343: CLAUDE.md hardcoded frontier score literals lack "
            "canonical pointer reference or HISTORICAL_SCORE_LITERAL_OK waiver.\n"
            + "\n".join(f"  - {v}" for v in violations[:5])
            + "\n\nFix: cite `.omx/state/canonical_frontier_pointer.json` adjacent "
            "(within +/-5 lines) OR add same-line waiver "
            "`# HISTORICAL_SCORE_LITERAL_OK:<rationale>` for historical context."
        )
    return violations


# ── Catalog #335: cathedral consumer directory canonical contract ────────────
#
# Per CATHEDRAL-AUTO-INGEST-PARADIGM-SHIFT 2026-05-19 (operator NON-NEGOTIABLE
# verbatim "fix permanently and self protect against" the orphan-signal class).
# Sister of Catalog #265 `check_symposium_impls_canonical_contract` (same
# canonical contract pattern at a different surface — symposium_impls/* vs
# cathedral_consumers/*).
#
# THE PARADIGM SHIFT: convention-over-configuration. Packages in
# src/tac/cathedral_consumers/ MUST satisfy
# tac.cathedral.consumer_contract.CathedralConsumerContract OR carry
# `# CATHEDRAL_CONSUMER_DEFERRED_OK:<rationale>` waiver in __init__.py first
# 30 lines. The auto-discovery loop at
# tools/cathedral_autopilot_autonomous_loop.discover_and_register_consumers
# ingests every compliant consumer WITHOUT manual ranker-cascade edits.

_CHECK_335_CONSUMER_DIR_RELPATH = "src/tac/cathedral_consumers"
_CHECK_335_EXEMPT_SUBDIRS: frozenset[str] = frozenset({"__pycache__", "tests"})


def check_cathedral_consumer_directory_package_exposes_canonical_contract(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #335 — cathedral_consumers/* exposes canonical contract.

    Per operator directive 2026-05-19 + CLAUDE.md "Bugs must be permanently
    fixed AND self-protected against" non-negotiable. Sister of Catalog
    #265 (symposium_impls canonical contract).

    Refuses any subdirectory under ``src/tac/cathedral_consumers/`` that
    is a Python package (contains ``__init__.py``) but does NOT satisfy
    :class:`tac.cathedral.consumer_contract.CathedralConsumerContract`.

    Acceptance: (a) package implements the canonical contract (validated
    via :func:`tac.cathedral.consumer_contract.validate_consumer_module`);
    (b) package carries same-line waiver
    ``# CATHEDRAL_CONSUMER_DEFERRED_OK:<rationale>`` in ``__init__.py``
    first 30 lines with non-placeholder rationale (≥4 chars; ``<rationale>``
    / ``<reason>`` placeholders rejected per Catalog #287 sister discipline).

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
    — live count at landing: 0 (the reference ``_example_consumer`` is
    contract-compliant and serves as the permanent positive fixture).
    Strict-flip atomic with the first NEW consumer landing (which by
    construction will be contract-compliant since the gate fires
    structurally before commit).

    Sister of Catalog #265 (symposium_impls 5-token contract) + Catalog
    #287 (placeholder-rationale rejection) + Catalog #125 (6-hook wire-in
    non-negotiable) + Catalog #176 (META-meta: STRICT callsites have
    CLAUDE.md row) + Catalog #185 (META-meta: Live count: 0 verified
    empirically).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    consumer_dir = root / _CHECK_335_CONSUMER_DIR_RELPATH
    if not consumer_dir.is_dir():
        if verbose:
            print(
                f"  [cathedral-consumer-contract] {_CHECK_335_CONSUMER_DIR_RELPATH} "
                "not present, skipping"
            )
        return []

    # Late import: the contract lives in tac.cathedral; avoid circular import
    # at preflight module load time.
    try:
        from tac.cathedral.consumer_contract import (
            discover_waiver_in_init,
            validate_consumer_module,
        )
    except ImportError as exc:
        # If the contract module is missing entirely, that IS a violation:
        # the canonical contract surface MUST be present alongside the
        # consumer directory.
        if strict:
            raise PreflightError(
                f"check_cathedral_consumer_directory_package_exposes_canonical_contract: "
                f"tac.cathedral.consumer_contract import failed: {exc}; Catalog #335 "
                "REQUIRES the canonical contract surface present alongside the "
                "consumer directory"
            )
        return [f"tac.cathedral.consumer_contract import failed: {exc}"]

    violations: list[str] = []
    import importlib

    for sub in sorted(consumer_dir.iterdir()):
        if not sub.is_dir():
            continue
        if sub.name in _CHECK_335_EXEMPT_SUBDIRS:
            continue
        init_path = sub / "__init__.py"
        if not init_path.exists():
            # Not a Python package; not a contract claim.
            continue

        module_dotted = f"tac.cathedral_consumers.{sub.name}"
        rel = str(sub.relative_to(root))

        # Check waiver FIRST (waiver shortcircuits contract validation).
        rationale, waiver_active = discover_waiver_in_init(init_path)
        if waiver_active:
            # Explicit operator-approved deferral; respect it.
            continue

        # Try contract validation.
        try:
            mod = importlib.import_module(module_dotted)
        except ImportError as exc:
            violations.append(
                f"{rel}: import failed ({type(exc).__name__}: {exc}); "
                "Catalog #335 requires every cathedral_consumers/* package to "
                "import cleanly + satisfy CathedralConsumerContract OR carry "
                "# CATHEDRAL_CONSUMER_DEFERRED_OK:<rationale> waiver in first 30 lines"
            )
            continue

        reg = validate_consumer_module(mod, module_path=module_dotted)
        if not reg.contract_compliant:
            error_summary = "; ".join(reg.validation_errors[:5])
            violations.append(
                f"{rel}: contract violation(s) [{error_summary}]; "
                "Catalog #335 requires CathedralConsumerContract OR same-line "
                "# CATHEDRAL_CONSUMER_DEFERRED_OK:<rationale> waiver in first 30 lines"
            )

    if verbose:
        print(f"  [cathedral-consumer-contract] {len(violations)} violation(s)")
    if violations and strict:
        raise PreflightError(
            "check_cathedral_consumer_directory_package_exposes_canonical_contract "
            f"found {len(violations)} violation(s). Catalog #335 enforces the "
            "canonical CathedralConsumerContract on src/tac/cathedral_consumers/* "
            "per CLAUDE.md 'Bugs must be permanently fixed AND self-protected "
            "against' non-negotiable (sister of Catalog #265):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ────────────────────────────────────────────────────────────────────────────
# Catalog #356 — per-axis decomposition carries canonical Provenance
# ────────────────────────────────────────────────────────────────────────────
#
# Per WAVE-1-DIM-3-PROTOCOL-AND-HELPER 2026-05-20 (operator blanket approval
# 2026-05-20 per CATHEDRAL-SMARTER-DESIGN-MEMO Dim 3 Steps 3.1-3.3) + CLAUDE.md
# "Apples-to-apples evidence discipline" + Catalog #287 / #323 sister discipline.
#
# Sister of Catalog #335 at the per-axis emission sub-surface. Where #335
# enforces the canonical Protocol contract at the package surface, #356
# enforces the canonical Provenance shape on the OPTIONAL
# ``predicted_axis_decomposition`` field a consumer MAY emit.
#
# Bug class: a cathedral consumer that emits ``predicted_axis_decomposition``
# without canonical Provenance can silently leak a per-axis prediction into
# the autopilot ranker's downstream consumers (Pareto polytope solver,
# bit-allocator) without the canonical axis_tag + hardware_substrate +
# evidence_grade triple per Catalog #323. Per CLAUDE.md "Forbidden
# empirical-claim-without-evidence-tag" + the meta-class extinction at
# Catalog #323, the canonical Provenance is the structural protection that
# per-axis predictions cannot be silently promoted to score signals or used
# without proper non-promotable markers per Catalog #341.
#
# Acceptance: (a) consumer package does not emit per-axis decomposition (the
# Catalog #341 backward-compat scalar-only path); (b) consumer's source
# carries the canonical Provenance import + non-empty Provenance construction
# adjacent to the per-axis emission; (c) same-line waiver
# ``# PER_AXIS_DECOMPOSITION_PROVENANCE_OK:<rationale>`` on the emission line
# with non-placeholder rationale (≥4 chars).
#
# Detection is intentionally LIBERAL (looks for the literal field name in any
# consumer's __init__.py); the structural protection is REQUIRING the
# canonical Provenance builder call OR explicit waiver in the same file. This
# is the same shape as Catalog #335 (package-level structural validation) +
# Catalog #287 (placeholder-rationale rejection).
#
# Memory: feedback_wave_1_dim_3_per_axis_decomposition_foundation_landed_20260520.

_CHECK_356_CONSUMER_DIR_RELPATH = "src/tac/cathedral_consumers"
_CHECK_356_EXEMPT_SUBDIRS: frozenset[str] = frozenset({"__pycache__", "tests"})
_CHECK_356_TRIGGER_TOKEN = "predicted_axis_decomposition"
# Canonical Provenance acceptance tokens (any one of these in the consumer's
# source within the same file satisfies the Provenance requirement).
_CHECK_356_PROVENANCE_TOKENS: tuple[str, ...] = (
    "build_provenance_for_predicted",
    "build_provenance_for_archive_member",
    "build_provenance_for_macos_cpu_advisory",
    "build_provenance_for_mps_proxy",
    "build_provenance_for_research_sidecar",
    "build_provenance_aggregate",
    "from tac.provenance",
    "provenance_to_dict",
    "canonical_provenance=",
)
_CHECK_356_WAIVER_TOKEN = "PER_AXIS_DECOMPOSITION_PROVENANCE_OK"
_CHECK_356_PLACEHOLDER_RATIONALES = frozenset(
    {"<rationale>", "<reason>", "rationale", "reason"}
)
_CHECK_356_MIN_RATIONALE_LEN = 4


def _check_356_extract_waiver_rationale(line: str) -> str | None:
    """Extract waiver rationale from a same-line ``# WAIVER_TOKEN:<rationale>``."""
    marker = f"# {_CHECK_356_WAIVER_TOKEN}:"
    idx = line.find(marker)
    if idx < 0:
        return None
    raw = line[idx + len(marker):].strip()
    # Strip trailing punctuation / quotes.
    rationale = raw.rstrip("'\"`*").strip()
    if not rationale:
        return None
    if rationale.lower() in _CHECK_356_PLACEHOLDER_RATIONALES:
        return None
    if len(rationale) < _CHECK_356_MIN_RATIONALE_LEN:
        return None
    return rationale


def check_per_axis_decomposition_carries_canonical_provenance(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #356 — per-axis decomposition emission carries Provenance.

    Per CATHEDRAL-SMARTER-DESIGN-MEMO Dim 3 Steps 3.1-3.3 + Catalog #287 /
    #323 sister discipline. Sister of Catalog #335 at the per-axis emission
    sub-surface.

    Refuses any subdirectory under ``src/tac/cathedral_consumers/`` whose
    ``__init__.py`` references the canonical trigger token
    ``predicted_axis_decomposition`` (the field a consumer would emit per
    CATHEDRAL-SMARTER-DESIGN-MEMO Dim 3 Step 3.1) WITHOUT either:

    1. A canonical Provenance builder import / construction in the same file
       (per ``_CHECK_356_PROVENANCE_TOKENS`` set covering
       ``build_provenance_for_predicted`` + sister builders + the
       ``canonical_provenance=`` keyword assignment); OR
    2. A same-line waiver
       ``# PER_AXIS_DECOMPOSITION_PROVENANCE_OK:<rationale>`` on the
       trigger-token line with non-placeholder rationale
       (≥4 chars; ``<rationale>`` / ``<reason>`` placeholders rejected per
       Catalog #287 sister discipline so the gate's docstring example
       cannot self-waive).

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
    — live count at landing: 0 (the canonical reference fixture
    ``_example_consumer`` does not yet emit per-axis decomposition; no
    production consumer has been migrated to Tier B yet per Dim 3 Step
    3.4 / Dim 6 Step 6.5). Strict-flip atomic with the first NEW per-axis
    emission landing (which by construction will carry canonical
    Provenance because the gate fires structurally before commit).

    Sister of:
    - Catalog #335 (canonical Protocol contract at the package surface;
      #356 is the per-axis sub-surface)
    - Catalog #287 (placeholder-rationale rejection)
    - Catalog #323 (canonical Provenance umbrella)
    - Catalog #125 (6-hook wire-in non-negotiable)
    - Catalog #176 (META-meta: STRICT callsites have CLAUDE.md row)
    - Catalog #185 (META-meta: Live count: 0 verified empirically)
    - Catalog #341 (Tier-A canonical-routing-markers; #356 preserves
      Tier-A backward-compat by gating on TRIGGER TOKEN presence, not
      forcing emission)
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    consumer_dir = root / _CHECK_356_CONSUMER_DIR_RELPATH
    if not consumer_dir.is_dir():
        if verbose:
            print(
                f"  [per-axis-provenance] {_CHECK_356_CONSUMER_DIR_RELPATH} "
                "not present, skipping"
            )
        return []

    violations: list[str] = []
    for sub in sorted(consumer_dir.iterdir()):
        if not sub.is_dir():
            continue
        if sub.name in _CHECK_356_EXEMPT_SUBDIRS:
            continue
        init_path = sub / "__init__.py"
        if not init_path.exists():
            continue

        try:
            with init_path.open("r", encoding="utf-8", errors="replace") as fh:
                text = fh.read()
        except OSError:
            continue

        # Quick reject: no trigger token in source → out of scope.
        if _CHECK_356_TRIGGER_TOKEN not in text:
            continue

        # Detect trigger token positions; check each line for waiver OR file-
        # level Provenance acceptance. The acceptance is FILE-WIDE because a
        # single canonical Provenance builder call serves multiple emissions
        # in the same consumer (e.g. one builder, multiple per-axis branches).
        has_provenance_token = any(
            tok in text for tok in _CHECK_356_PROVENANCE_TOKENS
        )

        # Per-line waiver check on every line containing the trigger token.
        trigger_lines: list[tuple[int, str]] = []
        for lineno, line in enumerate(text.splitlines(), start=1):
            if _CHECK_356_TRIGGER_TOKEN in line:
                trigger_lines.append((lineno, line))

        # If every trigger line has a valid waiver, the consumer is exempt.
        all_lines_waived = trigger_lines and all(
            _check_356_extract_waiver_rationale(line) is not None
            for _, line in trigger_lines
        )

        if has_provenance_token or all_lines_waived:
            continue

        rel = str(sub.relative_to(root))
        first_lineno = trigger_lines[0][0] if trigger_lines else 0
        violations.append(
            f"{rel}: emits `predicted_axis_decomposition` (first at line "
            f"{first_lineno}) without canonical Provenance "
            f"({', '.join(_CHECK_356_PROVENANCE_TOKENS[:3])}, ...) "
            f"OR same-line `# {_CHECK_356_WAIVER_TOKEN}:<rationale>` waiver. "
            "Catalog #356 requires canonical Provenance per Catalog #323 "
            "to prevent silent phantom-score leak into autopilot ranker "
            "via per-axis emission (CATHEDRAL-SMARTER-DESIGN-MEMO Dim 3)."
        )

    if verbose:
        print(
            f"  [per-axis-provenance] {len(violations)} violation(s) "
            f"(Catalog #356 WARN-ONLY initial wire-in)"
        )
    if violations and strict:
        raise PreflightError(
            "check_per_axis_decomposition_carries_canonical_provenance "
            f"found {len(violations)} violation(s). Catalog #356 enforces "
            "canonical Provenance on per-axis emission per "
            "CATHEDRAL-SMARTER-DESIGN-MEMO Dim 3 + Catalog #287 / #323:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


