def _check_203_project_dependency_names(pyproject_path: Path) -> set[str]:
    try:
        payload = tomllib.loads(pyproject_path.read_text(encoding="utf-8"))
    except (OSError, tomllib.TOMLDecodeError):
        return set()
    project = payload.get("project", {})
    if not isinstance(project, dict):
        return set()
    deps = project.get("dependencies", [])
    if not isinstance(deps, list):
        return set()
    names: set[str] = set()
    for dep in deps:
        if not isinstance(dep, str):
            continue
        name = re.split(r"[<>=!~;\[\]\s]", dep, maxsplit=1)[0].strip().lower()
        if name:
            names.add(name)
    return names


def _check_203_python_string_literals(path: Path) -> tuple[set[str], str | None]:
    try:
        text = path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        return set(), f"read error {exc!s}"
    try:
        tree = ast.parse(text)
    except SyntaxError as exc:
        return set(), f"syntax error {exc!s}"
    literals: set[str] = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Constant) and isinstance(node.value, str):
            literals.add(node.value)
    return literals, None


def check_modal_training_image_includes_hard_runtime_deps(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #203. Refuse Modal training images that omit hard runtime
    dependencies declared by ``pyproject.toml`` for entropy-coded archive
    paths.

    The check is deliberately narrow: it only guards dependencies that are both
    hard project runtime deps and known to be needed by PR86/PR91/PR101/PR103
    archive or packet-compiler surfaces. It does not require every project
    dependency in the Modal training image.
    """

    root = (repo_root or Path.cwd()).resolve()
    pyproject_path = root / _CHECK_203_PYPROJECT_PATH
    modal_path = root / _CHECK_203_MODAL_TRAINING_IMAGE_PATH
    violations: list[str] = []

    if not pyproject_path.is_file():
        violations.append(f"{_CHECK_203_PYPROJECT_PATH}: missing")
        project_deps: set[str] = set()
    else:
        project_deps = _check_203_project_dependency_names(pyproject_path)

    if not modal_path.is_file():
        violations.append(
            f"{_CHECK_203_MODAL_TRAINING_IMAGE_PATH}: missing canonical Modal "
            "training dispatcher"
        )
        modal_literals: set[str] = set()
    else:
        modal_literals, parse_error = _check_203_python_string_literals(modal_path)
        if parse_error:
            violations.append(
                f"{_CHECK_203_MODAL_TRAINING_IMAGE_PATH}: {parse_error}"
            )

    for dep_name, specs in _CHECK_203_HARD_RUNTIME_DEPS.items():
        pyproject_names = {name.lower() for name in specs["pyproject"]}
        if project_deps and dep_name not in project_deps and not (
            pyproject_names & project_deps
        ):
            continue
        if not any(spec in modal_literals for spec in specs["modal"]):
            violations.append(
                f"{_CHECK_203_MODAL_TRAINING_IMAGE_PATH}: Modal training image "
                f"omits hard runtime dependency `{dep_name}` required by "
                f"{_CHECK_203_PYPROJECT_PATH}; add one of "
                f"{', '.join(repr(s) for s in specs['modal'])} to pip_install."
            )

    for literal in _CHECK_203_REQUIRED_MODAL_ENV_LITERALS:
        if literal not in modal_literals:
            violations.append(
                f"{_CHECK_203_MODAL_TRAINING_IMAGE_PATH}: Modal training "
                f"runtime env omits required literal {literal!r}. General "
                "training lanes that run inline CUDA auth-eval must inherit "
                "DALI_DISABLE_NVML=1 and CUDA allocator config before "
                "upstream/evaluate.py starts."
            )

    if verbose:
        if violations:
            print(f"  [modal-training-runtime-deps] {len(violations)} violation(s):")
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [modal-training-runtime-deps] OK "
                "(Modal training image carries hard entropy runtime deps "
                "and CUDA/DALI env guards)"
            )

    if violations and strict:
        raise PreflightError(
            "check_modal_training_image_includes_hard_runtime_deps found "
            f"{len(violations)} contract violation(s). Modal training images "
            "must include pyproject hard entropy/runtime dependencies before "
            "paid provider dispatch:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# check_no_unwaived_pyppmd_imports
#
# The pyppmd package is LGPL-2.1-or-later. It is permitted only for narrow,
# explicitly reviewed public-archive replay / legacy wire-format paths. New
# imports must either use the canonical constriction/Brotli paths or carry a
# same-line waiver that states why PPMd compatibility is unavoidable.
# ----------------------------------------------------------------------------

_CHECK_PYPPMD_IMPORT_RE = re.compile(
    r"^\s*(?:from\s+pyppmd\b|import\s+pyppmd\b)"
)
_CHECK_PYPPMD_WAIVER_TOKEN = "PYPPMD_LGPL_OK:"


def check_no_unwaived_pyppmd_imports(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Refuse package-runtime ``pyppmd`` imports without an explicit waiver.

    The scan is intentionally scoped to ``src/tac`` package code and skips
    tests. Tests may exercise optional replay paths; package imports are the
    OSS/compliance-sensitive surface.
    """

    root = (repo_root or Path.cwd()).resolve()
    source_root = root / "src" / "tac"
    if not source_root.is_dir():
        return []

    violations: list[str] = []
    for path in sorted(source_root.rglob("*.py")):
        rel = path.relative_to(root).as_posix()
        if "/tests/" in f"/{rel}/":
            continue
        try:
            lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
        except OSError as exc:
            violations.append(f"{rel}: read error {exc!s}")
            continue
        for line_no, line in enumerate(lines, start=1):
            if not _CHECK_PYPPMD_IMPORT_RE.match(line):
                continue
            if _CHECK_PYPPMD_WAIVER_TOKEN in line:
                continue
            violations.append(
                f"{rel}:{line_no}: unwaived pyppmd import. pyppmd is "
                "LGPL-2.1-or-later; use a permissive codec path or add a "
                "same-line `PYPPMD_LGPL_OK:<rationale>` waiver for a narrow "
                "public-archive replay compatibility path."
            )

    if verbose:
        if violations:
            print(f"  [pyppmd-import-license] {len(violations)} violation(s):")
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [pyppmd-import-license] OK "
                "(all package pyppmd imports are explicitly waived)"
            )

    if violations and strict:
        raise PreflightError(
            "check_no_unwaived_pyppmd_imports found "
            f"{len(violations)} unwaived package import(s). pyppmd may only "
            "remain in explicitly waived public-archive replay compatibility "
            "paths:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #204 - check_pr95plus_modal_smoke_uses_durable_provider_output
# ----------------------------------------------------------------------------

_CHECK_204_REMOTE_LANE_PATH = (
    "scripts/remote_lane_substrate_pr101_lc_v2_clone_enhanced_curriculum.sh"
)
_CHECK_204_TRAINER_PATH = (
    "experiments/train_substrate_pr101_lc_v2_clone_enhanced_curriculum.py"
)
_CHECK_204_MODAL_DISPATCHER_PATH = "experiments/modal_train_lane.py"
_CHECK_204_SUBSTRATE_DRIVER_GLOB = "scripts/remote_lane_substrate_*.sh"
# Canonical 3-branch shape: an elif MODAL_RUNTIME=="1" block whose body
# assigns OUTPUT_DIR to /modal_results/<job>/output. Allows optional
# `&& [ -d "/modal_results" ]` clause and whitespace/comments between the
# elif and the OUTPUT_DIR assignment.
_CHECK_204_CROSS_DRIVER_THREE_BRANCH_RE = re.compile(
    r'elif\s*\[\s*"\$\{MODAL_RUNTIME:-0\}"\s*=\s*"1"\s*\]'
    r'(?:\s*&&\s*\[\s*-d\s*"/modal_results"\s*\])?'
    r'\s*;\s*then[\s\S]{0,400}?OUTPUT_DIR\s*=\s*"?/modal_results/',
    re.MULTILINE,
)
# Same-line waiver for the rare deliberate non-Modal driver or scaffold.
_CHECK_204_CROSS_DRIVER_WAIVER_RE = re.compile(
    r"#\s*CATALOG_204_CROSS_DRIVER_WAIVED:\s*(\S.{2,})"
)


def check_pr95plus_modal_smoke_uses_durable_provider_output(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #204. Keep PR95++ Modal smoke auth-eval evidence off ``/tmp``.

    The 2026-05-14 clean-head PR95++ smoke reached inline
    ``contest_auth_eval.py`` and failed closed because the score JSON was under
    ``/tmp/pact``. The correct fix is durable provider output, not the
    diagnostic ``--allow-temp-work-dir`` bypass.

    Cross-driver expansion (2026-05-19): per the Catalog #244 NVML wave
    precedent, the gate ALSO refuses any ``scripts/remote_lane_substrate_*.sh``
    driver that fails to route OUTPUT_DIR through the canonical 3-branch
    Modal-aware resolution. Sister anchors: ``stack_of_stacks`` (commit
    ``956ad2e76`` 2026-05-19) + ``stc_v2`` 2026-05-14 hit the same bug class
    that the PR95++ anchor surfaces. Cross-driver scope-extension extincts
    the class structurally across all 50 substrate drivers.

    Acceptance per driver:
      (a) Driver matches the canonical 3-branch shape
          ``elif [ "${MODAL_RUNTIME:-0}" = "1" ] ... ; then\\n    OUTPUT_DIR="/modal_results/..."``.
      (b) Driver has no ``OUTPUT_DIR=`` assignment at all (the rare scaffold
          that never writes archive/runtime/auth-eval evidence).
      (c) Same-line ``# CATALOG_204_CROSS_DRIVER_WAIVED:<rationale>`` waiver
          on any ``OUTPUT_DIR=`` line; rationale must be non-trivial.
    """

    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []

    remote_path = root / _CHECK_204_REMOTE_LANE_PATH
    if not remote_path.is_file():
        violations.append(f"{_CHECK_204_REMOTE_LANE_PATH}: missing")
        remote_text = ""
    else:
        remote_text = remote_path.read_text(encoding="utf-8")
        if 'OUTPUT_DIR="${PR95PLUS_OUTPUT_DIR:-$LOG_DIR/output}"' in remote_text:
            violations.append(
                f"{_CHECK_204_REMOTE_LANE_PATH}: PR95PLUS output still defaults "
                "to $LOG_DIR/output under the Modal /tmp workspace"
            )
        for snippet in (
            'OUTPUT_DIR="/modal_results/${DISPATCH_INSTANCE_JOB_ID}/output"',
            'elif [ "${MODAL_RUNTIME:-0}" = "1" ] && [ -d "/modal_results" ]; then',
            'export CUBLAS_WORKSPACE_CONFIG="${CUBLAS_WORKSPACE_CONFIG:-:4096:8}"',
        ):
            if snippet not in remote_text:
                violations.append(
                    f"{_CHECK_204_REMOTE_LANE_PATH}: missing durable Modal "
                    f"smoke contract snippet {snippet!r}"
                )

    trainer_path = root / _CHECK_204_TRAINER_PATH
    if not trainer_path.is_file():
        violations.append(f"{_CHECK_204_TRAINER_PATH}: missing")
    else:
        trainer_text = trainer_path.read_text(encoding="utf-8")
        if "--allow-temp-work-dir" in trainer_text:
            violations.append(
                f"{_CHECK_204_TRAINER_PATH}: trainer must not pass "
                "--allow-temp-work-dir for PR95++ smoke score custody"
            )

    modal_path = root / _CHECK_204_MODAL_DISPATCHER_PATH
    if not modal_path.is_file():
        violations.append(f"{_CHECK_204_MODAL_DISPATCHER_PATH}: missing")
    else:
        modal_text = modal_path.read_text(encoding="utf-8")
        if "volume_dir," not in modal_text:
            violations.append(
                f"{_CHECK_204_MODAL_DISPATCHER_PATH}: Modal recovery artifact "
                "scan_roots must include volume_dir so /modal_results outputs "
                "are returned by modal_recover_lane.py"
            )

    # Cross-driver expansion: every substrate driver must use the canonical
    # 3-branch OUTPUT_DIR resolution (or carry a same-line waiver).
    scripts_dir = root / "scripts"
    if scripts_dir.is_dir():
        for driver_path in sorted(
            scripts_dir.glob("remote_lane_substrate_*.sh")
        ):
            try:
                driver_text = driver_path.read_text(encoding="utf-8")
            except (OSError, UnicodeDecodeError):
                continue
            if "OUTPUT_DIR=" not in driver_text:
                # Acceptance (b): scaffold driver with no OUTPUT_DIR — out of scope.
                continue
            if _CHECK_204_CROSS_DRIVER_THREE_BRANCH_RE.search(driver_text):
                continue
            # Acceptance (c): same-line waiver on any OUTPUT_DIR= line.
            waiver_present = False
            for line in driver_text.splitlines():
                if "OUTPUT_DIR=" in line and not line.lstrip().startswith("#"):
                    m = _CHECK_204_CROSS_DRIVER_WAIVER_RE.search(line)
                    if m and m.group(1).strip() not in {
                        "<rationale>", "<reason>", "",
                    }:
                        waiver_present = True
                        break
            if waiver_present:
                continue
            rel = driver_path.relative_to(root).as_posix()
            violations.append(
                f"{rel}: substrate driver missing canonical 3-branch "
                "OUTPUT_DIR Modal-aware resolution (Catalog #204 cross-driver "
                "expansion). Apply pattern from "
                "scripts/remote_lane_substrate_pr101_lc_v2_clone_enhanced_curriculum.sh "
                "lines 50-59 or add # CATALOG_204_CROSS_DRIVER_WAIVED:<rationale>"
            )

    if verbose:
        if violations:
            print(f"  [pr95plus-durable-modal-output] {len(violations)} violation(s):")
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [pr95plus-durable-modal-output] OK "
                "(PR95++ Modal smoke writes auth-eval custody under /modal_results; "
                "all substrate drivers route to durable provider output)"
            )

    if violations and strict:
        raise PreflightError(
            "check_pr95plus_modal_smoke_uses_durable_provider_output found "
            f"{len(violations)} contract violation(s). PR95++ Modal smoke + "
            "all substrate drivers must write archive/runtime/auth-eval "
            "evidence under durable provider storage and recover that path, "
            "not bypass temp-output custody:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #167 - check_substrate_dispatch_uses_smoke_before_full_pattern
#
# PHASE-B1-PIVOT bug-class anchor (2026-05-12). Two consecutive 2000-epoch
# sane_hnerv Modal A100 dispatches crashed rc=1 within 15s and 72s respectively
# - burned $0.30 + a harvest slot each. A 100-epoch ~$0.30 smoke would have
# caught the integration failure for the same cost; the operator could have
# fixed the integration BEFORE the $5-15 full canary fired.
#
# This gate refuses ``scripts/operator_authorize_substrate_*_modal_*.sh``
# operator-authorize wrappers whose corresponding recipe declares
# ``cost_band.epochs >= 1000`` (a "full" canary by canonical convention)
# WITHOUT routing through ``tools/run_modal_smoke_before_full.py`` (the
# canonical wrapper that fires a 100-epoch smoke first, validates rc=0 +
# auth-eval ran + score-in-band, and only proceeds to the full dispatch on
# smoke-green).
#
# Same-line waiver on the dispatch invocation line: ``# SMOKE_BEFORE_FULL_OK:
# <reason>`` reserved for established trainers with >=3 successful Modal
# anchors at the target config (cost band is empirically calibrated; smoke
# would not surface new info).
#
# Sister of Catalog #146 (trainer runtime contract) + Catalog #151
# (env->CLI flag wire-up) + Catalog #152 (required-input validation) +
# Catalog #166 (HEAD parity ledger).
# ----------------------------------------------------------------------------

_CHECK_167_WRAPPER_GLOB = "scripts/operator_authorize_substrate_*_modal_*.sh"
_CHECK_167_RECIPE_DIR = ".omx/operator_authorize_recipes"
_CHECK_167_FULL_EPOCHS_THRESHOLD = 1000
_CHECK_167_SMOKE_TOOL_NAME = "run_modal_smoke_before_full"
_CHECK_167_WAIVER_TOKEN = "# SMOKE_BEFORE_FULL_OK:"


def _check_167_extract_recipe_epochs(recipe_text: str) -> int | None:
    """Parse the YAML-ish ``cost_band.epochs`` value out of a recipe.

    The recipe schema is small and ad-hoc; we use simple line-scanning rather
    than pulling pyyaml as a runtime dep. Returns the integer epoch count or
    None if the field is missing/unparseable.
    """
    in_cost_band = False
    for line in recipe_text.splitlines():
        stripped = line.rstrip()
        if not stripped or stripped.lstrip().startswith("#"):
            continue
        # Top-level "cost_band:" opens the block; any other top-level key
        # (no leading whitespace, ends in ":") closes it.
        if not line.startswith(" ") and not line.startswith("\t"):
            in_cost_band = stripped.startswith("cost_band:")
            continue
        if in_cost_band and "epochs:" in stripped:
            value = stripped.split("epochs:", 1)[1].strip().strip('"').strip("'")
            try:
                return int(value)
            except ValueError:
                return None
    return None


def check_substrate_dispatch_uses_smoke_before_full_pattern(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #167. Refuse operator-authorize wrappers that fire a "full"
    canary without routing through the canonical smoke-before-full helper.

    A wrapper is a "full" canary when its recipe declares
    ``cost_band.epochs >= 1000``. The canonical helper is
    ``tools/run_modal_smoke_before_full.py``. Same-line waiver
    ``# SMOKE_BEFORE_FULL_OK:<reason>`` on the dispatch invocation line is
    accepted for established trainers.
    """
    root = (repo_root or Path.cwd()).resolve()
    wrappers_root = root / "scripts"
    recipes_root = root / _CHECK_167_RECIPE_DIR

    violations: list[str] = []

    if not wrappers_root.is_dir():
        return violations

    for wrapper in sorted(wrappers_root.glob("operator_authorize_substrate_*_modal_*.sh")):
        try:
            wrapper_text = wrapper.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            violations.append(
                f"{wrapper.relative_to(root)}: read error {exc!s}"
            )
            continue

        # Same-line waiver -> short-circuit the entire wrapper.
        if _CHECK_167_WAIVER_TOKEN in wrapper_text:
            continue

        # Resolve the recipe name from the wrapper. Convention:
        # `scripts/operator_authorize_<recipe_name>.sh` invokes
        # `--recipe <recipe_name>`. We sniff for either the `--recipe X`
        # token or the wrapper's stem-derived name.
        recipe_name: str | None = None
        for line in wrapper_text.splitlines():
            if "--recipe" in line:
                parts = line.split("--recipe", 1)[1].strip().split()
                if parts:
                    recipe_name = parts[0].strip("\\").strip("'\"")
                    break
        if not recipe_name:
            recipe_name = wrapper.stem.replace("operator_authorize_", "")
        recipe_path = recipes_root / f"{recipe_name}.yaml"
        if not recipe_path.is_file():
            # No recipe -> outside Catalog #167 scope (probably old style
            # wrapper; wired later if/when the recipe lands).
            continue
        try:
            recipe_text = recipe_path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            violations.append(
                f"{recipe_path.relative_to(root)}: read error {exc!s}"
            )
            continue

        epochs = _check_167_extract_recipe_epochs(recipe_text)
        if epochs is None or epochs < _CHECK_167_FULL_EPOCHS_THRESHOLD:
            # Not a "full" canary; smoke-before-full is not required.
            continue

        # The wrapper IS firing a full canary. It must invoke the canonical
        # smoke-before-full helper somewhere in its body OR carry the waiver.
        if _CHECK_167_SMOKE_TOOL_NAME not in wrapper_text:
            violations.append(
                f"{wrapper.relative_to(root)} fires a full canary "
                f"({epochs} epochs from {recipe_path.relative_to(root)}) "
                "without routing through "
                f"`tools/{_CHECK_167_SMOKE_TOOL_NAME}.py`. Add the smoke-"
                "before-full call OR carry a same-line "
                f"`{_CHECK_167_WAIVER_TOKEN}<reason>` waiver if the trainer "
                "has >=3 successful Modal anchors at the target config."
            )

    if verbose:
        if violations:
            print(
                f"  [smoke-before-full] {len(violations)} violation(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [smoke-before-full] OK "
                "(every full-canary wrapper routes through the canonical "
                "smoke helper or carries an explicit waiver)"
            )

    if violations and strict:
        raise PreflightError(
            "check_substrate_dispatch_uses_smoke_before_full_pattern found "
            f"{len(violations)} violation(s). Catalog #167 (PHASE-B1-PIVOT) "
            "refuses full Modal canaries that skip the 100-epoch smoke that "
            "would have caught two sane_hnerv crashes in 2026-05-12 for "
            "$0.30 each instead of $5-15 each:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #168: check_ast_walker_handles_both_assign_and_annassign
# ============================================================================
# META-CLASS gate: refuses any AST extractor function that filters by
# `ast.Assign` ONLY without also handling `ast.AnnAssign`. The bug class
# silently bypasses static analysis when the target code uses annotated
# assignment syntax (`name: type = value`).
#
# Bug-class anchor: 2026-05-12 META-CATALOG-152-FIX. The
# `_check_151_extract_tier_manifests` AST walker filtered `ast.Assign` only.
# Substrate trainers (sane_hnerv, balle, SIREN, Cool-Chic, VQ-VAE, hybrid_*,
# self_compress, TCNeRV, BlockNeRV, FFNeRV, DSNeRV, HiNeRV) declare the
# manifest as `TIER_<N>_OPERATOR_REQUIRED_FLAGS: dict[str, dict[str, Any]]
# = {...}` (`ast.AnnAssign`), so 12/12 substrate trainers silently returned
# empty manifests -- making Catalog #151 + #152 STRICT modes structurally
# false-OK across the entire substrate canvas. WAVE-1-A (VQ-VAE subagent)
# confirmed; PHASE-B2-BUILD subagent caught the architecture gap.
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against":
# the structural fix is a META-CLASS gate that refuses ANY future surface
# that re-introduces the same Assign-only walk. AST extractor sites that
# legitimately need only Assign (e.g. parsing PEP 8 module-level constants
# where annotation is forbidden) must carry the same-line waiver
# `# ASSIGN_ONLY_OK:<reason>`.

_CHECK_168_SCAN_DIRS = ("src/tac", "tools", "experiments")
# Require a real rationale after the colon. Reject the literal placeholder
# `<reason>` (which appears in this gate's own docstring/source) so the
# gate doesn't waive itself accidentally.
_CHECK_168_WAIVER_RE = re.compile(
    r"#\s*ASSIGN_ONLY_OK:\s*(?!<reason>)\S+"
)
# Files that legitimately walk only `ast.Assign` for non-extraction reasons
# (e.g. tests that intentionally exercise the Assign-only path), or are this
# check's own definition / test file.
# File-level waiver marker. We require a real rationale (not the literal
# placeholder `<reason>`) so the literal token appearing in this gate's own
# docstring/source is NOT a self-waiver.
_CHECK_168_FILE_LEVEL_WAIVER_RE = re.compile(
    r"#\s*CHECK_168_FILE_LEVEL_WAIVED:\s*(?!<reason>)\S+"
)
_CHECK_168_EXEMPT_FILES = (
    "src/tac/tests/test_check_168_ast_walker_handles_assign_and_annassign.py",
)
# Per Catalog #113 artifact-lifecycle: DERIVED_OUTPUT / vendored-intake /
# OSS-export-mirror trees are reproduction snapshots, not active code that
# the gate should police. Sister exclusion to Catalog #109 + #151's
# `_CHECK_151_EXCLUDED_PATH_MARKERS`.
_CHECK_168_EXCLUDED_PATH_MARKERS = (
    "experiments/results/",  # build artifacts (DERIVED_OUTPUT per #113)
    "_intake_",
    ".omx/oss_export/",
    "vendored",
)


def _check_168_isinstance_filters_assign_only(
    node: ast.AST,
) -> bool:
    """Return True iff `node` is an `isinstance(_, ast.Assign)` call WITHOUT
    a sibling reference to `ast.AnnAssign` in the same isinstance type-tuple.

    Accepted (correct dual handling) at this CALL level:
      isinstance(x, (ast.Assign, ast.AnnAssign))      -> OK
      isinstance(x, (ast.AnnAssign, ast.Assign))      -> OK

    Rejected (Assign-only) at this CALL level:
      isinstance(x, ast.Assign)                       -> CANDIDATE
      isinstance(x, (ast.Assign,))                    -> CANDIDATE
      isinstance(x, (ast.Assign, ast.AugAssign))      -> CANDIDATE
        (AugAssign is augmented assign `x += y`, NOT annotated assign)

    NOTE: Returns CANDIDATE status. The caller must additionally check
    enclosing-scope context (sister `isinstance(_, ast.AnnAssign)` call in
    the SAME function/method/module-level for-loop body) to suppress the
    common if/elif chain pattern where each AST node-kind is handled in
    its own branch.
    """
    if not isinstance(node, ast.Call):
        return False
    func = node.func
    if not (isinstance(func, ast.Name) and func.id == "isinstance"):
        return False
    if len(node.args) < 2:
        return False
    type_arg = node.args[1]
    # Collect every `ast.<Name>` reference inside the type-arg.
    referenced: set[str] = set()
    for sub in ast.walk(type_arg):
        if isinstance(sub, ast.Attribute) and isinstance(sub.value, ast.Name):
            if sub.value.id == "ast":
                referenced.add(sub.attr)
    # Trigger only if `ast.Assign` is referenced AND `ast.AnnAssign` is NOT.
    if "Assign" not in referenced:
        return False
    if "AnnAssign" in referenced:
        return False
    return True


def _check_168_scope_handles_annassign(
    scope_node: ast.AST,
) -> bool:
    """Return True iff `scope_node` (a function, method, or module) contains
    AT LEAST ONE `isinstance(_, ast.AnnAssign)` call anywhere in its body.

    This is the if/elif chain accept rule: a function whose body has

        if isinstance(node, ast.Assign):
            handle_assign(...)
        elif isinstance(node, ast.AnnAssign):
            handle_annassign(...)

    legitimately filters by Assign at the first branch BECAUSE the second
    branch handles AnnAssign. The Catalog #168 META class is only a real bug
    when AnnAssign is NEVER referenced anywhere in the same scope.
    """
    for sub in ast.walk(scope_node):
        if not isinstance(sub, ast.Call):
            continue
        func = sub.func
        if not (isinstance(func, ast.Name) and func.id == "isinstance"):
            continue
        if len(sub.args) < 2:
            continue
        for inner in ast.walk(sub.args[1]):
            if (isinstance(inner, ast.Attribute)
                    and isinstance(inner.value, ast.Name)
                    and inner.value.id == "ast"
                    and inner.attr == "AnnAssign"):
                return True
    return False


def _check_168_enclosing_scope(
    target_node: ast.AST,
    tree: ast.Module,
) -> ast.AST:
    """Find the smallest enclosing FunctionDef / AsyncFunctionDef / ClassDef
    that contains `target_node`, falling back to the module.
    """
    best: ast.AST = tree
    for ancestor in ast.walk(tree):
        if not isinstance(
            ancestor,
            (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef),
        ):
            continue
        for sub in ast.walk(ancestor):
            if sub is target_node:
                # Pick the smallest scope (innermost). We approximate by
                # function definitions because preflight extractors are
                # typically module-top function bodies.
                best = ancestor
                break
    return best


def _check_168_line_has_waiver(text_line: str) -> bool:
    return bool(_CHECK_168_WAIVER_RE.search(text_line))


def _check_168_file_has_waiver(text: str) -> bool:
    return bool(_CHECK_168_FILE_LEVEL_WAIVER_RE.search(text))


def check_ast_walker_handles_both_assign_and_annassign(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #168. META-CLASS gate. Refuses AST extractor sites that walk
    only `ast.Assign` without also handling `ast.AnnAssign`.

    Scan scope: every `.py` file under `src/tac/`, `tools/`, `experiments/`.

    Acceptance:
      - The isinstance type-tuple references both `ast.Assign` AND `ast.AnnAssign`.
      - Same-line waiver `# ASSIGN_ONLY_OK:<reason>` (annotated assign genuinely
        irrelevant for the surface — e.g. a parser of PEP 8 `__all__` lists,
        or a security check looking at unannotated dynamic-eval RHS).
      - File-level waiver `# CHECK_168_FILE_LEVEL_WAIVED:<reason>` for files
        that are testing the violation behavior (e.g. this check's own tests).
      - Files in `_CHECK_168_EXEMPT_FILES` (this check's test file).
    """
    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    scanned = 0
    source_index = _current_source_index(root)
    if source_index is not None:
        py_files = source_index.files_containing_substrings(
            _CHECK_168_SCAN_DIRS,
            pattern="*.py",
            substrings=("isinstance", "ast.Assign"),
            require_all=True,
        )
    else:
        rg_candidates = _rg_python_files_matching_regex(
            root,
            _CHECK_168_SCAN_DIRS,
            r"ast\.Assign",
        )
        if rg_candidates is not None:
            py_files = rg_candidates
        else:
            py_file_list: list[Path] = []
            for scan_dir in _CHECK_168_SCAN_DIRS:
                scan_root = root / scan_dir
                if scan_root.is_dir():
                    py_file_list.extend(scan_root.rglob("*.py"))
            py_files = tuple(sorted(py_file_list, key=lambda item: item.as_posix()))

    for py_file in py_files:
        try:
            rel = py_file.relative_to(root).as_posix()
        except ValueError:
            continue
        if rel in _CHECK_168_EXEMPT_FILES:
            continue
        if any(marker in rel for marker in _CHECK_168_EXCLUDED_PATH_MARKERS):
            continue
        try:
            text = (
                source_index.read_text(py_file)
                if source_index is not None
                else py_file.read_text(encoding="utf-8", errors="replace")
            )
        except (UnicodeDecodeError, OSError):
            if source_index is None:
                continue
            try:
                text = source_index.read_text(
                    py_file,
                    encoding="utf-8",
                    errors="replace",
                )
            except OSError:
                continue
        if "isinstance" not in text or "ast.Assign" not in text:
            continue
        scanned += 1
        if _check_168_file_has_waiver(text):
            continue
        try:
            tree = (
                source_index.python_ast(py_file)
                if source_index is not None
                else ast.parse(text, filename=str(py_file))
            )
        except (SyntaxError, UnicodeDecodeError, OSError):
            try:
                tree = ast.parse(text, filename=str(py_file))
            except SyntaxError:
                continue
        lines = text.splitlines()
        for node in ast.walk(tree):
            if not _check_168_isinstance_filters_assign_only(node):
                continue
            lineno = getattr(node, "lineno", 0)
            if lineno <= 0 or lineno > len(lines):
                continue
            # Same-line waiver respects either the isinstance line OR
            # the immediately preceding line (multi-line isinstance
            # callsite indent style).
            line_idx = lineno - 1
            target_lines = [lines[line_idx]]
            if line_idx > 0:
                target_lines.append(lines[line_idx - 1])
            if any(_check_168_line_has_waiver(L) for L in target_lines):
                continue
            # Scope-aware accept: if the enclosing function/method ALSO
            # contains an `isinstance(_, ast.AnnAssign)` call, the
            # if/elif chain pattern handles AnnAssign separately and
            # the Assign-only branch is correct by design.
            scope = _check_168_enclosing_scope(node, tree)
            if _check_168_scope_handles_annassign(scope):
                continue
            snippet = lines[line_idx].strip()[:200]
            violations.append(
                f"{rel}:{lineno}: AST extractor walks `ast.Assign` only "
                f"without `ast.AnnAssign`; annotated assignments will be "
                f"silently skipped. Update to "
                f"`isinstance(x, (ast.Assign, ast.AnnAssign))` and handle "
                f"the AnnAssign branch (single `node.target` not `node.targets`, "
                f"check `node.value is not None`). Same-line waiver "
                f"`# ASSIGN_ONLY_OK:<reason>` if annotated assign is genuinely "
                f"irrelevant for this surface.\n    Code: {snippet}"
            )

    if verbose:
        if violations:
            print(
                f"  [ast-walker-assign-vs-annassign] {len(violations)} "
                f"violation(s) across {scanned} file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:300]}")
        else:
            print(
                f"  [ast-walker-assign-vs-annassign] OK ({scanned} file(s) scanned; "
                "0 Assign-only AST extractor surface(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_ast_walker_handles_both_assign_and_annassign found "
            f"{len(violations)} META-CLASS violation(s). Catalog #168 closes "
            "the AST-extractor type-annotation-syntax bypass class anchored "
            "by 2026-05-12 META-CATALOG-152-FIX (12 substrate trainer "
            "manifests silently false-OK):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


