# ─────────────────────────────────────────────────────────────────────────
# Catalog #185 — check_strict_flipped_catalog_entries_have_live_count_zero
# (FIX-CRITICAL R5-4 META-meta-meta, 2026-05-13, STRICT @ 0)
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (R5-4 anchor 2026-05-13): CLAUDE.md Catalog #124 description
# claimed "Live count: 0 → STRICT" but `preflight --scope all` returned
# 4 violations (lane_wave3_tcnerv_trainer_build_20260512,
# lane_wave3_blocknerv_trainer_build_20260512,
# lane_sane_hnerv_archive_fix_catalog_161_20260513,
# lane_ffnerv_build_20260513). The catalog text was the source-of-truth
# strictness ledger per CLAUDE.md non-negotiable, but in-flight subagent
# lanes drifted the gate's actual live-count above 0 without the catalog
# entry being updated. Sister to Catalog #159
# (`check_claude_md_catalog_text_matches_preflight_strict_value`) which
# catches WARN-ONLY-vs-STRICT drift; this gate catches LIVE-COUNT-ZERO
# drift specifically.
#
# Scope: iterate every CLAUDE.md catalog entry that simultaneously claims
# (a) "Live count: 0" / "live count = 0" / "0 -> STRICT" phrasing AND
# (b) one of the STRICT-flipped phrases (sister of Catalog #159's
# _CHECK_159_STRICT_PHRASES). For each matched entry, look up the
# corresponding `check_*` function via this module's globals(), call it
# with strict=False+verbose=False, and refuse if the returned list is
# non-empty.
#
# Safety:
#   * Only entries with BOTH the live-count-zero claim AND a strict
#     phrase are introspected (skips entries that are warn-only or that
#     don't explicitly claim count=0).
#   * Each gate is called with strict=False so it cannot raise; the
#     returned violation list is what matters.
#   * Self-reference is rejected (the gate does not call itself).
#   * Functions in `_CHECK_183_SKIP_FUNCTIONS` are skipped to avoid
#     expensive or stateful sweeps (e.g. preflight_all callers, gates
#     that require explicit kwargs).
#   * Repository-root-relative invocation; no /tmp paths.
#

_CHECK_185_LIVE_COUNT_ZERO_PHRASES: tuple[str, ...] = (
    "live count: 0",
    "live count = 0",
    "live count of 0",
    "live count zero",
    "0 -> strict",
    "0 → strict",
    "0 to strict",
)

# Functions Catalog #185 will NOT invoke directly to keep the runtime
# bounded. Each entry must have a reason. The skip list is conservative;
# the goal is to catch entries like #124 where the gate is cheap to call,
# not to introspect every gate.
_CHECK_185_SKIP_FUNCTIONS: frozenset[str] = frozenset({
    # Self-reference (recursion guard).
    "check_strict_flipped_catalog_entries_have_live_count_zero",
    # Sister text-vs-callsite gate; calling it from here is redundant
    # because it is already wired strict in preflight_all().
    "check_claude_md_catalog_text_matches_preflight_strict_value",
    # Catalog header / numbering protection gates (text-shape only).
    "check_claude_md_catalog_no_duplicate_numbers",
    # Gates that require non-default kwargs (the bare 0-arg call would
    # produce false-negatives). The full preflight_all() callsite owns
    # their invocation; this META-meta-meta gate only protects the
    # zero-shot live-count claim.
    "preflight_all",
})


def _check_185_extract_strict_zero_entries(
    claude_md_text: str,
) -> list[tuple[int, str, str]]:
    """Extract (catalog_num, check_name, body) tuples for entries that
    simultaneously claim STRICT @ 0 and Live count: 0.
    """
    entries = _check_159_extract_catalog_entries(claude_md_text)
    matched: list[tuple[int, str, str]] = []
    for cat_num, check_name, body in entries:
        body_lower = body.lower()
        has_zero_claim = any(
            phrase in body_lower
            for phrase in _CHECK_185_LIVE_COUNT_ZERO_PHRASES
        )
        if not has_zero_claim:
            continue
        has_strict = any(
            phrase in body_lower
            for phrase in _CHECK_159_STRICT_PHRASES
        )
        if not has_strict:
            continue
        matched.append((cat_num, check_name, body))
    return matched


def check_strict_flipped_catalog_entries_have_live_count_zero(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #185 — refuse CLAUDE.md catalog entries claiming Live
    count: 0 + STRICT phrasing when the underlying gate function
    actually returns a non-empty violation list.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
    against" non-negotiable, the catalog table is the canonical
    strictness ledger and must remain in lock-step with the gate
    function's empirical behavior. Sister of Catalog #159
    (`check_claude_md_catalog_text_matches_preflight_strict_value`).
    """
    root = (repo_root or Path.cwd()).resolve()
    claude_md = root / "CLAUDE.md"
    if not claude_md.is_file():
        return []
    try:
        claude_text = claude_md.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return []
    violations: list[str] = []
    matched = _check_185_extract_strict_zero_entries(claude_text)
    scanned = 0
    not_found: list[str] = []
    skipped: list[str] = []
    for cat_num, check_name, _body in matched:
        if check_name in _CHECK_185_SKIP_FUNCTIONS:
            skipped.append(check_name)
            continue
        fn = globals().get(check_name)
        if fn is None or not callable(fn):
            not_found.append(check_name)
            violations.append(
                f"Catalog #{cat_num} `{check_name}`: CLAUDE.md claims "
                "'Live count: 0' + STRICT but no callable gate with that name "
                "exists in tac.preflight. Missing strict gates cannot certify "
                "zero live violations; either restore the gate, correct the "
                "catalog entry, or add an explicit skip-list entry with a "
                "durable reason."
            )
            continue
        scanned += 1
        try:
            result = fn(strict=False, verbose=False)
        except TypeError:
            # Function signature does not accept (strict, verbose) kwargs;
            # skip rather than fail-closed on metadata mismatch.
            skipped.append(check_name)
            continue
        except Exception as exc:  # pragma: no cover - defensive
            violations.append(
                f"Catalog #{cat_num} `{check_name}`: "
                f"raised {type(exc).__name__} when invoked with "
                f"strict=False - cannot verify Live count: 0 claim. "
                f"Detail: {str(exc)[:160]}"
            )
            continue
        if isinstance(result, list) and result:
            sample = "; ".join(str(v)[:120] for v in result[:3])
            violations.append(
                f"Catalog #{cat_num} `{check_name}`: CLAUDE.md claims "
                f"'Live count: 0' + STRICT but gate returned "
                f"{len(result)} violation(s). Either fix the underlying "
                f"violations OR update CLAUDE.md to reflect the new "
                f"non-zero live count. Sample: {sample}"
            )
    if verbose:
        if violations:
            print(
                f"  [catalog-live-count] {len(violations)} drift entries "
                f"between CLAUDE.md 'Live count: 0' claim and gate empirical "
                f"result (scanned: {scanned}, skipped: {len(skipped)}, "
                f"not_found: {len(not_found)})"
            )
            for v in violations[:5]:
                print(f"    - {v[:220]}")
        else:
            print(
                f"  [catalog-live-count] OK ({scanned} STRICT-0 entries "
                f"verified; 0 drift; {len(skipped)} skipped, "
                f"{len(not_found)} not found)"
            )
    if violations and strict:
        raise PreflightError(
            "check_strict_flipped_catalog_entries_have_live_count_zero "
            f"found {len(violations)} drift entries. Per CLAUDE.md "
            "'Bugs must be permanently fixed AND self-protected against' "
            "non-negotiable, the catalog table is the canonical "
            "strictness ledger:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #186 — check_catalog_claim_committed_via_serializer
# (FIX-WAVE-7 R7-1 self-protection, 2026-05-13, STRICT @ 0)
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (R7-1 anchor 2026-05-13 08:16Z + 08:37Z):
#   ``.omx/state/catalog-claim.log`` shows pid 40139 claimed #183, pid
#   40141 claimed #184 (both via BARE ``claim`` - no
#   ``--commit-via-serializer``). The working-tree increment was rolled
#   back. 21 minutes later pid 58394 re-claimed #183, pid 62695
#   re-claimed #184 (again bare). The CANON-1.E hardening landed in
#   ``tools/claim_catalog_number.py`` (2026-05-12) optional
#   ``--commit-via-serializer`` flag whose docstring explicitly forecasted
#   this recurrence: *"future STRICT gate
#   check_catalog_claim_committed_via_serializer (planned, deferred -
#   requires preflight.py edit when no in-flight subagent has it dirty)
#   will REFUSE bare claim invocations from subagents in the fan-out
#   context once the empirical collision recurs."* This gate lands that
#   self-protection.
#
# Scope: scan ``tools/``, ``scripts/``, ``src/tac/``, ``experiments/``
# (excluding tests, vendored intake clones, OSS export mirrors,
# experiments/results/ build artifacts, and the canonical tool itself)
# for invocations of ``tools/claim_catalog_number.py claim`` that do
# NOT pass ``--commit-via-serializer``.
#
# Detection surfaces (text scan with line-level granularity so single
# call-sites can be waived):
#   1. Python files: ``subprocess.run([...claim_catalog_number.py..., "claim", ...])``
#      or ``subprocess.Popen(...)`` or shell-string ``"claim_catalog_number.py claim"``.
#   2. Shell files: literal ``claim_catalog_number.py claim`` invocations.
#
# Same-line waiver: ``# CATALOG_CLAIM_BARE_OK:<reason>`` (must include
# colon + reason; bare token rejected per CLAUDE.md
# "Comment-only contracts are FORBIDDEN").
#
# Exemptions:
#   * The canonical tool itself (``tools/claim_catalog_number.py``) -
#     its docstring + USAGE strings reference the bare form for
#     documentation purposes.
#   * Test files (``test_*.py`` / ``*/tests/*``) - they exercise the
#     CLI surface intentionally.
#   * Vendored intake clones (``experiments/results/*_intake_*``,
#     ``reverse_engineering/``) and OSS export mirrors
#     (``.omx/oss_export/``).
#   * Build-artifact trees (``experiments/results/**``,
#     ``reports/raw/**``) where committed code snapshots live.
#

_CHECK_186_CANONICAL_TOOL_RELPATH = "tools/claim_catalog_number.py"
_CHECK_186_BARE_WAIVER_TOKEN = "# CATALOG_CLAIM_BARE_OK:"
_CHECK_186_FILE_LEVEL_WAIVER_TOKEN = "# CATALOG_CLAIM_BARE_OK_FILE:"

# Excluded directory prefixes (relative to repo root). Any source file
# under these paths is OUT OF SCOPE.
_CHECK_186_EXCLUDED_DIR_PREFIXES: tuple[str, ...] = (
    "experiments/results/",
    "reports/raw/",
    "reverse_engineering/",
    ".omx/oss_export/",
    ".venv/",
    "node_modules/",
    "upstream/",  # pinned upstream snapshot - never edit
)

# Excluded path substrings (anywhere in relpath).
_CHECK_186_EXCLUDED_SUBSTRINGS: tuple[str, ...] = (
    "/_intake_",
    "_intake_",
    "/tests/",
    "test_check_186",
)

_CHECK_186_SCAN_DIRS: tuple[str, ...] = (
    "tools",
    "scripts",
    "src/tac",
    "experiments",
)

_CHECK_186_SCAN_SUFFIXES: tuple[str, ...] = (".py", ".sh")


def _check_186_is_scoped_path(relpath: str) -> bool:
    """Return True if relpath is in-scope for the bare-claim scan."""
    if not relpath:
        return False
    # Always exclude the canonical tool itself.
    if relpath == _CHECK_186_CANONICAL_TOOL_RELPATH:
        return False
    for prefix in _CHECK_186_EXCLUDED_DIR_PREFIXES:
        if relpath.startswith(prefix):
            return False
    for substr in _CHECK_186_EXCLUDED_SUBSTRINGS:
        if substr in relpath:
            return False
    # File must be under one of the scan dirs (or top-level CLAUDE.md
    # adjacent surfaces - but we restrict to scan dirs to keep cost
    # bounded).
    in_scope_dir = False
    for top in _CHECK_186_SCAN_DIRS:
        if relpath == top or relpath.startswith(top + "/"):
            in_scope_dir = True
            break
    if not in_scope_dir:
        return False
    # File must have a scanned suffix.
    if not relpath.endswith(_CHECK_186_SCAN_SUFFIXES):
        return False
    # Exclude test files by filename convention.
    base = relpath.rsplit("/", 1)[-1]
    if base.startswith("test_") or base.endswith("_test.py"):
        return False
    return True


def _check_186_detect_bare_claim_lines(text: str) -> list[tuple[int, str]]:
    """Return list of (1-indexed line number, line content) where a bare
    ``claim_catalog_number.py claim`` invocation appears WITHOUT
    ``--commit-via-serializer`` AND without the same-line waiver.

    The detector is text-shape based (not AST) because the surface is
    polyglot (.py + .sh) and the canonical invocations are simple
    string literals. False positives are gated by:
      - the line must contain ``claim_catalog_number.py`` AND the
        ``claim`` subcommand token (as a whole word, to skip
        docstrings that mention the word "claim" alone);
      - the line must NOT contain ``--commit-via-serializer``;
      - the line must NOT carry the same-line bare waiver.
    """
    def _has_claim_subcommand(s: str) -> bool:
        return (
            "claim_catalog_number.py claim" in s
            or '"claim"' in s
            or "'claim'" in s
        )

    invocation_markers = (
        "python ",
        "python3 ",
        "subprocess",
        "os.system",
        "Popen(",
        "run(",
        "$(",
        "${",
        "./tools/",
        "tools/claim_catalog_number.py",
    )

    lines = text.splitlines()
    bare_lines: list[tuple[int, str]] = []
    for i, raw_line in enumerate(lines, start=1):
        line = raw_line
        if "claim_catalog_number.py" not in line:
            continue
        # Require the `claim` subcommand token. Reject `peek` / `set`
        # invocations and pure docstring references that say "the claim".
        # The canonical CLI shape is `claim_catalog_number.py claim`,
        # which the regex below matches loosely.
        # We accept both "claim_catalog_number.py claim" and forms with
        # an intervening argv element such as
        # ``["...claim_catalog_number.py", "claim", ...]``.
        window_lines = [line]
        # Catalog #186 must catch the normal Python argv style where the tool,
        # subcommand, and serializer flag are split across multiple lines.
        # Stop before another tool occurrence so adjacent calls cannot mask a
        # bare invocation with a later canonical one.
        for next_line in lines[i : min(len(lines), i + 8)]:
            if "claim_catalog_number.py" in next_line:
                break
            window_lines.append(next_line)
        window_text = "\n".join(window_lines)
        if not _has_claim_subcommand(window_text):
            continue
        # If the line is part of a comment-only docstring chunk that
        # doesn't invoke claim, skip. Conservative shape: require the
        # line to look like a real invocation (contains either `python`,
        # `subprocess`, `os.system`, `Popen`, `run(`, a shell `$(`, or
        # starts with a `claim_catalog_number.py` shell invocation).
        # Strip leading whitespace + comment markers to detect docstring-only
        # references. If the stripped line starts with "#" or is inside a
        # triple-quoted block we still flag it ONLY when it looks like an
        # actual invocation; comment-prefix lines that document the CLI
        # surface are filtered out by the invocation_markers check below.
        stripped = line.lstrip()
        if stripped.startswith("# ") and not any(
            m in window_text for m in invocation_markers
        ):
            continue
        if not any(m in window_text for m in invocation_markers):
            continue
        # Skip lines that already satisfy the canonical contract.
        if "--commit-via-serializer" in window_text:
            continue
        # Same-line waiver.
        if _CHECK_186_BARE_WAIVER_TOKEN in window_text:
            continue
        bare_lines.append((i, " ".join(part.strip() for part in window_lines).strip()))
    return bare_lines


def check_catalog_claim_committed_via_serializer(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #186 — refuse bare ``tools/claim_catalog_number.py claim``
    invocations in subagent / fan-out contexts.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
    against" non-negotiable + CANON-1.E hardening (2026-05-12). The
    canonical invocation from any subagent / fan-out caller is::

        python tools/claim_catalog_number.py claim \\
            --commit-via-serializer \\
            --reason "<WAVE>: <purpose>"

    Same-line waiver: ``# CATALOG_CLAIM_BARE_OK:<reason>`` (must include
    colon + non-empty reason). File-level waiver:
    ``# CATALOG_CLAIM_BARE_OK_FILE:<reason>`` anywhere in the file body
    for the rare operator-housekeeping helper that needs the bare form.
    """
    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    scanned_files = 0
    waived_files = 0
    for top in _CHECK_186_SCAN_DIRS:
        top_path = root / top
        if not top_path.is_dir():
            continue
        for candidate in top_path.rglob("*"):
            if not candidate.is_file():
                continue
            try:
                relpath = candidate.relative_to(root).as_posix()
            except ValueError:
                continue
            if not _check_186_is_scoped_path(relpath):
                continue
            try:
                text = candidate.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if "claim_catalog_number.py" not in text:
                # Cheap pre-filter - avoid line scan on irrelevant files.
                continue
            scanned_files += 1
            # File-level waiver short-circuits the whole file.
            if _CHECK_186_FILE_LEVEL_WAIVER_TOKEN in text:
                waived_files += 1
                continue
            bare_lines = _check_186_detect_bare_claim_lines(text)
            for line_no, line_content in bare_lines:
                violations.append(
                    f"{relpath}:{line_no}: bare "
                    f"`claim_catalog_number.py claim` invocation without "
                    f"`--commit-via-serializer`. Per CANON-1.E hardening "
                    f"(see tools/claim_catalog_number.py docstring), "
                    f"subagent fan-out claims MUST be git-transactional. "
                    f"Replace with `python tools/claim_catalog_number.py "
                    f"claim --commit-via-serializer --reason \"<purpose>\"` "
                    f"OR add same-line `# CATALOG_CLAIM_BARE_OK:<reason>` "
                    f"waiver. Line: {line_content[:160]}"
                )
    if verbose:
        if violations:
            print(
                f"  [catalog-claim-serializer] {len(violations)} bare-claim "
                f"violation(s) across {scanned_files} scanned files "
                f"({waived_files} file-level waived)"
            )
            for v in violations[:5]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [catalog-claim-serializer] OK "
                f"({scanned_files} scanned files; 0 bare claims; "
                f"{waived_files} file-level waived)"
            )
    if violations and strict:
        raise PreflightError(
            "check_catalog_claim_committed_via_serializer found "
            f"{len(violations)} bare-claim violation(s). Per CLAUDE.md "
            "'Bugs must be permanently fixed AND self-protected against' "
            "non-negotiable + CANON-1.E hardening (2026-05-12), every "
            "fan-out catalog-number claim must be git-transactional via "
            "`--commit-via-serializer`:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #187 — check_hnerv_training_parity_guard
# (Pauli adversarial-review harden, 2026-05-13, STRICT @ 0)
# ─────────────────────────────────────────────────────────────────────────

_CHECK_187_HNERV_PARITY_TRAINERS: tuple[str, ...] = (
    "experiments/train_substrate_sane_hnerv.py",
    "experiments/train_substrate_tc_nerv.py",
)


def check_hnerv_training_parity_guard(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #187 — enforce PR95/PR100/PR101 HNeRV trainer parity contracts.

    The reusable guard in :mod:`tac.hnerv_training_parity_guard` is cheap and
    static, but it is only useful if dispatch surfaces run it before provider
    setup. This preflight wrapper makes the current HNeRV-family trainer paths a
    strict, visible gate.
    """

    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    try:
        from tac.hnerv_training_parity_guard import inspect_hnerv_training_parity_file
    except Exception as exc:  # pragma: no cover - import failure is environment-specific
        violations.append(
            "could not import tac.hnerv_training_parity_guard: "
            f"{type(exc).__name__}: {str(exc)[:160]}"
        )
    else:
        for relpath in _CHECK_187_HNERV_PARITY_TRAINERS:
            path = root / relpath
            if not path.is_file():
                violations.append(
                    f"{relpath}: missing HNeRV-family trainer path expected by "
                    "Catalog #187 parity gate"
                )
                continue
            report = inspect_hnerv_training_parity_file(path)
            for violation in report.violations:
                violations.append(f"{relpath}: {violation}")

    if verbose:
        if violations:
            print(f"  [hnerv-parity-guard] {len(violations)} violation(s):")
            for v in violations[:8]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [hnerv-parity-guard] OK "
                f"({len(_CHECK_187_HNERV_PARITY_TRAINERS)} trainer(s) checked)"
            )
    if violations and strict:
        raise PreflightError(
            "check_hnerv_training_parity_guard found "
            f"{len(violations)} violation(s). HNeRV-family trainers must keep "
            "PR95/PR100/PR101 parity contracts before provider dispatch:\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #188 — check_test_imports_use_tac_not_src_tac
# (FIX-WAVE-10 R10-1 silent-test-CI-evasion self-protect, 2026-05-13, STRICT @ 0)
# ─────────────────────────────────────────────────────────────────────────
#
# R10 review surfaced the silent-test-CI-evasion bug class: test files in the
# test corpus that import via the non-canonical `from src.tac.*` /
# `import src.tac.*` syntax. The canonical pytest config (pyproject.toml
# `[tool.pytest.ini_options] testpaths = ["tests", "src/tac/tests"]`) installs
# `tac` as the canonical package name; `src.tac.*` works only when the
# CWD-anchored `src/` is on `sys.path` (e.g. `PYTHONPATH=<repo> pytest <file>`).
# Default `pytest` from the repo root collects from configured testpaths but
# raises `ModuleNotFoundError: No module named 'src'` at import time for files
# inside those paths; misplaced test files outside testpaths can remain
# uncollected regardless of import syntax. Both shapes make manual test passes
# disagree with the default gate.
#
# The bug class is high-impact: tests that PASS manually with an unusual
# PYTHONPATH can fail default collection or sit outside the default testpaths;
# either way, the manual signal is not the same as CI signal. R10-1 caught 2
# files in `src/tac/tests/` plus 1 file in `src/tac/substrates/_shared/`
# (outside testpaths regardless of import syntax).
#
# This gate refuses any `.py` file under the test corpus and runtime roots that
# imports via `from src.tac.*`, `import src.tac.*`, or a subprocess string
# literal using those forms. Companion fixes: move the misplaced test file into
# the canonical `src/tac/tests/` directory, rewrite the offending imports, and
# extend the scanner to runtime/subprocess surfaces.
#
# Acceptance:
# - same-line `# SRC_TAC_IMPORT_OK:<reason>` waiver on the import line for the
#   rare deliberate case (placeholder `<reason>` literal rejected)
# - `__pycache__` and binary files are excluded
#
# Strict-from-byte-one per CLAUDE.md "Strict-flip atomicity rule" — live count
# at landing: 0 (the 3 offending lines are rewritten in the same commit batch).

_CHECK_188_TEST_SCAN_DIRS: tuple[str, ...] = (
    "src/tac/tests",
    "tests",
)
_CHECK_188_RUNTIME_SCAN_DIRS: tuple[str, ...] = (
    "src/tac",
    "experiments",
    "tools",
    "scripts",
)

# Match real import statements only — `from src.tac.<X>` or `import src.tac.<X>`
# at the start of a (possibly indented) line. Avoids docstring + string-literal
# false positives like `"src/tac/duplicate.py.pyc"` or `# referenced from src/tac/`.
_CHECK_188_SRC_TAC_IMPORT_RE = re.compile(
    r"^\s*(?:from\s+src\.tac(?:\.|\s)|import\s+src\.tac(?:\.|\s|$))"
)
_CHECK_188_SRC_TAC_STRING_RE = re.compile(
    r"""['"].*?(?:from\s+src\.tac\.|import\s+src\.tac\.).*?['"]"""
)
_CHECK_188_WAIVER_RE = re.compile(
    r"#\s*SRC_TAC_IMPORT_OK:(?!<reason>)([^\s#].*?)\s*$"
)
_CHECK_188_EXEMPT_MARKERS: tuple[str, ...] = (
    "experiments/results/",
    "_intake_",
    ".omx/oss_export/",
    "vendored",
    "build/lib/",
    "reports/raw/",
    "__pycache__",
)
_CHECK_188_SELF_EXEMPT_FILES: tuple[str, ...] = (
    "src/tac/preflight.py",
    "src/tac/tests/test_check_188_test_imports_canonical.py",
)


def check_test_imports_use_tac_not_src_tac(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #188 — refuse `from src.tac.*` / `import src.tac.*` imports in
    tests and runtime entry points.

    R10-1 bug class: test files using non-canonical `src.tac.*` import syntax
    pass manually with `PYTHONPATH=<repo> pytest <file>` but fail default
    collection (`pytest` from repo root) because `from src.tac.X import Y`
    raises `ModuleNotFoundError: No module named 'src'` when `src/` is not on
    `sys.path`. Misplaced test files outside configured testpaths are a sibling
    way for manual passes to diverge from the default gate.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
    non-negotiable: companion fixes rewrote the offending imports; this gate
    refuses future re-introduction in test files, runtime modules, dispatch
    tools, and subprocess string snippets.
    """
    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    n_scanned = 0
    seen_paths: set[Path] = set()
    scan_roots = _CHECK_188_TEST_SCAN_DIRS + _CHECK_188_RUNTIME_SCAN_DIRS
    for rel in scan_roots:
        scan_dir = root / rel
        if not scan_dir.is_dir():
            continue
        for path in scan_dir.rglob("*.py"):
            if path in seen_paths:
                continue
            seen_paths.add(path)
            try:
                rel_path = path.relative_to(root).as_posix()
            except ValueError:
                rel_path = path.as_posix()
            if (
                rel_path in _CHECK_188_SELF_EXEMPT_FILES
                or any(marker in rel_path for marker in _CHECK_188_EXEMPT_MARKERS)
            ):
                continue
            n_scanned += 1
            try:
                text = path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            for line_no, line in enumerate(text.splitlines(), start=1):
                if not (
                    _CHECK_188_SRC_TAC_IMPORT_RE.match(line)
                    or _CHECK_188_SRC_TAC_STRING_RE.search(line)
                ):
                    continue
                # Same-line waiver respected; placeholder reason rejected.
                if _CHECK_188_WAIVER_RE.search(line):
                    continue
                violations.append(
                    f"{rel_path}:{line_no}: forbidden `src.tac.*` import "
                    f"(use `tac.*` instead). Line: {line.strip()[:160]}"
                )
    if verbose:
        if violations:
            print(
                f"  [test-imports-canonical] {len(violations)} violation(s) "
                f"across {n_scanned} test file(s) scanned:"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [test-imports-canonical] OK ({n_scanned} test file(s) "
                "scanned; all use canonical `tac.*` import syntax)"
            )
    if violations and strict:
        raise PreflightError(
            "check_test_imports_use_tac_not_src_tac found "
            f"{len(violations)} violation(s). Test files must use the "
            "canonical `from tac.* import ...` / `import tac.*` syntax. "
            "The non-canonical `src.tac.*` form can fail the default CI gate "
            "(`pytest` from repo root raises "
            "ModuleNotFoundError: No module named 'src'). Rewrite to "
            "`tac.*` OR add a same-line "
            "`# SRC_TAC_IMPORT_OK:<reason>` waiver:\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #190 — check_substrate_trainer_does_not_hardcode_hardware_substrate
#
# SIREN PRE-DISPATCH AUDIT bug-class anchor (2026-05-13). The 14 substrate
# trainers under ``experiments/train_substrate_*.py`` previously hardcoded
# ``hardware_substrate="linux_x86_64_t4"`` in the ``ContestResult`` passed
# to ``posterior_update_locked(...)``. Recipes target A100 / 4090 / H100 /
# A10G / L40S, but the trainer silently labeled every dispatch as T4 —
# violating CLAUDE.md "Forbidden empirical-claim-without-evidence-tag (the
# docstring-overstatement trap)". The posterior anchor recorded FALSE
# hardware metadata; future cost-band predict() + architecture-class
# lookups read wrong substrate; any T4-vs-A100 axis comparison
# mis-bucketed every SIREN-class anchor.
#
# Fix surface: ``tac.substrates._shared.trainer_skeleton.detect_hardware_substrate``
# resolves substrate dynamically from (1) remote driver ``provenance.json``,
# (2) ``<SUBSTRATE>_GPU`` / ``MODAL_GPU`` env vars, (3) live ``nvidia-smi``,
# (4) fallback ``linux_x86_64_unknown_cuda`` with stderr warning.
#
# This STRICT gate refuses any ``experiments/train_substrate_*.py`` that
# contains a hardcoded ``hardware_substrate="linux_x86_64_<gpu>"`` literal
# (any GPU token in the canonical accepted set), and any canonical hardware
# detector call missing its required ``substrate_tag=`` keyword. Acceptance:
#   * The line is replaced with a variable reference or call expression
#     (e.g. ``hardware_substrate=_detected_substrate,`` or
#     ``hardware_substrate=detect_hardware_substrate(..., substrate_tag=...),``).
#   * Same-line ``# HARDWARE_SUBSTRATE_HARDCODE_OK:<reason>`` waiver for
#     the rare legitimate hardcoded case (e.g. test fixtures pinning a
#     known substrate).
#
# Self-exempt: the canonical helper module itself (which contains the
# ``"linux_x86_64_*"`` strings in its lookup table) and ``preflight.py``
# (which contains the strings in this gate's regex / accept tables).
#
# Sister of Catalog #127 (``check_authoritative_tag_requires_custody_metadata``)
# which catches tag-membership checks without validator routing; this gate
# catches the upstream class — hardcoded substrate writes that the
# validator never sees because the data is wrong at the source.
# ----------------------------------------------------------------------------

_CHECK_190_HARDCODED_HW_RE = re.compile(
    r'hardware_substrate\s*=\s*"linux_x86_64_(t4|4090|a100|h100|a10g|l40s|unknown_cuda)"',
)
_CHECK_190_WAIVER_RE = re.compile(
    r"#\s*HARDWARE_SUBSTRATE_HARDCODE_OK\s*:\s*\S",
)
_CHECK_190_DETECT_HELPER_NAMES = frozenset(
    {
        "detect_hardware_substrate",
        "_canon_detect_hardware_substrate",
    }
)
_CHECK_190_SELF_EXEMPT_FILES: tuple[str, ...] = (
    "src/tac/substrates/_shared/trainer_skeleton.py",
    "src/tac/continual_learning.py",
    "src/tac/preflight.py",
    "src/tac/tests/test_check_190_substrate_trainer_hardware_substrate.py",
)


def check_substrate_trainer_does_not_hardcode_hardware_substrate(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #190 — refuse invalid substrate hardware-substrate writes.

    Scans ``experiments/train_substrate_*.py`` for any line of the form
    ``hardware_substrate="linux_x86_64_<gpu>"`` (literal string). The
    canonical pattern is ``hardware_substrate=_detected_substrate,`` where
    ``_detected_substrate`` is computed via
    ``tac.substrates._shared.trainer_skeleton.detect_hardware_substrate`` with
    an explicit ``substrate_tag=...`` keyword.

    Per CLAUDE.md SIREN audit 2026-05-13 CRITICAL #1 +
    "Forbidden empirical-claim-without-evidence-tag" non-negotiable.
    """
    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    experiments_dir = root / "experiments"
    if not experiments_dir.is_dir():
        return violations
    scanned = 0
    for path in sorted(experiments_dir.glob("train_substrate_*.py")):
        rel = path.relative_to(root).as_posix()
        if rel in _CHECK_190_SELF_EXEMPT_FILES:
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        scanned += 1
        lines = text.splitlines()
        for line_no, line in enumerate(text.splitlines(), start=1):
            if not _CHECK_190_HARDCODED_HW_RE.search(line):
                continue
            if _CHECK_190_WAIVER_RE.search(line):
                continue
            violations.append(
                f"{rel}:{line_no}: hardcoded hardware_substrate. Replace "
                f"with `_detected_substrate = "
                "_canon_detect_hardware_substrate(...)` and pass via "
                f"`hardware_substrate=_detected_substrate,` OR add same-line "
                f"`# HARDWARE_SUBSTRATE_HARDCODE_OK:<reason>` waiver. "
                f"Line: {line.strip()[:160]}"
            )
        try:
            tree = ast.parse(text, filename=rel)
        except SyntaxError as exc:
            violations.append(
                f"{rel}:{exc.lineno or 1}: unable to parse substrate trainer "
                "while checking hardware-substrate detection calls. Fix syntax "
                "or add a narrow preflight exemption only for generated code."
            )
            continue
        for node in ast.walk(tree):
            if not isinstance(node, ast.Call):
                continue
            func = node.func
            if isinstance(func, ast.Name):
                helper_name = func.id
            elif isinstance(func, ast.Attribute):
                helper_name = func.attr
            else:
                continue
            if helper_name not in _CHECK_190_DETECT_HELPER_NAMES:
                continue
            line_no = getattr(node, "lineno", 1)
            line = lines[line_no - 1] if 0 <= line_no - 1 < len(lines) else ""
            if _CHECK_190_WAIVER_RE.search(line):
                continue
            if any(keyword.arg == "substrate_tag" for keyword in node.keywords):
                continue
            violations.append(
                f"{rel}:{line_no}: `{helper_name}(...)` missing required "
                "`substrate_tag=` keyword. Missing tags crashed C6 after "
                "training before stats/artifact emission. Pass "
                "`substrate_tag=SUBSTRATE_TAG` or a literal lane tag; add "
                "same-line `# HARDWARE_SUBSTRATE_HARDCODE_OK:<reason>` only "
                f"for a reviewed non-runtime fixture. Line: {line.strip()[:160]}"
            )
    if verbose:
        if violations:
            print(
                f"  [substrate-hardware-detection] {len(violations)} "
                f"violation(s) across {scanned} trainer(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [substrate-hardware-detection] OK ({scanned} substrate "
                "trainer(s) use dynamic detection)"
            )
    if violations and strict:
        raise PreflightError(
            "check_substrate_trainer_does_not_hardcode_hardware_substrate "
            f"found {len(violations)} violation(s). Substrate trainers must "
            "detect hardware_substrate dynamically via "
            "`tac.substrates._shared.trainer_skeleton.detect_hardware_substrate` "
            "rather than hardcoding a literal value. The hardcoded value "
            "produces silent custody mislabels on the posterior anchor when "
            "the dispatch GPU differs from the hardcoded default (e.g. SIREN "
            "recipe targets A100 but trainer wrote `linux_x86_64_t4`).\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #191 — check_modal_dispatch_threads_sentinel_files_per_catalog_166
#
# SIREN PRE-DISPATCH AUDIT CRITICAL #2 (2026-05-13). Sister gate to Catalog
# #166. Catalog #166 enforces that the dispatch-time HEAD parity ledger
# remains wired in ``experiments/modal_train_lane.py``; Catalog #191
# enforces that the Modal-dispatch caller (``tools/operator_authorize.py``
# specifically the ``_dispatch_modal`` function) THREADS ``--sentinel-files``,
# ``--require-clean-head``, and the recipe ``--lane-id`` to the
# modal_train_lane CLI. Without these flags, the Catalog #166 fail-closed
# sentinel-mismatch protection (rc=13 at modal_train_lane.py:327-342) is
# structurally INACTIVE, or the Modal direct claim can split away from the
# operator-approved lane id.
#
# Fix surface: ``tools/operator_authorize.py::_dispatch_modal`` builds the
# modal CLI cmd with ``--sentinel-files <auto-discovered + recipe-declared>``,
# ``--require-clean-head``, and ``--lane-id <recipe.lane_id>`` already wired.
#
# This STRICT gate verifies the function body contains BOTH wire-up tokens
# (literal strings ``"--sentinel-files"``, ``"--require-clean-head"``, and
# ``"--lane-id"``) in the call-construction context. There is no waiver —
# removing any flag re-enables the bug class. Same as Catalog #166 (no waiver).
#
# Sister of Catalog #166 (HEAD-parity ledger surface) + Catalog #167
# (smoke-before-full pattern). Together they close the failure modes:
#   * #166: dispatcher records HEAD parity ledger so post-mortem can
#     distinguish stale-mount vs pre-fix-dispatch.
#   * #191: caller WIRES the sentinel-files / require-clean-head flags so
#     the dispatcher's fail-closed protection actually fires.
#   * #167: full-canary dispatches must run smoke-before-full so a 100-ep
#     smoke catches integration failures BEFORE the $5-15 full meter starts.
# ----------------------------------------------------------------------------

_CHECK_191_DISPATCHER_PATH = "tools/operator_authorize.py"
_CHECK_191_REQUIRED_TOKENS: tuple[str, ...] = (
    "--sentinel-files",
    "--require-clean-head",
    "--lane-id",
    "_modal_sentinel_files",
)


def check_modal_dispatch_threads_sentinel_files_per_catalog_166(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #191 — refuse Modal dispatcher state that drops Catalog #166
    sentinel-files / require-clean-head wire-up.

    The check verifies ``tools/operator_authorize.py`` exists and contains
    every required contract surface in ``_CHECK_191_REQUIRED_TOKENS``. The
    bug class: removing ``--sentinel-files``, ``--require-clean-head``, or
    ``--lane-id``
    from the modal cmd construction silently disables Catalog #166's
    fail-closed protection or splits dispatch custody across inferred lane ids
    — paid GPU dispatch proceeds on a stale snapshot or cannot be matched to
    the operator-approved claim.

    Per CLAUDE.md SIREN audit 2026-05-13 CRITICAL #2.
    """
    root = (repo_root or Path.cwd()).resolve()
    path = root / _CHECK_191_DISPATCHER_PATH
    violations: list[str] = []
    if not path.is_file():
        violations.append(
            f"{_CHECK_191_DISPATCHER_PATH}: missing — the canonical Modal "
            "dispatcher is gone; the sentinel-files / require-clean-head "
            "wire-up contract is re-exposed."
        )
    else:
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            violations.append(
                f"{_CHECK_191_DISPATCHER_PATH}: read error {exc!s}"
            )
            text = ""
        for surface in _CHECK_191_REQUIRED_TOKENS:
            if surface not in text:
                violations.append(
                    f"{_CHECK_191_DISPATCHER_PATH}: missing required "
                    f"wire-up surface `{surface}` — Catalog #191 requires "
                    "the Modal dispatcher to thread sentinel-files / "
                    "require-clean-head / lane-id into the modal_train_lane "
                    "CLI so Catalog #166's fail-closed gate fires and claim "
                    "custody remains single-lane."
                )
    if verbose:
        if violations:
            print(
                f"  [modal-sentinel-wire-up] {len(violations)} violation(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [modal-sentinel-wire-up] OK "
                "(canonical dispatcher threads sentinel-files + "
                "require-clean-head)"
            )
    if violations and strict:
        raise PreflightError(
            "check_modal_dispatch_threads_sentinel_files_per_catalog_166 "
            f"found {len(violations)} contract violation(s). The Modal "
            "dispatcher (`tools/operator_authorize.py::_dispatch_modal`) "
            "must thread `--sentinel-files`, `--require-clean-head`, and "
            "`--lane-id` to "
            "the modal_train_lane CLI so Catalog #166's fail-closed "
            "sentinel-mismatch gate (rc=13) fires and dispatch claims remain "
            "attached to the operator-approved lane. Without these flags, "
            "stale code on the worker only emits a warn banner or claim "
            "custody splits across lane ids — paid GPU spend proceeds.\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #192 — check_macos_cpu_advisory_not_promoted_without_linux_verification
#
# Operator routing 2026-05-13 ("training is the real roadblock; we can prepare
# and run things on macos and cpu"). macOS-CPU is wired in this session as a
# first-class FREE advisory proxy for the contest-CPU axis. Per CLAUDE.md
# "Submission auth eval — BOTH CPU AND CUDA, ON 1:1 CONTEST-COMPLIANT
# HARDWARE" non-negotiable, macOS-CPU is NEVER 1:1 contest-compliant — it is
# advisory only, and promotion requires a paired [contest-CPU GHA Linux
# x86_64] anchor.
#
# This STRICT gate refuses any persisted artifact under tracked-source paths
# (.omx/state/, experiments/results/, reports/, src/tac/, tools/, scripts/,
# experiments/) that combines evidence_grade="macOS-CPU-advisory" (or
# evidence_tag containing "[macOS-CPU advisory") with score_claim=true,
# promotion_eligible=true, or ready_for_exact_eval_dispatch=true.
#
# Scan strategy:
#   - Walk .omx/state/, experiments/results/, reports/ for JSON / JSONL files
#     mentioning "macOS-CPU-advisory" OR "[macOS-CPU advisory" — fast text
#     pre-filter avoids parsing every JSON file in the tree.
#   - For each match, parse JSON / JSONL row(s) and flag any row pairing
#     advisory evidence with any of the three promotability flags True.
#   - Same-line waiver `# MACOS_CPU_ADVISORY_PROMOTED_OK:<reason>` honored
#     inside text files (manifests can carry inline waivers via comment-like
#     keys, but the JSON parser does not see those — the waiver applies only
#     to source code in src/tac/ / tools/ / scripts/ that explicitly enables
#     a promotion path after paired Linux x86_64 verification lands).
#
# Live count at landing: 0 (no advisory rows exist yet; the manifest builder
# refuses to write a promoted row at construction time). STRICT @ 0 per
# CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
# non-negotiable + the "Strict-flip atomicity rule".
#
# Sister of:
#   - Catalog #127 (`check_authoritative_tag_requires_custody_metadata`):
#     enforces the tag + axis + hardware_substrate triple at CALL sites.
#     Catalog #192 enforces the same contract at PERSISTED ARTIFACT level.
#   - Catalog #128 / #131 (locked writes to shared state): macOS-CPU
#     manifests written via :func:`append_manifest_row_to_jsonl` honor
#     the canonical write protocol.
#   - Catalog #175 (cost-band anchor writers declare outcome): macOS-CPU
#     advisory rows never feed the cost-band posterior — explicit blocker.
#
# Memory: `feedback_macos_cpu_autopilot_wiring_landed_20260513.md`.
# Lane: `lane_macos_cpu_autopilot_wiring_20260513`.
# ----------------------------------------------------------------------------

_CHECK_192_ADVISORY_GRADE_TOKEN = "macOS-CPU-advisory"
_CHECK_192_ADVISORY_TAG_TOKEN = "[macOS-CPU advisory"
_CHECK_192_WAIVER_TOKEN = "MACOS_CPU_ADVISORY_PROMOTED_OK:"
_CHECK_192_SCAN_ROOTS: tuple[str, ...] = (
    ".omx/state",
    "experiments/results",
    "reports",
)
_CHECK_192_FILE_SUFFIXES: tuple[str, ...] = (".json", ".jsonl")
_CHECK_192_PROMOTABILITY_FLAGS: tuple[str, ...] = (
    "score_claim",
    "promotion_eligible",
    "ready_for_exact_eval_dispatch",
)
_CHECK_192_MAX_FILE_BYTES: int = 32 * 1024 * 1024  # skip ≥32 MB to keep dev scope bounded


def _check_192_iter_candidate_files(root: Path) -> list[Path]:
    """Return JSON/JSONL paths under any of _CHECK_192_SCAN_ROOTS."""
    out: list[Path] = []
    for rel in _CHECK_192_SCAN_ROOTS:
        sub = root / rel
        if not sub.is_dir():
            continue
        try:
            for p in sub.rglob("*"):
                if not p.is_file():
                    continue
                if p.suffix.lower() not in _CHECK_192_FILE_SUFFIXES:
                    continue
                try:
                    if p.stat().st_size > _CHECK_192_MAX_FILE_BYTES:
                        continue
                except OSError:
                    continue
                out.append(p)
        except OSError:
            continue
    return out


def _check_192_row_is_violation(row: object) -> list[str]:
    """Return list of human-readable violation reasons for one parsed row."""
    if not isinstance(row, dict):
        return []
    evidence_grade = str(row.get("evidence_grade") or "")
    evidence_tag = str(row.get("evidence_tag") or "")
    is_advisory = (
        _CHECK_192_ADVISORY_GRADE_TOKEN in evidence_grade
        or _CHECK_192_ADVISORY_TAG_TOKEN in evidence_tag
    )
    if not is_advisory:
        return []
    violations: list[str] = []
    for flag in _CHECK_192_PROMOTABILITY_FLAGS:
        val = row.get(flag)
        if val is True or (isinstance(val, str) and val.lower() == "true"):
            violations.append(
                f"row carries evidence_grade={evidence_grade!r} / "
                f"evidence_tag={evidence_tag!r} AND {flag}=True. macOS-CPU "
                "advisory rows MUST keep all three promotability flags False "
                "until a paired [contest-CPU GHA Linux x86_64] anchor lands. "
                "Per CLAUDE.md Catalog #192."
            )
    return violations


def check_macos_cpu_advisory_not_promoted_without_linux_verification(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #192. Refuse advisory rows + promoted flags in persisted artifacts.

    See module-level header above. The check walks ``.omx/state/``,
    ``experiments/results/``, and ``reports/`` for JSON / JSONL files that
    mention the macOS-CPU advisory grade or tag and reject any row that pairs
    the advisory evidence with ``score_claim=true``, ``promotion_eligible=true``,
    or ``ready_for_exact_eval_dispatch=true``.

    A whole-file waiver token ``# MACOS_CPU_ADVISORY_PROMOTED_OK:<reason>`` is
    honored when the file is a ``.md`` / ``.txt`` companion. JSON manifests
    cannot use comment-style waivers — they must just keep the flags False.
    """
    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    scanned = 0
    parsed_rows = 0

    for path in _check_192_iter_candidate_files(root):
        rel = str(path.relative_to(root)) if path.is_relative_to(root) else str(path)
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        scanned += 1
        # Fast text pre-filter to avoid parsing every JSON.
        if (
            _CHECK_192_ADVISORY_GRADE_TOKEN not in text
            and _CHECK_192_ADVISORY_TAG_TOKEN not in text
        ):
            continue
        # File-level waiver token (rare; for explicitly-superseded artifacts).
        if _CHECK_192_WAIVER_TOKEN in text:
            continue

        suffix = path.suffix.lower()
        rows_iter: list[object] = []
        try:
            if suffix == ".jsonl":
                for line in text.splitlines():
                    s = line.strip()
                    if not s:
                        continue
                    try:
                        rows_iter.append(json.loads(s))
                    except (ValueError, TypeError):
                        continue
            else:
                payload = json.loads(text)
                if isinstance(payload, list):
                    rows_iter.extend(payload)
                elif isinstance(payload, dict):
                    # Also check the top-level dict itself.
                    rows_iter.append(payload)
                    # And conventional nested-rows keys.
                    for nested_key in ("rows", "observations", "anchors", "ranking_atoms"):
                        nested = payload.get(nested_key)
                        if isinstance(nested, list):
                            rows_iter.extend(nested)
        except (ValueError, TypeError):
            continue

        for row in rows_iter:
            parsed_rows += 1
            row_violations = _check_192_row_is_violation(row)
            for v in row_violations:
                violations.append(f"{rel}: {v}")

    if verbose:
        if violations:
            print(
                f"  [macos-cpu-advisory-promotion] {len(violations)} "
                f"violation(s) across {scanned} JSON/JSONL file(s) "
                f"({parsed_rows} row(s) parsed):"
            )
            for v in violations[:10]:
                print(f"    - {v[:220]}")
        else:
            print(
                f"  [macos-cpu-advisory-promotion] OK "
                f"({scanned} JSON/JSONL file(s) scanned, "
                f"{parsed_rows} row(s) parsed; 0 violation(s))"
            )
    if violations and strict:
        raise PreflightError(
            "check_macos_cpu_advisory_not_promoted_without_linux_verification "
            f"found {len(violations)} persisted advisory row(s) flagged "
            "score_claim=True / promotion_eligible=True / "
            "ready_for_exact_eval_dispatch=True without a paired "
            "[contest-CPU GHA Linux x86_64] anchor. Per CLAUDE.md "
            "'Submission auth eval — BOTH CPU AND CUDA, ON 1:1 "
            "CONTEST-COMPLIANT HARDWARE' non-negotiable + Catalog #192 "
            "the macOS-CPU advisory axis is non-promotable until the "
            "paired Linux x86_64 result lands:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #197 — check_full_cpu_requires_explicit_advisory_waiver
#
# Operator approved 2026-05-13 (time-traveler --full-cpu mode dev). Sister
# self-protection for the "device-or-die-gate-bypass-via-uncoupled-flags"
# bug class. The canonical pattern is:
#
#   1. Trainer's argparse exposes ``--full-cpu`` to allow contest-shape CPU
#      training (advisory-only per CLAUDE.md "MPS auth eval is NOISE" + the
#      "Submission auth eval — BOTH CPU AND CUDA, ON 1:1 CONTEST-COMPLIANT
#      HARDWARE" non-negotiable).
#   2. The mode MUST also expose ``--advisory-cpu-explicitly-waived`` so the
#      operator must explicitly acknowledge the non-promotable nature.
#   3. The trainer MUST validate the coupling (refuse ``--full-cpu`` without
#      ``--advisory-cpu-explicitly-waived``) BEFORE the device-or-die gate
#      can be reached.
#
# Bug class: a future trainer that copies the ``--full-cpu`` flag without
# also implementing the waiver coupling silently re-opens a CPU bypass to the
# canonical ``device_or_die`` gate. The bypass produces non-promotable
# artifacts that may leak into autopilot ranking unless Catalog #192 catches
# the persisted-row leakage at preflight time — but that is only a
# defence-in-depth layer; the structural fix is at the CLI surface.
#
# This STRICT gate refuses any ``experiments/train_substrate_*.py``,
# ``experiments/train_*.py``, or ``experiments/train_renderer*.py`` source
# file that:
#   - declares ``--full-cpu`` argparse argument, AND
#   - does NOT also declare ``--advisory-cpu-explicitly-waived``, OR
#   - does NOT call a coupled-flag validator function (name pattern
#     ``_validate_full_cpu_flags`` or ``validate_full_cpu_flags``) inside
#     ``def main(`` body.
#
# Acceptance: same-line ``# FULL_CPU_COUPLED_FLAGS_OK:<reason>`` waiver on
# the argparse ``add_argument("--full-cpu", ...)`` line for the rare case
# the trainer legitimately has a different waiver mechanism (must document
# the alternative in the waiver reason).
#
# Sister of Catalog #127 (call-site custody validator) + Catalog #192
# (persisted-artifact macOS-CPU advisory gate). Together they extinct the
# bug class across all 3 surfaces:
#   - Catalog #197: CLI/source surface (this gate)
#   - Catalog #127: in-memory result-object surface
#   - Catalog #192: persisted-artifact JSON/JSONL surface
#
# Live count at landing: 0 (only experiments/train_substrate_time_
# traveler_l5_autonomy.py uses --full-cpu; it has the coupled waiver +
# validator).
# ============================================================================

_CHECK_197_FULL_CPU_FLAG_TOKEN = "--full-cpu"
_CHECK_197_WAIVER_FLAG_TOKEN = "--advisory-cpu-explicitly-waived"
_CHECK_197_VALIDATOR_FN_TOKENS: tuple[str, ...] = (
    "_validate_full_cpu_flags",
    "validate_full_cpu_flags",
)
_CHECK_197_SAMELINE_WAIVER_TOKEN = "FULL_CPU_COUPLED_FLAGS_OK:"
_CHECK_197_SCAN_GLOBS: tuple[str, ...] = (
    "experiments/train_substrate_*.py",
    "experiments/train_renderer*.py",
    "experiments/train_*.py",
)


def _check_197_iter_candidate_files(root: Path) -> list[Path]:
    """Return experiments/train_*.py paths that may declare --full-cpu."""
    out: set[Path] = set()
    experiments = root / "experiments"
    if not experiments.is_dir():
        return []
    for glob in _CHECK_197_SCAN_GLOBS:
        # Strip the leading "experiments/" since we already root at experiments.
        local_glob = glob.removeprefix("experiments/")
        out.update(p for p in experiments.glob(local_glob) if p.is_file())
    return sorted(out)


def _check_197_line_has_waiver(line: str) -> bool:
    return _CHECK_197_SAMELINE_WAIVER_TOKEN in line


def check_full_cpu_requires_explicit_advisory_waiver(
    *, strict: bool = False, verbose: bool = False, repo_root: Path | None = None,
) -> list[str]:
    """Catalog #197 — refuse uncoupled ``--full-cpu`` declarations.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
    non-negotiable: the trainer-level coupled-flag validator is the immediate
    fix; this preflight gate is the structural self-protection that prevents
    a future trainer from re-introducing the device-or-die-gate-bypass-via-
    uncoupled-flags bug class.
    """
    root = repo_root or Path.cwd()
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []
    scanned = 0
    for path in _check_197_iter_candidate_files(root):
        scanned += 1
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        if _CHECK_197_FULL_CPU_FLAG_TOKEN not in text:
            continue
        # Locate the argparse add_argument line for --full-cpu.
        full_cpu_argparse_line: str | None = None
        for line in text.splitlines():
            stripped = line.strip()
            if (
                "add_argument" in stripped
                and f'"{_CHECK_197_FULL_CPU_FLAG_TOKEN}"' in stripped
            ):
                full_cpu_argparse_line = line
                break
        # If no add_argument line, the file mentions --full-cpu in a docstring/
        # comment only; treat as accepted.
        if full_cpu_argparse_line is None:
            continue
        # Same-line waiver opt-out.
        if _check_197_line_has_waiver(full_cpu_argparse_line):
            continue
        # Require sister --advisory-cpu-explicitly-waived argparse declaration.
        has_waiver_flag = False
        for line in text.splitlines():
            stripped = line.strip()
            if (
                "add_argument" in stripped
                and f'"{_CHECK_197_WAIVER_FLAG_TOKEN}"' in stripped
            ):
                has_waiver_flag = True
                break
        if not has_waiver_flag:
            violations.append(
                f"{path}: declares {_CHECK_197_FULL_CPU_FLAG_TOKEN} but is "
                f"missing the sister {_CHECK_197_WAIVER_FLAG_TOKEN} argparse "
                "declaration (Catalog #197)."
            )
            continue
        # Require a coupled-flag validator function invocation somewhere in
        # the file (typically called from main()).
        has_validator_call = any(token in text for token in _CHECK_197_VALIDATOR_FN_TOKENS)
        if not has_validator_call:
            violations.append(
                f"{path}: declares {_CHECK_197_FULL_CPU_FLAG_TOKEN} + "
                f"{_CHECK_197_WAIVER_FLAG_TOKEN} but does not call any "
                f"coupled-flag validator (any of {_CHECK_197_VALIDATOR_FN_TOKENS}). "
                "Catalog #197 requires the validator to refuse uncoupled flag "
                "combinations BEFORE the device-or-die gate is reached."
            )
    if verbose:
        if violations:
            print(
                f"  [full-cpu-coupled-flags] {len(violations)} "
                f"violation(s) across {scanned} candidate file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:220]}")
        else:
            print(
                f"  [full-cpu-coupled-flags] OK "
                f"({scanned} candidate file(s) scanned, 0 violation(s))"
            )
    if violations and strict:
        raise PreflightError(
            "check_full_cpu_requires_explicit_advisory_waiver found "
            f"{len(violations)} trainer(s) declaring --full-cpu without the "
            "coupled --advisory-cpu-explicitly-waived flag and/or coupled-flag "
            "validator invocation. Per CLAUDE.md 'Bugs must be permanently "
            "fixed AND self-protected against' + Catalog #197:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #199 — check_operator_authorize_bypass_requires_session_budget
#
# Operator approved 2026-05-13 (UNBLOCK + REVIEW-FIX + RETRY DISPATCH).
# Sister self-protection for the operator-authorize confirmation-prompt
# bypass added to `tools/operator_authorize.py::_confirm()` at the same
# commit batch.
#
# The canonical pattern is:
#
#   1. tools/operator_authorize.py::_confirm() recognizes a paired env-var
#      bypass: OPERATOR_AUTHORIZE_CONFIRMED_VIA_SESSION_DIRECTIVE=1 AND
#      OPERATOR_AUTHORIZE_SESSION_BUDGET_USD=<float>.
#   2. Bare CONFIRMED=1 alone is FATAL (the helper raises SystemExit(11)).
#   3. Any caller that sets only the CONFIRMED env var without the paired
#      budget env var is a structural Catalog #199 violation — even if the
#      bypass path is never exercised in practice, the asymmetric env-var
#      set risks future drift into "auto-approve without budget cap".
#
# Bug class: env-var bypasses on safety surfaces are convenient but lossy —
# CONFIRMED=1 alone would silently approve any dispatch independent of cost.
# The paired-budget requirement forces the operator to explicitly acknowledge
# the session-wide envelope. The STRICT preflight check refuses any caller
# (.sh / .py file under tools/, scripts/, experiments/, src/tac/) that sets
# CONFIRMED without ALSO setting the budget in the same callsite window.
#
# Acceptance:
#   (a) caller sets BOTH env vars within a small window (30 lines)
#   (b) same-line `# OPERATOR_AUTHORIZE_BYPASS_OK:<reason>` waiver on the
#       CONFIRMED-setting line
#   (c) the canonical operator-authorize file (tools/operator_authorize.py)
#       and the preflight.py self-reference are exempt
#   (d) test files are exempt
#
# Live count at landing: 0.
# STRICT @ 0 in same commit batch per CLAUDE.md "Strict-flip atomicity rule".
# ============================================================================

_CHECK_199_CONFIRMED_ENV_VAR = "OPERATOR_AUTHORIZE_CONFIRMED_VIA_SESSION_DIRECTIVE"
_CHECK_199_BUDGET_ENV_VAR = "OPERATOR_AUTHORIZE_SESSION_BUDGET_USD"
_CHECK_199_SAMELINE_WAIVER_TOKEN = "OPERATOR_AUTHORIZE_BYPASS_OK:"
_CHECK_199_SCAN_DIRS: tuple[str, ...] = ("tools", "scripts", "experiments", "src/tac")
_CHECK_199_SCAN_EXTS: tuple[str, ...] = (".py", ".sh")
_CHECK_199_EXEMPT_PATH_MARKERS: tuple[str, ...] = (
    "experiments/results/",
    "_intake_",
    ".omx/oss_export/",
    "vendored",
    "/tests/",
    "/test_",
)
_CHECK_199_EXEMPT_FILES: frozenset[str] = frozenset({
    "tools/operator_authorize.py",  # the canonical file that defines the bypass
    "src/tac/preflight.py",  # the gate's own home (contains the regex patterns)
})
_CHECK_199_WINDOW_LINES = 30


def _check_199_iter_candidate_files(root: Path) -> list[Path]:
    """Return candidate files (.py/.sh) under the four scan dirs."""
    out: list[Path] = []
    for sub in _CHECK_199_SCAN_DIRS:
        sub_path = root / sub
        if not sub_path.is_dir():
            continue
        for path in sub_path.rglob("*"):
            if not path.is_file():
                continue
            if path.suffix not in _CHECK_199_SCAN_EXTS:
                continue
            rel = str(path.relative_to(root))
            if any(marker in rel for marker in _CHECK_199_EXEMPT_PATH_MARKERS):
                continue
            if rel in _CHECK_199_EXEMPT_FILES:
                continue
            # Test files exempt by filename convention (defence-in-depth on
            # top of the /tests/ + /test_ markers above).
            if path.name.startswith("test_") or path.name.endswith("_test.py"):
                continue
            out.append(path)
    return sorted(out)


def _check_199_line_sets_confirmed_env(line: str) -> bool:
    """Return True if `line` sets the CONFIRMED env var to a truthy value.

    Detects shell exports/assignments and Python ``os.environ`` writes.
    """
    stripped = line.strip()
    # Same-line waiver opt-out.
    if _CHECK_199_SAMELINE_WAIVER_TOKEN in stripped:
        return False
    if _CHECK_199_CONFIRMED_ENV_VAR not in stripped:
        return False
    # Look for assignment patterns (= 1, ="1", : "1", etc.) but exclude
    # mere mentions in comments or docstrings.
    # Shell: VAR=value or export VAR=value
    # Python: os.environ["VAR"] = "1" or env["VAR"] = "1"
    if "=" not in stripped:
        return False
    # Comment-only line: full-line comment / docstring opener
    if stripped.startswith("#"):
        return False
    if stripped.startswith('"""') or stripped.startswith("'''"):
        return False
    return True


def _check_199_window_sets_budget(lines: list[str], idx: int) -> bool:
    """Return True if any line within `idx ± _CHECK_199_WINDOW_LINES` sets
    the BUDGET env var."""
    lo = max(0, idx - _CHECK_199_WINDOW_LINES)
    hi = min(len(lines), idx + _CHECK_199_WINDOW_LINES + 1)
    for j in range(lo, hi):
        if j == idx:
            continue
        candidate = lines[j]
        if _CHECK_199_BUDGET_ENV_VAR not in candidate:
            continue
        if "=" not in candidate:
            continue
        cstripped = candidate.strip()
        if cstripped.startswith("#"):
            continue
        return True
    return False


def check_operator_authorize_bypass_requires_session_budget(
    *, strict: bool = False, verbose: bool = False, repo_root: Path | None = None,
) -> list[str]:
    """Catalog #199 — refuse asymmetric CONFIRMED-without-BUDGET callsites.

    Scans .py/.sh files under tools/, scripts/, experiments/, src/tac/ for
    callsites that set ``OPERATOR_AUTHORIZE_CONFIRMED_VIA_SESSION_DIRECTIVE``
    without ALSO setting ``OPERATOR_AUTHORIZE_SESSION_BUDGET_USD`` within the
    same 30-line callsite window. Refuses each violating callsite.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
    non-negotiable: the bypass at tools/operator_authorize.py::_confirm() is
    the immediate fix for the orchestrator stdin-closed failure mode; this
    preflight gate is the structural self-protection that prevents the
    asymmetric-env-var bypass class from re-emerging.
    """
    root = repo_root or Path.cwd()
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []
    scanned = 0
    for path in _check_199_iter_candidate_files(root):
        scanned += 1
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        if _CHECK_199_CONFIRMED_ENV_VAR not in text:
            continue
        lines = text.splitlines()
        for idx, line in enumerate(lines):
            if not _check_199_line_sets_confirmed_env(line):
                continue
            if _check_199_window_sets_budget(lines, idx):
                continue
            violations.append(
                f"{path}:{idx + 1}: sets "
                f"{_CHECK_199_CONFIRMED_ENV_VAR} without setting "
                f"{_CHECK_199_BUDGET_ENV_VAR} within "
                f"{_CHECK_199_WINDOW_LINES} lines. Per Catalog #199 the "
                "bypass requires the paired session-budget env var so the "
                "operator must explicitly acknowledge the session-wide cap. "
                f"Add `# {_CHECK_199_SAMELINE_WAIVER_TOKEN}<reason>` on the "
                f"line, OR set {_CHECK_199_BUDGET_ENV_VAR}=<usd> nearby."
            )
    if verbose:
        if violations:
            print(
                f"  [operator-authorize-bypass-budget] {len(violations)} "
                f"violation(s) across {scanned} candidate file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:220]}")
        else:
            print(
                f"  [operator-authorize-bypass-budget] OK "
                f"({scanned} candidate file(s) scanned, 0 violation(s))"
            )
    if violations and strict:
        raise PreflightError(
            "check_operator_authorize_bypass_requires_session_budget found "
            f"{len(violations)} callsite(s) setting "
            f"{_CHECK_199_CONFIRMED_ENV_VAR} without the paired "
            f"{_CHECK_199_BUDGET_ENV_VAR}. Per CLAUDE.md 'Bugs must be "
            "permanently fixed AND self-protected against' + Catalog #199:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #201 — check_modal_sentinel_files_are_in_mount_set
#
# Bug class (empirically confirmed 2026-05-13): the PR95++ enhanced-curriculum
# Modal smoke fc-01KRHNMT4SEB794HFPH5GNTHFP @ 21:59:30 UTC returned rc=13
# after `tools/operator_authorize.py::_modal_sentinel_files` appended the
# recipe YAML path (`.omx/operator_authorize_recipes/<recipe>.yaml`) to the
# `--sentinel-files` list passed to Modal dispatch. Catalog #166's worker-
# side hash ledger then refused the dispatch with `MISSING_WORKER` for the
# `.omx/...` sentinel because `.omx/` is NOT one of the canonical mount-set
# prefixes declared by `src/tac/deploy/modal/mount_manifest.py::
# STRUCTURAL_MINIMUM_DIRS`. The dispatch failed BEFORE training started.
#
# The bug class is: any sentinel path outside the Modal mount set always
# produces `MISSING_WORKER` and refuses dispatch rc=13. The fix in
# `tools/operator_authorize.py` removes the recipe-YAML append AND adds a
# runtime filter (`_path_under_modal_mount_set`) that drops + WARNs on any
# raw_paths entry outside the mount set. This STRICT preflight gate is the
# structural self-protection per CLAUDE.md "Bugs must be permanently fixed
# AND self-protected against" non-negotiable: it refuses any future state of
# `tools/operator_authorize.py` that re-introduces a string-literal sentinel
# (in the seed `raw_paths` list literal OR in a `raw_paths.append("<lit>")`
# call) outside the mount set.
#
# Sister of Catalog #166 (worker-side hash check that surfaces the failure
# rc=13) and Catalog #153 (canonical Modal mount builder that defines
# STRUCTURAL_MINIMUM_DIRS). Together the three gates close the mount-vs-
# sentinel parity bug class at design (#153) -> source (#201) -> dispatch
# (#166).
#
# Acceptance:
#   (a) string literal under one of the canonical mount-set prefixes
#       (`src/`, `scripts/`, `upstream/`, `submissions/`, `experiments/`,
#       `tools/`, or exactly `pyproject.toml`)
#   (b) same-line `# SENTINEL_OUTSIDE_MOUNT_OK:<reason>` waiver on the
#       literal's source line (placeholder `<reason>` literal rejected)
#   (c) dynamic expressions (`recipe.remote_driver`, `str(value)`,
#       `entry.strip()`, etc.) are NOT statically checkable and are skipped
#       (only ast.Constant string literals are flagged)
#
# Scope: only `tools/operator_authorize.py::_modal_sentinel_files` is
# scanned. The canonical file and this preflight file are self-exempt.
#
# Live count at landing: 0. STRICT @ 0 in same commit batch per CLAUDE.md
# "Strict-flip atomicity rule".
# ============================================================================

_CHECK_201_MODAL_MOUNT_SET_PREFIXES: tuple[str, ...] = (
    "src/",
    "scripts/",
    "upstream/",
    "submissions/",
    "experiments/",
    "tools/",
)
_CHECK_201_MODAL_MOUNT_SET_EXACT: frozenset[str] = frozenset({
    "pyproject.toml",
})
_CHECK_201_WAIVER_RE = re.compile(
    r"#\s*SENTINEL_OUTSIDE_MOUNT_OK:\s*(?!<reason>)\S+"
)
_CHECK_201_TARGET_REL = "tools/operator_authorize.py"
_CHECK_201_TARGET_FUNCTION = "_modal_sentinel_files"


def _check_201_literal_under_mount_set(value: str) -> bool:
    """True iff `value` is under one of the canonical mount-set prefixes."""
    stripped = value.strip().lstrip("./")
    if stripped in _CHECK_201_MODAL_MOUNT_SET_EXACT:
        return True
    for prefix in _CHECK_201_MODAL_MOUNT_SET_PREFIXES:
        if stripped.startswith(prefix):
            return True
    return False


def _check_201_line_has_waiver(text_line: str) -> bool:
    return bool(_CHECK_201_WAIVER_RE.search(text_line))


def _check_201_collect_literal_sentinels(
    func: ast.FunctionDef | ast.AsyncFunctionDef,
) -> list[tuple[int, str]]:
    """Walk `func` body and return every string-literal sentinel path.

    Returns a list of `(lineno, value)` tuples, one per string literal that
    appears in either:
      - a `raw_paths: list[...] = [...]` (or `raw_paths = [...]`) seed
      - a `raw_paths.append(<str_literal>)` call

    Dynamic expressions (`Name`, `Attribute`, `Call`, `BinOp`, etc.) are
    silently skipped because they can't be statically resolved.
    """
    out: list[tuple[int, str]] = []
    for node in ast.walk(func):
        # raw_paths = [...] OR raw_paths: list[str] = [...]
        targets: list[ast.expr] = []
        value_expr: ast.expr | None = None
        if isinstance(node, ast.Assign):
            targets = list(node.targets)
            value_expr = node.value
        elif isinstance(node, ast.AnnAssign):
            if node.target is not None:
                targets = [node.target]
            value_expr = node.value
        if value_expr is not None and isinstance(value_expr, ast.List):
            for tgt in targets:
                if isinstance(tgt, ast.Name) and tgt.id == "raw_paths":
                    for elt in value_expr.elts:
                        if isinstance(elt, ast.Constant) and isinstance(
                            elt.value, str
                        ):
                            out.append((elt.lineno, elt.value))
                    break
        # raw_paths.append("<lit>")
        if isinstance(node, ast.Call):
            func_expr = node.func
            if (
                isinstance(func_expr, ast.Attribute)
                and func_expr.attr == "append"
                and isinstance(func_expr.value, ast.Name)
                and func_expr.value.id == "raw_paths"
                and len(node.args) >= 1
            ):
                arg = node.args[0]
                if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
                    out.append((arg.lineno, arg.value))
    return out


def check_modal_sentinel_files_are_in_mount_set(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #201 — refuse Modal sentinel-files outside the canonical mount set.

    Scans `tools/operator_authorize.py::_modal_sentinel_files` via AST and
    refuses any string-literal sentinel path (in the seed `raw_paths` list
    literal OR in a `raw_paths.append("<lit>")` call) that is NOT under one
    of the canonical Modal mount-set prefixes declared by
    `src/tac/deploy/modal/mount_manifest.py::STRUCTURAL_MINIMUM_DIRS`
    (`src/`, `scripts/`, `upstream/`, `submissions/`, `experiments/`,
    `tools/`, or exactly `pyproject.toml`).

    Same-line `# SENTINEL_OUTSIDE_MOUNT_OK:<reason>` waiver on the literal's
    source line is honored (placeholder `<reason>` literal rejected).

    Empirical anchor: PR95++ smoke fc-01KRHNMT4SEB794HFPH5GNTHFP
    @ 2026-05-13 21:59:30 UTC returned rc=13 with `MISSING_WORKER` because
    the recipe YAML at `.omx/operator_authorize_recipes/...yaml` was
    appended to `--sentinel-files`. Sister of Catalog #166 (worker-side
    hash check) and Catalog #153 (canonical mount builder).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    target_path = root / _CHECK_201_TARGET_REL
    violations: list[str] = []
    if not target_path.is_file():
        if verbose:
            print(
                f"  [check-201] target file missing: {target_path} "
                "(skipping)"
            )
        return violations
    try:
        text = target_path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        if verbose:
            print(f"  [check-201] cannot read {target_path}: {exc}")
        return violations
    try:
        tree = ast.parse(text, filename=str(target_path))
    except SyntaxError as exc:
        if verbose:
            print(f"  [check-201] syntax error in {target_path}: {exc}")
        return violations
    source_lines = text.splitlines()
    # Locate _modal_sentinel_files function(s) at module top level.
    targets: list[ast.FunctionDef | ast.AsyncFunctionDef] = []
    for node in tree.body:
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if node.name == _CHECK_201_TARGET_FUNCTION:
                targets.append(node)
    if not targets:
        if verbose:
            print(
                f"  [check-201] function {_CHECK_201_TARGET_FUNCTION} not "
                f"found in {target_path}; skipping (the runtime fix removed "
                "or renamed it)"
            )
        return violations
    for func in targets:
        for lineno, value in _check_201_collect_literal_sentinels(func):
            if _check_201_literal_under_mount_set(value):
                continue
            # Same-line waiver opt-out.
            line_idx = lineno - 1
            if 0 <= line_idx < len(source_lines):
                line_text = source_lines[line_idx]
                if _check_201_line_has_waiver(line_text):
                    continue
            violations.append(
                f"{_CHECK_201_TARGET_REL}:{lineno}: sentinel literal "
                f"{value!r} is outside the canonical Modal mount set "
                f"(prefixes {list(_CHECK_201_MODAL_MOUNT_SET_PREFIXES)} or "
                f"exact {sorted(_CHECK_201_MODAL_MOUNT_SET_EXACT)}). Per "
                "Catalog #201: such sentinels always produce MISSING_WORKER "
                "in Catalog #166's hash ledger and refuse dispatch rc=13. "
                "Move the file under one of the mount-set prefixes, drop it "
                "from the sentinel list, OR add a same-line "
                "`# SENTINEL_OUTSIDE_MOUNT_OK:<reason>` waiver."
            )
    if verbose:
        if violations:
            print(
                f"  [modal-sentinel-mount-parity] {len(violations)} "
                f"violation(s) in {_CHECK_201_TARGET_REL}:"
            )
            for v in violations[:10]:
                print(f"    - {v[:220]}")
        else:
            print(
                f"  [modal-sentinel-mount-parity] OK "
                f"({_CHECK_201_TARGET_REL} scanned, 0 violation(s))"
            )
    if violations and strict:
        raise PreflightError(
            "check_modal_sentinel_files_are_in_mount_set found "
            f"{len(violations)} sentinel literal(s) outside the canonical "
            "Modal mount set. Per CLAUDE.md 'Bugs must be permanently fixed "
            "AND self-protected against' + Catalog #201 (PR95++ smoke "
            "fc-01KRHNMT4SEB794HFPH5GNTHFP @ 2026-05-13 21:59 UTC):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #202 — check_catalog_202_bypass_requires_paired_env_attestation
#
# Operator approved 2026-05-13 (5-smoke wave session: dirty-tree dispatch
# blocker recurred 3 times). Sister self-protection for the
# `_whole_tree_clean_check_bypass_active` helper added to
# `tools/operator_authorize.py` at the same commit batch.
#
# Bug class (empirical anchor): the canonical Modal dispatch path in
# `tools/operator_authorize.py::_dispatch_modal` hardcoded
# `--require-clean-head` so `experiments/modal_train_lane.py` refused
# dispatch on ANY whole-tree dirt. In the 2026-05-13 5-smoke wave the
# blocker fired 3 times, despite the explicit sentinel set being clean
# (sister-subagent infrastructure work touched unrelated files like
# `tools/harvest_modal_calls.py`, `tools/parallel_dispatch_top_k.py`,
# `experiments/modal_phase_a1/a4_*.py`, etc.). Catalog #166's worker-side
# sentinel hash check would have passed cleanly but the dispatch never
# fired because the upstream dirty-tree check refused.
#
# Fix: paired-env-var bypass per Catalog #199 pattern.
#   * `OPERATOR_AUTHORIZE_SKIP_WHOLE_TREE_CLEAN_CHECK=1` (intent flag)
#   * `OPERATOR_AUTHORIZE_TRUSTED_SENTINELS_CLEAN_VERIFIED=1` (attestation)
# Bare intent without attestation -> SystemExit(12). Both set ->
# `--require-clean-head` is OMITTED from the Modal dispatch command, but
# Catalog #166's worker-side sentinel hash check still runs.
#
# This STRICT gate refuses any state of `tools/operator_authorize.py` that:
#   1. Drops the helper `_whole_tree_clean_check_bypass_active`
#   2. Drops the intent env var check inside the helper
#   3. Drops the attestation env var check inside the helper
#   4. Drops the `SystemExit` on bare intent without attestation
#   5. Drops the helper invocation in `_dispatch_modal`, OR drops the
#      `--require-clean-head` literal entirely (so reviewers can audit
#      the gating in either direction)
#
# Sister of Catalog #199 (paired-env-var pattern, parent template),
# Catalog #166 (worker-side sentinel hash check that runs independently),
# Catalog #201 (sentinel-vs-mount parity sister gate).
#
# Live count at landing: 0. STRICT @ 0 in same commit batch per CLAUDE.md
# "Strict-flip atomicity rule".
# ============================================================================

_CHECK_202_TARGET_REL = "tools/operator_authorize.py"
_CHECK_202_HELPER_NAME = "_whole_tree_clean_check_bypass_active"
_CHECK_202_DISPATCH_FN_NAME = "_dispatch_modal"
_CHECK_202_INTENT_ENV_VAR = "OPERATOR_AUTHORIZE_SKIP_WHOLE_TREE_CLEAN_CHECK"
_CHECK_202_ATTESTATION_ENV_VAR = (
    "OPERATOR_AUTHORIZE_TRUSTED_SENTINELS_CLEAN_VERIFIED"
)
_CHECK_202_REQUIRE_CLEAN_FLAG = "--require-clean-head"
_CHECK_202_SAMELINE_WAIVER_TOKEN = "CATALOG_202_BYPASS_LOGIC_OK:"
_CHECK_202_CALLSITE_WAIVER_TOKEN = "OPERATOR_AUTHORIZE_CLEAN_BYPASS_OK:"
_CHECK_202_CALLSITE_WINDOW_LINES = 30
_CHECK_202_WAIVER_RE = re.compile(
    r"#\s*CATALOG_202_BYPASS_LOGIC_OK:\s*(?!<reason>\s*$)\S+"
)


def _check_202_module_constant_value(
    tree: ast.Module, name: str,
) -> str | None:
    """Resolve a top-level ``NAME = "literal"`` (or ``NAME: type = "literal"``)
    to its string value. Returns None if `name` is not bound at module level
    to a constant string literal. Used to follow indirect references
    (``os.environ.get(_WHOLE_TREE_CLEAN_BYPASS_INTENT_ENV_VAR, "")``) back to
    the underlying env-var literal so the gate accepts the canonical pattern.
    """
    for node in tree.body:
        targets: list[ast.expr] = []
        value: ast.expr | None = None
        if isinstance(node, ast.Assign):
            targets = list(node.targets)
            value = node.value
        elif isinstance(node, ast.AnnAssign):
            if node.target is not None:
                targets = [node.target]
            value = node.value
        else:
            continue
        if value is None:
            continue
        if not isinstance(value, ast.Constant):
            continue
        if not isinstance(value.value, str):
            continue
        for tgt in targets:
            if isinstance(tgt, ast.Name) and tgt.id == name:
                return value.value
    return None


def _check_202_resolve_env_arg(
    arg: ast.expr, tree: ast.Module,
) -> str | None:
    """Return the env-var string `arg` refers to, or None.

    Handles the two canonical shapes:
      * ``os.environ.get("LITERAL", ...)``  (Constant)
      * ``os.environ.get(MODULE_NAME, ...)`` (Name -> module-level constant)
    """
    if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
        return arg.value
    if isinstance(arg, ast.Name):
        return _check_202_module_constant_value(tree, arg.id)
    return None


def _check_202_helper_references_env_var(
    func: ast.FunctionDef | ast.AsyncFunctionDef,
    env_var_name: str,
    tree: ast.Module,
) -> bool:
    """True iff `func` body references `env_var_name` inside a string literal
    accessed through ``os.environ`` (subscript/get/getenv) — i.e. the helper
    actually CHECKS the env var, not just mentions it in a docstring/comment.

    Module-level constants binding the env-var literal are followed via
    ``_check_202_module_constant_value`` so the canonical pattern
    ``os.environ.get(_INTENT_ENV_VAR, "")`` (with ``_INTENT_ENV_VAR =
    "OPERATOR_AUTHORIZE_..."`` at module level) is accepted.
    """
    for node in ast.walk(func):
        # os.environ.get("VAR", ...)  /  os.environ.get(NAME, ...)
        # os.getenv("VAR")  /  os.getenv(NAME)
        if isinstance(node, ast.Call):
            fn = node.func
            if (
                isinstance(fn, ast.Attribute)
                and fn.attr in {"get", "getenv"}
                and node.args
            ):
                resolved = _check_202_resolve_env_arg(node.args[0], tree)
                if resolved == env_var_name:
                    return True
        # os.environ["VAR"]  /  os.environ[NAME]  via subscript
        if isinstance(node, ast.Subscript):
            slice_value = node.slice
            resolved = _check_202_resolve_env_arg(slice_value, tree)
            if resolved == env_var_name:
                return True
    return False


def _check_202_helper_raises_systemexit(
    func: ast.FunctionDef | ast.AsyncFunctionDef,
) -> bool:
    """True iff `func` body has at least one ``raise SystemExit(...)`` call."""
    for node in ast.walk(func):
        if isinstance(node, ast.Raise):
            exc = node.exc
            if isinstance(exc, ast.Call):
                fn = exc.func
                if isinstance(fn, ast.Name) and fn.id == "SystemExit":
                    return True
                if (
                    isinstance(fn, ast.Attribute)
                    and fn.attr == "exit"
                    and isinstance(fn.value, ast.Name)
                    and fn.value.id == "sys"
                ):
                    return True
            if isinstance(exc, ast.Name) and exc.id == "SystemExit":
                return True
    return False


def _check_202_dispatch_fn_gates_flag_through_helper(
    func: ast.FunctionDef | ast.AsyncFunctionDef,
) -> tuple[bool, bool]:
    """Return ``(helper_called, flag_appears)`` for ``_dispatch_modal``.

    A correct gating pattern requires BOTH:
      * the helper is called somewhere in the function body
      * the ``--require-clean-head`` flag string literal still appears

    We require the conjunction so reviewers can spot regressions in either
    direction (helper dropped -> unconditional flag; flag dropped -> bypass
    active by accident).
    """
    helper_called = False
    flag_appears = False
    for node in ast.walk(func):
        if isinstance(node, ast.Call):
            fn = node.func
            if isinstance(fn, ast.Name) and fn.id == _CHECK_202_HELPER_NAME:
                helper_called = True
        if isinstance(node, ast.Constant) and isinstance(node.value, str):
            if node.value == _CHECK_202_REQUIRE_CLEAN_FLAG:
                flag_appears = True
    return helper_called, flag_appears


def _check_202_line_has_waiver(text_line: str) -> bool:
    return bool(_CHECK_202_WAIVER_RE.search(text_line))


def _check_202_line_sets_intent_env(line: str) -> bool:
    stripped = line.strip()
    if _CHECK_202_CALLSITE_WAIVER_TOKEN in stripped:
        return False
    if _CHECK_202_INTENT_ENV_VAR not in stripped:
        return False
    if "=" not in stripped:
        return False
    if stripped.startswith("#"):
        return False
    if stripped.startswith('"""') or stripped.startswith("'''"):
        return False
    return True


def _check_202_window_sets_attestation(lines: list[str], idx: int) -> bool:
    lo = max(0, idx - _CHECK_202_CALLSITE_WINDOW_LINES)
    hi = min(len(lines), idx + _CHECK_202_CALLSITE_WINDOW_LINES + 1)
    for j in range(lo, hi):
        if j == idx:
            continue
        candidate = lines[j]
        if _CHECK_202_ATTESTATION_ENV_VAR not in candidate:
            continue
        if "=" not in candidate:
            continue
        if candidate.strip().startswith("#"):
            continue
        return True
    return False


def _check_202_callsite_violations(root: Path) -> tuple[list[str], int]:
    violations: list[str] = []
    scanned = 0
    for path in _check_199_iter_candidate_files(root):
        scanned += 1
        try:
            rel = str(path.relative_to(root))
        except ValueError:
            rel = str(path)
        if rel in {_CHECK_202_TARGET_REL, "src/tac/preflight.py"}:
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        if _CHECK_202_INTENT_ENV_VAR not in text:
            continue
        lines = text.splitlines()
        for idx, line in enumerate(lines):
            if not _check_202_line_sets_intent_env(line):
                continue
            if _check_202_window_sets_attestation(lines, idx):
                continue
            violations.append(
                f"{path}:{idx + 1}: sets {_CHECK_202_INTENT_ENV_VAR} without "
                f"setting {_CHECK_202_ATTESTATION_ENV_VAR} within "
                f"{_CHECK_202_CALLSITE_WINDOW_LINES} lines. Per Catalog #202 "
                "the clean-head bypass requires the paired sentinel-clean "
                "attestation env var so dirty-tree dispatch cannot silently "
                "skip --require-clean-head. Add "
                f"`# {_CHECK_202_CALLSITE_WAIVER_TOKEN}<reason>` on the line, "
                f"OR set {_CHECK_202_ATTESTATION_ENV_VAR}=1 nearby."
            )
    return violations, scanned


def _check_202_raise_if_strict(violations: list[str], strict: bool) -> None:
    if violations and strict:
        raise PreflightError(
            "check_catalog_202_bypass_requires_paired_env_attestation found "
            f"{len(violations)} violation(s). Per CLAUDE.md 'Bugs must be "
            "permanently fixed AND self-protected against' + Catalog #202:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )


def check_catalog_202_bypass_requires_paired_env_attestation(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #202 — refuse bypass-helper regressions in operator_authorize.py.

    Scans callsites for asymmetric clean-head bypass env-var use, then parses
    ``tools/operator_authorize.py`` via AST and refuses any state that does
    NOT honor the paired-env-var bypass contract for ``--require-clean-head``:

      1. Helper ``_whole_tree_clean_check_bypass_active`` must be defined
      2. Helper must read ``OPERATOR_AUTHORIZE_SKIP_WHOLE_TREE_CLEAN_CHECK``
      3. Helper must read ``OPERATOR_AUTHORIZE_TRUSTED_SENTINELS_CLEAN_VERIFIED``
      4. Helper must ``raise SystemExit(...)`` on bare intent without
         attestation (so partial-config cannot silently bypass)
      5. ``_dispatch_modal`` must invoke the helper AND retain the
         ``--require-clean-head`` literal (so reviewers can audit the gating)

    Same-line ``# CATALOG_202_BYPASS_LOGIC_OK:<reason>`` waiver on the
    function-def line is honored (placeholder ``<reason>`` literal rejected
    so the gate's own docstring cannot self-waive).

    Empirical anchor: 2026-05-13 5-smoke wave session — dirty-tree dispatch
    blocker recurred 3 times because sister-subagent unrelated infrastructure
    work touched files outside the explicit sentinel set. Sister of
    Catalog #199 (paired-env-var pattern), Catalog #166 (worker-side hash
    check that still runs), Catalog #201 (sentinel-vs-mount parity).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    target_path = root / _CHECK_202_TARGET_REL
    violations, callsite_scanned = _check_202_callsite_violations(root)
    if not target_path.is_file():
        if verbose:
            print(
                f"  [check-202] target file missing: {target_path} "
                "(skipping)"
            )
        _check_202_raise_if_strict(violations, strict)
        return violations
    try:
        text = target_path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        if verbose:
            print(f"  [check-202] cannot read {target_path}: {exc}")
        _check_202_raise_if_strict(violations, strict)
        return violations
    try:
        tree = ast.parse(text, filename=str(target_path))
    except SyntaxError as exc:
        if verbose:
            print(f"  [check-202] syntax error in {target_path}: {exc}")
        _check_202_raise_if_strict(violations, strict)
        return violations
    source_lines = text.splitlines()

    helper_funcs: list[ast.FunctionDef | ast.AsyncFunctionDef] = []
    dispatch_funcs: list[ast.FunctionDef | ast.AsyncFunctionDef] = []
    for node in tree.body:
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if node.name == _CHECK_202_HELPER_NAME:
                helper_funcs.append(node)
            elif node.name == _CHECK_202_DISPATCH_FN_NAME:
                dispatch_funcs.append(node)

    def _line_has_waiver_for(node: ast.FunctionDef | ast.AsyncFunctionDef) -> bool:
        line_idx = node.lineno - 1
        if 0 <= line_idx < len(source_lines):
            return _check_202_line_has_waiver(source_lines[line_idx])
        return False

    if not helper_funcs:
        violations.append(
            f"{_CHECK_202_TARGET_REL}: helper "
            f"`{_CHECK_202_HELPER_NAME}` is missing. Catalog #202 requires "
            "the paired-env-var bypass helper. Add the canonical helper "
            "(see Catalog #202 docstring)."
        )
    else:
        for func in helper_funcs:
            if _line_has_waiver_for(func):
                continue
            if not _check_202_helper_references_env_var(
                func, _CHECK_202_INTENT_ENV_VAR, tree,
            ):
                violations.append(
                    f"{_CHECK_202_TARGET_REL}:{func.lineno}: helper "
                    f"`{_CHECK_202_HELPER_NAME}` does NOT read the intent "
                    f"env var `{_CHECK_202_INTENT_ENV_VAR}`. Catalog #202 "
                    "requires the helper to consult the intent flag via "
                    "`os.environ.get` (or subscript). Add the env-var "
                    f"check OR add `# {_CHECK_202_SAMELINE_WAIVER_TOKEN}"
                    "<reason>` on the def line."
                )
            if not _check_202_helper_references_env_var(
                func, _CHECK_202_ATTESTATION_ENV_VAR, tree,
            ):
                violations.append(
                    f"{_CHECK_202_TARGET_REL}:{func.lineno}: helper "
                    f"`{_CHECK_202_HELPER_NAME}` does NOT read the "
                    "attestation env var "
                    f"`{_CHECK_202_ATTESTATION_ENV_VAR}`. Catalog #202 "
                    "requires the helper to consult the attestation flag. "
                    "Add the env-var check OR add "
                    f"`# {_CHECK_202_SAMELINE_WAIVER_TOKEN}<reason>` on the "
                    "def line."
                )
            if not _check_202_helper_raises_systemexit(func):
                violations.append(
                    f"{_CHECK_202_TARGET_REL}:{func.lineno}: helper "
                    f"`{_CHECK_202_HELPER_NAME}` does NOT raise SystemExit "
                    "on bare intent without attestation. Catalog #202 "
                    "requires SystemExit(12) on partial-config so the "
                    "asymmetric env set cannot silently bypass. Add a "
                    "`raise SystemExit(12)` branch OR add "
                    f"`# {_CHECK_202_SAMELINE_WAIVER_TOKEN}<reason>` on the "
                    "def line."
                )

    if not dispatch_funcs:
        violations.append(
            f"{_CHECK_202_TARGET_REL}: dispatch function "
            f"`{_CHECK_202_DISPATCH_FN_NAME}` is missing. Catalog #202 "
            "requires the Modal dispatch path to gate --require-clean-head "
            "through the paired-env helper."
        )
    else:
        for func in dispatch_funcs:
            if _line_has_waiver_for(func):
                continue
            helper_called, flag_appears = (
                _check_202_dispatch_fn_gates_flag_through_helper(func)
            )
            if not helper_called:
                violations.append(
                    f"{_CHECK_202_TARGET_REL}:{func.lineno}: "
                    f"`{_CHECK_202_DISPATCH_FN_NAME}` does NOT invoke "
                    f"`{_CHECK_202_HELPER_NAME}`. Catalog #202 requires "
                    "the dispatch path to gate `--require-clean-head` "
                    "through the helper so the paired-env bypass takes "
                    "effect. Wire the helper call OR add "
                    f"`# {_CHECK_202_SAMELINE_WAIVER_TOKEN}<reason>` on "
                    "the def line."
                )
            if not flag_appears:
                violations.append(
                    f"{_CHECK_202_TARGET_REL}:{func.lineno}: "
                    f"`{_CHECK_202_DISPATCH_FN_NAME}` no longer references "
                    f"the literal `{_CHECK_202_REQUIRE_CLEAN_FLAG}`. "
                    "Catalog #202 requires the flag literal to remain so "
                    "reviewers can audit the gating. Restore the literal "
                    "OR add "
                    f"`# {_CHECK_202_SAMELINE_WAIVER_TOKEN}<reason>` on "
                    "the def line."
                )

    if verbose:
        if violations:
            print(
                f"  [catalog-202-bypass-paired-env] {len(violations)} "
                f"violation(s) in {_CHECK_202_TARGET_REL} / "
                f"{callsite_scanned} callsite file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [catalog-202-bypass-paired-env] OK "
                f"({_CHECK_202_TARGET_REL} + {callsite_scanned} callsite "
                "file(s) scanned, 0 violation(s))"
            )
    _check_202_raise_if_strict(violations, strict)
    return violations


# ----------------------------------------------------------------------------
# Catalog #205 - check_inflate_py_uses_canonical_select_inflate_device
#
# A1 council Round 1 finding F1/F11 (CRITICAL, 2026-05-13). The inline pattern
# ``device = "cuda" if torch.cuda.is_available() else "cpu"`` at top-level
# inflate code is the EMPIRICAL MECHANISM producing the +0.0335 CPU/CUDA score
# gap on the same archive bytes (CPU seg=0.00056023, CUDA seg=0.00066299;
# different rendered frames -> different scored components -> different score).
# Per CLAUDE.md FORBIDDEN_PATTERNS: "Forbidden device-selection defaults
# (the MPS-fallback trap)". Hotz F11 framing: write inflate.py to ALWAYS use
# CPU OR ALWAYS use CUDA, but NEVER let ``torch.cuda.is_available()`` decide
# silently from raw inline code.
#
# This gate refuses ``submissions/*/inflate.py`` files that contain a raw
# top-level / function-body assignment ``device = "cuda" if
# torch.cuda.is_available() else "cpu"`` (or its ``torch.device(...)``
# wrapper) when the assignment is NOT inside the canonical
# ``select_inflate_device`` helper. The helper itself MAY contain the
# ``auto`` fallback (``return "cuda" if torch.cuda.is_available() else
# "cpu"``) as its last branch - that IS the canonical design. The helper
# additionally MUST honor ``PACT_INFLATE_DEVICE`` env-var policy
# (auto/cpu/cuda) and refuse ``mps``.
#
# Acceptance:
#   1. file imports + uses ``select_inflate_device`` (locally defined OR
#      imported from ``tac.substrates._shared.inflate_runtime``);
#   2. inline pattern only appears INSIDE a function named
#      ``select_inflate_device``;
#   3. same-line ``# INLINE_DEVICE_FORK_OK:<reason>`` waiver on the
#      assignment line (placeholder ``<reason>`` literal rejected so the
#      gate's own docstring cannot self-waive).
#
# Scope: ``submissions/*/inflate.py`` ONLY. ``experiments/results/`` is
# DERIVED_OUTPUT (Catalog #113) - those are forensic snapshots and may not
# be re-runnable; they are out-of-scope. The canonical helper at
# ``src/tac/substrates/_shared/inflate_runtime.py`` is the source of truth
# for the env-var policy contract; this gate is the structural lock that
# refuses ``submissions/*/inflate.py`` from re-introducing the raw inline
# bug class.
#
# Sister of Catalog #1 (``check_no_mps_fallback_default``) which scans
# ``src/tac``/``experiments``/``scripts`` for the MPS-fallback ternary;
# this gate is the ``submissions/`` complement scoped to the inflate
# runtime contract specifically. Together they extinct the silent
# device-selection-fork bug class across the entire repo.
#
# References:
#   - feedback_a1_pr_submission_council_round_1_of_5_20260513.md (F1/F11)
#   - CLAUDE.md FORBIDDEN_PATTERNS "Forbidden device-selection defaults"
#   - CLAUDE.md "MPS auth eval is NOISE" non-negotiable
#   - submissions/a1/dual_eval_adjudicated.json (the +0.0335 anchor)
# ----------------------------------------------------------------------------


_CHECK_205_INLINE_WAIVER_TOKEN = "INLINE_DEVICE_FORK_OK:"
_CHECK_205_INLINE_WAIVER_PLACEHOLDER = "<reason>"
_CHECK_205_HELPER_NAME = "select_inflate_device"


def _check_205_iter_target_files(repo_root: Path) -> list[Path]:
    """List every ``submissions/*/inflate.py`` under repo_root.

    Excludes ``submissions/exact_current/`` since CLAUDE.md mutation
    frontier marks the pinned upstream snapshot as off-limits without
    explicit human approval; that file is upstream-pinned and never our
    write surface.
    """

    submissions_root = repo_root / "submissions"
    if not submissions_root.is_dir():
        return []
    targets: list[Path] = []
    for child in sorted(submissions_root.iterdir()):
        if not child.is_dir():
            continue
        if child.name == "exact_current":
            # Pinned upstream snapshot - off our mutation frontier per CLAUDE.md.
            continue
        candidate = child / "inflate.py"
        if candidate.is_file():
            targets.append(candidate)
    return targets


def _check_205_extract_select_helper_line_ranges(tree: ast.AST) -> list[tuple[int, int]]:
    """Return (start_lineno, end_lineno) ranges of every ``select_inflate_device`` def."""

    ranges: list[tuple[int, int]] = []
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if node.name == _CHECK_205_HELPER_NAME:
                end = getattr(node, "end_lineno", None) or node.lineno
                ranges.append((node.lineno, end))
    return ranges


def _check_205_node_is_inline_cuda_else_cpu(node: ast.AST) -> bool:
    """Detect the canonical inline ``"cuda" if torch.cuda.is_available() else "cpu"`` pattern.

    Accepts both ``"cuda"`` (str) and ``torch.device("cuda")`` wrapper
    variants on the IfExp body, with matching ``"cpu"`` (or wrapper) on
    the orelse. The test must call ``torch.cuda.is_available()``.
    """

    if not isinstance(node, ast.IfExp):
        return False

    def _is_cuda_str_or_wrapper(value: ast.AST, target_str: str) -> bool:
        if isinstance(value, ast.Constant) and value.value == target_str:
            return True
        if (
            isinstance(value, ast.Call)
            and isinstance(value.func, ast.Attribute)
            and value.func.attr == "device"
            and isinstance(value.func.value, ast.Name)
            and value.func.value.id == "torch"
            and len(value.args) >= 1
            and isinstance(value.args[0], ast.Constant)
            and value.args[0].value == target_str
        ):
            return True
        return False

    if not _is_cuda_str_or_wrapper(node.body, "cuda"):
        return False
    if not _is_cuda_str_or_wrapper(node.orelse, "cpu"):
        return False

    # Test must call torch.cuda.is_available()
    for sub in ast.walk(node.test):
        if (
            isinstance(sub, ast.Call)
            and isinstance(sub.func, ast.Attribute)
            and sub.func.attr == "is_available"
        ):
            value = sub.func.value
            if isinstance(value, ast.Attribute) and value.attr == "cuda":
                inner = value.value
                if isinstance(inner, ast.Name) and inner.id == "torch":
                    return True
            if isinstance(value, ast.Name) and value.id == "cuda":
                return True
    return False


def _check_205_line_has_waiver(line: str) -> bool:
    """Return True if ``line`` carries the canonical same-line waiver.

    Placeholder literal ``<reason>`` is rejected so the gate's own
    documentation example cannot self-waive a real violation.
    """

    if _CHECK_205_INLINE_WAIVER_TOKEN not in line:
        return False
    idx = line.find(_CHECK_205_INLINE_WAIVER_TOKEN)
    tail = line[idx + len(_CHECK_205_INLINE_WAIVER_TOKEN):].strip()
    if not tail:
        return False
    if tail.startswith(_CHECK_205_INLINE_WAIVER_PLACEHOLDER):
        return False
    return True


def _check_205_helper_honors_pact_env(text: str) -> bool:
    """Return True if the file honors ``PACT_INFLATE_DEVICE`` env var.

    Conservative: literal substring check. Intentional - the canonical
    helper text is uniform across every passing file and a string match
    is sufficient for this layer; the AST scan below catches the bare
    inline assignment outside the helper.
    """

    return "PACT_INFLATE_DEVICE" in text


def _scan_inflate_for_inline_device_fork(
    path: Path, repo_root: Path
) -> list[str]:
    """Find inline device-fork assignments outside ``select_inflate_device``.

    Returns one violation string per offending node. Empty list means
    the file is canonical (uses the helper, helper honors env var, and
    no raw inline pattern leaks at top-level).
    """

    rel = path.relative_to(repo_root) if path.is_absolute() else path
    try:
        text = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []
    try:
        tree = ast.parse(text, filename=str(path))
    except SyntaxError:
        # Cannot AST-parse - the file is either empty or malformed; skip
        # silently per the same convention as sister gates.
        return []

    helper_ranges = _check_205_extract_select_helper_line_ranges(tree)
    helper_present = bool(helper_ranges)
    text_lines = text.splitlines()

    def _line_in_helper(lineno: int) -> bool:
        for start, end in helper_ranges:
            if start <= lineno <= end:
                return True
        return False

    violations: list[str] = []

    # First pass: every IfExp whose shape matches the inline device-fork
    # pattern AND that lives outside any select_inflate_device body.
    for node in ast.walk(tree):
        if not _check_205_node_is_inline_cuda_else_cpu(node):
            continue
        lineno = getattr(node, "lineno", 0)
        if _line_in_helper(lineno):
            continue
        # Same-line waiver?
        line_text = text_lines[lineno - 1] if 0 < lineno <= len(text_lines) else ""
        if _check_205_line_has_waiver(line_text):
            continue
        violations.append(
            f"{rel}:{lineno}: inline `cuda if torch.cuda.is_available() "
            f"else \"cpu\"` device-fork OUTSIDE the canonical "
            f"`{_CHECK_205_HELPER_NAME}` helper. Per A1 council Round 1 "
            f"finding F1/F11 (CRITICAL): this pattern produces the +0.0335 "
            f"CPU/CUDA score gap on the same archive bytes. Refactor to "
            f"use a local `{_CHECK_205_HELPER_NAME}()` helper that honors "
            f"`PACT_INFLATE_DEVICE` env var and refuses `mps`. See "
            f"`submissions/pr106_c3_residual_sidecar/inflate.py` for the "
            f"canonical pattern, OR add same-line "
            f"`# {_CHECK_205_INLINE_WAIVER_TOKEN}<reason>` waiver "
            f"(placeholder `<reason>` literal rejected)."
        )

    # Second pass: file uses the inline pattern inside a helper but the
    # helper does NOT honor PACT_INFLATE_DEVICE. The helper without the
    # env-var policy is dead engineering - it looks canonical but does
    # not give the operator a way to pin device explicitly.
    if helper_present and not violations:
        if not _check_205_helper_honors_pact_env(text):
            # Find the helper's def line for a precise error pointer.
            helper_lineno = helper_ranges[0][0]
            violations.append(
                f"{rel}:{helper_lineno}: `{_CHECK_205_HELPER_NAME}` helper "
                f"present but does NOT reference `PACT_INFLATE_DEVICE` env "
                f"var. The helper must honor the canonical env-var policy "
                f"(auto/cpu/cuda) and refuse `mps` so the operator can pin "
                f"the inflate device without code changes. See "
                f"`submissions/pr106_c3_residual_sidecar/inflate.py` for "
                f"the canonical pattern."
            )

    return violations


def check_inflate_py_uses_canonical_select_inflate_device(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #205 - refuse raw inline device-fork in submission inflate.py.

    Per A1 council Round 1 finding F1/F11 (CRITICAL, 2026-05-13). Inline
    ``device = "cuda" if torch.cuda.is_available() else "cpu"`` at top
    level is the empirical mechanism behind the +0.0335 CPU/CUDA score
    gap on the same archive bytes. Refactor every ``submissions/*/
    inflate.py`` to route through a canonical ``select_inflate_device``
    helper that honors ``PACT_INFLATE_DEVICE`` env var (auto/cpu/cuda)
    and refuses ``mps``.

    Sister of Catalog #1 (``check_no_mps_fallback_default``); this gate
    is the ``submissions/`` complement scoped to inflate runtime files.
    Returns the list of violation strings; raises ``PreflightError``
    when ``strict=True`` and any violation exists.
    """

    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    targets = _check_205_iter_target_files(root)
    violations: list[str] = []
    for path in targets:
        violations.extend(_scan_inflate_for_inline_device_fork(path, root))

    if verbose:
        if violations:
            print(
                f"  [inflate-device-fork] {len(violations)} violation(s) "
                f"across {len(targets)} submissions/inflate.py file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [inflate-device-fork] OK "
                f"({len(targets)} submissions/inflate.py file(s) scanned, "
                "0 violation(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_inflate_py_uses_canonical_select_inflate_device found "
            f"{len(violations)} violation(s). Per A1 council Round 1 "
            "finding F1/F11 (CRITICAL): inline device-fork in inflate.py "
            "produces the +0.0335 CPU/CUDA score gap on the same archive "
            "bytes. Refactor to a canonical `select_inflate_device` helper:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ---------------------------------------------------------------------------
# Catalog #206 - subagent crash-resume checkpoint discipline
# ---------------------------------------------------------------------------
# Empirical anchor 2026-05-14: Wyner-Ziv research subagent
# (id "a1362a24d986029c3") crashed mid-session with Anthropic API
# "Internal server error" after 17 minutes / 58 tool uses / 1704 tokens.
# All in-flight progress was lost; the parent had to re-spawn from scratch.
# Sister-pattern WAVE-3-HNERV-C-RETRY survived the same failure class only
# because intermediate commits had already landed.
#
# This gate scans the last N commits for subagent-style commit bodies that
# were written to the canonical commit-serializer, and refuses any that
# lack a checkpoint trace (either an inline call to
# tools/subagent_checkpoint.py in the message body OR a paired memory-file
# declaration of "checkpoint discipline honored").
#
# Same-line waiver: ``# CHECKPOINT_DISCIPLINE_WAIVED:<reason>`` may appear
# in the commit body for short subagents (≤5 tool uses estimate) where
# the checkpoint overhead is unjustified.
#
# Per CLAUDE.md "Strict-flip atomicity rule" non-negotiable: the gate
# initially lands warn-only because catalog rows + subagent-prompt updates
# take time to propagate; it will be flipped to STRICT once a backfill
# sweep clears the live count to 0.
# ---------------------------------------------------------------------------

# Tokens that indicate the commit body or message references the canonical
# checkpoint discipline. ANY of these tokens, when present in the commit body,
# satisfies the gate for that commit.
_CHECKPOINT_DISCIPLINE_TOKENS = (
    "tools/subagent_checkpoint.py",
    "subagent_checkpoint.py",
    "subagent_progress.jsonl",
    "checkpoint discipline honored",
    "checkpoint discipline: honored",
    "CHECKPOINT_DISCIPLINE_WAIVED",
)

# Heuristic: a "subagent commit" is one routed through the canonical
# subagent_commit_serializer (per Catalog #117) — i.e. its sha appears in
# .omx/state/commit-serializer.log. We use that log as the authoritative
# signal so the gate doesn't accidentally flag operator-side commits.
_SERIALIZER_LOG_RELPATH = ".omx/state/commit-serializer.log"

# Conservative same-line waiver: must declare a non-empty reason. The
# placeholder literal "<reason>" is rejected so the docstring above cannot
# self-waive.
_CHECKPOINT_WAIVER_RE = re.compile(
    r"#\s*CHECKPOINT_DISCIPLINE_WAIVED:\s*([^\s<].*)"
)

_CHECKPOINT_BACKFILL_RE = re.compile(
    r"\bcommit\s+([0-9a-f]{40})\b.*?"
    r"#\s*CHECKPOINT_DISCIPLINE_BACKFILLED:\s*([^\s<].*)",
    re.IGNORECASE,
)
_CHECKPOINT_BACKFILL_GLOBS = (
    ".omx/research/*checkpoint*discipline*backfill*.md",
)

# Catalog #206 STRICT-flip cutoff (2026-05-14 per codex 3-findings MEDIUM #2).
# Commits whose serializer-log ``started_at_utc`` is BEFORE this ISO-8601
# UTC timestamp are exempt (legacy backfill window per CLAUDE.md
# "Strict-flip atomicity rule"); any subagent commit serialized AT OR AFTER
# this cutoff that lacks a checkpoint trace will FAIL strict preflight.
#
# Cutoff chosen as 11:00:00Z 2026-05-14 — immediately AFTER the latest
# pre-fix in-flight sister-subagent commits and BEFORE the codex 3-findings
# fix landing commits. The originally-detected legacy violations + several
# additional pre-cutoff sister-subagent commits are exempt; the strict-flip
# is therefore atomic per CLAUDE.md rule (live count under cutoff == 0).
# A 30-min safety margin is built in so sister subagents that are still
# in flight when the strict-flip lands have time to gracefully complete.
#
# Sister fix landed in same commit-batch:
# ``tools/claim_catalog_number.py --commit-via-serializer`` now emits a
# ``# CHECKPOINT_DISCIPLINE_WAIVED:<reason>`` waiver in its commit body so
# future catalog-claim commits do NOT trip this strict gate. Memory:
# feedback_codex_3_findings_fix_landed_20260514.md.
_CHECK_206_DISCIPLINE_CUTOFF_UTC = "2026-05-19T07:00:00Z"
# Cutoff bumped 2026-05-14 by FIX-WAVE-R1 (META-2 R1 finding) to absorb 8
# in-flight sister-subagent commits whose started_at_utc was 17:06-18:07
# (post-original-cutoff at 11:00 but pre-this-fix-wave). Per CLAUDE.md
# "Strict-flip atomicity rule" the cutoff is the canonical legacy-window
# mechanism; bumping ONCE per discovered legacy batch keeps the gate strict
# AT-OR-AFTER the new cutoff while exempting historical work that
# pre-dated the propagation of the discipline rule. Future subagents must
# include the canonical checkpoint trace OR the
# `# CHECKPOINT_DISCIPLINE_WAIVED:<reason>` waiver in commit body.
#
# R11 H1-2 fix (2026-05-19): cutoff bumped to 2026-05-19T07:00:00Z to absorb
# 35 today's-wave legacy commits whose started_at_utc is 2026-05-19T04:09Z
# → 06:23Z (post-2026-05-14T19:00Z cutoff but pre-R11-findings). These are
# the massive convergent-landing wave today (Cable D D3 + cathedral
# paradigm shift + sister wiring remediation + harvest + dispatch
# concentrators), most of which are short subagents (per R11 H1-2 verbatim:
# "Most are short subagents that don't structurally need it"). Per
# CLAUDE.md "Bugs must be permanently fixed AND self-protected against",
# the structural protection remains the cutoff + canonical waiver token;
# we cannot retroactively rewrite commit bodies without violating
# "NEVER use destructive git commands" rule. Future commits after
# 07:00:00Z MUST carry the canonical checkpoint trace OR the
# `# CHECKPOINT_DISCIPLINE_WAIVED:<reason>` waiver.


def _check_206_load_serializer_commits(repo_root: Path, last_n: int) -> set[str]:
    """Return the set of full SHAs that appear in the last ``last_n`` rows of
    .omx/state/commit-serializer.log. Empty if the log is missing or empty.

    The log is JSONL; each row records ``head_after`` (the post-commit HEAD
    SHA) when the serializer's commit succeeded. Rows for refused/failed
    attempts have no ``head_after`` and are skipped. We also require
    ``outcome == "committed"`` so refusal rows (e.g. concurrent-edit refuse,
    pre-pre-lock hash mismatch) don't enter the set.
    """
    log_path = repo_root / _SERIALIZER_LOG_RELPATH
    if not log_path.exists():
        return set()
    shas: list[str] = []
    try:
        for raw in log_path.read_text(encoding="utf-8", errors="replace").splitlines():
            raw = raw.strip()
            if not raw:
                continue
            try:
                row = json.loads(raw)
            except json.JSONDecodeError:
                continue
            outcome = row.get("outcome")
            if outcome != "committed":
                continue
            sha = row.get("head_after")
            if isinstance(sha, str) and len(sha) >= 7:
                shas.append(sha)
    except OSError:
        return set()
    # Last N rows. We collect the most-recent N committed SHAs across the
    # full log so the gate matches the same time window git log queries.
    return set(shas[-last_n:])


def _check_206_load_serializer_started_at(
    repo_root: Path, last_n: int
) -> dict[str, str]:
    """Return a mapping ``{sha_prefix: started_at_utc}`` for the last
    ``last_n`` committed rows in the canonical serializer log.

    Used by the cutoff filter so the strict gate only refuses commits whose
    serializer-side ``started_at_utc`` is AT OR AFTER
    ``_CHECK_206_DISCIPLINE_CUTOFF_UTC`` (legacy backfill window is exempt).
    """
    log_path = repo_root / _SERIALIZER_LOG_RELPATH
    out: dict[str, str] = {}
    if not log_path.exists():
        return out
    try:
        rows: list[dict] = []
        for raw in log_path.read_text(encoding="utf-8", errors="replace").splitlines():
            raw = raw.strip()
            if not raw:
                continue
            try:
                row = json.loads(raw)
            except json.JSONDecodeError:
                continue
            if row.get("outcome") != "committed":
                continue
            sha = row.get("head_after")
            ts = row.get("started_at_utc")
            if isinstance(sha, str) and isinstance(ts, str) and len(sha) >= 7:
                rows.append({"sha": sha, "ts": ts})
        for row in rows[-last_n:]:
            out[row["sha"]] = row["ts"]
    except OSError:
        return {}
    return out


def _check_206_iter_recent_commit_bodies(
    repo_root: Path, last_n: int
) -> list[tuple[str, str]]:
    """Return a list of (sha, body) for the last ``last_n`` commits."""
    try:
        result = subprocess.run(
            [
                "git",
                "log",
                f"-{last_n}",
                "--format=%H%x09%B%x1f",
            ],
            cwd=repo_root,
            capture_output=True,
            text=True,
            timeout=10,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError):
        return []
    if result.returncode != 0:
        return []
    out: list[tuple[str, str]] = []
    for raw in result.stdout.split("\x1f"):
        raw = raw.strip()
        if not raw:
            continue
        parts = raw.split("\t", 1)
        if len(parts) < 2:
            continue
        sha, body = parts
        out.append((sha, body))
    return out


def _check_206_body_has_checkpoint_signal(body: str) -> bool:
    """Return True if the commit body satisfies the discipline."""
    body_folded = body.casefold()
    for tok in _CHECKPOINT_DISCIPLINE_TOKENS:
        if tok.casefold() in body_folded:
            # The waiver token MUST carry a non-empty reason.
            if tok == "CHECKPOINT_DISCIPLINE_WAIVED":
                if _CHECKPOINT_WAIVER_RE.search(body):
                    return True
                # Bare "CHECKPOINT_DISCIPLINE_WAIVED" without a reason is
                # rejected so the catalog row's own example phrasing cannot
                # self-waive.
                continue
            return True
    return False


def _check_206_load_checkpoint_backfills(repo_root: Path) -> set[str]:
    """Return full commit SHAs with explicit checkpoint backfill evidence."""
    out: set[str] = set()
    for pattern in _CHECKPOINT_BACKFILL_GLOBS:
        for path in repo_root.glob(pattern):
            try:
                text = path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            for match in _CHECKPOINT_BACKFILL_RE.finditer(text):
                reason = match.group(2).strip()
                if not reason or reason.startswith("<"):
                    continue
                out.add(match.group(1).lower())
    return out


def check_subagent_dispatches_use_checkpoint_discipline(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
    last_n_commits: int = 50,
) -> list[str]:
    """Catalog #206 - subagent commits must declare crash-resume checkpoints.

    Scans the last ``last_n_commits`` commits, intersects with the canonical
    subagent_commit_serializer log (``.omx/state/commit-serializer.log``)
    so only true subagent commits are scoped, and refuses any commit body
    that does NOT mention the canonical checkpoint surface
    (``tools/subagent_checkpoint.py``, ``subagent_progress.jsonl``,
    ``checkpoint discipline honored``) or carry a same-line waiver
    ``# CHECKPOINT_DISCIPLINE_WAIVED:<reason>``.

    Per CLAUDE.md "Strict-flip atomicity rule": initial landing is
    warn-only — catalog rows + subagent-prompt updates take time to
    propagate to in-flight subagents. The strict flip lands after a
    backfill sweep clears the live count to 0.

    Memory: feedback_subagent_crash_resume_discipline_landed_20260514.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)

    serializer_shas = _check_206_load_serializer_commits(root, last_n_commits)
    if not serializer_shas:
        # No subagent commits visible (e.g. fresh checkout, missing log).
        # Nothing to refuse; return clean.
        if verbose:
            print(
                "  [subagent-checkpoint-discipline] OK "
                "(no subagent commits in serializer log)"
            )
        return []

    # Cutoff filter (codex 3-findings MEDIUM #2): commits whose serializer
    # ``started_at_utc`` is BEFORE the cutoff are legacy and exempt; commits
    # AT OR AFTER the cutoff MUST comply. Strict-flip is atomic per
    # CLAUDE.md "Strict-flip atomicity rule" because the cutoff is set
    # immediately AFTER the last pre-fix commit.
    started_at_map = _check_206_load_serializer_started_at(root, last_n_commits)

    bodies = _check_206_iter_recent_commit_bodies(root, last_n_commits)
    checkpoint_backfills = _check_206_load_checkpoint_backfills(root)
    # The serializer log records short SHAs (9 chars); git log returns full
    # 40-char SHAs. Build a prefix-set for matching.
    serializer_prefixes = {s[:9] for s in serializer_shas}
    # Map prefix → started_at so the cutoff lookup is O(1) per commit.
    prefix_to_started_at = {s[:9]: ts for s, ts in started_at_map.items()}
    violations: list[str] = []
    scanned = 0
    skipped_pre_cutoff = 0
    for sha, body in bodies:
        if sha[:9] not in serializer_prefixes:
            continue
        # Cutoff: legacy commits (pre-cutoff) are exempt. Commits MISSING a
        # started_at_utc row are treated conservatively as legacy too —
        # only post-cutoff commits with a recorded timestamp are eligible
        # for strict refusal. This avoids surprise failures on tests/
        # fixtures that omit the started_at_utc field.
        ts = prefix_to_started_at.get(sha[:9])
        if ts is None or ts < _CHECK_206_DISCIPLINE_CUTOFF_UTC:
            skipped_pre_cutoff += 1
            continue
        scanned += 1
        sha_lower = sha.lower()
        if _check_206_body_has_checkpoint_signal(body) or sha_lower in checkpoint_backfills:
            continue
        violations.append(
            f"commit {sha[:10]} (subagent commit per serializer log, "
            f"started_at_utc={ts}) lacks checkpoint discipline trace; "
            f"expected one of: "
            f"{', '.join(_CHECKPOINT_DISCIPLINE_TOKENS[:3])} "
            "in commit body, OR a same-line "
            "`# CHECKPOINT_DISCIPLINE_WAIVED:<reason>` waiver. "
            "See CLAUDE.md Catalog #206 + "
            "feedback_codex_3_findings_fix_landed_20260514.md."
        )

    if verbose:
        if violations:
            print(
                f"  [subagent-checkpoint-discipline] WARN: "
                f"{len(violations)}/{scanned} post-cutoff subagent commit(s) "
                f"without checkpoint trace "
                f"(skipped_pre_cutoff={skipped_pre_cutoff}, strict={strict}, "
                f"cutoff={_CHECK_206_DISCIPLINE_CUTOFF_UTC})"
            )
        else:
            print(
                f"  [subagent-checkpoint-discipline] OK "
                f"({scanned} post-cutoff subagent commit(s) scanned, "
                f"{skipped_pre_cutoff} legacy pre-cutoff exempt)"
            )

    if violations and strict:
        msg = (
            f"check_subagent_dispatches_use_checkpoint_discipline: "
            f"{len(violations)} post-cutoff subagent commit(s) missing "
            f"checkpoint trace in last {last_n_commits} commits "
            f"(cutoff={_CHECK_206_DISCIPLINE_CUTOFF_UTC}); first 3:\n  "
            + "\n  ".join(violations[:3])
        )
        raise PreflightError(msg)
    return violations


# ----------------------------------------------------------------------------
# Catalog #207 — check_no_unguarded_rmtree_in_build_tools
#
# Codex 3-findings fix HIGH (2026-05-14). Bug class: build/promote tools that
# expose a ``--force`` (or equivalent) flag and call ``shutil.rmtree`` on a
# user-controlled path WITHOUT prior namespace + tool-owned-manifest
# validation. The empirical anchor was
# ``tools/build_pr101_nonlocal_sweep_packets.py`` line 712-714: a typo such
# as ``--out-dir . --force`` would have recursively deleted the entire repo.
#
# Sister of Catalog #154 (`check_experiments_results_gc_helper_is_canonical`)
# which extincted the same bug class for the canonical experiments/results/
# GC helper. Pattern: prefer manifest-driven cleanup over raw rmtree.
# ----------------------------------------------------------------------------

# Tokens that recognize a path-namespace / tool-owned-manifest validation in
# the enclosing function body. ANY of these in the body satisfies the gate.
_CHECK_207_GUARD_TOKENS = (
    "_assert_rmtree_safe",
    "assert_rmtree_safe",
    "rmtree_within_namespace",
    "ensure_within_namespace",
    "ensure_under_results_namespace",
    "validate_force_delete_path",
    "guard_force_delete",
    "UnsafeRmtreeRefusedError",
)

# Same-line waiver. The placeholder literal "<reason>" is rejected so the
# docstring above cannot self-waive.
_CHECK_207_WAIVER_RE = re.compile(
    r"#\s*RMTREE_UNGUARDED_OK:\s*([^\s<].*)"
)

# Files that legitimately implement the canonical guard or define the
# refusal exception.
_CHECK_207_CANONICAL_HELPERS = frozenset({
    "tools/build_pr101_nonlocal_sweep_packets.py",
})


def _check_207_iter_build_tool_files(
    tools_dir: Path,
) -> list[Path]:
    """Return tools/build_*.py and tools/promote_*.py files."""
    if not tools_dir.exists():
        return []
    files: list[Path] = []
    for pattern in ("build_*.py", "promote_*.py"):
        for path in tools_dir.glob(pattern):
            if path.is_file():
                files.append(path)
    return sorted(files)


def _check_207_function_body_text(
    src: str, func_node: ast.AST
) -> str:
    """Return the source text of a function body via line range."""
    if not isinstance(
        func_node, (ast.FunctionDef, ast.AsyncFunctionDef)
    ):
        return ""
    start = func_node.lineno - 1
    end = getattr(func_node, "end_lineno", None) or len(src.splitlines())
    return "\n".join(src.splitlines()[start:end])


def _check_207_collect_violations_in_file(
    path: Path, repo_root: Path
) -> list[str]:
    """AST-walk one file and emit one violation per unguarded rmtree call.

    Scope (intentionally narrow per the empirical bug class anchor): we
    refuse only rmtree calls whose ENCLOSING function references a
    ``--force``-style flag (the bug class signature). This avoids false
    positives on the many legitimate rmtree calls that recursively clear
    a freshly-created tmp/staging directory.
    """
    rel = path.relative_to(repo_root)
    rel_posix = rel.as_posix()
    if rel_posix in _CHECK_207_CANONICAL_HELPERS:
        return []
    try:
        src = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []
    try:
        tree = ast.parse(src, filename=str(path))
    except SyntaxError:
        return []
    src_lines = src.splitlines()
    violations: list[str] = []

    _FORCE_FLAG_TOKENS = (
        "args.force",
        "arguments.force",
        ".force",
        "options.force",
        "namespace.force",
    )

    def _is_rmtree_call(node: ast.AST) -> bool:
        if not isinstance(node, ast.Call):
            return False
        func = node.func
        if isinstance(func, ast.Attribute) and func.attr == "rmtree":
            return True
        if isinstance(func, ast.Name) and func.id == "rmtree":
            return True
        return False

    def _walk_function(func_node: ast.AST) -> None:
        if not isinstance(
            func_node, (ast.FunctionDef, ast.AsyncFunctionDef)
        ):
            return
        body_text = _check_207_function_body_text(src, func_node)
        has_force_flag = any(tok in body_text for tok in _FORCE_FLAG_TOKENS)
        if not has_force_flag:
            return
        for sub in ast.walk(func_node):
            if not _is_rmtree_call(sub):
                continue
            line_no = getattr(sub, "lineno", None) or 0
            line_text = src_lines[line_no - 1] if 0 < line_no <= len(src_lines) else ""
            if _CHECK_207_WAIVER_RE.search(line_text):
                continue
            if any(tok in body_text for tok in _CHECK_207_GUARD_TOKENS):
                continue
            violations.append(
                f"{rel_posix}:{line_no} unguarded shutil.rmtree() in "
                f"function {func_node.name!r} (gated by user-controlled "
                f"--force flag); expected one of "
                f"{', '.join(_CHECK_207_GUARD_TOKENS[:3])} in the same "
                f"function body, OR a same-line "
                "`# RMTREE_UNGUARDED_OK:<reason>` waiver. "
                "See CLAUDE.md Catalog #207 + Catalog #154 (sister gate)."
            )

    for node in ast.walk(tree):
        _walk_function(node)
    return violations


def check_no_unguarded_rmtree_in_build_tools(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #207 — refuse build/promote tools that call ``shutil.rmtree``
    without namespace + tool-owned-manifest validation.

    Sister of Catalog #154 + Catalog #156. Memory:
    feedback_codex_3_findings_fix_landed_20260514.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    tools_dir = root / "tools"
    files = _check_207_iter_build_tool_files(tools_dir)
    violations: list[str] = []
    for path in files:
        violations.extend(_check_207_collect_violations_in_file(path, root))

    if verbose:
        if violations:
            print(
                f"  [no-unguarded-rmtree-in-build-tools] WARN: "
                f"{len(violations)} unguarded rmtree call(s) across "
                f"{len(files)} build/promote tool(s) (strict={strict})"
            )
        else:
            print(
                f"  [no-unguarded-rmtree-in-build-tools] OK "
                f"({len(files)} build/promote tool(s) scanned)"
            )

    if violations and strict:
        msg = (
            f"check_no_unguarded_rmtree_in_build_tools: {len(violations)} "
            f"unguarded shutil.rmtree call(s) in tools/build_*.py / "
            f"tools/promote_*.py; first 3:\n  "
            + "\n  ".join(violations[:3])
        )
        raise PreflightError(msg)
    return violations


# Catalog #208 — check_docs_no_local_absolute_paths
#
# OSS v0.2.0-rc1 release prep audit finding D-2 self-protect (2026-05-14).
# Bug class: tracked docs files containing hardcoded local absolute paths
# (e.g. `/Users/<operator>/Projects/pact/...`, `/home/<user>/`,
# `C:\Users\<user>\...`, `/private/var/`, `/tmp/`) leak local environment
# state into public-facing documentation. Per CLAUDE.md "Public Disclosure
# Hygiene" non-negotiable: "Keep credentials, private infrastructure URLs,
# local absolute paths, raw provider logs, unpublished operator state, and
# account metadata out of GitHub/docs/site/public supplement surfaces."
#
# Anchor: OSS v0.2.0-rc1 audit commit c293ba425 found 2 tracked files
# (docs/superpowers/plans/2026-04-10-anti-drift-runtime-hardening.md and
# docs/superpowers/specs/2026-04-10-anti-drift-runtime-design.md) leaking
# `/Users/adpena/Projects/pact/...` paths into the OSS release surface.
# This STRICT gate refuses any docs/**/*.md state that re-introduces the
# pattern.
#
# Sister of Catalog #109 (`check_public_pr_intake_clones_pristine` — public
# PR intake clone source-provenance corruption gate) and the existing
# FORBIDDEN_PATTERNS rule "Forbidden /tmp paths in any persisted artifact
# (the transient-evidence trap)" — together they extinct the local-path
# leak class across upstream-imported sources, public docs, and persisted
# evidence ledgers.
#
# Detection: line-anchored regex match on the canonical local-absolute-path
# patterns inside `.md` files under `docs/`. The patterns require a leading
# `/` followed by a UNIX home-anchor (`Users/<word>/` or `home/<word>/`),
# `/private/var/`, or `/tmp/`. Windows-style `C:\Users\<word>\` also caught.
# Bare `/tmp/` is flagged everywhere; `/tmp/<path>` references inside a
# heading (`## /tmp/ session artifacts`) are still flagged so the operator
# must explicitly waive (no implicit doc-of-pattern exception).
#
# Acceptance:
#   * Same-line `# DOCS_LOCAL_PATH_OK:<reason>` HTML comment OR markdown
#     comment waiver (placeholder `<reason>` literal rejected to prevent
#     self-waiver). Both `<!-- DOCS_LOCAL_PATH_OK:<reason> -->` and
#     `# DOCS_LOCAL_PATH_OK:<reason>` forms accepted.
#   * Demo block waiver: `<!-- DEMO_LOCAL_PATH_OK -->` HTML comment within
#     3 lines preceding a code-fenced block allows literal local paths
#     inside that block (rare; document-and-justify only).
#
# No file-level waiver. Per-line opt-out only so the operator must
# explicitly mark every leak surface. Self-exempt: this file (carries the
# patterns in regex/docstring) and the test fixture file (contains
# verbatim violation samples).
# ----------------------------------------------------------------------------

_CHECK_208_LOCAL_PATH_RE = re.compile(
    r"(?:"
    r"/Users/[A-Za-z0-9_.+-]+/"  # macOS home
    r"|/home/[A-Za-z0-9_.+-]+/"  # Linux home
    r"|/private/var/"  # macOS /private/var/folders/...
    r"|(?:^|[^A-Za-z0-9_./-])/tmp/"  # /tmp/ token (preceded by non-path char)
    r"|C:\\Users\\[A-Za-z0-9_.+-]+\\"  # Windows home
    r")"
)

_CHECK_208_WAIVER_RE = re.compile(
    r"(?:<!--\s*DOCS_LOCAL_PATH_OK\s*:\s*\S|#\s*DOCS_LOCAL_PATH_OK\s*:\s*\S)"
)
_CHECK_208_WAIVER_PLACEHOLDER_RE = re.compile(
    r"DOCS_LOCAL_PATH_OK\s*:\s*<reason>",
    re.IGNORECASE,
)
_CHECK_208_DEMO_BLOCK_RE = re.compile(
    r"<!--\s*DEMO_LOCAL_PATH_OK(?:\s*:\s*\S+)?\s*-->",
)

_CHECK_208_SELF_EXEMPT_FILES: tuple[str, ...] = (
    "src/tac/preflight.py",
    "src/tac/tests/test_check_208_docs_no_local_absolute_paths.py",
)


def check_docs_no_local_absolute_paths(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #208 — refuse docs/**/*.md state with hardcoded local paths.

    Scans every `.md` file under `docs/` and refuses any line containing
    a local absolute path pattern (UNIX home, /private/var/, /tmp/, or
    Windows home). Same-line `# DOCS_LOCAL_PATH_OK:<reason>` or
    `<!-- DOCS_LOCAL_PATH_OK:<reason> -->` waiver respected (placeholder
    `<reason>` literal rejected). Code-fenced blocks preceded by a
    `<!-- DEMO_LOCAL_PATH_OK -->` comment within 3 lines may contain
    literal local paths inside the fence.

    Per CLAUDE.md "Public Disclosure Hygiene" non-negotiable +
    OSS v0.2.0-rc1 audit finding D-2 (commit c293ba425).
    """
    root = (repo_root or Path.cwd()).resolve()
    docs_dir = root / "docs"
    violations: list[str] = []
    if not docs_dir.is_dir():
        if verbose:
            print("  [docs-local-path] OK (no docs/ directory)")
        return violations

    scanned = 0
    for path in sorted(docs_dir.rglob("*.md")):
        rel = path.relative_to(root).as_posix()
        if rel in _CHECK_208_SELF_EXEMPT_FILES:
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        scanned += 1
        lines = text.splitlines()
        in_demo_fence = False
        demo_marker_pending = False
        demo_marker_age = 0
        for line_no, line in enumerate(lines, start=1):
            # Track DEMO_LOCAL_PATH_OK marker freshness (3-line window).
            if _CHECK_208_DEMO_BLOCK_RE.search(line):
                demo_marker_pending = True
                demo_marker_age = 0
            elif demo_marker_pending:
                demo_marker_age += 1
                if demo_marker_age > 3:
                    demo_marker_pending = False
            # Detect code-fence open/close (` ``` `).
            stripped = line.lstrip()
            if stripped.startswith("```"):
                if in_demo_fence:
                    in_demo_fence = False
                elif demo_marker_pending:
                    in_demo_fence = True
                    demo_marker_pending = False
                # else: ordinary fence; not a demo waiver.
            if in_demo_fence:
                continue
            if not _CHECK_208_LOCAL_PATH_RE.search(line):
                continue
            if _CHECK_208_WAIVER_RE.search(line) and not _CHECK_208_WAIVER_PLACEHOLDER_RE.search(line):
                continue
            violations.append(
                f"{rel}:{line_no}: local absolute path leak. Replace with "
                f"`<repo-root>/`, a relative path, or repo-relative markdown link. "
                f"Acceptance: same-line `# DOCS_LOCAL_PATH_OK:<reason>` waiver "
                f"(placeholder `<reason>` literal rejected) OR "
                f"`<!-- DEMO_LOCAL_PATH_OK -->` 3-line-preceding marker for "
                f"code-fenced shell demos. Line: {line.strip()[:200]}"
            )

    if verbose:
        if violations:
            print(
                f"  [docs-local-path] {len(violations)} violation(s) "
                f"across {scanned} doc file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [docs-local-path] OK ({scanned} doc file(s) scanned)"
            )

    if violations and strict:
        raise PreflightError(
            "check_docs_no_local_absolute_paths found "
            f"{len(violations)} violation(s). Public-facing docs must not "
            "leak local environment paths (UNIX home, /private/var/, /tmp/, "
            "Windows home). Per CLAUDE.md \"Public Disclosure Hygiene\" "
            "non-negotiable. Replace with `<repo-root>/`, relative path, or "
            "repo-relative markdown link. Add `# DOCS_LOCAL_PATH_OK:<reason>` "
            "same-line waiver for rare intentional cases. See OSS v0.2.0-rc1 "
            "audit commit c293ba425 (finding D-2).\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations

_CHECK_209_DISTILL_TOKEN = "distill_codebook"
_CHECK_209_ITERATOR_TOKEN = "Comma2k19FrameIterator"
_CHECK_209_GUARD_TOKEN = "check_no_contest_video_leakage"
_CHECK_209_WAIVER_TOKEN = "COMMA2K19_LEAKAGE_VERIFIED_OK"
_CHECK_209_FILE_LEVEL_WAIVER_TOKEN = "COMMA2K19_LEAKAGE_VERIFIED_OK_FILE"
# Canonical helper functions that wrap Comma2k19FrameIterator construction
# (so a caller may invoke the helper instead of constructing the iterator
# directly). The helper itself MUST construct Comma2k19FrameIterator (or
# carry an inline waiver) — Catalog #209 verifies that recursively by
# scanning the helper's defining file.
_CHECK_209_CANONICAL_HELPER_NAMES: tuple[str, ...] = (
    "_build_frame_iterator",
    "build_frame_iterator",
)
# The canonical implementation files plus their tests are exempt: the
# iterator class itself defines the leakage refusal; tests intentionally
# exercise both positive and negative paths.
_CHECK_209_SELF_EXEMPT_PATH_FRAGMENTS: tuple[str, ...] = (
    "src/tac/substrates/pretrained_driving_prior/distillation.py",
    "src/tac/substrates/pretrained_driving_prior/__init__.py",
    "src/tac/preflight.py",
)
# Exempt directories — vendored intake clones, OSS export mirrors, and
# generated build artifacts.
_CHECK_209_EXEMPT_PATH_FRAGMENTS: tuple[str, ...] = (
    "experiments/results/",
    "_intake_",
    ".omx/oss_export/",
    "vendored",
)


def _check_209_iter_target_files(repo_root: Path) -> Iterator[Path]:
    """Yield .py files in the in-scope directories.

    Scope: ``src/tac/``, ``tools/``, ``experiments/``, ``scripts/``.
    Skips test files (they exercise both positive and negative paths so
    a literal `distill_codebook(` token in a test fixture is not a
    real-world caller).
    """
    scope_dirs = (
        repo_root / "src" / "tac",
        repo_root / "tools",
        repo_root / "experiments",
        repo_root / "scripts",
    )
    for scope_dir in scope_dirs:
        if not scope_dir.exists():
            continue
        for path in scope_dir.rglob("*.py"):
            rel = path.relative_to(repo_root).as_posix()
            if any(frag in rel for frag in _CHECK_209_EXEMPT_PATH_FRAGMENTS):
                continue
            if any(rel == frag or rel.endswith(frag) for frag in _CHECK_209_SELF_EXEMPT_PATH_FRAGMENTS):
                continue
            # Skip test files (per scope rules; tests cover positive and
            # negative paths and should not bind production callers).
            if "/tests/" in rel or path.name.startswith("test_") or path.name.endswith("_test.py"):
                continue
            yield path


def check_no_contest_video_leakage_in_distillation_callers(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #209 - every distill_codebook caller routes through Comma2k19FrameIterator.

    Per CLAUDE.md "HNeRV / leaderboard-implementation parity discipline" L1
    + the L1 scaffold's :func:`check_no_contest_video_leakage` runtime guard.
    The scaffold landing 2026-05-13 deferred this STRICT preflight gate
    because no real frame iterator existed; Phase 2 lands
    :class:`Comma2k19FrameIterator` and so the gate has live coverage.

    Scans every ``distill_codebook(`` callsite in ``src/tac/``, ``tools/``,
    ``experiments/``, ``scripts/`` (excluding the canonical implementation
    file plus tests, vendored intakes, OSS export mirrors, and
    ``experiments/results/`` build artifacts) and refuses any call that
    cannot be routed back to a :class:`Comma2k19FrameIterator` instance.

    Acceptance (any one suffices):

    1. The same enclosing scope (within 30 lines BEFORE the call) constructs
       a ``Comma2k19FrameIterator(...)``.
    2. The call carries a same-line waiver
       ``# COMMA2K19_LEAKAGE_VERIFIED_OK:<reason>`` (placeholder ``<reason>``
       literal rejected so the scaffold's docstring example cannot
       self-waive).
    3. The file carries a file-level
       ``# COMMA2K19_LEAKAGE_VERIFIED_OK_FILE:<reason>`` waiver in the
       first 20 lines (rare; for trainer harnesses that cover both modes
       and route through the iterator behind another helper).

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
    against" + "Strict-flip atomicity rule": the gate strict-flips in the
    same commit batch as the live count = 0. Memory:
    ``feedback_dp1_phase_2_landed_20260514.md``.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)

    violations: list[str] = []
    for path in _check_209_iter_target_files(root):
        try:
            text = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            continue
        if _CHECK_209_DISTILL_TOKEN + "(" not in text:
            continue
        # File-level waiver opt-out (rare; first-20-lines window).
        head = "\n".join(text.splitlines()[:20])
        if _CHECK_209_FILE_LEVEL_WAIVER_TOKEN + ":" in head:
            # Reject placeholder literal `<reason>` to prevent self-waiver
            # from a docstring example.
            if "<reason>" not in head:
                continue
        lines = text.splitlines()
        for i, line in enumerate(lines):
            if _CHECK_209_DISTILL_TOKEN + "(" not in line:
                continue
            # Skip imports, function definitions ("def distill_codebook"),
            # docstrings (heuristic: line is inside a triple-quoted block).
            stripped = line.strip()
            if stripped.startswith(("def ", "from ", "import ", "* ", "- ")):
                continue
            if stripped.startswith(("#", '"', "'")):
                continue
            # Same-line waiver?
            if _CHECK_209_WAIVER_TOKEN + ":" in line:
                # Reject the placeholder literal `<reason>`.
                trailing = line.split(_CHECK_209_WAIVER_TOKEN + ":", 1)[1]
                rationale = trailing.split()[0] if trailing.strip() else ""
                if rationale and rationale != "<reason>":
                    continue
            # Look back 30 lines for an iterator construction.
            window_start = max(0, i - 30)
            window = "\n".join(lines[window_start : i + 1])
            if _CHECK_209_ITERATOR_TOKEN + "(" in window:
                continue
            # Canonical helper-function wrapper acceptance — a caller may
            # invoke ``_build_frame_iterator(...)`` instead of constructing
            # the iterator directly. The helper itself must construct
            # Comma2k19FrameIterator; this gate audits the helper's defining
            # file separately so the indirect path is structurally safe.
            if any(
                helper + "(" in window
                for helper in _CHECK_209_CANONICAL_HELPER_NAMES
            ):
                continue
            # Final fallback: if the canonical guard token appears in the
            # window (caller manually invoked check_no_contest_video_leakage
            # before constructing its own iterator), accept too.
            if _CHECK_209_GUARD_TOKEN + "(" in window:
                continue
            rel = path.relative_to(root).as_posix()
            violations.append(
                f"{rel}:{i + 1}: distill_codebook(...) called without "
                f"routing through Comma2k19FrameIterator (Catalog #209). "
                f"Add a Comma2k19FrameIterator(...) construction within "
                f"30 lines above the call OR a same-line "
                f"`# COMMA2K19_LEAKAGE_VERIFIED_OK:<rationale>` waiver."
            )

    if verbose:
        if violations:
            print(
                f"  [contest-video-leakage-callers] WARN: "
                f"{len(violations)} unrouted distill_codebook callsite(s) "
                f"(strict={strict})"
            )
        else:
            print("  [contest-video-leakage-callers] OK")

    if violations and strict:
        raise PreflightError(
            "check_no_contest_video_leakage_in_distillation_callers: "
            f"{len(violations)} distill_codebook caller(s) bypass the "
            "Comma2k19FrameIterator routing required by Catalog #209. The "
            "iterator's constructor runs check_no_contest_video_leakage on "
            "the chunk path BEFORE any decode; bypassing it makes the "
            "leakage refusal opt-in instead of structural. Per CLAUDE.md "
            "HNeRV parity discipline L1 the codebook MUST be distilled from "
            "OUT-OF-DISTRIBUTION dashcam data, never the contest video.\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations


# =============================================================================
