def _check_213_iter_target_files(repo_root: Path) -> Iterator[Path]:
    """Yield .py + .sh files that could fetch Comma2k19 outside the canonical cache.

    Scope: ``src/tac/``, ``tools/``, ``experiments/``, ``scripts/``.
    Skips tests, vendored intake clones, OSS export mirrors,
    ``experiments/results/`` build artifacts, ``reports/raw/`` outputs.
    """
    scope_dirs = (
        repo_root / "src" / "tac",
        repo_root / "tools",
        repo_root / "experiments",
        repo_root / "scripts",
    )
    for scope_dir in scope_dirs:
        if not scope_dir.exists():
            continue
        for ext in ("*.py", "*.sh"):
            for path in scope_dir.rglob(ext):
                rel = path.relative_to(repo_root).as_posix()
                if any(frag in rel for frag in _CHECK_213_EXEMPT_PATH_FRAGMENTS):
                    continue
                if any(
                    rel == frag or rel.endswith(frag)
                    for frag in _CHECK_213_SELF_EXEMPT_PATH_FRAGMENTS
                ):
                    continue
                if (
                    "/tests/" in rel
                    or path.name.startswith("test_")
                    or path.name.endswith("_test.py")
                ):
                    continue
                yield path


def check_comma2k19_downloads_route_through_canonical_cache(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #213 - Comma2k19 chunk downloads must route through the canonical helper.

    Per the 2026-05-14 operator directive "you can download the dataset
    locally and configure the chunks dir to be fed dynamically cached with
    a log incremental generator", the DP1 substrate now ships a canonical
    auto-download cache:
    :class:`tac.substrates.pretrained_driving_prior.Comma2k19LocalCache`.
    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
    against" non-negotiable, every Comma2k19 chunk fetch MUST route
    through this helper so:

    1. **Source-of-truth pinning** — the canonical URL list lives in ONE
       place (``DEFAULT_CHUNK_MANIFEST`` in ``local_chunk_cache.py``);
       ad-hoc curl/wget bypasses can silently point at a tampered mirror.
    2. **SHA-256 integrity verification** — the cache verifies every
       downloaded chunk against the pinned hash before use; bare downloads
       cannot detect bit-flips or man-in-the-middle tampering.
    3. **License-tag propagation** — the cache stamps every entry with
       ``license="MIT"`` + ``source_url`` provenance, which Catalog #210
       requires DP1 archives to carry.
    4. **Disk-budget LRU eviction** — the cache caps disk usage at
       ``max_disk_gb`` and evicts oldest-LRU entries to fit new downloads;
       bare fetches can fill the worker disk and crash the dispatch.
    5. **Resumable + idempotent** — partial downloads land in
       ``<cache_dir>/.downloads/`` (NEVER ``/tmp`` per CLAUDE.md "Forbidden
       /tmp paths") and are ``os.replace``-d atomically into place.

    Bug class: any caller under ``tools/``, ``scripts/``, ``experiments/``,
    or ``src/tac/`` that uses ``urllib.request.urlopen`` /
    ``urllib.request.urlretrieve`` / ``requests.get`` / shell ``wget`` /
    ``curl`` / ``aria2c`` against a Comma2k19 URL OUTSIDE the canonical
    cache helper bypasses all 5 protections above. Refuses unless the
    file also imports or invokes the canonical cache class
    (``Comma2k19LocalCache``, ``.fetch_chunk(``, etc.).

    Acceptance:

    1. The file imports + uses :class:`Comma2k19LocalCache` (or one of
       ``fetch_chunk`` / ``fetch_chunks`` / a ``local_chunk_cache``
       module-level reference within a 30-line window of the download call).
    2. Same-line waiver ``# COMMA2K19_DOWNLOAD_OK:<rationale>`` (placeholder
       ``<reason>`` literal rejected so the gate's docstring cannot
       self-waive).
    3. File-level waiver
       ``# COMMA2K19_DOWNLOAD_OK_FILE:<rationale>`` (in first 10 lines) for
       legitimate one-off operator-reviewed download scripts (rare).

    Self-exempt: the canonical implementation file
    (``local_chunk_cache.py``), the log-incremental feeder that uses it,
    the substrate ``__init__.py`` (re-exports), and ``preflight.py``
    (carries the URL/token literals in the regex/docstring).

    Per CLAUDE.md "Strict-flip atomicity rule" — STRICT @ 0 at landing.
    Live count: 0 at the time of this gate landing — the canonical helper
    is the ONLY file with the URL literals + download tokens (it's the
    canonical source-of-truth + ``DEFAULT_CHUNK_MANIFEST`` table).

    Sister of Catalog #209 (``check_no_contest_video_leakage_in_distillation_callers``,
    which refuses non-canonical iterator construction at the distill side;
    #213 refuses non-canonical fetches at the DOWNLOAD side) and Catalog
    #210 (DP1 codebook provenance metadata; the cache provides the
    ``license_tags`` source). Together they extinct the bug class
    bidirectionally:

    * #209: any caller of ``distill_codebook(frames=...)`` must use
      ``Comma2k19FrameIterator``.
    * #213: any caller that fetches Comma2k19 chunks must use
      ``Comma2k19LocalCache``.
    * #210: the resulting archive must carry the provenance the cache
      stamped.

    Per CLAUDE.md "Subagent coherence-by-default" non-negotiable: lane
    ``lane_dp1_comma2k19_autoload_log_incremental_20260514``.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)

    violations: list[str] = []
    for path in _check_213_iter_target_files(root):
        try:
            text = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            continue
        # Quick filter: file must reference at least one Comma2k19 URL fragment
        # AND at least one download-call token.
        has_url = any(frag in text for frag in _CHECK_213_COMMA2K19_URL_FRAGMENTS)
        if not has_url:
            continue
        has_download = any(tok in text for tok in _CHECK_213_DOWNLOAD_CALL_TOKENS)
        if not has_download:
            # File mentions a Comma2k19 URL (e.g. in a comment / docstring)
            # but doesn't perform a download call — accept silently.
            continue
        # File-level waiver?
        head = "\n".join(text.splitlines()[:10])
        if _CHECK_213_WAIVER_FILE_TOKEN + ":" in head:
            trailing = head.split(_CHECK_213_WAIVER_FILE_TOKEN + ":", 1)[1]
            rationale = trailing.split()[0] if trailing.strip() else ""
            if rationale and rationale != "<reason>":
                continue
        # File-level canonical-helper presence accepts the whole file when
        # at least one canonical cache token is used somewhere AND no bare
        # download call exists on the same lines as a Comma2k19 URL.
        # Per-line check: for each line that has BOTH a Comma2k19 URL
        # fragment AND a download call token, require a same-line waiver
        # OR a 30-line window with a canonical-cache token.
        lines = text.splitlines()
        for i, line in enumerate(lines):
            if not any(frag in line for frag in _CHECK_213_COMMA2K19_URL_FRAGMENTS):
                continue
            # Look for download call on this OR adjacent lines (±2 lines
            # to handle multi-line argument lists).
            window_lo = max(0, i - 2)
            window_hi = min(len(lines), i + 3)
            window_str = "\n".join(lines[window_lo:window_hi])
            if not any(tok in window_str for tok in _CHECK_213_DOWNLOAD_CALL_TOKENS):
                continue
            # Same-line waiver?
            if _CHECK_213_WAIVER_TOKEN + ":" in line:
                trailing = line.split(_CHECK_213_WAIVER_TOKEN + ":", 1)[1]
                rationale = trailing.split()[0] if trailing.strip() else ""
                if rationale and rationale != "<reason>":
                    continue
            # Local-window canonical-cache token within ±30 lines?
            local_lo = max(0, i - 15)
            local_hi = min(len(lines), i + 16)
            local_window = "\n".join(lines[local_lo:local_hi])
            if any(tok in local_window for tok in _CHECK_213_CANONICAL_CACHE_TOKENS):
                continue
            rel = path.relative_to(root).as_posix()
            violations.append(
                f"{rel}:{i + 1}: downloads Comma2k19 chunk bytes outside "
                f"the canonical helper (Catalog #213). Use "
                f"``tac.substrates.pretrained_driving_prior.Comma2k19LocalCache."
                f"fetch_chunk(...)`` instead of bare urlopen / requests / "
                f"curl / wget / aria2c. Same-line "
                f"``# COMMA2K19_DOWNLOAD_OK:<rationale>`` waiver available."
            )
            # Cap violations per file at 3 so a stencil-style file doesn't
            # explode the report.
            if len([v for v in violations if rel in v]) >= 3:
                break

    if verbose:
        if violations:
            print(
                f"  [comma2k19-canonical-download] WARN: {len(violations)} "
                f"non-canonical Comma2k19 fetch site(s) (strict={strict})"
            )
        else:
            print("  [comma2k19-canonical-download] OK")

    if violations and strict:
        raise PreflightError(
            "check_comma2k19_downloads_route_through_canonical_cache: "
            f"{len(violations)} site(s) fetch Comma2k19 outside the canonical "
            "Comma2k19LocalCache helper (Catalog #213). The cache pins URLs, "
            "verifies SHA-256, propagates license tags, applies LRU disk "
            "budgeting, and never uses /tmp. Routing through it is the only "
            "way DP1 archives meet Catalog #210 provenance requirements.\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #215 - check_modal_smoke_recipe_min_gpu_class_consistent
# ─────────────────────────────────────────────────────────────────────────
# P0 fix 2026-05-14 (FIX-HARDEN-OPT). The SIREN smoke timeout
# 2026-05-13T14:04:10Z (label substrate_siren_modal_a100_dispatch_..._smoke,
# rc=124, ~3601s wall-clock) showed the smoke-before-full wrapper defaults
# to T4 even when the recipe's full-run GPU is A100. T4 is too slow for
# compute-heavy substrates (SIREN coordinate-MLP, D4 residual-codec) at the
# smoke epoch count (100 epochs), so the smoke times out and the operator
# never gets the cheap integration validation that smoke-before-full is
# designed to provide.
#
# The fix lives in ``tools/run_modal_smoke_before_full.py``: recipes can
# declare ``min_smoke_gpu: "<class>"`` and the smoke wrapper honors it over
# a CLI downgrade. This WARN-ONLY-INITIAL preflight gate enforces
# RECIPE-LEVEL CONSISTENCY: a recipe whose full-run GPU is one of
# A100/H100/L40S must also declare ``min_smoke_gpu``. Same-line waiver
# ``# MIN_SMOKE_GPU_OK:<reason>`` (placeholder ``<reason>`` literal
# rejected) for recipes that explicitly opt to run smoke on T4.

_CHECK_215_RECIPE_DIR = ".omx/operator_authorize_recipes"
_CHECK_215_RECIPE_GLOB = "substrate_*_modal_*_dispatch.yaml"
_CHECK_215_REQUIRE_MIN_SMOKE_GPU_FULL_CLASSES: frozenset[str] = frozenset(
    {"A100", "H100", "L40S"}
)
_CHECK_215_VALID_SMOKE_CLASSES: frozenset[str] = frozenset(
    {"T4", "L4", "A10G", "L40S", "A100", "H100"}
)
_CHECK_215_GPU_FIELD_RE = re.compile(
    r'^gpu\s*:\s*"?(?:\${MODAL_GPU:-)?([A-Za-z0-9_]+)\}?"?\s*(?:#.*)?$',
    re.MULTILINE,
)
_CHECK_215_MIN_SMOKE_GPU_FIELD_RE = re.compile(
    r'^min_smoke_gpu\s*:\s*"?([A-Za-z0-9_]+)"?\s*(?:#.*)?$',
    re.MULTILINE,
)
_CHECK_215_WAIVER_RE = re.compile(
    r"#\s*MIN_SMOKE_GPU_OK:\s*(?!<reason>)\S+"
)


def check_modal_smoke_recipe_min_gpu_class_consistent(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #215. P0 FIX-HARDEN-OPT 2026-05-14. Refuses substrate
    recipes whose full-run GPU is A100/H100/L40S WITHOUT declaring
    ``min_smoke_gpu``. Same-line ``# MIN_SMOKE_GPU_OK:<reason>`` waiver
    accepts the recipe (placeholder ``<reason>`` rejected).
    """
    root = (repo_root or Path.cwd()).resolve()
    recipes_dir = root / _CHECK_215_RECIPE_DIR
    violations: list[str] = []
    if not recipes_dir.is_dir():
        if verbose:
            print(
                "  [modal-smoke-recipe-min-gpu-class-consistent] OK "
                "(no operator_authorize_recipes dir; 0 file(s) scanned)"
            )
        return violations
    scanned = 0
    for path in sorted(recipes_dir.glob(_CHECK_215_RECIPE_GLOB)):
        rel = str(path.relative_to(root))
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            violations.append(f"{rel}: read error {exc!s}")
            continue
        scanned += 1
        if _CHECK_215_WAIVER_RE.search(text):
            continue
        m = _CHECK_215_GPU_FIELD_RE.search(text)
        if m is None:
            continue
        full_gpu = m.group(1).strip()
        if full_gpu not in _CHECK_215_REQUIRE_MIN_SMOKE_GPU_FULL_CLASSES:
            continue
        m2 = _CHECK_215_MIN_SMOKE_GPU_FIELD_RE.search(text)
        if m2 is None:
            violations.append(
                f"{rel}: full-run gpu={full_gpu!r} requires "
                f"`min_smoke_gpu: <class>` so the smoke phase compute-class "
                f"matches recipe-design intent (SIREN/D4 anchor: smoke "
                f"timeout on T4 default). Add `min_smoke_gpu: \"{full_gpu}\"` "
                f"OR a `# MIN_SMOKE_GPU_OK:<reason>` waiver."
            )
            continue
        declared = m2.group(1).strip()
        if declared not in _CHECK_215_VALID_SMOKE_CLASSES:
            violations.append(
                f"{rel}: min_smoke_gpu={declared!r} not in valid set "
                f"{sorted(_CHECK_215_VALID_SMOKE_CLASSES)}"
            )
    if verbose:
        if violations:
            print(
                f"  [modal-smoke-recipe-min-gpu-class-consistent] "
                f"{len(violations)} violation(s) across {scanned} substrate "
                f"recipe(s) (strict={strict})"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [modal-smoke-recipe-min-gpu-class-consistent] OK "
                f"({scanned} substrate recipe(s) scanned)"
            )
    if violations and strict:
        raise PreflightError(
            "check_modal_smoke_recipe_min_gpu_class_consistent found "
            f"{len(violations)} violation(s). Catalog #215 closes the "
            "smoke-GPU-class-mismatch bug class (SIREN 2026-05-13 timeout):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #218 — check_substrate_reconstruct_methods_support_mini_batch
#
# D4 OOM fix self-protection (2026-05-14). Bug class: substrate reconstruct
# methods that accept a per-pair batch tensor (e.g. ``reconstruct_pair``,
# ``synthesize_frame_0``, ``archive_build_pass``) without supporting any of
# (a) ``pair_indices`` / ``chunk_size`` / ``indices`` mini-batch kwarg,
# (b) internal chunking helper invocation, or (c) ``torch.no_grad`` /
# ``torch.inference_mode`` context. Such methods force callers into the
# full-N-pair forward path which OOMs on T4 (14.56 GB) when N is the
# contest pair count (600 pairs) — anchored at
# fc-01KRK9RKD3QV4C276Y5KXFMF65 (D4 Modal T4 smoke 2026-05-14 13:10:25Z
# rc=1 elapsed 121s; CUDA OOM at synthesize_frame_0 F.interpolate residual
# upsample with 600-pair batch needing ~13 GB activation memory).
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
# + "Strict-flip atomicity rule" — STRICT-from-byte-one because the D4
# substrate (the empirical anchor) gained the ``pair_indices`` kwarg in the
# same commit batch.
#
# Sister of Catalog #154 (`check_experiments_results_gc_helper_is_canonical`)
# + Catalog #207 (`check_no_unguarded_rmtree_in_build_tools`) — same pattern
# of "force callers into the canonical bounded-memory path" applied to a
# different bug class (full-batch reconstruction OOM instead of unguarded
# rmtree).
#
# Lane: lane_d4_oom_fix_minibatch_reconstruct_20260514.
# ----------------------------------------------------------------------------

# Method/function-name tokens that trigger the gate. These are the canonical
# substrate "rebuild the per-pair output from per-pair parameters" surfaces
# that scale with num_pairs.
_CHECK_218_METHOD_NAME_TOKENS = (
    "reconstruct_pair",
    "reconstruct_pairs",
    "reconstruct_batch",
    "archive_build_pass",
)

# Per-function-body acceptance tokens. ANY of these in the body satisfies
# the gate (the method either supports a mini-batch kwarg OR operates under
# an inference-mode context OR delegates to a sister chunking helper).
_CHECK_218_BODY_ACCEPT_TOKENS = (
    "torch.no_grad",
    "torch.inference_mode",
    "@torch.no_grad",
    "@torch.inference_mode",
    "no_grad()",
    "inference_mode()",
)

# Argument-name tokens that recognize a mini-batch kwarg in the function
# signature. ANY of these in the signature satisfies the gate.
_CHECK_218_SIGNATURE_KWARG_TOKENS = (
    "pair_indices",
    "chunk_size",
    "indices",
    "batch_indices",
    "minibatch_indices",
)

# Same-line waiver. Placeholder literal "<reason>" is rejected so the
# docstring above cannot self-waive.
_CHECK_218_WAIVER_RE = re.compile(
    r"#\s*RECONSTRUCT_BATCH_OOM_OK:\s*([^\s<].*)"
)

# Substrate files that are out-of-scope (smoke-only fixtures, helpers that
# delegate, etc.). Add narrowly with rationale.
_CHECK_218_FILE_ALLOWLIST: frozenset[str] = frozenset()


def _check_218_iter_substrate_architecture_files(
    repo_root: Path,
) -> list[Path]:
    """Return ``src/tac/substrates/*/architecture.py`` + sister surfaces."""
    files: list[Path] = []
    substrates_dir = repo_root / "src" / "tac" / "substrates"
    if substrates_dir.exists():
        for arch in substrates_dir.glob("*/architecture.py"):
            if arch.is_file():
                files.append(arch)
        # Also scan frame-synthesis-style helpers that take a batch.
        for synth in substrates_dir.glob("*/frame*_synthesis.py"):
            if synth.is_file():
                files.append(synth)
        for synth in substrates_dir.glob("*/synthesis.py"):
            if synth.is_file():
                files.append(synth)
    return sorted(files)


def _check_218_function_body_text(
    src: str, func_node: ast.AST
) -> str:
    """Return the source text of a function body via line range."""
    if not isinstance(
        func_node, (ast.FunctionDef, ast.AsyncFunctionDef)
    ):
        return ""
    start = func_node.lineno - 1
    end = getattr(func_node, "end_lineno", None) or len(src.splitlines())
    return "\n".join(src.splitlines()[start:end])


def _check_218_signature_has_minibatch_kwarg(
    func_node: ast.AST,
) -> bool:
    """Return True if the function signature accepts a mini-batch kwarg."""
    if not isinstance(
        func_node, (ast.FunctionDef, ast.AsyncFunctionDef)
    ):
        return False
    arg_names: list[str] = []
    arg_names.extend(a.arg for a in func_node.args.args)
    arg_names.extend(a.arg for a in func_node.args.kwonlyargs)
    if func_node.args.vararg is not None:
        arg_names.append(func_node.args.vararg.arg)
    if func_node.args.kwarg is not None:
        arg_names.append(func_node.args.kwarg.arg)
    return any(name in _CHECK_218_SIGNATURE_KWARG_TOKENS for name in arg_names)


def _check_218_function_name_matches(func_node: ast.AST) -> bool:
    """Return True if the function name matches one of the canonical
    per-pair-batch reconstruct method patterns."""
    if not isinstance(
        func_node, (ast.FunctionDef, ast.AsyncFunctionDef)
    ):
        return False
    name = func_node.name
    return any(tok in name for tok in _CHECK_218_METHOD_NAME_TOKENS)


def _check_218_collect_violations_in_file(
    path: Path, repo_root: Path
) -> list[str]:
    """AST-walk one file and emit one violation per unprotected reconstruct."""
    rel = path.relative_to(repo_root)
    rel_posix = rel.as_posix()
    if rel_posix in _CHECK_218_FILE_ALLOWLIST:
        return []
    try:
        src = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []
    try:
        tree = ast.parse(src, filename=str(path))
    except SyntaxError:
        return []
    src_lines = src.splitlines()
    violations: list[str] = []

    for node in ast.walk(tree):
        if not _check_218_function_name_matches(node):
            continue
        # Acceptance: signature kwarg OR body inference-mode context.
        if _check_218_signature_has_minibatch_kwarg(node):
            continue
        # Decorator acceptance: @torch.no_grad / @torch.inference_mode on
        # the function itself is equivalent to wrapping the body in a
        # no_grad context.
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            decorator_match = False
            for dec in node.decorator_list:
                dec_inner = dec.func if isinstance(dec, ast.Call) else dec
                if isinstance(dec_inner, ast.Attribute):
                    if dec_inner.attr in ("no_grad", "inference_mode"):
                        decorator_match = True
                        break
                elif isinstance(dec_inner, ast.Name):
                    if dec_inner.id in ("no_grad", "inference_mode"):
                        decorator_match = True
                        break
            if decorator_match:
                continue
        body_text = _check_218_function_body_text(src, node)
        if any(tok in body_text for tok in _CHECK_218_BODY_ACCEPT_TOKENS):
            continue
        # Check def-line waiver.
        line_no = getattr(node, "lineno", None) or 0
        line_text = src_lines[line_no - 1] if 0 < line_no <= len(src_lines) else ""
        if _CHECK_218_WAIVER_RE.search(line_text):
            continue
        violations.append(
            f"{rel_posix}:{line_no} substrate reconstruct method "
            f"{node.name!r} accepts a per-pair batch without "
            f"``pair_indices`` / ``chunk_size`` / ``indices`` kwarg AND "
            f"without a ``torch.no_grad`` / ``torch.inference_mode`` body "
            f"context. Per Catalog #218 (D4 OOM fix self-protect): the "
            f"full-N-pair forward forces callers into a ~13 GB activation "
            f"memory path that OOMs T4 (14.56 GB). Add a `pair_indices` "
            f"kwarg (canonical pattern: see "
            f"`src/tac/substrates/d4_wyner_ziv_frame_0/architecture.py::"
            f"reconstruct_pair`) OR wrap the body in `torch.no_grad()` for "
            f"non-trainable archive-build passes, OR add a same-line "
            f"`# RECONSTRUCT_BATCH_OOM_OK:<reason>` waiver on the def line. "
            f"See CLAUDE.md Catalog #218."
        )
    return violations


def check_substrate_reconstruct_methods_support_mini_batch(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #218 — refuse substrate reconstruct methods that don't
    support a mini-batch / no-grad path.

    Per the 2026-05-14 D4 OOM anchor (fc-01KRK9RKD3QV4C276Y5KXFMF65), a
    ``reconstruct_pair(frame_1)`` that requires the full 600-pair batch
    blows past T4 GPU memory at the F.interpolate residual upsample.
    The fix landed a ``pair_indices`` kwarg in the same commit batch;
    this STRICT gate keeps the bug class extinct across all future
    substrates that ship a per-pair reconstruct surface.

    Sister of Catalog #154 + #207 (canonical-path-enforcement gates).
    Memory: feedback_d4_oom_fix_minibatch_landed_20260514.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    files = _check_218_iter_substrate_architecture_files(root)
    violations: list[str] = []
    for path in files:
        violations.extend(_check_218_collect_violations_in_file(path, root))

    if verbose:
        if violations:
            print(
                f"  [substrate-reconstruct-mini-batch] WARN: "
                f"{len(violations)} unprotected reconstruct method(s) "
                f"across {len(files)} substrate file(s) (strict={strict})"
            )
        else:
            print(
                f"  [substrate-reconstruct-mini-batch] OK "
                f"({len(files)} substrate file(s) scanned)"
            )

    if violations and strict:
        msg = (
            f"check_substrate_reconstruct_methods_support_mini_batch: "
            f"{len(violations)} reconstruct method(s) lack mini-batch "
            f"or inference-mode protection (Catalog #218 — D4 OOM "
            f"self-protect); first 3:\n  "
            + "\n  ".join(violations[:3])
        )
        raise PreflightError(msg)
    return violations


# ----------------------------------------------------------------------------
# Catalog #219 — check_archive_promotion_blocked_by_mdl_density_above_threshold
#
# Z1 empirical revision self-protection (2026-05-14). Bug class: a lane in the
# registry can be promoted to Level 2+ (real_archive_empirical / contest_cuda /
# contest_cpu gate satisfied) with archive bytes whose scorer-conditional MDL
# density is empirically class-saturated (> 0.90 — see Z1 ablation memo
# `feedback_z1_mdl_ablation_landed_20260514.md` + sister band memo
# `.omx/research/zen_floor_band_v2_post_z1_ablation_20260514.md`). High MDL
# density empirically means the archive's score budget within the current
# substrate class is exhausted — A1 measured 99.29% density and PR106 r2 at
# 97.21%. The next dispatch round should be a class-shift (predictive-receiver
# / cooperative-receiver / foveation / Wyner-Ziv) not another within-class
# bolt-on. This STRICT gate refuses any L2+ lane whose real_archive_empirical
# evidence string references an archive sha256 with measured MDL density above
# the 0.90 threshold.
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against" +
# "Strict-flip atomicity rule" + Z1 operator decision #5: live count at landing
# is bounded (only A1 + PR106 have MDL ablation evidence; both are explicit
# operator-acknowledged baselines / frontier anchors). Initial wire-in is
# warn-only per "Strict-flip atomicity rule" — strict-flip atomically once 0
# violations are confirmed across MDL-evidence-bearing lanes AND the baseline
# A1 lane carries the canonical `# MDL_DENSITY_OVER_THRESHOLD_OK:` waiver in
# its registry-notes (the operator-explicit waiver pattern documented below).
#
# Sister of Catalog #90 (`check_lane_registry_consistent`, the umbrella that
# enforces registry schema invariants) + Catalog #127
# (`check_authoritative_tag_requires_custody_metadata`, the per-anchor custody
# rule). Together they extinct the "class-saturated archive silently promoted
# to L2+" bug class.
#
# Lane: lane_mdl_density_gate_and_autopilot_ranker_20260514.
# Memory: feedback_mdl_density_gate_and_autopilot_ranker_landed_20260514.md.
# ----------------------------------------------------------------------------

# Threshold above which a measured MDL density indicates class-saturation per
# the Z1 ablation. The threshold 0.90 was chosen by the Z1 council per
# `feedback_z1_mdl_ablation_landed_20260514.md` operator decision #5; >0.90
# means substrate-class headroom is exhausted and the next dispatch should
# attempt a class-shift architecture, not another within-class bolt-on.
_CHECK_219_MDL_DENSITY_THRESHOLD = 0.90

# Lane-level evidence-bearing gate names. If any of these gates carry a sha256
# evidence string AND that sha is measured with MDL density >threshold, the
# lane is class-saturated and L2+ promotion is refused.
_CHECK_219_L2_PROMOTION_GATE_NAMES = (
    "real_archive_empirical",
    "contest_cuda",
    "contest_cpu",
)

# Lane-class / target-mode tokens that exempt a lane from the gate. Lanes
# whose explicit purpose is research-only or class-shift substrate engineering
# don't need the within-class trap protection. Exemption is by-design and
# requires the lane to declare its scope. Sister of HNeRV parity discipline
# lesson 7 (substrate engineering tag).
_CHECK_219_EXEMPT_LANE_CLASS_TOKENS = (
    "substrate_class_shift",
    "substrate_engineering",
    "research_substrate",
)

# Target-modes tokens (sub-strings) that exempt a lane. Lanes producing only
# `research_substrate` or `production_*` artifacts are not in scope for the
# contest-promotion gate.
_CHECK_219_EXEMPT_TARGET_MODE_TOKENS = (
    "research_substrate",
    "research_only",
)

# Same-line/notes waiver. Placeholder literal "<reason>" is rejected so the
# docstring above cannot self-waive.
_CHECK_219_WAIVER_RE = re.compile(
    r"#\s*MDL_DENSITY_OVER_THRESHOLD_OK:\s*([^\s<].*)"
)
_CHECK_219_WAIVER_INLINE_RE = re.compile(
    r"MDL_DENSITY_OVER_THRESHOLD_OK:\s*([^\s<,;]+)"
)

# Regex matching an 8-64 hex sha-prefix token in an evidence string. The
# canonical lane-registry style is the 8-char prefix (e.g. ``87ec7ca5...492b5``)
# so the matcher accepts short prefixes and uses set-membership against the
# full sha index to avoid false positives on accidental hex words.
_CHECK_219_SHA256_TOKEN_RE = re.compile(r"\b([a-fA-F0-9]{8,64})\b")

# Minimum prefix length required for a registry-shortened sha to match a full
# sha. The 8-char prefix is canonical in the registry; we accept >=8 hex chars
# for matching but require the abbreviated form to be sha-like (preceded /
# followed by sha-indicative context like ``sha256=`` / ``sha `` / ``...``).
_CHECK_219_MIN_SHA_PREFIX_LEN = 8

# Context tokens that confirm a hex string is actually a sha (vs accidental
# hex like timestamps or counters). At least one must appear in the evidence
# string for a sha-prefix to count.
_CHECK_219_SHA_CONTEXT_TOKENS = (
    "sha256",
    "sha=",
    "sha ",
    "sha:",
    "archive sha",
    "archive_sha256",
    "...",  # the canonical lane-registry abbreviation `87ec7ca5...492b5`
)


def _check_219_discover_mdl_results(
    repo_root: Path,
) -> dict[str, dict]:
    """Return {sha256_full: {density_lo: float, source_path: str, ...}}.

    Scans ``experiments/results/mdl_ablation*/`` for ``*_mdl_ablation.json``
    files matching the canonical Z1 schema (archive_sha256 +
    mdl_density_estimate_lo). Returns a dict keyed by FULL sha256 so the
    lane-evidence shortened-sha matcher can do prefix membership.
    """
    out: dict[str, dict] = {}
    results_dir = repo_root / "experiments" / "results"
    if not results_dir.is_dir():
        return out
    for entry in results_dir.iterdir():
        if not entry.is_dir():
            continue
        if "mdl_ablation" not in entry.name.lower():
            continue
        for json_file in entry.glob("*_mdl_ablation.json"):
            if json_file.name == "summary_mdl_ablation.json":
                # Aggregate summary file - readable but redundant; we prefer
                # per-archive results that carry archive_sha256 directly.
                continue
            try:
                payload = json.loads(json_file.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError, UnicodeDecodeError):
                continue
            sha = payload.get("archive_sha256")
            density_lo = payload.get("mdl_density_estimate_lo")
            density_hi = payload.get("mdl_density_estimate_hi")
            if not sha or not isinstance(sha, str):
                continue
            if density_lo is None:
                continue
            try:
                density_lo = float(density_lo)
            except (TypeError, ValueError):
                continue
            sha_low = sha.lower()
            # Keep the highest density observed for the same sha. Subsequent
            # higher-precision runs may revise; we always gate on the most
            # recent / highest reading so we never silently drop the alert.
            if sha_low in out:
                prev = out[sha_low].get("density_lo", 0.0)
                if density_lo <= prev:
                    continue
            out[sha_low] = {
                "density_lo": density_lo,
                "density_hi": float(density_hi) if density_hi is not None else density_lo,
                "source_path": str(json_file.relative_to(repo_root)),
                "archive_size_bytes": payload.get("archive_size_bytes"),
                "zen_floor_band_recommendation": payload.get("zen_floor_band_recommendation", ""),
            }
    return out


def _check_219_lane_is_exempt(lane: dict) -> bool:
    """Return True if the lane is explicitly research/substrate-engineering
    scope and therefore exempt from the contest-promotion gate.

    Acceptance:
      - ``lane_class`` field has any of _CHECK_219_EXEMPT_LANE_CLASS_TOKENS;
      - ``target_modes`` list contains any of
        _CHECK_219_EXEMPT_TARGET_MODE_TOKENS;
      - the ``notes`` body contains ``research_only=true`` OR
        ``lane_class=<exempt token>``;
      - the ``notes`` body contains a substrate-engineering exception phrase.
    """
    lane_class = lane.get("lane_class", "")
    if isinstance(lane_class, str):
        for tok in _CHECK_219_EXEMPT_LANE_CLASS_TOKENS:
            if tok in lane_class:
                return True
    target_modes = lane.get("target_modes") or []
    if isinstance(target_modes, list):
        for mode in target_modes:
            if isinstance(mode, str):
                for tok in _CHECK_219_EXEMPT_TARGET_MODE_TOKENS:
                    if tok in mode:
                        return True
    notes = lane.get("notes") or ""
    if isinstance(notes, str):
        lower = notes.lower()
        if "research_only=true" in lower:
            return True
        if "research_only:true" in lower:
            return True
        if "substrate_engineering_exception" in lower:
            return True
        for tok in _CHECK_219_EXEMPT_LANE_CLASS_TOKENS:
            if f"lane_class={tok}" in lower or f"lane_class:{tok}" in lower:
                return True
    return False


def _check_219_lane_has_waiver(lane: dict) -> tuple[bool, str]:
    """Return (waived, reason) if the lane carries a # MDL_DENSITY_OVER_THRESHOLD_OK:
    waiver in its registry notes / evidence body.

    Sister of Catalog #218's same-line waiver pattern. Placeholder literal
    ``<reason>`` is rejected so the gate cannot self-waive on docstring text.
    """
    notes = lane.get("notes") or ""
    if not isinstance(notes, str):
        notes = ""
    text_buckets = [notes]
    gates = lane.get("gates") or {}
    if isinstance(gates, dict):
        for gate_name in _CHECK_219_L2_PROMOTION_GATE_NAMES:
            gate = gates.get(gate_name) or {}
            ev = gate.get("evidence") if isinstance(gate, dict) else None
            if isinstance(ev, str):
                text_buckets.append(ev)
    for text in text_buckets:
        m = _CHECK_219_WAIVER_RE.search(text)
        if m is None:
            m = _CHECK_219_WAIVER_INLINE_RE.search(text)
        if m is None:
            continue
        reason = m.group(1).strip().rstrip(",;").strip()
        if not reason or reason in {"<reason>", "<rationale>"}:
            continue
        return True, reason
    return False, ""


def _check_219_text_has_sha_context(text: str) -> bool:
    """Return True if the text contains at least one sha-indicative context
    token (sha256, sha=, ..., etc.). Used to reject accidental hex strings
    (timestamps, counters) from being treated as sha prefixes.
    """
    if not isinstance(text, str):
        return False
    lower = text.lower()
    return any(tok in lower for tok in _CHECK_219_SHA_CONTEXT_TOKENS)


def _check_219_extract_sha_tokens(lane: dict) -> set[str]:
    """Collect every 8-64-hex-char sha-prefix token referenced by the lane's
    L2+ promotion gates' evidence strings and notes body.

    Only fields where the surrounding text contains a sha-indicative context
    token (`sha256`, `sha=`, `...`, etc.) are scanned to avoid false positives
    on accidental hex words (timestamps, line counters, run-id fragments).

    Returns a set of LOWERCASE hex strings.
    """
    tokens: set[str] = set()

    def _scan(text: str) -> None:
        if not isinstance(text, str):
            return
        if not _check_219_text_has_sha_context(text):
            return
        for m in _CHECK_219_SHA256_TOKEN_RE.finditer(text):
            t = m.group(1).lower()
            if len(t) >= _CHECK_219_MIN_SHA_PREFIX_LEN:
                tokens.add(t)

    gates = lane.get("gates") or {}
    if isinstance(gates, dict):
        for gate_name in _CHECK_219_L2_PROMOTION_GATE_NAMES:
            gate = gates.get(gate_name) or {}
            if not isinstance(gate, dict):
                continue
            if not gate.get("status"):
                continue
            _scan(gate.get("evidence", ""))
    _scan(lane.get("notes", "") or "")
    return tokens


def _check_219_match_sha_against_mdl_index(
    lane_tokens: set[str], mdl_index: dict[str, dict]
) -> list[tuple[str, dict]]:
    """Return [(sha_full, mdl_record)] for any lane-token that prefixes a full
    sha in the MDL ablation index. Lane evidence often abbreviates 64-char
    sha to first 8 chars (e.g. ``87ec7ca5...492b5``); we match by prefix.
    """
    matches: list[tuple[str, dict]] = []
    seen: set[str] = set()
    for tok in lane_tokens:
        if len(tok) < _CHECK_219_MIN_SHA_PREFIX_LEN:
            continue
        for sha_full, rec in mdl_index.items():
            if sha_full in seen:
                continue
            if len(tok) <= len(sha_full):
                if sha_full.startswith(tok):
                    matches.append((sha_full, rec))
                    seen.add(sha_full)
            else:
                # Token longer than full sha would be unusual; require exact
                # prefix match of the full sha to avoid false positives.
                if tok.startswith(sha_full):
                    matches.append((sha_full, rec))
                    seen.add(sha_full)
    return matches


def check_archive_promotion_blocked_by_mdl_density_above_threshold(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #219 — refuse L2+ archive promotion when measured scorer-
    conditional MDL density exceeds the class-saturation threshold (0.90).

    Per Z1 empirical revision 2026-05-14 (`feedback_z1_mdl_ablation_landed_
    20260514.md` operator decision #5): a measured MDL density above 0.90
    means the substrate class is empirically saturated and any further
    within-class encoder/codec refinement yields diminishing returns. The
    operator should route the next dispatch to a class-shift architecture.

    The gate scans `.omx/state/lane_registry.json` for lanes with L2+
    promotion gates satisfied (`real_archive_empirical` /
    `contest_cuda` / `contest_cpu` status=True), extracts any sha256 tokens
    from those evidence strings, and cross-references each token against the
    discovered MDL ablation results under
    `experiments/results/mdl_ablation*/`. A lane is refused if it
    references a sha256 whose `mdl_density_estimate_lo` > 0.90 AND the lane
    is not exempt (lane_class / target_modes / notes opt-out) AND the lane
    does not carry a `# MDL_DENSITY_OVER_THRESHOLD_OK:<reason>` waiver.

    Initial landing is warn-only per CLAUDE.md "Strict-flip atomicity rule":
    A1 (sha 87ec7ca5...) and PR106 r2 (sha 7f926bc3...) are the only lanes
    with measured MDL density at the time of landing, and both are explicit
    operator-acknowledged baselines whose lane-registry notes should carry
    the canonical waiver in the same commit batch.

    Sister of Catalog #90 (`check_lane_registry_consistent`) +
    Catalog #127 (`check_authoritative_tag_requires_custody_metadata`).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    registry_path = root / ".omx" / "state" / "lane_registry.json"
    if not registry_path.is_file():
        if verbose:
            print("  [mdl-density-promotion-gate] OK (no lane_registry.json)")
        return violations

    try:
        registry = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if verbose:
            print(f"  [mdl-density-promotion-gate] WARN registry read error: {exc}")
        return violations

    mdl_index = _check_219_discover_mdl_results(root)
    if not mdl_index:
        if verbose:
            print(
                "  [mdl-density-promotion-gate] OK (no MDL ablation evidence "
                "found under experiments/results/mdl_ablation*/)"
            )
        return violations

    threshold = _CHECK_219_MDL_DENSITY_THRESHOLD
    lanes_scanned = 0
    lanes_with_mdl_evidence = 0

    for lane in registry.get("lanes", []):
        if not isinstance(lane, dict):
            continue
        lanes_scanned += 1
        level = int(lane.get("level", 0) or 0)
        if level < 2:
            continue
        # Quick L2-promotion check: at least one L2+ gate must be satisfied.
        gates = lane.get("gates") or {}
        any_l2_gate_satisfied = False
        if isinstance(gates, dict):
            for gate_name in _CHECK_219_L2_PROMOTION_GATE_NAMES:
                gate = gates.get(gate_name) or {}
                if isinstance(gate, dict) and gate.get("status"):
                    any_l2_gate_satisfied = True
                    break
        if not any_l2_gate_satisfied:
            continue

        # Match against the MDL ablation index.
        sha_tokens = _check_219_extract_sha_tokens(lane)
        if not sha_tokens:
            continue
        matches = _check_219_match_sha_against_mdl_index(sha_tokens, mdl_index)
        if not matches:
            continue
        lanes_with_mdl_evidence += 1

        # Find the maximum measured density across all matched archives.
        max_density = 0.0
        max_match: tuple[str, dict] | None = None
        for sha_full, rec in matches:
            d = rec.get("density_lo", 0.0)
            if d > max_density:
                max_density = d
                max_match = (sha_full, rec)
        if max_density <= threshold:
            continue

        # Density exceeds threshold. Apply opt-out cascades.
        if _check_219_lane_is_exempt(lane):
            continue
        waived, reason = _check_219_lane_has_waiver(lane)
        if waived:
            continue

        sha_full, rec = max_match  # type: ignore[misc]
        violations.append(
            f"lane {lane.get('id', '?')!r} (L{level}) references sha "
            f"{sha_full[:16]}... with measured MDL density "
            f"{max_density:.4f} > {threshold:.2f} threshold "
            f"(source: {rec.get('source_path', '?')}; "
            f"zen_floor_band={rec.get('zen_floor_band_recommendation', 'unknown')[:80]!r}). "
            f"Per Z1 empirical revision (CLAUDE.md Catalog #219): the "
            f"substrate class is empirically saturated; further within-class "
            f"promotion is diminishing-returns. Route the next dispatch to a "
            f"class-shift architecture (predictive-receiver / cooperative-"
            f"receiver / foveation / Wyner-Ziv) OR add a `# MDL_DENSITY_OVER"
            f"_THRESHOLD_OK:<reason>` waiver to the lane's registry notes "
            f"(operator-explicit acknowledgement, e.g. baseline-anchor / "
            f"frontier-reference). Memory: feedback_mdl_density_gate_and_"
            f"autopilot_ranker_landed_20260514.md."
        )

    if verbose:
        if violations:
            print(
                f"  [mdl-density-promotion-gate] {len(violations)} violation(s) "
                f"across {lanes_scanned} lane(s) ({lanes_with_mdl_evidence} "
                f"L2+ lane(s) had MDL evidence; strict={strict})"
            )
            for v in violations[:5]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [mdl-density-promotion-gate] OK "
                f"({lanes_scanned} lane(s) scanned, "
                f"{lanes_with_mdl_evidence} L2+ MDL-evidenced lane(s) clean)"
            )

    if violations and strict:
        raise PreflightError(
            f"check_archive_promotion_blocked_by_mdl_density_above_threshold "
            f"found {len(violations)} L2+ archive(s) with measured MDL density "
            f"> {threshold:.2f} (Catalog #219 — Z1 empirical revision "
            f"self-protect):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #227 — check_substrate_class_promotion_requires_tier_c_evidence
#
# Tier C empirical revision self-protection (2026-05-14). Sister of Catalog
# #219 (Tier A within-class density gate). Where #219 refuses L2+ promotion
# when Tier A density > 0.90, #227 refuses substrate-class-shift PROMOTION
# (lanes claiming `lane_class` ∈ class-shift tokens OR `notes` referencing
# class-shift literature anchors) at L2+ WITHOUT Tier C empirical evidence.
#
# Bug class: Tier A is brotli-saturated at the byte layer (any fp16-weight +
# brotli archive sits at Tier A density ~0.99) and structurally CANNOT
# discriminate substrate class. A lane can claim ACROSS-CLASS lineage via
# its lane_class / notes / literature_anchor field WITHOUT empirically
# demonstrating the class-shift signature via Tier C post-decode
# perturbation. Per the C6 5ep empirical anchor `feedback_mdl_ablation_
# tier_c_ibps1_landed_20260514.md`, the dispositive test is Tier C — the
# latent Δscore at σ=1.0 must be sub-0.05 AND state_dict perturbation
# must show a knee+plateau structural signature.
#
# This gate refuses any L2+ class-shift lane whose evidence does NOT
# reference a Tier C ablation result on the lane's archive bytes. The
# acceptance includes a waiver mechanism for genuinely-pre-empirical lanes
# (still in design / 5ep / pre-Tier-C-feasibility).
#
# Lane: lane_autopilot_tier_c_integration_catalog_227_20260514.
# Memory: feedback_autopilot_tier_c_integration_catalog_227_landed_20260514.md.
# Cross-ref:
#   - Catalog #219 (Tier A density-saturation gate; sister)
#   - Catalog #125 (subagent landing 6-hook wire-in; this gate IS hook #4
#     for the Tier C result loop)
#   - CLAUDE.md "HNeRV / leaderboard-implementation parity discipline"
#     lesson 6 (score-domain Lagrangian via Tier C, not byte-domain Tier A)
# ----------------------------------------------------------------------------

# Substrate-class-shift tokens that trigger Catalog #227. Sister of the
# autopilot ranker's `_CLASS_SHIFT_LANE_CLASS_TOKENS` /
# `_CLASS_SHIFT_LITERATURE_TOKENS` constants in
# `tools/cathedral_autopilot_autonomous_loop.py`.
_CHECK_227_CLASS_SHIFT_LANE_CLASS_TOKENS = (
    "substrate_class_shift",
    "predictive_receiver",
    "cooperative_receiver",
    "foveation",
)

_CHECK_227_CLASS_SHIFT_NOTES_TOKENS = (
    "cooperative-receiver",
    "cooperative_receiver",
    "predictive-coding",
    "predictive_coding",
    "predictive-receiver",
    "predictive_receiver",
    "foveation",
    "Tishby-Zaslavsky",
    "Atick-Redlich",
    "Rao-Ballard",
    "Wyner-Ziv",
    "Information Bottleneck",
    "information_bottleneck",
    "MDL-IBPS",
    "Slepian-Wolf",
    "world_model",
    "world-model",
    "time_traveler",
    "time-traveler",
    "Ha-Schmidhuber",
    "Ha Schmidhuber",
    "Hafner",
    "DreamerV3",
)

# Same-line waiver. Placeholder literal "<reason>" / "<rationale>" rejected
# so the docstring above cannot self-waive.
_CHECK_227_WAIVER_RE = re.compile(
    r"#\s*TIER_C_EVIDENCE_PENDING_OK:\s*([^\s<].*)"
)
_CHECK_227_WAIVER_INLINE_RE = re.compile(
    r"TIER_C_EVIDENCE_PENDING_OK:\s*([^\s<,;]+)"
)

# Tier C evidence requires that the lane's evidence string OR notes mention
# a Tier C ablation in one of the canonical ways:
#   * literal "tier_c" / "tier c" / "Tier C" in evidence / notes
#   * an archive_sha256 that appears in the MDL ablation index AND that
#     index entry's source file has Tier C rows
_CHECK_227_TIER_C_TOKENS = (
    "tier_c",
    "tier c",
    "Tier C",
    "TIER_C",
    "mdl_tier_c",
    "tier-c",
)


# Catalog #227-specific exemption tokens. Sister of Catalog #219's
# _CHECK_219_EXEMPT_LANE_CLASS_TOKENS but DOES NOT include
# "substrate_class_shift" (the whole point of #227 is to gate class-shift
# lanes!). The Catalog #227 exemption is narrower: ONLY research-only and
# substrate_engineering scopes that are OUT of contest-promotion scope.
_CHECK_227_EXEMPT_LANE_CLASS_TOKENS = (
    "substrate_engineering",
    "research_substrate",
)

_CHECK_227_EXEMPT_TARGET_MODE_TOKENS = (
    "research_substrate",
    "research_only",
)


def _check_227_lane_is_exempt(lane: dict) -> bool:
    """Return True if the lane is explicitly research-only OR substrate-
    engineering scope (out of contest-promotion eligibility).

    Narrower than `_check_219_lane_is_exempt` — Catalog #227 does NOT exempt
    `substrate_class_shift` lanes (those ARE the lanes being gated).
    """
    lane_class = lane.get("lane_class", "")
    if isinstance(lane_class, str):
        for tok in _CHECK_227_EXEMPT_LANE_CLASS_TOKENS:
            if tok in lane_class:
                return True
    target_modes = lane.get("target_modes") or []
    if isinstance(target_modes, list):
        for mode in target_modes:
            if isinstance(mode, str):
                for tok in _CHECK_227_EXEMPT_TARGET_MODE_TOKENS:
                    if tok in mode:
                        return True
    notes = lane.get("notes") or ""
    if isinstance(notes, str):
        lower = notes.lower()
        if "research_only=true" in lower:
            return True
        if "research_only:true" in lower:
            return True
        if "substrate_engineering_exception" in lower:
            return True
        for tok in _CHECK_227_EXEMPT_LANE_CLASS_TOKENS:
            if f"lane_class={tok}" in lower or f"lane_class:{tok}" in lower:
                return True
    return False


def _check_227_lane_is_class_shift_claim(lane: dict) -> bool:
    """Return True if the lane CLAIMS substrate-class-shift lineage via any of:
      - lane_class field contains class-shift token
      - notes body contains class-shift literature token
      - notes body contains lane_class=<class-shift token>
    """
    lane_class = lane.get("lane_class") or ""
    if isinstance(lane_class, str):
        for tok in _CHECK_227_CLASS_SHIFT_LANE_CLASS_TOKENS:
            if tok in lane_class:
                return True
    notes = lane.get("notes") or ""
    if isinstance(notes, str):
        for tok in _CHECK_227_CLASS_SHIFT_LANE_CLASS_TOKENS:
            if f"lane_class={tok}" in notes or f"lane_class:{tok}" in notes:
                return True
        for tok in _CHECK_227_CLASS_SHIFT_NOTES_TOKENS:
            if tok in notes:
                return True
    return False


def _check_227_lane_has_tier_c_evidence(
    lane: dict, mdl_tier_c_index: dict[str, dict]
) -> bool:
    """Return True if the lane has Tier C ablation evidence.

    Acceptance:
      (a) any gate evidence string OR notes body contains a Tier C token
          (literal "tier_c" / "Tier C" / etc.), OR
      (b) the lane's archive sha256 is in the Tier C index (an MDL ablation
          JSON with non-empty tier_c rows exists for the archive).
    """
    text_buckets: list[str] = []
    gates = lane.get("gates") or {}
    if isinstance(gates, dict):
        for gate_name in _CHECK_219_L2_PROMOTION_GATE_NAMES:
            gate = gates.get(gate_name) or {}
            ev = gate.get("evidence") if isinstance(gate, dict) else None
            if isinstance(ev, str):
                text_buckets.append(ev)
    notes = lane.get("notes") or ""
    if isinstance(notes, str):
        text_buckets.append(notes)

    # Token-based acceptance (a)
    for text in text_buckets:
        for tok in _CHECK_227_TIER_C_TOKENS:
            if tok in text:
                return True

    # SHA-based acceptance (b)
    if mdl_tier_c_index:
        sha_tokens = _check_219_extract_sha_tokens(lane)
        if sha_tokens:
            matches = _check_219_match_sha_against_mdl_index(
                sha_tokens, mdl_tier_c_index
            )
            if matches:
                return True
    return False


def _check_227_lane_has_waiver(lane: dict) -> tuple[bool, str]:
    """Return (waived, reason) if the lane carries a # TIER_C_EVIDENCE_PENDING_OK:
    waiver in its registry notes / evidence body.

    Sister of Catalog #219's waiver pattern. Placeholder literal
    ``<reason>`` is rejected so the gate cannot self-waive on docstring text.
    """
    notes = lane.get("notes") or ""
    if not isinstance(notes, str):
        notes = ""
    text_buckets = [notes]
    gates = lane.get("gates") or {}
    if isinstance(gates, dict):
        for gate_name in _CHECK_219_L2_PROMOTION_GATE_NAMES:
            gate = gates.get(gate_name) or {}
            ev = gate.get("evidence") if isinstance(gate, dict) else None
            if isinstance(ev, str):
                text_buckets.append(ev)
    for text in text_buckets:
        m = _CHECK_227_WAIVER_RE.search(text)
        if m is None:
            m = _CHECK_227_WAIVER_INLINE_RE.search(text)
        if m is None:
            continue
        reason = m.group(1).strip().rstrip(",;").strip()
        if not reason or reason in {"<reason>", "<rationale>"}:
            continue
        return True, reason
    return False, ""


def _check_227_discover_tier_c_results(
    repo_root: Path,
) -> dict[str, dict]:
    """Return {sha256_full: {density_lo, has_tier_c, source_path, ...}}.

    Same scan-shape as Catalog #219's helper, but additionally requires the
    JSON to have a non-empty ``tier_c`` list so the index only carries
    archives that actually have Tier C measurements.
    """
    out: dict[str, dict] = {}
    results_dir = repo_root / "experiments" / "results"
    if not results_dir.is_dir():
        return out
    for entry in results_dir.iterdir():
        if not entry.is_dir():
            continue
        if "mdl_ablation" not in entry.name.lower():
            continue
        for json_file in entry.glob("*_mdl_ablation.json"):
            if json_file.name == "summary_mdl_ablation.json":
                continue
            try:
                payload = json.loads(json_file.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError, UnicodeDecodeError):
                continue
            sha = payload.get("archive_sha256")
            tier_c_rows = payload.get("tier_c") or []
            if not sha or not isinstance(sha, str):
                continue
            if not isinstance(tier_c_rows, list) or not tier_c_rows:
                continue
            density_lo = payload.get("mdl_density_estimate_lo", 0.0)
            try:
                density_lo = float(density_lo)
            except (TypeError, ValueError):
                density_lo = 0.0
            tier_c_density = payload.get("mdl_tier_c_density_estimate", 0.0)
            try:
                tier_c_density = float(tier_c_density)
            except (TypeError, ValueError):
                tier_c_density = 0.0
            sha_low = sha.lower()
            out[sha_low] = {
                "has_tier_c": True,
                "density_lo": density_lo,
                "tier_c_density": tier_c_density,
                "tier_c_verdict": payload.get(
                    "mdl_tier_c_substrate_class_verdict", ""
                ),
                "source_path": str(json_file.relative_to(repo_root)),
                "n_tier_c_rows": len(tier_c_rows),
            }
    return out


def check_substrate_class_promotion_requires_tier_c_evidence(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #227 — refuse L2+ promotion of substrate-class-shift lanes
    without Tier C empirical evidence.

    Per `feedback_mdl_ablation_tier_c_ibps1_landed_20260514.md` operator
    decision #4 + the C6 5ep ACROSS-CLASS verdict
    (`project_c6_substrate_class_shift_first_empirical_confirmation_tier_c_
    20260514.md`): Tier A density alone CANNOT discriminate substrate class
    because brotli saturation makes Tier A indistinguishable for any fp16-
    weight + brotli archive (within OR across class, all saturate at ~0.99).
    The dispositive test is Tier C (post-decode perturbation curve shape).

    The gate scans `.omx/state/lane_registry.json` for L2+ lanes that CLAIM
    substrate-class-shift lineage (via lane_class field OR class-shift
    literature anchor tokens in notes) AND refuses any such lane lacking
    Tier C evidence on its archive.

    Acceptance cascades (lane must satisfy at least one):
      (a) Lane evidence/notes contain a Tier C token ("tier_c" / "Tier C" /
          etc.) — the operator has explicitly acknowledged Tier C either
          ran OR is in flight.
      (b) Lane's archive sha256 is in the Tier C ablation index (an MDL
          ablation JSON with non-empty tier_c rows exists for the archive).
      (c) Lane carries a same-line `# TIER_C_EVIDENCE_PENDING_OK:<rationale>`
          waiver. Reserved for pre-empirical lanes (still in design / 5ep
          / pre-Tier-C-feasibility); placeholder `<reason>` literal rejected.
      (d) Lane is exempt via lane_class / target_modes opt-out OR has the
          waiver per Catalog #219's sister exemption mechanism. Specifically
          a research_only / research_substrate lane is exempt — those are
          not contest-promotion eligible regardless of Tier C status.

    Initial wire-in is warn-only per CLAUDE.md "Strict-flip atomicity rule".
    Strict-flip planned once 0 violations are confirmed across class-shift
    lanes AND the canonical Tier C anchor for at least one substrate
    (C6 IBPS1) lands at converged 100ep+ level.

    Sister of Catalog #219 (Tier A density gate; brotli-saturated layer) +
    Catalog #125 (subagent landing 6-hook wire-in). Together they extinct
    the "class-shift claim without empirical Tier C evidence" bug class.

    Per CLAUDE.md "Forbidden premature KILL without research exhaustion":
    the gate REFUSES promotion of an unproven class-shift CLAIM but does
    NOT kill the lane; the operator can either run Tier C OR add the
    waiver for pre-empirical scope.

    Memory: feedback_autopilot_tier_c_integration_catalog_227_landed_20260514.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    registry_path = root / ".omx" / "state" / "lane_registry.json"
    if not registry_path.is_file():
        if verbose:
            print("  [tier-c-class-shift-promotion-gate] OK (no lane_registry.json)")
        return violations

    try:
        registry = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if verbose:
            print(
                f"  [tier-c-class-shift-promotion-gate] WARN registry read error: {exc}"
            )
        return violations

    tier_c_index = _check_227_discover_tier_c_results(root)

    lanes_scanned = 0
    class_shift_lanes_scanned = 0

    for lane in registry.get("lanes", []):
        if not isinstance(lane, dict):
            continue
        lanes_scanned += 1
        level = int(lane.get("level", 0) or 0)
        if level < 2:
            continue
        # L2-promotion gate satisfaction.
        gates = lane.get("gates") or {}
        any_l2_gate_satisfied = False
        if isinstance(gates, dict):
            for gate_name in _CHECK_219_L2_PROMOTION_GATE_NAMES:
                gate = gates.get(gate_name) or {}
                if isinstance(gate, dict) and gate.get("status"):
                    any_l2_gate_satisfied = True
                    break
        if not any_l2_gate_satisfied:
            continue

        if not _check_227_lane_is_class_shift_claim(lane):
            continue
        class_shift_lanes_scanned += 1

        # Catalog #227-specific exemption: research_only / research_substrate
        # / substrate_engineering lanes are out of contest-promotion scope.
        # Narrower than Catalog #219's exemption — we do NOT exempt
        # `substrate_class_shift` here (those are the gated lanes).
        if _check_227_lane_is_exempt(lane):
            continue

        # Tier C evidence cascade (a)+(b)
        if _check_227_lane_has_tier_c_evidence(lane, tier_c_index):
            continue

        # Waiver cascade (c)
        waived, reason = _check_227_lane_has_waiver(lane)
        if waived:
            continue

        # Build the violation message.
        violations.append(
            f"lane {lane.get('id', '?')!r} (L{level}) CLAIMS substrate-class-shift "
            f"lineage (lane_class={lane.get('lane_class', '')!r} OR class-shift "
            f"literature token in notes) but lacks Tier C empirical evidence. "
            f"Per Z1 deep-math + C6 5ep ACROSS-CLASS verdict, Tier A density "
            f"is brotli-saturated and CANNOT discriminate substrate class; "
            f"Tier C is the dispositive disambiguator. Either (a) run "
            f"`tools/mdl_scorer_conditional_ablation.py --run-tier-c-only` on "
            f"the lane's archive and add the result path to the lane's "
            f"evidence, OR (b) add a `# TIER_C_EVIDENCE_PENDING_OK:<rationale>` "
            f"waiver to the lane's registry notes for pre-empirical scope. "
            f"Memory: feedback_autopilot_tier_c_integration_catalog_227_"
            f"landed_20260514.md."
        )

    if verbose:
        if violations:
            print(
                f"  [tier-c-class-shift-promotion-gate] {len(violations)} "
                f"violation(s) across {class_shift_lanes_scanned} class-shift "
                f"lane(s) of {lanes_scanned} total (strict={strict})"
            )
            for v in violations[:5]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [tier-c-class-shift-promotion-gate] OK "
                f"({lanes_scanned} lane(s) scanned, "
                f"{class_shift_lanes_scanned} class-shift lane(s) clean)"
            )

    if violations and strict:
        raise PreflightError(
            f"check_substrate_class_promotion_requires_tier_c_evidence "
            f"found {len(violations)} L2+ class-shift lane(s) lacking Tier C "
            f"evidence (Catalog #227 — Tier C empirical revision self-protect):"
            f"\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #233 — check_l1_to_l2_promotion_canonical_4_gate
#
# Operationalize the council Decision 8 binding verdict from the omnibus
# commit ``7872c9f4b`` ledger
# (``.omx/research/grand_council_omnibus_design_decisions_20260514.md``,
# lines 336-388, 11/11 unanimous PROCEED Option D).
#
# Decision 8 binding verdict (verbatim, lines 366-371):
#
#   PROCEED Option D. The L1 → L2 substrate-class promotion canonical:
#     1. Smoke green (rc=0 + auth-eval JSON parseable).
#     2. Tier C MDL density measured
#        (`tools/mdl_scorer_conditional_ablation.py` on the smoke artifact).
#     3. 100ep auth-eval anchor with byte-deterministic archive
#        (sha256 stable across re-runs).
#     4. Custody validated per Catalog #127 (`evidence_grade` matches axis +
#        hardware).
#     5. (Conditional) Probe-disambiguator built if 2+ defensible
#        interpretations exist.
#
# This gate scans ``.omx/state/lane_registry.json`` for in-scope substrate
# lanes at L2+ and refuses any lane whose registry evidence does NOT
# demonstrate ALL FOUR mandatory gates.
#
# Bug class anchor: per the council ledger's math+rationale section
# (lines 375-381), each gate is "structurally non-redundant" with the
# others. Together they prevent THREE failure modes:
#   - "substrate trained but never validated"  (smoke gate)
#   - "substrate validated but within-class saturated"  (Tier C gate)
#   - "score claim without custody"  (100ep auth-eval + Catalog #127 gates)
#
# Sister of:
#   - Catalog #127 (`check_authoritative_tag_requires_custody_metadata`) —
#     the per-call-site custody-validator routing gate; this gate is its
#     lane-registry-level enforcement complement.
#   - Catalog #220 (`check_substrate_l1_scaffold_no_byte_addition_without_
#     operational_score_improvement_mechanism`) — refuses L1+ scaffolds
#     that add bytes without operational mechanism; this gate refuses L2+
#     promotion claims that lack the canonical 4-gate evidence.
#   - Catalog #227 (`check_substrate_class_promotion_requires_tier_c_
#     evidence`) — refuses L2+ class-shift lanes lacking Tier C; this gate
#     extends to ALL L2+ substrate lanes (not only class-shift) and
#     enforces 4 gates instead of the single Tier C gate.
#
# Per CLAUDE.md "Strict-flip atomicity rule" the initial wire-in is
# warn-only because the council's operator-routable checkpoint #2 says
# "any L2-claimed lane WITHOUT all 4 gates is forensically reviewed and
# downgraded if necessary" — strict-flip lands after the operator-routed
# audit-and-downgrade sweep brings live count to 0.
#
# Lane: lane_d8_l1_l2_promotion_canonical_strict_preflight_20260514.
# ----------------------------------------------------------------------------

