def _check_233_lane_is_in_scope(lane_id: str) -> bool:
    """Return True if the lane id matches a substrate-class pattern."""
    if not lane_id:
        return False
    needle = lane_id.lower()
    return any(token in needle for token in _CHECK_233_IN_SCOPE_ID_SUBSTRINGS)


def _check_233_lane_is_exempt(lane: dict) -> bool:
    """Return True if the lane is research-only / substrate-engineering scope.

    These lanes are explicitly NOT contest-promotion eligible per HNeRV
    parity discipline lessons 2 + 7; the 4-gate canonical does not apply.
    """
    lane_class = lane.get("lane_class", "")
    if isinstance(lane_class, str):
        for tok in _CHECK_233_EXEMPT_LANE_CLASS_TOKENS:
            if tok in lane_class:
                return True
    target_modes = lane.get("target_modes") or []
    if isinstance(target_modes, list):
        for mode in target_modes:
            if isinstance(mode, str):
                for tok in _CHECK_233_EXEMPT_TARGET_MODE_TOKENS:
                    if tok in mode:
                        return True
    notes = lane.get("notes") or ""
    if isinstance(notes, str):
        lower = notes.lower()
        if "research_only=true" in lower:
            return True
        if "research_only:true" in lower:
            return True
        if "substrate_engineering_exception" in lower:
            return True
        for tok in _CHECK_233_EXEMPT_LANE_CLASS_TOKENS:
            if f"lane_class={tok}" in lower or f"lane_class:{tok}" in lower:
                return True
    return False


def _check_233_collect_lane_text(lane: dict) -> str:
    """Concatenate every text field of a lane for token extraction.

    Concatenates ``notes`` plus every gate's ``evidence`` string so a token
    appearing in any of them satisfies the gate.
    """
    parts: list[str] = []
    notes = lane.get("notes")
    if isinstance(notes, str):
        parts.append(notes)
    gates = lane.get("gates") or {}
    if isinstance(gates, dict):
        for gate_name, gate in gates.items():
            if isinstance(gate, dict):
                ev = gate.get("evidence")
                if isinstance(ev, str):
                    parts.append(ev)
    return "\n".join(parts)


def _check_233_lane_has_waiver(text: str) -> tuple[bool, str]:
    """Return (waived, reason). Placeholder literal rejected."""
    if not text:
        return False, ""
    m = _CHECK_233_WAIVER_RE.search(text)
    if m is None:
        m = _CHECK_233_WAIVER_INLINE_RE.search(text)
    if m is None:
        return False, ""
    reason = m.group(1).strip().rstrip(",;").strip()
    if not reason or reason in _CHECK_233_WAIVER_PLACEHOLDER_REJECTS:
        return False, ""
    return True, reason


def _check_233_text_contains_any_token(text: str, tokens: Iterable[str]) -> bool:
    """Case-insensitive literal-token match with identifier boundaries.

    This helper is retained for token-audit tests. The production 4-gate
    evaluator below uses gate-specific structured regexes so prose such as
    ``"100ep vs 200ep tradeoffs"`` cannot satisfy the auth-eval gate.
    """
    if not text:
        return False
    for tok in tokens:
        literal = re.escape(tok).replace(r"\ ", r"\s+")
        if re.search(rf"(?i)(?<![\w-]){literal}(?![\w-])", text):
            return True
    return False


def _check_233_text_matches_any_pattern(
    text: str,
    patterns: tuple[re.Pattern[str], ...],
) -> bool:
    """Return True when any structured Catalog #233 evidence pattern matches."""
    if not text:
        return False
    return any(pattern.search(text) for pattern in patterns)


def _check_233_custody_validated(text: str) -> bool:
    """Return True if custody evidence is structured enough for Catalog #233."""
    if _check_233_text_matches_any_pattern(
        text, _CHECK_233_CUSTODY_VALIDATOR_PATTERNS
    ):
        return True
    return (
        _CHECK_233_EVIDENCE_GRADE_RE.search(text) is not None
        and _CHECK_233_HARDWARE_SUBSTRATE_RE.search(text) is not None
    )


def _check_233_text_has_prose_negation_for_auth_eval(text: str) -> bool:
    """Return True when prose-discussion context surrounds the 100ep mention.

    TAO-1 self-protection (Catalog #236): retired-config descriptions like
    "previously 100ep auth-eval was attempted; superseded by 200ep" or
    "discussion of 100ep auth-eval tradeoffs" trip the loose co-occurrence
    pattern but do NOT prove a converged 100ep auth-eval anchor exists. The
    prose-context guard scans for negation/discussion tokens within a
    160-char window around any "100ep" mention (preceding 80 chars + the
    surrounding sentence). If any negation token appears in window, the
    gate REJECTS the loose match.

    The structured patterns (`auth_eval_score_axis=...`, `[contest-CUDA]`,
    `auth_eval_complete`, etc.) are NOT subject to the prose guard because
    those are key=value pairs / tagged lane labels and cannot appear in
    prose discussion accidentally.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
    against": this is the same bug class as Catalog #136 (custody validator
    bag-of-tokens) — a token set that did not require structural context.
    """
    if not text:
        return False
    lower = text.lower()
    # Find every 100ep / 100_ep / "100 epochs" position.
    needles = ("100ep", "100_ep", "100 epochs")
    positions: list[int] = []
    for needle in needles:
        idx = 0
        while True:
            j = lower.find(needle, idx)
            if j == -1:
                break
            positions.append(j)
            idx = j + len(needle)
    if not positions:
        return False
    # Around each position, check for any negation token in a 160-char
    # window (80 before + 80 after).
    for pos in positions:
        start = max(0, pos - 80)
        end = min(len(lower), pos + 80)
        window = lower[start:end]
        for neg_tok in _CHECK_233_PROSE_NEGATION_TOKENS:
            if neg_tok in window:
                return True
    return False


def _check_233_evaluate_4_gates(text: str) -> tuple[bool, bool, bool, bool]:
    """Return (smoke_green, tier_c_measured, auth_eval_100ep, custody_validated)
    booleans for a lane's concatenated registry text.

    Per Catalog #236 (TAO-1 self-protection 2026-05-15): gate 3
    (auth_eval_100ep) requires AFFIRMATIVE structured evidence and rejects
    prose-discussion contexts. The structured patterns (key=value pairs,
    lane tags) always satisfy the gate; the loose "100ep + auth-eval"
    co-occurrence patterns are accepted ONLY when no negation/discussion
    token appears in window. This eliminates the bug class anchored by the
    R2 ledger TAO-1 finding.
    """
    smoke_green = _check_233_text_matches_any_pattern(
        text, _CHECK_233_SMOKE_GREEN_PATTERNS
    )
    tier_c_measured = _check_233_text_matches_any_pattern(
        text, _CHECK_233_TIER_C_PATTERNS
    )

    # Gate 3 — affirmative structured evidence path is unconditional.
    auth_eval_100ep_structured = _check_233_text_matches_any_pattern(
        text, _CHECK_233_AUTH_EVAL_100EP_STRUCTURED_PATTERNS
    )
    if auth_eval_100ep_structured:
        auth_eval_100ep = True
    else:
        # Loose co-occurrence path is gated by the prose-negation guard.
        loose = _check_233_text_matches_any_pattern(
            text, _CHECK_233_AUTH_EVAL_100EP_LOOSE_PATTERNS
        )
        if loose and _check_233_text_has_prose_negation_for_auth_eval(text):
            auth_eval_100ep = False
        else:
            auth_eval_100ep = loose

    custody_validated = _check_233_custody_validated(text)
    return smoke_green, tier_c_measured, auth_eval_100ep, custody_validated


def check_l1_to_l2_promotion_canonical_4_gate(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #233 — refuse L2+ substrate lanes lacking the council Decision 8
    4-gate canonical evidence.

    Per the council omnibus commit ``7872c9f4b`` Decision 8 binding verdict
    (PROCEED Option D, 11/11 unanimous), L1 → L2 substrate-class promotion
    requires ALL FOUR gates:

    1. Smoke green (rc=0 + auth-eval JSON parseable).
    2. Tier C MDL density measured
       (``tools/mdl_scorer_conditional_ablation.py`` on the smoke artifact).
    3. 100ep auth-eval anchor with byte-deterministic archive (sha256
       stable across re-runs).
    4. Custody validated per Catalog #127 (``evidence_grade`` matches
       axis + hardware).

    The (conditional) 5th gate — probe-disambiguator built if 2+ defensible
    interpretations exist — is enforced separately via Catalog #125
    (`check_subagent_landing_has_solver_wire_in`) hook #6 for landings
    where the lane has multiple defensible interpretations. This gate
    enforces only the 4 mandatory gates.

    Acceptance per lane:
      (a) Lane is out-of-scope (not a substrate-id pattern) → skipped.
      (b) Lane is at level < 2 → skipped (gate is L1→L2 promotion gate).
      (c) Lane is exempt via ``lane_class=substrate_engineering`` /
          ``lane_class=research_substrate`` / ``target_modes`` containing
          ``research_substrate`` or ``research_only`` / notes carrying
          ``research_only=true`` or ``substrate_engineering_exception``.
          These lanes are explicitly NOT contest-promotion eligible.
      (d) Lane carries a same-line ``# L1_L2_PROMOTION_CANONICAL_OK:<reason>``
          waiver in registry notes / evidence (placeholder ``<reason>``
          literal rejected so the docstring cannot self-waive).
      (e) ALL four gate tokens appear in the lane's concatenated text
          (notes + every gate's evidence string).

    Initial wire-in is warn-only per CLAUDE.md "Strict-flip atomicity rule"
    + the council's operator-routable checkpoint #2 ("any L2-claimed lane
    WITHOUT all 4 gates is forensically reviewed and downgraded"). The
    operator-routed audit sweep is the pre-condition for STRICT-flip.

    Sister of:
      - Catalog #127 (the call-site custody validator routing gate)
      - Catalog #220 (the L1 scaffold byte-addition gate)
      - Catalog #227 (the L2+ class-shift Tier C evidence gate)

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-lane diagnostic.

    Returns:
        List of violation messages (one per refused lane).

    Memory: feedback_d8_l1_l2_promotion_canonical_strict_preflight_landed_
    20260514.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    registry_path = root / ".omx" / "state" / "lane_registry.json"
    if not registry_path.is_file():
        if verbose:
            print("  [catalog-233] OK (no lane_registry.json)")
        return violations

    try:
        registry = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if verbose:
            print(f"  [catalog-233] WARN registry read error: {exc}")
        return violations

    lanes = registry.get("lanes")
    if not isinstance(lanes, list):
        if verbose:
            print("  [catalog-233] OK (registry has no lanes list)")
        return violations

    lanes_scanned = 0
    in_scope_l2_lanes = 0
    waived_lanes = 0
    exempt_lanes = 0

    for lane in lanes:
        if not isinstance(lane, dict):
            continue
        lane_id = str(lane.get("id", ""))
        if not _check_233_lane_is_in_scope(lane_id):
            continue
        level = int(lane.get("level", 0) or 0)
        if level < 2:
            continue
        lanes_scanned += 1
        in_scope_l2_lanes += 1

        # Exemption cascade.
        if _check_233_lane_is_exempt(lane):
            exempt_lanes += 1
            if verbose:
                print(
                    f"  [catalog-233] EXEMPT lane={lane_id} "
                    f"(research_only / substrate_engineering scope)"
                )
            continue

        text = _check_233_collect_lane_text(lane)

        # Same-line waiver cascade.
        waived, reason = _check_233_lane_has_waiver(text)
        if waived:
            waived_lanes += 1
            if verbose:
                print(
                    f"  [catalog-233] WAIVED lane={lane_id} reason={reason!r}"
                )
            continue

        # 4-gate evaluation.
        gates = _check_233_evaluate_4_gates(text)
        smoke_green, tier_c, auth_100ep, custody = gates

        if smoke_green and tier_c and auth_100ep and custody:
            if verbose:
                print(
                    f"  [catalog-233] OK lane={lane_id} "
                    f"all 4 canonical gates satisfied"
                )
            continue

        # Build the violation message naming WHICH gates are missing.
        missing: list[str] = []
        if not smoke_green:
            missing.append(
                "(1) smoke green (rc=0 + auth-eval JSON parseable)"
            )
        if not tier_c:
            missing.append(
                "(2) Tier C MDL density measured "
                "(tools/mdl_scorer_conditional_ablation.py)"
            )
        if not auth_100ep:
            missing.append(
                "(3) 100ep auth-eval anchor with byte-deterministic archive"
            )
        if not custody:
            missing.append(
                "(4) custody validated per Catalog #127 "
                "(evidence_grade + axis + hardware)"
            )

        violations.append(
            f"lane {lane_id!r} (L{level}) claims L2+ substrate-class "
            f"promotion but is missing {len(missing)} of 4 canonical "
            f"gates per council Decision 8 (omnibus commit 7872c9f4b, "
            f"PROCEED Option D 11/11): "
            + "; ".join(missing)
            + ". Either (a) backfill the missing gate evidence into the "
            "lane's registry notes / gate.evidence text, OR (b) downgrade "
            "the lane to L1 if the 4-gate canonical cannot be satisfied "
            "yet, OR (c) re-classify as research_only=true / "
            "lane_class=substrate_engineering if the lane is "
            "explicitly NOT contest-promotion eligible, OR (d) add a "
            "same-line `# L1_L2_PROMOTION_CANONICAL_OK:<rationale>` "
            "waiver to the lane's registry notes for council-reviewed "
            "exception. Per CLAUDE.md \"Subagent coherence-by-default\" + "
            "Catalog #127 (custody validator) + Catalog #220 (operational "
            "mechanism) + Catalog #227 (Tier C evidence)."
        )

    if verbose:
        print(
            f"  [catalog-233] scanned={lanes_scanned} "
            f"in_scope_L2={in_scope_l2_lanes} "
            f"exempt={exempt_lanes} waived={waived_lanes} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            f"check_l1_to_l2_promotion_canonical_4_gate found "
            f"{len(violations)} L2+ substrate lane(s) lacking the "
            f"council Decision 8 4-gate canonical evidence "
            f"(Catalog #233 — D8 L1→L2 promotion canonical):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ---------------------------------------------------------------------------
# Catalog #220 — substrate scaffold byte addition without operational mechanism
# ---------------------------------------------------------------------------

# Threshold below which the byte addition is too small to matter (e.g. probe
# packets, byte-anchor metadata). At >1 KB we expect the substrate to either
# operationally consume the bytes or explicitly tag itself research_only /
# pre-build substrate_engineering.
_CHECK_220_BYTE_ADDITION_THRESHOLD_KB: float = 1.0

# Regex patterns to extract byte-addition signals from a lane's notes /
# evidence strings. A match suggests the lane adds non-trivial bytes to a
# composition archive.
_CHECK_220_BYTE_ADDITION_TOKEN_PATTERNS: tuple[str, ...] = (
    r"[+~]\s*\d+(?:\.\d+)?\s*KB",         # "+43 KB" / "+1.5 KB" / "~2.7 KB"
    r"overhead[^a-zA-Z0-9]*[~+]?\s*\d+(?:\.\d+)?\s*(?:KB|B|bytes)",  # "overhead ~43 KB"
    r"sidecar[^a-zA-Z0-9]*[~+]?\s*\d+(?:\.\d+)?\s*(?:KB|B|bytes)",   # "sidecar 2 KB"
    r"d1_overhead_bytes\s*=\s*~?\d+",     # explicit D1 overhead
    r"archive_bytes_added\s*=\s*[+~]?\s*\d+(?:\.\d+)?",  # canonical declaration
    r"rate\s*\+0?\.\d+",                  # "rate +0.029" → byte addition
    r"\d+(?:,\d+)+\s*(?:bytes|B)\b",      # "43,296 B" / "43,296 bytes"
    r"=~\d+(?:\.\d+)?\s*KB",              # "archive_bytes_added=~43 KB"
)

# Token forms accepted as the OPERATIONAL signal that the substrate actually
# uses its added bytes for score improvement at inflate time.
_CHECK_220_OPERATIONAL_TOKENS: tuple[str, ...] = (
    "score_improvement_mechanism_status=OPERATIONAL",
    "score_improvement_mechanism=OPERATIONAL",
    "operational_score_improvement=true",
    "operational_overlay=true",
    "operational_consumption=true",
    "l2_integration_landed",
    "l2_overlay_active",
    "runtime_overlay_consumed=true",
)

# Token forms accepted as the RESEARCH-ONLY tag (CLAUDE.md HNeRV parity L2).
_CHECK_220_RESEARCH_ONLY_TOKENS: tuple[str, ...] = (
    "research_only=true",
    "research-only=true",
)

# Token forms accepted as the PRE-BUILD substrate_engineering opt-out.
# The substrate has declared itself as scaffold work and the trainer's
# _full_main is still NotImplementedError-gated; no $1+ dispatch can fire.
_CHECK_220_SUBSTRATE_ENGINEERING_TOKENS: tuple[str, ...] = (
    "lane_class=substrate_engineering",
)
_CHECK_220_PRE_BUILD_GATE_TOKENS: tuple[str, ...] = (
    "_full_main raises NotImplementedError",
    "full_main_raises_notimplemented",
    "full_path_council_gated",
    "pre_build_substrate_engineering",
    "scaffold_only",
)

# Same-line waiver pattern for the rare deliberate deferred-integration case.
_CHECK_220_WAIVER_PATTERN: str = (
    r"#\s*SCAFFOLD_DEFERRED_INTEGRATION_OK\s*:\s*([^\s].{1,200}?)(?:\s*#|$)"
)
_CHECK_220_WAIVER_PLACEHOLDER_RE_REJECTS: tuple[str, ...] = (
    "<reason>",
)

# Substrate-id token-substring forms in lane id. A lane whose id matches one
# of these is treated as in-scope. Helps distinguish substrate lanes from
# pure-infrastructure / wire-in / META lanes that may carry byte-related
# notes for unrelated reasons.
_CHECK_220_IN_SCOPE_ID_SUBSTRINGS: tuple[str, ...] = (
    "substrate_",
    "_substrate_",
    "_polytope_",
    "_sidecar_",
    "_overlay_",
    # Known substrate id roots that don't carry the "substrate" word.
    "yucr_",
    "d1_segnet",
    "d2_",
    "d4_",
    "lane_a1_",
    "_hnerv_",
    "_nerv_",
    "_lora_",
    "wavelet_residual",
    "siren_residual",
    "coord_mlp_residual",
)


def _check_220_lane_is_in_scope(lane_id: str) -> bool:
    """Return True if the lane id matches a substrate-class pattern."""
    if not lane_id:
        return False
    needle = lane_id.lower()
    return any(token in needle for token in _CHECK_220_IN_SCOPE_ID_SUBSTRINGS)


def _check_220_extract_byte_addition_kb(text: str) -> float | None:
    """Parse the largest byte-addition signal from a lane's text fields.

    Returns the byte addition in KB if a numeric signal is found, else None
    (no signal = no byte addition claimed). The largest signal wins so a
    lane that mentions both "43 KB" and "1 KB" is gated at 43 KB.
    """
    import re

    if not text:
        return None
    biggest_kb: float | None = None
    for pattern in _CHECK_220_BYTE_ADDITION_TOKEN_PATTERNS:
        for match in re.finditer(pattern, text, flags=re.IGNORECASE):
            raw = match.group(0).lower()
            # Extract the numeric value + unit. Anchor after the LAST '='
            # or '~' or '+' so we don't pick up stray digit prefixes (e.g.
            # the '1' in 'd1_overhead_bytes=43296').
            anchor_pos = max(
                raw.rfind("="), raw.rfind("~"), raw.rfind("+")
            )
            search_text = raw[anchor_pos + 1 :] if anchor_pos >= 0 else raw
            num_match = re.search(r"(\d+(?:\.\d+|,\d+)*)", search_text)
            if not num_match:
                continue
            num_str = num_match.group(1).replace(",", "")
            try:
                num = float(num_str)
            except ValueError:
                continue
            # Determine KB scale from the matched text. Order matters:
            # the most specific tokens are checked first so a raw containing
            # both ``bytes`` and ``kb`` is treated as bytes.
            if "overhead_bytes" in raw or "bytes_added" in raw:
                kb = num / 1024.0
            elif "kb" in raw:
                kb = num
            elif "bytes" in raw or " b" in raw or raw.endswith("b"):
                kb = num / 1024.0
            elif "rate" in raw and num < 1.0:
                # "rate +0.029" → ~43 KB equivalent on 37.5MB contest video.
                # 0.029 * 37545489 / 25 ≈ 43,553 B ≈ 42.5 KB.
                kb = (num * 37_545_489.0 / 25.0) / 1024.0
            else:
                # Fallback: assume KB (the most common unit in our notes).
                kb = num
            if biggest_kb is None or kb > biggest_kb:
                biggest_kb = kb
    return biggest_kb


def _check_220_lane_has_operational_signal(text: str) -> bool:
    if not text:
        return False
    lower = text.lower()
    return any(tok.lower() in lower for tok in _CHECK_220_OPERATIONAL_TOKENS)


def _check_220_lane_is_research_only(text: str) -> bool:
    if not text:
        return False
    lower = text.lower()
    return any(tok in lower for tok in _CHECK_220_RESEARCH_ONLY_TOKENS)


def _check_220_lane_is_pre_build_substrate_engineering(text: str) -> bool:
    """Pre-build substrate-engineering opt-out requires BOTH the lane_class
    tag AND a pre-build signal (full path gated / NotImplementedError /
    scaffold-only)."""
    if not text:
        return False
    lower = text.lower()
    has_substrate_engineering = any(
        tok.lower() in lower for tok in _CHECK_220_SUBSTRATE_ENGINEERING_TOKENS
    )
    if not has_substrate_engineering:
        return False
    return any(tok.lower() in lower for tok in _CHECK_220_PRE_BUILD_GATE_TOKENS)


def _check_220_lane_has_waiver(text: str) -> tuple[bool, str]:
    """Return (waived, reason). Placeholder ``<reason>`` literal rejected."""
    import re

    if not text:
        return False, ""
    match = re.search(_CHECK_220_WAIVER_PATTERN, text)
    if not match:
        return False, ""
    reason = match.group(1).strip().rstrip("#").strip()
    if not reason:
        return False, ""
    if reason in _CHECK_220_WAIVER_PLACEHOLDER_RE_REJECTS:
        return False, ""
    return True, reason


def _check_220_collect_lane_text(lane: dict) -> str:
    """Concatenate every text field of a lane for token extraction."""
    parts: list[str] = []
    notes = lane.get("notes")
    if isinstance(notes, str):
        parts.append(notes)
    gates = lane.get("gates") or {}
    if isinstance(gates, dict):
        for gate_name, gate in gates.items():
            if isinstance(gate, dict):
                ev = gate.get("evidence")
                if isinstance(ev, str):
                    parts.append(ev)
    return "\n".join(parts)


# ----------------------------------------------------------------------------
# Catalog #236 — TAO-1 prose-negation guard self-protection
# ----------------------------------------------------------------------------
#
# Prevents regression of the TAO-1 R2 finding (Tao + MacKay CRITICAL,
# 2026-05-14): Catalog #233 gate 3 (auth_eval_100ep) accepted prose
# co-occurrences of "100ep" + "auth-eval" within an 80-char window even
# when the surrounding context was clearly NOT affirmative evidence
# (retired-config descriptions, design discussions, tradeoff comparisons).
#
# This META gate enforces the structural invariant that the prose-negation
# guard helper `_check_233_text_has_prose_negation_for_auth_eval` continues
# to exist AND that the negation token set retains its non-trivial size.
# Refuses any state of `src/tac/preflight.py` that:
#   1. Drops the helper function name `_check_233_text_has_prose_negation_for_auth_eval`
#   2. Drops the canonical token-set name `_CHECK_233_PROSE_NEGATION_TOKENS`
#   3. Reduces the negation token set below the canonical floor (10 tokens)
#
# Sister of:
#   - Catalog #136 (`check_custody_gate_accept_tokens_concrete_only`) —
#     same META class for the custody validator token set.
#   - Catalog #185 (`check_strict_flipped_catalog_entries_have_live_count_zero`)
#     — META-meta-meta gate that refuses CLAUDE.md drift.
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against".
# Memory: feedback_r2_critical_fix_wave_tao1_boyd1_landed_20260515.md.

_CHECK_236_REQUIRED_PREFLIGHT_TOKENS: tuple[str, ...] = (
    "_check_233_text_has_prose_negation_for_auth_eval",
    "_CHECK_233_PROSE_NEGATION_TOKENS",
    "_CHECK_233_AUTH_EVAL_100EP_STRUCTURED_PATTERNS",
    "_CHECK_233_AUTH_EVAL_100EP_LOOSE_PATTERNS",
)
_CHECK_236_NEGATION_TOKEN_FLOOR: int = 10


def check_catalog_233_gate_3_prose_negation_guard_present(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #236 — refuse drift of the TAO-1 prose-negation guard.

    Refuses any state of ``src/tac/preflight.py`` that drops:
      - helper function ``_check_233_text_has_prose_negation_for_auth_eval``
      - canonical token-set ``_CHECK_233_PROSE_NEGATION_TOKENS``
      - structured patterns ``_CHECK_233_AUTH_EVAL_100EP_STRUCTURED_PATTERNS``
      - loose patterns ``_CHECK_233_AUTH_EVAL_100EP_LOOSE_PATTERNS``
    OR reduces the negation token set below the canonical floor
    (currently 10).

    There is no waiver — these surfaces ARE the contract. Sister of
    Catalog #136 (custody validator concrete-tokens-only) and Catalog
    #233 (the parent 4-gate canonical).

    Memory: feedback_r2_critical_fix_wave_tao1_boyd1_landed_20260515.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    target = root / "src" / "tac" / "preflight.py"
    if not target.is_file():
        # Not a hard violation — the caller may be running outside the
        # canonical repo layout (e.g. from a vendored copy).
        if verbose:
            print(
                "  [catalog-236] OK (preflight.py not present at canonical path)"
            )
        return violations

    text = target.read_text(encoding="utf-8")

    for token in _CHECK_236_REQUIRED_PREFLIGHT_TOKENS:
        if token not in text:
            violations.append(
                f"src/tac/preflight.py is missing required surface "
                f"{token!r} per Catalog #236 TAO-1 self-protection. "
                f"The Catalog #233 4-gate canonical relies on the "
                f"prose-negation guard to refuse retired-config / "
                f"discussion-of-tradeoffs false positives at gate 3. "
                f"Per CLAUDE.md \"Bugs must be permanently fixed AND "
                f"self-protected against\": this surface is the "
                f"runtime contract. Restore the helper / token set "
                f"OR reach out to land a council-grade revision."
            )

    # Try to import the live token set and confirm size.
    try:
        from tac.preflight import _CHECK_233_PROSE_NEGATION_TOKENS as _live_tokens
        if (
            isinstance(_live_tokens, frozenset)
            and len(_live_tokens) < _CHECK_236_NEGATION_TOKEN_FLOOR
        ):
            violations.append(
                f"_CHECK_233_PROSE_NEGATION_TOKENS has only "
                f"{len(_live_tokens)} entries — below the canonical "
                f"floor of {_CHECK_236_NEGATION_TOKEN_FLOOR} per "
                f"Catalog #236 TAO-1 self-protection. Adding tokens "
                f"is fine; reducing the set below the floor opens "
                f"the prose-negation guard's coverage gap that "
                f"caused the original bug class. Restore the missing "
                f"tokens OR raise the floor via a council-reviewed PR."
            )
    except ImportError:
        # The check is defensive; if the import fails, the surface-token
        # check above will already have flagged the missing definition.
        pass

    if verbose:
        print(
            f"  [catalog-236] scanned preflight.py "
            f"required_tokens={len(_CHECK_236_REQUIRED_PREFLIGHT_TOKENS)} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            f"check_catalog_233_gate_3_prose_negation_guard_present "
            f"found {len(violations)} drift violation(s) in src/tac/"
            f"preflight.py per Catalog #236 TAO-1 self-protection:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #237 — BOYD-1 fallback semantic disambiguator self-protection
# ----------------------------------------------------------------------------
#
# Prevents regression of the BOYD-1 R2 finding (Boyd + Tao CRITICAL,
# 2026-05-14): D9 ``FALLBACK_PROVIDERS_PER_CLASS`` was semantically
# overloaded — Time-Traveler amendment's cheaper-alternative trigger
# conflicted with ``long_burn``'s capacity-overflow fallback. The fix
# splits the dict into two semantically-distinct dicts gated by an
# explicit ``FallbackReason`` enum and ``capacity_overflow`` opt-in.
#
# This META gate enforces:
#   1. ``_CHEAPER_ALTERNATIVE_FALLBACKS_PER_CLASS`` exists in cost_band_calibration.py
#   2. ``_CAPACITY_OVERFLOW_FALLBACKS_PER_CLASS`` exists
#   3. ``FallbackReason`` enum exists with both members
#   4. ``select_provider_for_class`` declares the ``capacity_overflow`` parameter
#   5. The two dicts are disjoint per dispatch class (no double-classification)
#
# Sister of:
#   - Catalog #131 (`check_no_bare_writes_to_shared_state`) — META gate
#     for state-write discipline.
#   - Catalog #136 (`check_custody_gate_accept_tokens_concrete_only`) —
#     META gate for token-set discipline.
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against".
# Memory: feedback_r2_critical_fix_wave_tao1_boyd1_landed_20260515.md.

_CHECK_237_REQUIRED_TOKENS: tuple[str, ...] = (
    "_CHEAPER_ALTERNATIVE_FALLBACKS_PER_CLASS",
    "_CAPACITY_OVERFLOW_FALLBACKS_PER_CLASS",
    "class FallbackReason",
    "CHEAPER_ALTERNATIVE",
    "CAPACITY_OVERFLOW",
    "capacity_overflow: bool",
    "_fallback_reason_for",
)


def check_d9_fallback_semantic_disambiguator_present(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #237 — refuse drift of the BOYD-1 fallback-semantic disambiguator.

    Refuses any state of ``src/tac/cost_band_calibration.py`` that drops
    the canonical surfaces required by BOYD-1's permanent fix:
      - ``_CHEAPER_ALTERNATIVE_FALLBACKS_PER_CLASS`` dict
      - ``_CAPACITY_OVERFLOW_FALLBACKS_PER_CLASS`` dict
      - ``FallbackReason`` enum with both members
      - ``capacity_overflow`` parameter on ``select_provider_for_class``
      - ``_fallback_reason_for`` classifier helper

    Also enforces the disjointness invariant: a (provider, gpu) tuple
    must NOT appear in BOTH dicts for the same dispatch class. Same
    semantic in two places defeats the purpose of the disambiguator.

    There is no waiver — these surfaces ARE the contract. Sister of
    Catalog #131 (state-write discipline) and Catalog #136 (custody
    validator concrete-tokens-only).

    Memory: feedback_r2_critical_fix_wave_tao1_boyd1_landed_20260515.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    target = root / "src" / "tac" / "cost_band_calibration.py"
    if not target.is_file():
        if verbose:
            print(
                "  [catalog-237] OK (cost_band_calibration.py not present)"
            )
        return violations

    text = target.read_text(encoding="utf-8")

    for token in _CHECK_237_REQUIRED_TOKENS:
        if token not in text:
            violations.append(
                f"src/tac/cost_band_calibration.py is missing required "
                f"surface {token!r} per Catalog #237 BOYD-1 self-"
                f"protection. The fallback-semantic disambiguator "
                f"prevents regression of the cheaper-alternative-vs-"
                f"capacity-overflow conflation bug class anchored in "
                f"the R2 ledger BOYD-1 finding. Per CLAUDE.md \"Bugs "
                f"must be permanently fixed AND self-protected "
                f"against\": this surface is the runtime contract."
            )

    # Try to import the live dicts and verify disjointness invariant.
    try:
        from tac.cost_band_calibration import (
            _CAPACITY_OVERFLOW_FALLBACKS_PER_CLASS as _live_overflow,
            _CHEAPER_ALTERNATIVE_FALLBACKS_PER_CLASS as _live_cheaper,
            DISPATCH_CLASSES as _live_classes,
        )
        for cls in _live_classes:
            cheaper = set(_live_cheaper.get(cls, []))
            overflow = set(_live_overflow.get(cls, []))
            shared = cheaper & overflow
            if shared:
                violations.append(
                    f"D9 dispatch class {cls!r} has fallback "
                    f"{shared!r} in BOTH "
                    f"_CHEAPER_ALTERNATIVE_FALLBACKS_PER_CLASS AND "
                    f"_CAPACITY_OVERFLOW_FALLBACKS_PER_CLASS — this "
                    f"defeats the BOYD-1 disambiguator. Per CLAUDE.md "
                    f"\"Beauty, simplicity\" non-negotiable: every "
                    f"fallback has exactly one semantic. Move the "
                    f"shared entry to ONE of the dicts."
                )
    except ImportError:
        pass

    if verbose:
        print(
            f"  [catalog-237] scanned cost_band_calibration.py "
            f"required_tokens={len(_CHECK_237_REQUIRED_TOKENS)} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            f"check_d9_fallback_semantic_disambiguator_present found "
            f"{len(violations)} drift violation(s) in cost_band_"
            f"calibration.py per Catalog #237 BOYD-1 self-protection:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #239 — BOYD-2 classify_dispatch open-boundary self-protection
# ----------------------------------------------------------------------------
#
# Anchor: R2 ledger BOYD-2 finding (Boyd LOW, 2026-05-14, voice: convex
# optimization-feasibility lens). ``classify_dispatch`` numeric inference
# branches used CLOSED ``>=`` boundaries against
# ``PER_CLASS_SOFT_WALLCLOCK_CEILING_HR["full"]`` and
# ``PER_CLASS_SOFT_COST_CEILING_USD["long_burn"]`` so a borderline 12.0h
# wallclock estimate routed to ``long_burn`` (Lightning A100 subscription,
# $50+ class) instead of ``full`` (Vast.ai 4090, $2-15 class) — a 5-10x
# cost-class jump for a 1-second wallclock difference at the boundary.
#
# Per Boyd's R2 verdict: convex feasibility regions whose boundary crossing
# changes the cost class non-trivially MUST use OPEN boundaries (strict
# ``>``). The smoke downgrade boundaries keep CLOSED ``<=`` because they
# route DOWNWARD to the cheaper class — there is no cost penalty for
# over-routing to the cheaper class at the boundary.
#
# This META gate scans ``classify_dispatch`` for raw ``>=`` boundary
# checks against either ``PER_CLASS_SOFT_WALLCLOCK_CEILING_HR`` OR
# ``PER_CLASS_SOFT_COST_CEILING_USD`` indexed by an UPGRADE class
# (``"full"``, ``"long_burn"``, ``"eval"``). Smoke ``<=`` checks are
# explicitly out of scope (they route downward, not upward).
#
# Acceptance: same-line waiver
# ``# CLASSIFY_DISPATCH_GE_BOUNDARY_OK:<rationale>`` for the rare future
# case where a CLOSED upgrade boundary is genuinely required (e.g. a
# new dispatch class whose cost is identical to its successor); the
# rationale must be a real string (placeholder ``<reason>`` literal is
# rejected so this docstring cannot self-waive).
#
# Sister of:
#   - Catalog #237 (`check_d9_fallback_semantic_disambiguator_present`)
#     — same lane (D9 dispatch routing) different bug class.
#   - Catalog #136 (`check_custody_gate_accept_tokens_concrete_only`)
#     — same META pattern: refuse a class of subtle data-discipline
#     regressions at the source level.
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
# against" + "Beauty, simplicity" non-negotiables.
# Memory: feedback_r2_low_fix_wave_boyd2_mackay2_landed_20260515.md.

# Known UPGRADE-class names (cost increases when these classes are
# selected; OPEN boundary ``>`` required). Sister of
# :data:`tac.cost_band_calibration.DISPATCH_CLASSES` ordering
# ``smoke <= eval < full < long_burn``.
_CHECK_239_UPGRADE_CLASSES: frozenset[str] = frozenset({
    "full",
    "long_burn",
    "eval",
})

# Indexable canonical-ceiling dict names (any subscript expression
# whose value resolves to a per-class ceiling). The check fires when
# both the dict name AND an upgrade-class subscript appear in the
# left-hand-side of a ``>=`` comparison.
_CHECK_239_CEILING_DICT_NAMES: frozenset[str] = frozenset({
    "PER_CLASS_SOFT_WALLCLOCK_CEILING_HR",
    "PER_CLASS_SOFT_COST_CEILING_USD",
})

_CHECK_239_WAIVER_RE = re.compile(
    r"#\s*CLASSIFY_DISPATCH_GE_BOUNDARY_OK:\s*([^\s<].*)"
)
_CHECK_239_WAIVER_PLACEHOLDER_REJECTS: frozenset[str] = frozenset({
    "<reason>", "<rationale>",
})

# Pattern: ``X >= DICT_NAME["upgrade_class"] ...`` OR
# ``X >= DICT_NAME['upgrade_class'] ...`` on a single source line.
# Matches the right-hand-side of a comparison against an UPGRADE-class
# ceiling. The smoke ``<=`` boundaries are NOT matched (this regex
# explicitly anchors on ``>=``).
_CHECK_239_GE_UPGRADE_BOUNDARY_RE = re.compile(
    r">=\s*(?P<dict>[A-Z_][A-Z0-9_]+)\s*\[\s*[\"'](?P<cls>[a-z_]+)[\"']\s*\]"
)


def check_classify_dispatch_no_raw_ge_boundaries(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #239 — refuse raw ``>=`` boundary checks against UPGRADE-class
    ceilings in ``classify_dispatch`` per BOYD-2 R2 self-protection.

    Refuses any line in ``src/tac/cost_band_calibration.py::classify_dispatch``
    that performs ``estimated_X >= PER_CLASS_SOFT_*_CEILING_*[upgrade_class]``
    where ``upgrade_class`` is one of ``"full"``, ``"long_burn"``, or
    ``"eval"`` (cost-increasing routing). The OPEN boundary ``>`` is the
    canonical fix per Boyd's convex-feasibility verdict — at exactly the
    ceiling the safer routing is the CHEAPER class.

    Smoke downgrade boundaries (``<=`` against
    ``PER_CLASS_SOFT_*_CEILING_*["smoke"]``) are explicitly OUT of scope.

    Acceptance: same-line waiver
    ``# CLASSIFY_DISPATCH_GE_BOUNDARY_OK:<rationale>`` with a real
    rationale (placeholder ``<reason>`` literal rejected).

    Memory: feedback_r2_low_fix_wave_boyd2_mackay2_landed_20260515.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    target = root / "src" / "tac" / "cost_band_calibration.py"
    if not target.is_file():
        if verbose:
            print(
                "  [catalog-239] OK (cost_band_calibration.py not present)"
            )
        return violations

    text = target.read_text(encoding="utf-8")
    lines = text.splitlines()

    in_classify_dispatch = False
    classify_def_indent = -1

    for lineno, line in enumerate(lines, start=1):
        stripped = line.lstrip()
        # Track entry into classify_dispatch function body.
        if stripped.startswith("def classify_dispatch(") or (
            stripped.startswith("def classify_dispatch")
            and stripped.split("classify_dispatch")[1].startswith("(")
        ):
            in_classify_dispatch = True
            classify_def_indent = len(line) - len(stripped)
            continue
        if in_classify_dispatch:
            # Exit on next top-level def/class at SAME OR SHALLOWER indent.
            if stripped.startswith(("def ", "class ", "async def ")):
                cur_indent = len(line) - len(stripped)
                if cur_indent <= classify_def_indent:
                    in_classify_dispatch = False

        if not in_classify_dispatch:
            continue

        # Skip docstring/comment-only lines.
        if stripped.startswith("#") or stripped.startswith('"""'):
            continue

        match = _CHECK_239_GE_UPGRADE_BOUNDARY_RE.search(line)
        if not match:
            continue

        dict_name = match.group("dict")
        cls = match.group("cls")
        if dict_name not in _CHECK_239_CEILING_DICT_NAMES:
            continue
        if cls not in _CHECK_239_UPGRADE_CLASSES:
            continue

        # Same-line waiver mechanism.
        waiver_match = _CHECK_239_WAIVER_RE.search(line)
        if waiver_match:
            rationale = waiver_match.group(1).strip()
            if rationale and rationale not in _CHECK_239_WAIVER_PLACEHOLDER_REJECTS:
                # Honor the waiver.
                continue
            # Fall through to violation if rationale is the placeholder.

        violations.append(
            f"src/tac/cost_band_calibration.py:{lineno} — "
            f"classify_dispatch uses CLOSED boundary ``>=`` against "
            f"{dict_name}[{cls!r}] — UPGRADE-class boundary must be "
            f"OPEN (``>``) per BOYD-2 R2 verdict (Boyd convex-"
            f"feasibility lens). At the boundary exactly, the safer "
            f"routing is the CHEAPER class. Use ``>`` instead of "
            f"``>=`` OR add same-line waiver "
            f"``# CLASSIFY_DISPATCH_GE_BOUNDARY_OK:<rationale>`` with "
            f"a real reason. Per Catalog #239 self-protection."
        )

    if verbose:
        print(
            f"  [catalog-239] scanned classify_dispatch in "
            f"cost_band_calibration.py violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            f"check_classify_dispatch_no_raw_ge_boundaries found "
            f"{len(violations)} raw ``>=`` upgrade-boundary violation(s) "
            f"per Catalog #239 BOYD-2 self-protection:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ---------------------------------------------------------------------------
# Catalog #243 - WIRE-AND-INTEGRATE-ALL: dispatch wrappers must invoke local
# pre-deploy harness (tools/local_pre_deploy_check.py) before paid GPU dispatch
# so the 30s py-compile + archive-grammar + auth-eval-reachability + canonical
# inflate-device + deterministic-zip checks fire BEFORE the meter starts.
#
# Bug class anchor: 2026-05-15 Z3 v2 smoke `fc-01KRNHEGC9ZE48Y68GGJHP7FXN`
# ($2 wasted) + Z4 smoke `fc-01KRNHE942JSV7VRGXGR1FJGHQ` ($2 wasted) both
# crashed on bug classes the harness would have caught locally in 30s.
# Operator directive: *"shouldn't you run python compile locally before deploy
# to find those bugs"*. Companion runtime fix landed `_run_local_pre_deploy_check`
# in `tools/operator_authorize.py` between Catalog #152 required-input-files
# validation and `_native_dispatch_preflight`.
#
# Sister of Catalog #152 (`check_operator_wrapper_validates_required_input_files_pre_dispatch`
# - same insertion point, sister bug class) + Catalog #167 (smoke-before-full
# pattern - same dispatch-wrapper canonical-routing META).
# ---------------------------------------------------------------------------

_CHECK_243_LOCAL_PRE_DEPLOY_TOKEN = "tools/local_pre_deploy_check.py"
_CHECK_243_OPERATOR_AUTHORIZE_TOKEN = "tools/operator_authorize.py"
_CHECK_243_CANONICAL_HELPER_TOKEN = "_run_local_pre_deploy_check"
_CHECK_243_DISPATCH_TOKENS = _CHECK_152_DISPATCH_TOKENS  # reuse Catalog #152 set
_CHECK_243_EXCLUDED_PATH_MARKERS = _CHECK_152_EXCLUDED_PATH_MARKERS
_CHECK_243_WAIVER_RE = re.compile(
    r"#\s*LOCAL_PRE_DEPLOY_CHECK_BYPASS_OK:\s*\S+"
)
_CHECK_243_PLACEHOLDER_TOKEN = "<reason>"


def check_dispatch_wrappers_invoke_local_pre_deploy_check_first(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #243 - WIRE-AND-INTEGRATE-ALL self-protection 2026-05-15.

    Refuses any dispatch wrapper (a `.py` or `.sh` file under `tools/`,
    `scripts/`, `experiments/`, or `src/tac/` that contains a
    `_CHECK_152_DISPATCH_TOKENS` token) that BYPASSES the canonical
    `tools/operator_authorize.py` (which now wires
    `_run_local_pre_deploy_check` per WIRE-AND-INTEGRATE-ALL) AND does
    NOT invoke `tools/local_pre_deploy_check.py` directly.

    Acceptance:
      (a) The wrapper invokes `tools/operator_authorize.py` (which threads
          the local pre-deploy harness automatically).
      (b) The wrapper invokes `tools/local_pre_deploy_check.py` directly
          (e.g. as a manual --strict gate before its dispatch).
      (c) Same-line `# LOCAL_PRE_DEPLOY_CHECK_BYPASS_OK:<rationale>` waiver
          on the dispatch-token line (placeholder `<reason>` literal rejected
          so this docstring's example cannot self-waive).

    Sister of Catalog #152 (required-input-files validation - same canonical
    insertion point, complementary bug class) + Catalog #167 (smoke-before-full
    pattern - same dispatch-wrapper canonical-routing META).

    Initial wire-in: warn-only per CLAUDE.md "Strict-flip atomicity rule" -
    legacy wrappers may bypass operator_authorize.py for historical reasons
    and should migrate incrementally. Strict-flip pending audit + backfill.
    """
    root = Path(repo_root or REPO_ROOT)
    violations: list[str] = []

    scan_dirs = ["tools", "scripts", "experiments", "src/tac"]
    self_exempt_paths = {
        # The canonical helper itself
        root / "tools" / "local_pre_deploy_check.py",
        # The wrapper that invokes the helper
        root / "tools" / "operator_authorize.py",
        # The catalog that defines the constants
        root / "src" / "tac" / "preflight.py",
    }

    for scan_dir in scan_dirs:
        scan_root = root / scan_dir
        if not scan_root.is_dir():
            continue
        for ext in ("*.py", "*.sh"):
            for path in scan_root.rglob(ext):
                # Skip self-exempt
                if path in self_exempt_paths:
                    continue
                # Skip excluded paths (vendored intake, results, oss_export)
                rel = str(path)
                if any(marker in rel for marker in _CHECK_243_EXCLUDED_PATH_MARKERS):
                    continue
                # Skip test files
                if "/tests/" in rel or path.name.startswith("test_") or path.name.endswith("_test.py"):
                    continue
                try:
                    text = path.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                # Quick filter: must contain at least one dispatch token
                if not any(tok in text for tok in _CHECK_243_DISPATCH_TOKENS):
                    continue
                # Acceptance (a): routes through operator_authorize.py
                if _CHECK_243_OPERATOR_AUTHORIZE_TOKEN in text:
                    continue
                # Acceptance (b): invokes local_pre_deploy_check.py directly
                if _CHECK_243_LOCAL_PRE_DEPLOY_TOKEN in text:
                    continue
                # Acceptance (c): same-line waiver on each dispatch-token line
                lines = text.splitlines()
                all_lines_waived = True
                violating_line_nos: list[int] = []
                for line_no, line in enumerate(lines, start=1):
                    if not any(tok in line for tok in _CHECK_243_DISPATCH_TOKENS):
                        continue
                    waiver_match = _CHECK_243_WAIVER_RE.search(line)
                    if waiver_match:
                        # Reject placeholder rationale to prevent self-waiver
                        marker_text = waiver_match.group(0)
                        if _CHECK_243_PLACEHOLDER_TOKEN in marker_text:
                            all_lines_waived = False
                            violating_line_nos.append(line_no)
                            continue
                        # Real rationale - this line is waived
                        continue
                    all_lines_waived = False
                    violating_line_nos.append(line_no)
                if all_lines_waived:
                    continue
                violations.append(
                    f"[Check 243] {rel}:{','.join(str(n) for n in violating_line_nos[:3])} "
                    f"contains dispatch token(s) but does NOT invoke "
                    f"{_CHECK_243_OPERATOR_AUTHORIZE_TOKEN} OR "
                    f"{_CHECK_243_LOCAL_PRE_DEPLOY_TOKEN} (per WIRE-AND-INTEGRATE-ALL "
                    f"2026-05-15: every dispatch wrapper must run the 30s local "
                    f"pre-deploy harness BEFORE GPU spending). Fix: route through "
                    f"tools/operator_authorize.py (canonical) OR call "
                    f"tools/local_pre_deploy_check.py --trainer <path> --strict "
                    f"directly. Same-line waiver: "
                    f"# LOCAL_PRE_DEPLOY_CHECK_BYPASS_OK:<rationale>"
                )

    if verbose:
        if violations:
            print(
                f"  [check_dispatch_wrappers_invoke_local_pre_deploy_check_first] "
                f"{len(violations)} violation(s) (warn-only initially per "
                "Strict-flip atomicity rule)"
            )
        else:
            print(
                "  [check_dispatch_wrappers_invoke_local_pre_deploy_check_first] OK"
            )
    if violations and strict:
        raise PreflightError(
            f"check_dispatch_wrappers_invoke_local_pre_deploy_check_first: "
            f"{len(violations)} dispatch wrapper(s) bypass the local pre-deploy "
            f"harness per Catalog #243 WIRE-AND-INTEGRATE-ALL self-protection:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #244 (META-CONSOLIDATION-CRITICAL-PLUS-POC 2026-05-15)
#
# Refuses ``scripts/remote_lane_substrate_*.sh`` files that lack the canonical
# Modal/CUDA env hygiene block (3 exports: DALI_DISABLE_NVML +
# CUBLAS_WORKSPACE_CONFIG + PYTORCH_CUDA_ALLOC_CONF). D1 incident anchor
# 2026-05-15: substrate_d1_segnet_margin_polytope_modal_t4_dispatch__smoke__50ep
# crashed at "nvml error (999): A nvml internal driver error occurred" inside
# DALI fn.experimental.inputs.video pipeline. Sister lanes D4/Z3/Z4/Z5 had the
# 3 exports; D1 was the missing wire-in (commit 611495f26 patched D1 directly).
# This is the 6th occurrence of the same NVML 999 bug class on Modal workers
# in the 24h window preceding the gate landing.
#
# Companion runtime fix: ``tac.substrate_registry.driver_generator.generate_driver_shell``
# now AUTO-EMITS the 3 exports immediately after ``set -euo pipefail``,
# sourced from canonical constants in ``tac.deploy.modal.runtime``. New
# substrate drivers regenerated through the META layer cannot ship without
# the block. This STRICT preflight gate refuses ANY hand-written substrate
# driver lacking the block, structurally extincting the bug class even at
# the 31 legacy substrate drivers that pre-date the META layer.
#
# Per CLAUDE.md "Strict-flip atomicity rule" + "Forbidden premature KILL":
# initial wire-in is WARN-ONLY because 31/36 legacy substrate scripts are
# missing the block; strict-flip planned alongside the legacy backfill wave
# (which will either patch each script with the 3 exports OR carry a
# ``# CANONICAL_NVML_BLOCK_OK:<reason>`` waiver).
#
# Sister of Catalog #163 (`check_remote_lane_script_uses_sentinel_when_sourcing_bootstrap`)
# and Catalog #224 (`check_modal_training_image_includes_hard_runtime_deps`).
# Together they extinct the Modal NVML 999 bug class at THREE surfaces:
#   - Catalog #163: source-time canonical bootstrap sentinel.
#   - Catalog #224: Modal image includes the canonical env block.
#   - Catalog #244: every remote lane driver script exports the 3 vars.
#
# Cross-ref:
#   feedback_meta_consolidation_critical_plus_poc_landed_20260515.md
#   feedback_d1_modal_dispatch_council_omnibus_pri_2_landed_20260515.md
#   src/tac/substrate_registry/driver_generator.py (auto-emit producer)
#   src/tac/deploy/modal/runtime.py (canonical constants)
#   commit 611495f26 (D1 patch — the empirical anchor)

_CHECK_244_REMOTE_LANE_SUBSTRATE_GLOB = "remote_lane_substrate_*.sh"
_CHECK_244_REQUIRED_TOKENS: tuple[str, ...] = (
    "DALI_DISABLE_NVML",
    "CUBLAS_WORKSPACE_CONFIG",
    "PYTORCH_CUDA_ALLOC_CONF",
)
_CHECK_244_WAIVER_TOKEN = "CANONICAL_NVML_BLOCK_OK:"
_CHECK_244_WAIVER_PLACEHOLDER_REJECT = ("<reason>", "<rationale>")


def check_remote_lane_scripts_carry_canonical_nvml_block(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #244. Refuses ``scripts/remote_lane_substrate_*.sh`` that lack
    the canonical Modal/CUDA env hygiene block (3 required exports:
    ``DALI_DISABLE_NVML`` + ``CUBLAS_WORKSPACE_CONFIG`` +
    ``PYTORCH_CUDA_ALLOC_CONF``). D1 dispatch 2026-05-15 (Modal T4 smoke)
    crashed at NVML 999 because the lane script did not export
    ``DALI_DISABLE_NVML`` before DALI imported NVML.

    The companion fix in ``tac.substrate_registry.driver_generator`` AUTO-EMITS
    the block for every contract-driven driver; this gate refuses any
    hand-written script that omits it.

    Acceptance per substrate driver:
      (a) every required token appears in the file body, OR
      (b) the file body carries a ``# CANONICAL_NVML_BLOCK_OK:<reason>``
          waiver (placeholder ``<reason>`` / ``<rationale>`` literals
          rejected so the docstring example cannot self-waive).

    STRICT-FLIPPED 2026-05-15 by CATALOG-244-BACKFILL-31-DRIVERS subagent
    after all 31 legacy substrate drivers were backfilled with the canonical
    3-export block in the same commit batch per CLAUDE.md "Strict-flip
    atomicity rule". Live count at strict-flip: 0 (all 36 substrate drivers
    carry the block).
    """
    root = (repo_root or Path.cwd()).resolve()
    scripts_dir = root / "scripts"
    violations: list[str] = []
    scanned = 0
    if not scripts_dir.is_dir():
        if verbose:
            print(
                "  [check_remote_lane_scripts_carry_canonical_nvml_block] OK "
                "(no scripts/ directory; 0 substrate driver(s) scanned)"
            )
        return violations

    for wrapper in sorted(
        scripts_dir.glob(_CHECK_244_REMOTE_LANE_SUBSTRATE_GLOB)
    ):
        rel = str(wrapper.relative_to(root))
        try:
            text = wrapper.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        scanned += 1

        # Same-file waiver acceptance (substantive rationale required).
        waived = False
        for line in text.splitlines():
            if _CHECK_244_WAIVER_TOKEN not in line:
                continue
            # Extract rationale after the marker
            after = line.split(_CHECK_244_WAIVER_TOKEN, 1)[1].strip()
            # Strip trailing comment whitespace / closing markers
            after = after.rstrip(" \t#").strip()
            if not after:
                continue  # bare waiver without rationale - rejected
            if after in _CHECK_244_WAIVER_PLACEHOLDER_REJECT:
                continue  # placeholder rejected
            waived = True
            break
        if waived:
            continue

        missing = [tok for tok in _CHECK_244_REQUIRED_TOKENS if tok not in text]
        if missing:
            violations.append(
                f"{rel}: missing canonical Modal/CUDA env hygiene exports "
                f"{missing}. D1 incident anchor 2026-05-15 (commit 611495f26): "
                "substrate dispatch crashed at 'nvml error (999)' inside DALI "
                "fn.experimental.inputs.video because the lane script did not "
                "export DALI_DISABLE_NVML=1 before DALI imported NVML. Add the "
                "3 exports (CUBLAS_WORKSPACE_CONFIG=:4096:8 + DALI_DISABLE_NVML=1 "
                "+ PYTORCH_CUDA_ALLOC_CONF=expandable_segments:True) immediately "
                "after `set -euo pipefail`, OR regenerate the driver via "
                "tac.substrate_registry.driver_generator.generate_driver_shell "
                "(which auto-emits the block per Catalog #244), OR add a "
                "`# CANONICAL_NVML_BLOCK_OK:<rationale>` waiver."
            )

    if verbose:
        if violations:
            print(
                f"  [check_remote_lane_scripts_carry_canonical_nvml_block] "
                f"{len(violations)} violation(s) across {scanned} "
                f"substrate driver(s) (WARN-ONLY initially per Strict-flip "
                "atomicity rule):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [check_remote_lane_scripts_carry_canonical_nvml_block] OK "
                f"({scanned} substrate driver(s) scanned; 0 violation(s))"
            )
    if violations and strict:
        raise PreflightError(
            "check_remote_lane_scripts_carry_canonical_nvml_block found "
            f"{len(violations)} substrate driver script(s) missing the canonical "
            "Modal/CUDA env hygiene block (DALI_DISABLE_NVML + "
            "CUBLAS_WORKSPACE_CONFIG + PYTORCH_CUDA_ALLOC_CONF). Per CLAUDE.md "
            "'Bugs must be permanently fixed AND self-protected against' "
            "non-negotiable, this protects against the D1 NVML 999 dispatch "
            "failure class (commit 611495f26, 2026-05-15):\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #245 (MODAL-CALL-ID-LEDGER-CANONICAL-HELPER 2026-05-15)
# Modal .spawn() invocations must register the call_id in the canonical ledger.
# ─────────────────────────────────────────────────────────────────────────

# Tokens that satisfy the registration requirement when present in the
# local window around a `fn.spawn(` / `function.spawn(` call.
_CHECK_245_REGISTRATION_TOKENS: tuple[str, ...] = (
    "register_dispatched_call_id",
    "from tac.deploy.modal.call_id_ledger import",
    "tac.deploy.modal.call_id_ledger",
    "MODAL_CALL_ID_LEDGER_PATH",
)

# Same-line waiver marker for explicit operator-approved opt-out.
_CHECK_245_WAIVER_MARKER = "CALL_ID_LEDGER_REGISTRATION_OK"

# Files that legitimately implement the canonical helper itself OR are
# canonical CALLERS that already wrap the spawn surface (the wrapper is the
# canonical registration point and counts as the registration).
_CHECK_245_CANONICAL_FILES: tuple[str, ...] = (
    "src/tac/deploy/modal/call_id_ledger.py",
    "src/tac/deploy/modal/auth_eval.py",  # provides function_call_id helper
    "src/tac/preflight.py",  # this gate's own pattern literals
    "tools/backfill_modal_call_id_ledger.py",  # historical backfill helper
)

# Path markers that indicate a Modal-spawn-relevant file (prefilter).
_CHECK_245_MODAL_FILE_MARKERS: tuple[str, ...] = (
    "modal",
    ".spawn(",
)

# Regex for `<expr>.spawn(...)` invocations on Modal Function objects. We
# scope to `fn.spawn(` / `function.spawn(` / explicit Modal Function aliases
# to avoid false positives on multiprocessing.Process.spawn / similar.
_CHECK_245_SPAWN_RE = re.compile(
    r"\b(?:fn|function|run_lane_training_\w+|"
    r"run_lane_training|modal_fn|modal_func)\.spawn\s*\(",
)


def check_modal_dispatches_register_call_id(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #245 — Modal .spawn() invocations must register the call_id.

    Refuses any source-code site under ``experiments/``, ``tools/``, ``scripts/``,
    ``src/tac/`` that invokes ``fn.spawn(...)`` (or a recognized alias) on a
    Modal ``Function`` object WITHOUT one of:

    1. A reference to ``register_dispatched_call_id`` (or sister tokens) in
       the local window around the spawn invocation, OR
    2. A same-line ``# CALL_ID_LEDGER_REGISTRATION_OK:<rationale>`` waiver
       (placeholder ``<rationale>`` literal rejected).

    Per CLAUDE.md "Modal `.spawn()` HARVEST OR LOSE" non-negotiable: every
    dispatch via ``modal_train_lane.py`` MUST be followed by a scheduled
    harvest within 24h. Pre-Catalog #245, the per-dispatch sentinel files
    (``modal_call_id.txt`` / ``modal_metadata.json``) were the only canonical
    discovery surface — fragile O(N_dispatches) glob walks against an audit-
    grade ledger. Catalog #245 makes the canonical JSONL ledger
    (``.omx/state/modal_call_id_ledger.jsonl``) the single queryable source-
    of-truth, and this gate refuses any new spawn surface that bypasses it.

    Strict-flipped at landing per CLAUDE.md "Strict-flip atomicity rule": the
    existing producers land the canonical wire-in in the same commit batch as
    this gate; live count at landing is 0 across the production scan.

    Memory: feedback_modal_call_id_ledger_canonical_landed_20260515.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "experiments",
        root / "tools",
        root / "scripts",
        root / "src" / "tac",
    ]
    excluded_files = {root / p for p in _CHECK_245_CANONICAL_FILES}

    violations: list[str] = []
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if py in excluded_files:
                continue
            # Skip tests
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            # Skip vendored intake / hosted exports / build artifacts
            if (
                "experiments/results/" in s
                or "_intake_" in s
                or "/.omx/oss_export/" in s
                or "/build/lib/" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — file must reference a Modal-spawn marker.
            if not any(m in text for m in _CHECK_245_MODAL_FILE_MARKERS):
                continue
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                m = _CHECK_245_SPAWN_RE.search(line)
                if not m:
                    continue
                # Same-line waiver?
                if _CHECK_245_WAIVER_MARKER in line:
                    # Reject placeholder rationale per CLAUDE.md
                    # "Forbidden empirical-claim-without-evidence-tag" pattern.
                    waiver_idx = line.find(_CHECK_245_WAIVER_MARKER)
                    after = line[
                        waiver_idx + len(_CHECK_245_WAIVER_MARKER) :
                    ].lstrip(":").strip()
                    if after and after != "<rationale>" and after != "<reason>":
                        continue
                # ±100-line window scan for canonical token. Window is
                # generous because dispatch wrappers commonly write
                # per-dispatch sentinel files / metadata.json between the
                # spawn site and the ledger registration call.
                window_start = max(0, lineno - 100)
                window_end = min(len(lines), lineno + 100)
                window_text = "\n".join(lines[window_start:window_end])
                if any(t in window_text for t in _CHECK_245_REGISTRATION_TOKENS):
                    continue
                rel = py.relative_to(root) if py.is_absolute() else py
                violations.append(
                    f"{rel}:{lineno + 1} — Modal .spawn() invocation "
                    f"{line.strip()[:120]!r} does NOT register the call_id "
                    "in the canonical ledger. Add "
                    "`from tac.deploy.modal.call_id_ledger import "
                    "register_dispatched_call_id; "
                    "register_dispatched_call_id(call_id=..., lane_id=..., "
                    "label=..., ...)` near the spawn site, OR carry a "
                    "same-line `# CALL_ID_LEDGER_REGISTRATION_OK:<rationale>` "
                    "waiver."
                )

    if verbose:
        print(
            f"check_modal_dispatches_register_call_id: "
            f"{len(violations)} violations"
        )

    if violations and strict:
        raise PreflightError(
            "check_modal_dispatches_register_call_id found "
            f"{len(violations)} Modal .spawn() invocation(s) that do not "
            "register the call_id in the canonical ledger. Per CLAUDE.md "
            "'Modal `.spawn()` HARVEST OR LOSE' non-negotiable + Catalog "
            "#245 (canonical Modal call_id ledger):\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #330 (MODAL-HARVESTER-CALL-ID-OUTCOME-LEDGER 2026-05-18)
# Modal FunctionCall.get harvesters must record terminal call_id outcomes.
# ─────────────────────────────────────────────────────────────────────────

_CHECK_330_OUTCOME_TOKENS: tuple[str, ...] = (
    "append_terminal_call_id_ledger_event",
    "_append_call_id_ledger_terminal_event",
    "_append_terminal_call_id_ledger_safely",
    "update_call_id_outcome",
)
_CHECK_330_WAIVER_MARKER = "HARVESTER_LEDGER_WRITE_OK"
_CHECK_330_SCAN_DIRS: tuple[str, ...] = ("experiments", "tools", "scripts", "src/tac")
_CHECK_330_CANONICAL_FILES: frozenset[str] = frozenset(
    {
        "src/tac/deploy/modal/harvest_outcomes.py",
        "src/tac/preflight.py",
    }
)


def _check_330_has_nonplaceholder_waiver(text: str) -> bool:
    for line in text.splitlines():
        if _CHECK_330_WAIVER_MARKER not in line:
            continue
        after = line.split(_CHECK_330_WAIVER_MARKER, 1)[1].lstrip(":").strip()
        if after and after not in {"<rationale>", "<reason>"}:
            return True
    return False


def _check_330_line_is_comment_or_literal(line: str) -> bool:
    stripped = line.lstrip()
    return "``" in line or stripped.startswith(("#", '"', "'", "f\"", "f'", "r\"", "r'"))


def check_modal_harvesters_record_call_id_outcome(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #330 — Modal harvesters must terminalize call_id outcomes.

    Refuses any production source file under ``experiments/``, ``tools/``,
    ``scripts/``, or ``src/tac/`` that polls a Modal call via
    ``FunctionCall.from_id(...).get(...)`` without using the canonical terminal
    outcome helper or a visible ``HARVESTER_LEDGER_WRITE_OK:<rationale>``
    waiver.

    This is the harvest-side sister of Catalog #245. Registering a call_id at
    dispatch time is insufficient if a later harvester can observe terminal
    provider state and leave the canonical ledger in ``dispatched`` forever.
    """

    root = Path(repo_root or REPO_ROOT)
    violations: list[str] = []
    for rel_dir in _CHECK_330_SCAN_DIRS:
        scan_dir = root / rel_dir
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            rel = str(py.relative_to(root))
            if rel in _CHECK_330_CANONICAL_FILES:
                continue
            if "/tests/" in rel or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/" in rel
                or "_intake_" in rel
                or "/.omx/oss_export/" in rel
                or "/build/lib/" in rel
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                if "FunctionCall.from_id" not in line:
                    continue
                if _check_330_line_is_comment_or_literal(line):
                    continue
                # Harvester terminalization often happens after artifact writes,
                # terminal-claim evidence, and summary construction. Keep this
                # bounded to the surrounding harvest block rather than the
                # entire file.
                window = "\n".join(lines[max(0, lineno - 20) : min(len(lines), lineno + 180)])
                if ".get(" not in window:
                    continue
                if any(token in window for token in _CHECK_330_OUTCOME_TOKENS):
                    continue
                if _check_330_has_nonplaceholder_waiver(window):
                    continue
                violations.append(
                    f"{rel}:{lineno + 1} — Modal FunctionCall.from_id(...).get(...) "
                    "harvester does not record terminal outcomes in the canonical "
                    "call_id ledger. Use `tac.deploy.modal.harvest_outcomes."
                    "append_terminal_call_id_ledger_event(...)`, call "
                    "`update_call_id_outcome(...)`, or add "
                    "`# HARVESTER_LEDGER_WRITE_OK:<rationale>`."
                )

    if verbose:
        print(
            f"check_modal_harvesters_record_call_id_outcome: "
            f"{len(violations)} violations"
        )

    if violations and strict:
        raise PreflightError(
            "check_modal_harvesters_record_call_id_outcome found "
            f"{len(violations)} Modal harvester(s) that can observe terminal "
            "FunctionCall state without mirroring it to the canonical call_id "
            "ledger. Per Catalog #330 + Catalog #245, every terminal Modal "
            "call_id lifecycle must be append-only recoverable:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #246 - check_paired_dispatch_uses_anchor_skip_flag
# ----------------------------------------------------------------------------

_CHECK_246_TOOL_BASENAME = "dispatch_modal_paired_auth_eval.py"
_CHECK_246_REQUIRED_FLAG = "--skip-axis-if-promotable-anchor-exists"
_CHECK_246_WAIVER_TOKEN = "# PAIRED_DISPATCH_FORCE_REFIRE_OK:"
_CHECK_246_WAIVER_PLACEHOLDER_REJECT = "# PAIRED_DISPATCH_FORCE_REFIRE_OK:<rationale>"
_CHECK_246_SCAN_DIRS = ("tools", "scripts", "experiments", "src/tac")
_CHECK_246_EXEMPT_PATH_MARKERS = (
    "experiments/results/",
    "_intake_",
    ".omx/oss_export/",
    "vendored",
    "build/lib/",
    "reports/raw/",
)
_CHECK_246_SELF_EXEMPT_FILES = frozenset(
    {
        "tools/dispatch_modal_paired_auth_eval.py",
        "src/tac/preflight.py",
        "src/tac/tests/test_check_246_paired_dispatch_anchor_skip_flag.py",
    }
)


def _check_246_path_is_exempt(rel_path: str) -> bool:
    """True iff rel_path is in the Catalog #246 exemption set."""
    if rel_path in _CHECK_246_SELF_EXEMPT_FILES:
        return True
    if any(marker in rel_path for marker in _CHECK_246_EXEMPT_PATH_MARKERS):
        return True
    if "/tests/" in rel_path or rel_path.endswith("_test.py"):
        return True
    if "/test_" in rel_path or ("/" not in rel_path and rel_path.startswith("test_")):
        return True
    base = rel_path.rsplit("/", 1)[-1]
    return bool(base.startswith("test_"))


def _check_246_line_invokes_canonical_tool(line: str) -> bool:
    """True iff the line references the canonical paired-dispatch CLI."""
    return _CHECK_246_TOOL_BASENAME in line


def check_paired_dispatch_uses_anchor_skip_flag(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #246. Refuse paired-dispatch callers missing anchor-skip flag.

    Same-window waiver:
    ``# PAIRED_DISPATCH_FORCE_REFIRE_OK:<rationale>``. The placeholder
    literal is rejected so examples cannot self-waive.
    """
    root = (repo_root or Path.cwd()).resolve()
    violations: list[str] = []
    invocation_markers = (
        "subprocess",
        "Popen(",
        "run(",
        "check_call",
        "check_output",
        "os.system",
        "$(",
        "python ",
        "python3 ",
        ".venv/bin/python",
        "uv run",
    )

    for scan_dir in _CHECK_246_SCAN_DIRS:
        scan_root = root / scan_dir
        if not scan_root.is_dir():
            continue
        for ext in ("*.py", "*.sh"):
            for source in scan_root.rglob(ext):
                rel = source.relative_to(root).as_posix()
                if _check_246_path_is_exempt(rel):
                    continue
                try:
                    text = source.read_text(encoding="utf-8")
                except (OSError, UnicodeDecodeError):
                    continue
                if _CHECK_246_TOOL_BASENAME not in text:
                    continue

                lines = text.splitlines()
                for idx, raw_line in enumerate(lines):
                    if not _check_246_line_invokes_canonical_tool(raw_line):
                        continue

                    has_invocation_context = any(m in raw_line for m in invocation_markers)
                    if rel.endswith(".sh") and (
                        raw_line.lstrip().startswith(_CHECK_246_TOOL_BASENAME)
                        or "/" + _CHECK_246_TOOL_BASENAME in raw_line
                    ):
                        has_invocation_context = True
                    if not has_invocation_context:
                        neighborhood = "\n".join(
                            lines[max(0, idx - 5) : min(len(lines), idx + 6)]
                        )
                        has_invocation_context = any(m in neighborhood for m in invocation_markers)
                    if not has_invocation_context:
                        continue

                    window = "\n".join(lines[idx : min(len(lines), idx + 30)])
                    if _CHECK_246_REQUIRED_FLAG in window:
                        continue
                    if _CHECK_246_WAIVER_TOKEN in window:
                        if _CHECK_246_WAIVER_PLACEHOLDER_REJECT in window:
                            violations.append(
                                f"{rel}:{idx + 1}: paired-dispatch caller carries "
                                "PLACEHOLDER waiver token "
                                f"'{_CHECK_246_WAIVER_PLACEHOLDER_REJECT}'"
                            )
                        continue
                    violations.append(
                        f"{rel}:{idx + 1}: invokes {_CHECK_246_TOOL_BASENAME} "
                        f"without '{_CHECK_246_REQUIRED_FLAG}' flag and without "
                        f"'{_CHECK_246_WAIVER_TOKEN}<rationale>' waiver "
                        "(Catalog #246)"
                    )

    if verbose:
        print(
            f"check_paired_dispatch_uses_anchor_skip_flag: "
            f"{len(violations)} violations"
        )

    if violations and strict:
        raise PreflightError(
            "check_paired_dispatch_uses_anchor_skip_flag (Catalog #246) "
            f"found {len(violations)} caller(s) of {_CHECK_246_TOOL_BASENAME} "
            f"without {_CHECK_246_REQUIRED_FLAG}:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


def check_substrate_l1_scaffold_no_byte_addition_without_operational_score_improvement_mechanism(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #220 — refuse L1+ substrate scaffolds adding bytes without
    operational score-improvement mechanism.

    Anchor: D1 R3 dispatch 2026-05-14 produced score ~0.222 vs predicted band
    [0.181, 0.188] because the L1 SCAFFOLD landed a 43 KB sidecar that the
    inflate runtime did NOT consume (overlay was no-op-by-default). Per
    CLAUDE.md "HNeRV / leaderboard-implementation parity discipline" + the
    NEW "Substrate scaffolds MUST be COMPLETE or RESEARCH-ONLY" non-negotiable
    section: a substrate that adds bytes (>1 KB) MUST also wire the inflate
    runtime to OPERATIONALLY consume them for score improvement, OR tag itself
    ``research_only=true``, OR explicitly declare pre-build
    ``lane_class=substrate_engineering`` with the trainer's ``_full_main``
    raising NotImplementedError (so no $1+ dispatch can fire).

    The gate scans ``.omx/state/lane_registry.json`` for in-scope substrate
    lanes at L1+ (``level >= 1``); for each lane it extracts the byte-addition
    signal from notes + gate evidence strings; if the signal exceeds 1 KB,
    one of the following acceptance tokens MUST appear in the lane text:

    1. ``score_improvement_mechanism_status=OPERATIONAL`` (or
       ``l2_integration_landed`` / ``l2_overlay_active`` /
       ``operational_overlay=true`` / ``runtime_overlay_consumed=true`` / etc.)
    2. ``research_only=true``
    3. ``lane_class=substrate_engineering`` AND a pre-build signal
       (``_full_main raises NotImplementedError`` / ``full_path_council_gated``
       / ``scaffold_only`` / etc.)
    4. Same-line waiver ``# SCAFFOLD_DEFERRED_INTEGRATION_OK:<reason>`` with
       a real rationale (placeholder ``<reason>`` literal is rejected).

    Sister of Catalog #90 (`check_lane_registry_consistent`),
    Catalog #105 / #139 (no-op detector + packet compiler structural
    consumption proof), and Catalog #124 (representation-lane archive grammar
    at design time).

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-lane diagnostic.

    Returns:
        List of violation messages (one per refused lane).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    registry_path = root / ".omx" / "state" / "lane_registry.json"
    if not registry_path.is_file():
        if verbose:
            print("  [catalog-220] OK (no lane_registry.json)")
        return violations

    try:
        registry = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if verbose:
            print(f"  [catalog-220] WARN registry read error: {exc}")
        return violations

    lanes = registry.get("lanes")
    if not isinstance(lanes, list):
        if verbose:
            print("  [catalog-220] OK (registry has no lanes list)")
        return violations

    lanes_scanned = 0
    lanes_with_byte_addition = 0

    for lane in lanes:
        if not isinstance(lane, dict):
            continue
        lane_id = str(lane.get("id", ""))
        if not _check_220_lane_is_in_scope(lane_id):
            continue
        level = int(lane.get("level", 0) or 0)
        if level < 1:
            continue
        lanes_scanned += 1
        text = _check_220_collect_lane_text(lane)
        kb = _check_220_extract_byte_addition_kb(text)
        if kb is None or kb < _CHECK_220_BYTE_ADDITION_THRESHOLD_KB:
            continue
        lanes_with_byte_addition += 1

        # Cascade through accept paths in order.
        if _check_220_lane_has_operational_signal(text):
            if verbose:
                print(
                    f"  [catalog-220] OK lane={lane_id} kb={kb:.1f} "
                    "(operational mechanism declared)"
                )
            continue
        if _check_220_lane_is_research_only(text):
            if verbose:
                print(
                    f"  [catalog-220] OK lane={lane_id} kb={kb:.1f} "
                    "(research_only=true)"
                )
            continue
        if _check_220_lane_is_pre_build_substrate_engineering(text):
            if verbose:
                print(
                    f"  [catalog-220] OK lane={lane_id} kb={kb:.1f} "
                    "(pre-build substrate_engineering scaffold)"
                )
            continue
        waived, reason = _check_220_lane_has_waiver(text)
        if waived:
            if verbose:
                print(
                    f"  [catalog-220] WAIVED lane={lane_id} kb={kb:.1f} "
                    f"reason={reason!r}"
                )
            continue

        violations.append(
            f"lane {lane_id!r} (L{level}) declares byte addition "
            f"~{kb:.1f} KB without an operational score-improvement mechanism. "
            "Required: declare ``score_improvement_mechanism_status=OPERATIONAL`` "
            "(or sister token: l2_integration_landed / l2_overlay_active / "
            "runtime_overlay_consumed=true / operational_overlay=true) in the "
            "lane's notes or gate evidence, OR tag the lane research_only=true, "
            "OR declare lane_class=substrate_engineering + pre-build "
            "scaffold signal (_full_main raises NotImplementedError / "
            "scaffold_only / full_path_council_gated), OR carry a same-line "
            "`# SCAFFOLD_DEFERRED_INTEGRATION_OK:<rationale>` waiver. Per "
            "CLAUDE.md \"Substrate scaffolds MUST be COMPLETE or RESEARCH-"
            "ONLY\" non-negotiable + Catalog #220."
        )

    if verbose:
        print(
            f"  [catalog-220] scanned={lanes_scanned} "
            f"with_byte_addition={lanes_with_byte_addition} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            f"check_substrate_l1_scaffold_no_byte_addition_without_operational"
            f"_score_improvement_mechanism found {len(violations)} substrate "
            f"lane(s) with >{_CHECK_220_BYTE_ADDITION_THRESHOLD_KB:.0f} KB byte "
            f"addition but no operational score-improvement mechanism declared "
            f"(Catalog #220 — D1 R3 self-protect):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #240 — check_substrate_contest_cuda_chain_complete_or_research_only_tagged
#
# CANONICALIZE-SUBSTRATE-CONTEST-CHAIN self-protection (2026-05-15).
# Bug class: an operator-authorize recipe at
# ``.omx/operator_authorize_recipes/substrate_<id>_modal_<gpu>_dispatch.yaml``
# implicitly claims that its substrate is a contest-CUDA dispatch (no
# ``smoke_only: true`` / ``research_only: true`` / ``dispatch_enabled: false``
# flag), but the matching ``experiments/train_substrate_<id>.py`` trainer's
# ``_full_main`` raises ``NotImplementedError`` (Phase 2 council-gated). Modal
# dispatch reaches the trainer and crashes pre-auth-eval, burning $2-15 per
# failed smoke. Empirical anchors:
#
# - Z3 v2 smoke ``fc-01KRNHWD6AEMWGDJXBEY8GM0P3`` (2026-05-15): smoke green BUT
#   manifest shows ``"layout": "append_only_z3hp1_diagnostic"`` because the
#   recipe is ``smoke_only: true / research_only: true`` so the v2
#   latent-replacement code path NEVER ACTIVATES even though env→CLI wiring
#   is intact. The substrate looks "built" but contributes nothing to
#   contest-CUDA scoring on dispatch.
# - Z4 + Z5 (pre-fix 2026-05-15): contest recipes existed without research_only
#   tag, but trainers' ``_full_main`` raised NotImplementedError. Modal dispatch
#   would have crashed pre-auth-eval at higher cost than smoke.
#
# Per CLAUDE.md "HNeRV / leaderboard-implementation parity discipline" lesson 2
# (export-first design) + "Substrate scaffolds MUST be COMPLETE or RESEARCH-
# ONLY" non-negotiable + Catalog #220 (sister gate at the L2-promotion-of-
# substrate-with-byte-addition surface): every substrate recipe MUST be EITHER
# (a) a fully-complete contest-CUDA dispatch (trainer ``_full_main``
# implemented + auth_eval wired + recipe has cost_band + recipe declares
# contest target_modes), OR (b) explicitly tagged research-only (``smoke_only:
# true`` OR ``research_only: true`` OR ``dispatch_enabled: false`` at recipe
# top-level).
#
# The gate scans every ``substrate_*.yaml`` recipe under
# ``.omx/operator_authorize_recipes/`` and checks that EITHER:
#   1. The matching trainer's ``_full_main`` is implemented (no
#      ``raise NotImplementedError`` in the function body); OR
#   2. The recipe carries one of the research-only flags listed above; OR
#   3. The recipe has a same-line waiver
#      ``# CONTEST_CUDA_CHAIN_PARTIAL_OK:<rationale>`` on the trainer's recipe
#      file (placeholder ``<reason>`` literal rejected).
#
# Sister gates: Catalog #220 (L1+ substrate-scaffold-with-bytes-but-no-
# operational-mechanism), Catalog #226 (trainer auth_eval canonical helper),
# Catalog #167 (smoke-before-full pattern), Catalog #176 (operator-authorize
# canonical), Catalog #205 / #218 (canonical-path-enforcement). Together they
# extinct the "built-but-not-firing" bug class structurally.
#
# Strict-from-byte-one per CLAUDE.md "Strict-flip atomicity rule" — Z4 + Z5
# fix lands in the same commit batch driving live count to 0 (14
# DISPATCHABLE_CONTEST_CUDA + 17 RESEARCH_ONLY_TRANSPARENT, 0 violations).
#
# Lane: lane_canonicalize_substrate_contest_chain_20260515.
# Memory: feedback_canonicalize_substrate_contest_cuda_chain_landed_20260515.md.
# Audit: .omx/research/substrate_contest_cuda_chain_audit_20260515.md.
# Canonical pattern: .omx/research/canonical_substrate_contest_cuda_chain_pattern_20260515.md.
# Audit JSON (machine-readable): .omx/state/substrate_contest_cuda_chain_audit.json.
# ----------------------------------------------------------------------------

# Recipe-level top-level YAML flags accepted as "transparently non-dispatchable".
_CHECK_240_RESEARCH_ONLY_RECIPE_FLAG_PATTERNS: tuple[str, ...] = (
    r"^\s*smoke_only:\s*true\b",
    r"^\s*research_only:\s*true\b",
    r"^\s*dispatch_enabled:\s*false\b",
)

# Same-line waiver pattern for the rare deliberate operator-approved partial
# state. The waiver lives in the recipe YAML itself as a YAML comment.
_CHECK_240_WAIVER_PATTERN: str = (
    r"#\s*CONTEST_CUDA_CHAIN_PARTIAL_OK\s*:\s*([^\s].{1,200}?)(?:\s*#|$)"
)
_CHECK_240_WAIVER_PLACEHOLDER_REJECTS: tuple[str, ...] = (
    "<reason>",
    "<rationale>",
)

# Recipe filename suffix patterns — each provider/GPU combo. We strip these
# to derive the substrate id from the recipe basename.
_CHECK_240_RECIPE_SUFFIX_PATTERNS: tuple[str, ...] = (
    r"_modal_(t4|a100|l40s|l4|h100|a10g)_(?:smoke_)?dispatch$",
    r"_local_apple_silicon_dispatch$",
    r"_vastai_(?:t4|a100|4090|l40s)_dispatch$",
    r"_lightning_(?:t4|a100)_dispatch$",
)


def _check_240_recipe_id_from_path(recipe_path: Path) -> str:
    """Extract substrate id from a recipe path.

    e.g., ``substrate_z4_cooperative_receiver_loss_modal_t4_dispatch.yaml`` →
          ``z4_cooperative_receiver_loss``.
    """
    basename = recipe_path.stem  # drop .yaml
    if basename.startswith("substrate_"):
        basename = basename[len("substrate_") :]
    for pat in _CHECK_240_RECIPE_SUFFIX_PATTERNS:
        basename = re.sub(pat, "", basename)
    return basename


def _check_240_recipe_is_research_only(text: str) -> bool:
    """Return True if recipe top-level YAML declares research-only."""
    for pat in _CHECK_240_RESEARCH_ONLY_RECIPE_FLAG_PATTERNS:
        if re.search(pat, text, re.MULTILINE):
            return True
    return False


def _check_240_recipe_has_waiver(text: str) -> tuple[bool, str]:
    """Return (waived, rationale)."""
    # Walk text line-by-line so $ in the regex anchors to end-of-line under
    # MULTILINE; a single re.search(text, re.MULTILINE) is brittle when the
    # waiver appears mid-document.
    for line in text.splitlines():
        match = re.search(_CHECK_240_WAIVER_PATTERN, line)
        if match is None:
            continue
        rationale = match.group(1).strip()
        if rationale in _CHECK_240_WAIVER_PLACEHOLDER_REJECTS:
            continue
        return True, rationale
    return False, ""


def _check_240_trainer_full_main_raises_notimplementederror(
    trainer_path: Path,
) -> tuple[bool, str]:
    """Return (raises_not_impl, message).

    Inspects the trainer's ``_full_main`` body (first ~3000 chars after the
    def line). If ``_full_main`` does not exist OR does not raise
    NotImplementedError, returns (False, msg).
    """
    if not trainer_path.is_file():
        return False, f"trainer not found: {trainer_path.name}"
    try:
        text = trainer_path.read_text(encoding="utf-8", errors="ignore")
    except OSError:
        return False, f"trainer unreadable: {trainer_path.name}"

    full_main_def = re.search(r"^def\s+_full_main\s*\([^)]*\)[^:]*:", text, re.M)
    if full_main_def is None:
        return False, "no _full_main"
    body_start = full_main_def.end()
    body = text[body_start : body_start + 3000]
    if re.search(r"\braise\s+NotImplementedError\b", body):
        return True, "_full_main raises NotImplementedError (Phase 2 council-gated)"
    return False, "_full_main implemented"


def check_substrate_contest_cuda_chain_complete_or_research_only_tagged(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #240 — refuse substrate recipes that implicitly claim contest-
    CUDA dispatch capability while the trainer's ``_full_main`` is a
    ``NotImplementedError`` stub.

    Per CLAUDE.md "Substrate scaffolds MUST be COMPLETE or RESEARCH-ONLY"
    non-negotiable + "HNeRV / leaderboard-implementation parity discipline"
    lesson 2 + Catalog #220 (sister at L1+ substrate-byte-addition surface):
    every substrate recipe MUST be EITHER (a) a complete contest-CUDA
    dispatch (trainer ``_full_main`` implemented), OR (b) tagged research-only
    via top-level YAML flag (``smoke_only: true`` / ``research_only: true`` /
    ``dispatch_enabled: false``), OR (c) carry a same-line
    ``# CONTEST_CUDA_CHAIN_PARTIAL_OK:<rationale>`` waiver.

    Anchors:
    - Z3 v2 smoke ``fc-01KRNHWD6AEMWGDJXBEY8GM0P3`` (2026-05-15): substrate
      looks "built" but recipe is ``smoke_only: true`` so v2 path never
      activates on Modal.
    - Z4 + Z5 (pre-fix 2026-05-15): contest recipes existed without
      research-only tag, but trainers' ``_full_main`` raised
      NotImplementedError → Modal would have crashed pre-auth-eval at
      $2-15 cost per smoke.

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-recipe diagnostic.

    Returns:
        List of violation messages (one per refused recipe).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    recipes_dir = root / ".omx" / "operator_authorize_recipes"
    trainers_dir = root / "experiments"
    if not recipes_dir.is_dir():
        if verbose:
            print(f"  [catalog-240] OK (no recipes dir at {recipes_dir})")
        return violations

    recipes_scanned = 0
    recipes_research_only = 0
    recipes_complete = 0
    recipes_waived = 0
    recipes_orphan = 0

    for recipe_path in sorted(recipes_dir.glob("substrate_*.yaml")):
        recipes_scanned += 1
        substrate_id = _check_240_recipe_id_from_path(recipe_path)
        try:
            text = recipe_path.read_text(encoding="utf-8", errors="ignore")
        except OSError as exc:
            if verbose:
                print(f"  [catalog-240] WARN unreadable {recipe_path.name}: {exc}")
            continue

        # Acceptance path 1: recipe is research-only at top level.
        if _check_240_recipe_is_research_only(text):
            recipes_research_only += 1
            if verbose:
                print(
                    f"  [catalog-240] OK {recipe_path.name} "
                    "(recipe research-only/smoke-only/dispatch-disabled)"
                )
            continue

        # Acceptance path 3: same-line waiver (rare).
        waived, rationale = _check_240_recipe_has_waiver(text)
        if waived:
            recipes_waived += 1
            if verbose:
                print(
                    f"  [catalog-240] WAIVED {recipe_path.name} "
                    f"reason={rationale!r}"
                )
            continue

        # Now check trainer state. If trainer is missing, the recipe is an
        # orphan; orphan recipes are out of scope for THIS gate (they cannot
        # fire any dispatch because operator_authorize.py refuses missing
        # trainers earlier). They are surfaced separately by the audit.
        trainer_path = trainers_dir / f"train_substrate_{substrate_id}.py"
        if not trainer_path.is_file():
            recipes_orphan += 1
            if verbose:
                print(
                    f"  [catalog-240] OK {recipe_path.name} "
                    f"(orphan recipe — no train_substrate_{substrate_id}.py)"
                )
            continue

        # Acceptance path 2: trainer's _full_main is implemented.
        raises_not_impl, msg = (
            _check_240_trainer_full_main_raises_notimplementederror(trainer_path)
        )
        if not raises_not_impl:
            recipes_complete += 1
            if verbose:
                print(
                    f"  [catalog-240] OK {recipe_path.name} "
                    f"(trainer {msg})"
                )
            continue

        # VIOLATION: contest recipe + NotImplementedError trainer.
        violations.append(
            f"recipe {recipe_path.name!r} implicitly claims contest-CUDA "
            f"dispatch (no smoke_only: true / research_only: true / "
            f"dispatch_enabled: false flag), but the matching trainer "
            f"experiments/train_substrate_{substrate_id}.py has "
            f"`_full_main` raising NotImplementedError (Phase 2 council-"
            f"gated). Modal dispatch would crash pre-auth-eval, burning "
            f"$2-15 per smoke. Required: add `research_only: true` AND "
            f"`dispatch_blockers: [phase_2_council_approval_required_to_lift_"
            f"full_main_NotImplementedError]` to the recipe top level, OR "
            f"implement `_full_main` in the trainer, OR carry a same-line "
            f"`# CONTEST_CUDA_CHAIN_PARTIAL_OK:<rationale>` waiver. Per "
            f"CLAUDE.md \"Substrate scaffolds MUST be COMPLETE or RESEARCH-"
            f"ONLY\" non-negotiable + Catalog #240 (sister of Catalog #220)."
        )

    if verbose:
        print(
            f"  [catalog-240] scanned={recipes_scanned} "
            f"complete={recipes_complete} research_only={recipes_research_only} "
            f"waived={recipes_waived} orphan={recipes_orphan} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            f"check_substrate_contest_cuda_chain_complete_or_research_only_"
            f"tagged found {len(violations)} substrate recipe(s) implicitly "
            f"claiming contest-CUDA dispatch with NotImplementedError trainer "
            f"`_full_main` (Catalog #240 — Z3 v2 / Z4 / Z5 self-protect):\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #226 sister — train_renderer auth_eval_renderer CLI drift guard
#
# The substrate-trainer gate below (#226) refuses hand-rolled
# experiments/contest_auth_eval.py subprocess invocations. The canonical
# renderer trainer has a different auth path:
# src/tac/experiments/train_renderer.py builds a real submission archive and
# then calls experiments/auth_eval_renderer.py. Council R3 already caught this
# wiring drifting once: it passed invented flags, omitted --archive-size-bytes,
# and could silently skip the eval. This sister gate turns the focused
# regression tests into a preflight surface without refactoring any trainers.
# ----------------------------------------------------------------------------

_CHECK_TRAIN_RENDERER_AUTH_EVAL_REQUIRED_FLAGS = frozenset(
    {
        "--checkpoint",
        "--upstream-dir",
        "--device",
        "--archive-size-bytes",
        "--output-dir",
        "--poses",
    }
)


def _check_train_renderer_auth_eval_argparse_flags(
    auth_eval_path: Path,
) -> set[str]:
    """Return literal ``--flags`` declared by auth_eval_renderer's argparse."""
    try:
        text = auth_eval_path.read_text(encoding="utf-8")
        tree = ast.parse(text, filename=str(auth_eval_path))
    except (OSError, UnicodeDecodeError, SyntaxError):
        return set()
    flags: set[str] = set()
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        try:
            func_src = ast.unparse(node.func)
        except Exception:  # pragma: no cover - defensive
            continue
        if not func_src.endswith(".add_argument"):
            continue
        for arg in node.args:
            if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
                if arg.value.startswith("--"):
                    flags.add(arg.value)
    return flags


def _check_train_renderer_auth_eval_block(train_renderer_text: str) -> str | None:
    """Extract the train_renderer auth-eval-on-best block."""
    start = train_renderer_text.find("# Auth eval on best")
    if start < 0:
        return None
    end = train_renderer_text.find("return best_scorer", start)
    if end < 0:
        return None
    return train_renderer_text[start:end]


def _check_train_renderer_auth_eval_literal_flags(block: str) -> set[str]:
    """Return exact string-literal flags in the auth-eval block.

    This intentionally matches only standalone string literals like
    ``"--checkpoint"``. Help/error text such as
    ``f"--auth-eval-masks and --auth-eval-poses"`` is not a subprocess flag
    and should not count.
    """
    flags: set[str] = set()
    for match in re.finditer(
        r"(?P<prefix>^|[^A-Za-z0-9_])(?P<quote>[\"'])"
        r"(?P<flag>--[a-z0-9][a-z0-9_-]*)(?P=quote)",
        block,
    ):
        flags.add(match.group("flag"))
    return flags


def _check_train_renderer_auth_eval_masks_gate_fails_loud(block: str) -> bool:
    """Return True when missing masks/poses fail before auth eval."""
    marker = "if not args.auth_eval_masks or not args.auth_eval_poses:"
    idx = block.find(marker)
    if idx < 0:
        return False
    return "raise RuntimeError" in block[idx: idx + 1200]


def check_train_renderer_auth_eval_uses_current_auth_eval_renderer_cli(
    *,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Refuse train_renderer auth-eval-on-best wiring that drifts from
    ``experiments/auth_eval_renderer.py``.

    This is a narrow sister gate to Catalog #226. It protects the canonical
    renderer trainer from the Council R3 failure mode: invented
    auth_eval_renderer flags, missing ``--archive-size-bytes`` rate custody,
    renderer-only archive sizing, brittle auth_eval_renderer path resolution,
    or silent skip/fallback when masks/poses are absent.
    """
    root = Path(repo_root or REPO_ROOT)
    train_path = root / "src" / "tac" / "experiments" / "train_renderer.py"
    auth_eval_path = root / "experiments" / "auth_eval_renderer.py"
    violations: list[str] = []

    auth_flags = _check_train_renderer_auth_eval_argparse_flags(auth_eval_path)
    if not auth_eval_path.is_file():
        violations.append("experiments/auth_eval_renderer.py: missing")
    elif not auth_flags:
        violations.append(
            "experiments/auth_eval_renderer.py: no argparse --flags found; "
            "cannot verify train_renderer auth-eval CLI contract"
        )

    try:
        train_text = train_path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        violations.append("src/tac/experiments/train_renderer.py: missing/unreadable")
        train_text = ""

    block = _check_train_renderer_auth_eval_block(train_text)
    if block is None:
        violations.append(
            "src/tac/experiments/train_renderer.py: missing auth-eval-on-best "
            "block bounded by '# Auth eval on best' and 'return best_scorer'"
        )
    else:
        flags = _check_train_renderer_auth_eval_literal_flags(block)
        invented = sorted(flags - auth_flags)
        if invented and auth_flags:
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "passes flag(s) not declared by experiments/auth_eval_renderer.py "
                f"argparse: {invented}. This is the Council R3 dead-flag bug "
                "class; grep auth_eval_renderer.py parser.add_argument before "
                "adding flags."
            )

        missing_required = sorted(
            _CHECK_TRAIN_RENDERER_AUTH_EVAL_REQUIRED_FLAGS - flags
        )
        if missing_required:
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "is missing required auth_eval_renderer flag literal(s): "
                f"{missing_required}. Required flags preserve checkpoint, "
                "device, pose-conditioning, output custody, and archive-byte "
                "rate custody."
            )

        if "build_submission_archive" not in block:
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "does not call build_submission_archive before auth eval; "
                "renderer-only byte sizing is systematically optimistic."
            )

        if '"--archive-size-bytes", str(archive_bytes)' not in block:
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "does not pass --archive-size-bytes from the built archive "
                "via str(archive_bytes); rate custody would drift to "
                "renderer-only bytes."
            )

        if not _check_train_renderer_auth_eval_masks_gate_fails_loud(block):
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "must fail loud when --auth-eval-masks or --auth-eval-poses "
                "is missing. Silent skip/fallback recreates the Council R3 "
                "no-auth-eval failure mode."
            )

        soft_skip_re = (
            r"if not args\.auth_eval_masks[^\n]*:\s*\n"
            r"\s*print[^\n]*(WARN|Skipping)[\s\S]{0,400}\n\s*else:"
        )
        if re.search(soft_skip_re, block):
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "contains a masks-missing WARN/else skip pattern; use "
                "fail-loud masks+poses validation or --no-auth-eval-on-best."
            )

        if re.search(r"parents\[\d+\]\s*/\s*['\"]\.\.['\"]", block):
            violations.append(
                "src/tac/experiments/train_renderer.py: auth-eval-on-best "
                "uses brittle parents[N] / '..' path traversal; use the "
                "established _repo constant for auth_eval_renderer.py."
            )

    if verbose:
        if violations:
            print(
                "  [train-renderer-auth-eval-cli] "
                f"{len(violations)} violation(s)"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [train-renderer-auth-eval-cli] OK "
                "(train_renderer auth-eval block matches auth_eval_renderer CLI)"
            )

    if violations and strict:
        raise PreflightError(
            "check_train_renderer_auth_eval_uses_current_auth_eval_renderer_cli "
            f"found {len(violations)} renderer auth-eval wiring violation(s) "
            "(Catalog #226 sister gate):\n  "
            + "\n  ".join(violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #226 — check_trainer_auth_eval_uses_canonical_helper
#
# Trainer hand-rolled auth_eval subprocess self-protection (2026-05-14).
# Bug class: substrate trainers under ``experiments/train_substrate_*.py`` that
# call ``experiments/contest_auth_eval.py`` via a hand-built ``subprocess.run``
# invocation (typically ``cmd = [sys.executable, str(CONTEST_AUTH_EVAL_SCRIPT),
# ...]; subprocess.run(cmd, ...)``) WITHOUT routing through the canonical
# helper ``tac.substrates._shared.smoke_auth_eval_gate.gate_auth_eval_call``.
#
# Anchor: C6 5ep Modal T4 smoke ``fc-01KRKG566Z2F48CVCGF8JFA0S1`` (2026-05-14)
# returned ``auth_eval rc=2`` with a ``usage`` error in stderr because the C6
# trainer hand-wrote ``--archive-zip`` / ``--output-json`` flags that do NOT
# exist on ``experiments/contest_auth_eval.py`` (the canonical CLI surface
# uses ``--archive`` / ``--json-out``). The RECOVERY-2 fix landed at commit
# ``3e4571c3a`` and routed C6 through the canonical helper. This META gate
# refuses ANY future trainer from re-introducing the hand-rolled pattern at
# a different substrate file — even when the current flag set happens to be
# CORRECT, the hand-rolled pattern is the bug class because future CLI
# refactors of ``contest_auth_eval.py`` will silently break the hand-rolled
# callers but cannot break the canonical helper (which is the single source
# of truth for the contract).
#
# Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
# + "META-meta finding from a8bc7e79 sweep" (bug classes have 6-7× spread
# across the repo). Current audit: 18 substrate trainers hand-roll the
# pattern. Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip
# atomicity rule" — strict-flip planned once 0 violations are confirmed
# after a separate refactoring wave routes each trainer through the
# canonical helper. The wave is operator-routed because it touches 18
# files owned by multiple sister substrate subagents and must NOT collide
# with their in-flight work.
#
# Sister of Catalog #164 (`check_substrate_score_aware_loss_calls_preprocess_
# input_before_scorer`, the canonical scorer-preprocess routing) + Catalog
# #205 (`check_inflate_py_uses_canonical_select_inflate_device`, the
# canonical inflate device-fork) + Catalog #218 (`check_substrate_reconstruct_
# methods_support_mini_batch`, the canonical mini-batch reconstruct). Same
# pattern of "force callers into the canonical path" applied to a different
# bug class (auth_eval subprocess flag drift instead of scorer-preprocess
# bypass / inflate device-fork / full-batch reconstruct OOM).
#
# Lane: lane_catalog_221_auth_eval_gate_plus_d4_timeout_investigation_20260514.
# Memory: feedback_catalog_221_auth_eval_gate_and_d4_timeout_investigation_landed_20260514.md.
# ----------------------------------------------------------------------------

# Token identifying the canonical helper import path. Any trainer that
# imports the helper AND calls it from the same function that does the
# subprocess-style work is accepted.
_CHECK_226_CANONICAL_HELPER_TOKENS = (
    "smoke_auth_eval_gate",
    "gate_auth_eval_call",
)

# Subprocess attribute names that trigger inspection when invoked on the
# ``subprocess`` module.
_CHECK_226_SUBPROCESS_ATTRS = frozenset(
    {"run", "Popen", "call", "check_call", "check_output"}
)

# Tokens that mark a callsite as targeting contest_auth_eval.py.
_CHECK_226_CONTEST_AUTH_EVAL_TOKENS = (
    "CONTEST_AUTH_EVAL_SCRIPT",
    "contest_auth_eval.py",
    "contest_auth_eval",
)

# Same-line waiver. Placeholder ``<reason>`` literal is rejected so the
# docstring above cannot self-waive.
_CHECK_226_WAIVER_RE = re.compile(
    r"#\s*AUTH_EVAL_DIRECT_SUBPROCESS_OK:\s*([^\s<].*)"
)


def _check_226_iter_trainer_files(repo_root: Path) -> list[Path]:
    """Return ``experiments/train_substrate_*.py`` files."""
    files: list[Path] = []
    exp_dir = repo_root / "experiments"
    if exp_dir.exists():
        for f in exp_dir.glob("train_substrate_*.py"):
            if f.is_file():
                files.append(f)
    return sorted(files)


def _check_226_function_uses_canonical_helper(
    func_node: ast.AST, src: str
) -> bool:
    """Return True if the function body or its enclosing module imports +
    calls the canonical helper.

    The check accepts either:
    * a direct call to ``gate_auth_eval_call(...)`` (or its alias) inside
      the function body, OR
    * the function delegates to a sister wrapper that itself routes through
      the canonical helper (detected by the helper token appearing as a
      ``Call`` target inside the function body).
    """
    if not isinstance(func_node, (ast.FunctionDef, ast.AsyncFunctionDef)):
        return False
    for sub in ast.walk(func_node):
        if isinstance(sub, ast.Call):
            func = sub.func
            # Direct name call
            if isinstance(func, ast.Name) and any(
                tok in func.id for tok in _CHECK_226_CANONICAL_HELPER_TOKENS
            ):
                return True
            # Attribute call like module.gate_auth_eval_call(...)
            if isinstance(func, ast.Attribute) and any(
                tok in func.attr for tok in _CHECK_226_CANONICAL_HELPER_TOKENS
            ):
                return True
    return False


def _check_226_collect_subprocess_targets(
    func_node: ast.AST,
) -> list[tuple[int, str]]:
    """Walk a function body, collect subprocess.X(...) call sites that
    reference contest_auth_eval directly OR via a previously-assigned cmd
    variable that itself references contest_auth_eval.

    Returns a list of ``(lineno, cmd_var_name_or_inline)`` tuples.
    """
    if not isinstance(func_node, (ast.FunctionDef, ast.AsyncFunctionDef)):
        return []
    # First pass: collect Assign targets whose value mentions contest_auth_eval.
    cmd_var_names: set[str] = set()
    for sub in ast.walk(func_node):
        if isinstance(sub, ast.Assign) and len(sub.targets) == 1:
            tgt = sub.targets[0]
            if isinstance(tgt, ast.Name):
                try:
                    val_src = ast.unparse(sub.value)
                except Exception:  # pragma: no cover - defensive
                    continue
                if any(
                    tok in val_src for tok in _CHECK_226_CONTEST_AUTH_EVAL_TOKENS
                ):
                    cmd_var_names.add(tgt.id)

    # Second pass: find subprocess.X() Calls referencing those variables OR
    # containing contest_auth_eval inline.
    results: list[tuple[int, str]] = []
    for sub in ast.walk(func_node):
        if not isinstance(sub, ast.Call):
            continue
        func = sub.func
        is_subprocess = (
            isinstance(func, ast.Attribute)
            and func.attr in _CHECK_226_SUBPROCESS_ATTRS
            and isinstance(func.value, ast.Name)
            and func.value.id == "subprocess"
        )
        if not is_subprocess:
            continue
        try:
            args_src = " ".join(ast.unparse(a) for a in sub.args)
        except Exception:  # pragma: no cover - defensive
            continue
        inline_match = any(
            tok in args_src for tok in _CHECK_226_CONTEST_AUTH_EVAL_TOKENS
        )
        var_match = ""
        for a in sub.args:
            if isinstance(a, ast.Name) and a.id in cmd_var_names:
                var_match = a.id
                break
        if inline_match or var_match:
            tag = var_match or "inline-contest_auth_eval"
            results.append((sub.lineno, tag))
    return results


def _check_226_collect_violations_in_file(
    path: Path, repo_root: Path
) -> list[str]:
    """AST-walk one trainer file, emit one violation per offending
    subprocess invocation."""
    rel = path.relative_to(repo_root).as_posix()
    try:
        src = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []
    try:
        tree = ast.parse(src, filename=str(path))
    except SyntaxError:
        return []
    src_lines = src.splitlines()
    violations: list[str] = []
    for node in ast.walk(tree):
        if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            continue
        targets = _check_226_collect_subprocess_targets(node)
        if not targets:
            continue
        # Acceptance: the enclosing function uses the canonical helper.
        if _check_226_function_uses_canonical_helper(node, src):
            continue
        for lineno, cmd_tag in targets:
            line_text = (
                src_lines[lineno - 1] if 0 < lineno <= len(src_lines) else ""
            )
            if _CHECK_226_WAIVER_RE.search(line_text):
                continue
            violations.append(
                f"{rel}:{lineno} trainer function {node.name!r} invokes "
                f"``subprocess.run(...)`` on {cmd_tag} targeting "
                f"``experiments/contest_auth_eval.py`` WITHOUT routing "
                f"through the canonical helper "
                f"``tac.substrates._shared.smoke_auth_eval_gate."
                f"gate_auth_eval_call``. Per Catalog #226 (C6 auth_eval "
                f"rc=2 self-protect): hand-rolled subprocess invocations "
                f"silently drift on CLI refactors (canonical flags are "
                f"``--archive`` / ``--json-out``; C6 hand-wrote "
                f"``--archive-zip`` / ``--output-json`` which silently "
                f"skipped CUDA auth eval at 5ep Modal smoke). Route "
                f"through the canonical helper (canonical pattern: "
                f"``experiments/train_substrate_c6_e4_mdl_ibps.py`` "
                f"@ commit 3e4571c3a). Same-line waiver: "
                f"``# AUTH_EVAL_DIRECT_SUBPROCESS_OK:<reason>``. "
                f"See CLAUDE.md Catalog #226."
            )
    return violations


def check_trainer_auth_eval_uses_canonical_helper(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #226 — refuse substrate trainers that hand-roll auth_eval
    subprocess invocations instead of routing through the canonical helper.

    Per the 2026-05-14 C6 auth_eval rc=2 anchor (``fc-01KRKG566Z2F48CVCGF8JFA0S1``),
    a trainer that hand-writes ``subprocess.run([..., 'contest_auth_eval.py',
    '--archive-zip', ..., '--output-json', ...])`` silently skips CUDA auth
    eval because the contest_auth_eval CLI surface uses ``--archive`` /
    ``--json-out``. The canonical helper
    ``tac.substrates._shared.smoke_auth_eval_gate.gate_auth_eval_call`` is the
    single source of truth for the CLI contract; future CLI refactors of
    ``contest_auth_eval.py`` propagate through the helper automatically.

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
    because 18 substrate trainers currently hand-roll the pattern; strict-
    flip planned once a separate operator-routed refactoring wave drives
    the live count to 0.

    Sister of Catalog #164 (canonical scorer-preprocess) + Catalog #205
    (canonical inflate device-fork) + Catalog #218 (canonical mini-batch
    reconstruct). Memory:
    feedback_catalog_221_auth_eval_gate_and_d4_timeout_investigation_landed_20260514.md.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    files = _check_226_iter_trainer_files(root)
    violations: list[str] = []
    for path in files:
        violations.extend(_check_226_collect_violations_in_file(path, root))

    if verbose:
        if violations:
            print(
                f"  [catalog-226] WARN: {len(violations)} trainer "
                f"function(s) hand-roll auth_eval subprocess "
                f"across {len(files)} substrate trainer file(s) (strict={strict})"
            )
        else:
            print(
                f"  [catalog-226] OK ({len(files)} trainer file(s) scanned)"
            )

    if violations and strict:
        msg = (
            f"check_trainer_auth_eval_uses_canonical_helper: "
            f"{len(violations)} trainer function(s) hand-roll auth_eval "
            f"subprocess (Catalog #226 — C6 auth_eval rc=2 self-protect); "
            f"first 3:\n  "
            + "\n  ".join(violations[:3])
        )
        raise PreflightError(msg)
    return violations


# ----------------------------------------------------------------------------
# Catalog #249 — check_no_misleading_device_named_output_directories
#
# Phantom-score directory class permanent fix (2026-05-15). Refuses any caller
# under `src/tac/`, `tools/`, `experiments/`, `scripts/` that constructs an
# auth-eval output JSON path or work directory whose filename device-token
# (`_cuda` / `_cpu` / `_mps`) is HARDCODED instead of derived from the actual
# auth-eval device.
#
# Empirical anchor: Z3 v2 FULL Modal A100 dispatch 2026-05-15T11:41:15Z. The
# trainer hardcoded `result_json_path = out_dir / "contest_auth_eval_cuda.json"`
# regardless of `auth_eval_device`. The Modal dispatcher injected
# `AUTH_EVAL_DEVICE=cpu` + `MODAL_AUTH_EVAL_ADVISORY_ONLY=1`. Result:
# `contest_auth_eval_cuda.json` containing `device=cpu` + `score_axis=
# diagnostic_cpu`, plus `contest_auth_eval_cuda_work/` directory containing
# CPU-evaluated artifacts. Parent agent quoted "0.19869 [contest-CUDA T4]"
# from the FILENAME despite the metadata saying CPU. Paired re-eval revealed
# true CUDA = 0.2317 — the originally-claimed CUDA score did not exist.
#
# This is the "phantom-score directory" anti-pattern: an artifact whose
# FILENAME makes a claim its CONTENT cannot honor. Per CLAUDE.md
# "Apples-to-apples evidence discipline" + "Forbidden component-aliasing for
# baselines" non-negotiables, the filename MUST match the device that
# produced the contents OR be device-agnostic.
#
# Bug-class spread (META-meta 6-7x per CLAUDE.md): 23 substrate trainers +
# 4 deployment files + canonical helper all hardcoded `_cuda.json`. The
# canonical helper `gate_auth_eval_call` derives `work_dir` from
# `output_json.stem`, so a single misleading filename poisoned the work-dir
# name too. The companion runtime fix in
# `src/tac/substrates/_shared/smoke_auth_eval_gate.py` adds
# `_redirect_output_json_to_match_device` which auto-rewrites mismatched
# filenames at runtime + emits a loud `[phantom-score-fix]` warning so the
# upstream caller can be migrated.
#
# This STRICT preflight gate is the structural sister: it refuses any source
# code line that constructs a file path with a hardcoded device token under
# a context that suggests the path is an auth-eval output. The detection is
# AST-aware (string-literal targets only); same-line waiver
# `# DEVICE_NAMED_DIR_OK:<rationale>` accepts the rare deliberate case
# (e.g., a CUDA-only benchmark fixture). Placeholder `<rationale>` literal
# rejected so the docstring example cannot self-waive.
#
# Sister of Catalog #127 (custody validator routing) + Catalog #221
# (auth_eval result fail-closed) + Catalog #226 (canonical
# `gate_auth_eval_call` helper enforcement). Together they extinct the
# phantom-score class at FOUR surfaces: per-call-site custody routing
# (#127) + result-artifact fail-closed (#221) + caller-must-route-through-
# canonical-helper (#226) + filename-must-match-device (#249).
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
# because 23 substrate trainers + 4 deploy files currently hardcode
# `contest_auth_eval_cuda.json`. The runtime auto-redirect at the canonical
# helper extincts the actual lie surface immediately; the strict-flip
# planned once a sister wave drives caller-side hardcoded filenames to 0.
#
# Memory: feedback_misleading_directory_name_phantom_score_class_permanent_
# fix_landed_20260515.md.
# ----------------------------------------------------------------------------

# Tokens scanned for misleading device-suffix in auth-eval output filenames.
_CHECK_249_DEVICE_TOKENS: tuple[str, ...] = ("cuda", "cpu", "mps")

# Path-context tokens that indicate the string literal is being used as an
# auth-eval output path (high false-positive risk without context).
_CHECK_249_AUTH_EVAL_CONTEXT_TOKENS: tuple[str, ...] = (
    "contest_auth_eval",
    "auth_eval_result",
    "auth_eval_json",
    "auth_eval_path",
)

# Same-line waiver pattern; rationale required (no placeholder).
_CHECK_249_WAIVER_RE = re.compile(
    r"#\s*DEVICE_NAMED_DIR_OK\s*:\s*(.+?)\s*$"
)
_CHECK_249_WAIVER_PLACEHOLDER_LITERALS: frozenset[str] = frozenset({
    "<rationale>", "<reason>", "<...>", "TODO", "todo",
})

# Self-exempt files (canonical implementation + tests + this gate's own
# definition).
_CHECK_249_SELF_EXEMPT_PATH_SUFFIXES: tuple[str, ...] = (
    "src/tac/preflight.py",  # this file (gate definition)
    "src/tac/substrates/_shared/smoke_auth_eval_gate.py",  # canonical helper (auto-redirect logic)
)

# Path markers excluded from scope.
_CHECK_249_EXEMPT_PATH_MARKERS: tuple[str, ...] = (
    "experiments/results/",  # DERIVED_OUTPUT (Catalog #113)
    "_intake_",  # vendored PR clones (Catalog #109)
    ".omx/oss_export/",  # OSS mirror
    "vendored",
    "/tests/",
    "/test_",
    "build/lib/",
    "reports/raw/",
)


def _check_249_path_in_scope(path: Path, repo_root: Path) -> bool:
    """Return True if ``path`` is in scope for Catalog #249."""

    try:
        rel = str(path.relative_to(repo_root)).replace("\\", "/")
    except ValueError:
        return False
    # Must be a .py file under tools/, experiments/, scripts/, or src/tac/.
    if not rel.endswith(".py"):
        return False
    in_scope_root = (
        rel.startswith("src/tac/")
        or rel.startswith("tools/")
        or rel.startswith("experiments/")
        or rel.startswith("scripts/")
    )
    if not in_scope_root:
        return False
    # Self-exempt canonical helper + this gate's defining file.
    for suffix in _CHECK_249_SELF_EXEMPT_PATH_SUFFIXES:
        if rel == suffix or rel.endswith("/" + suffix):
            return False
    # Exempt path markers.
    for marker in _CHECK_249_EXEMPT_PATH_MARKERS:
        if marker in rel:
            return False
    # Exempt test files even outside /tests/ dir.
    name = path.name
    if name.startswith("test_") or name.endswith("_test.py"):
        return False
    return True


def _check_249_line_has_waiver(line: str) -> bool:
    """Return True if line carries a valid same-line Catalog #249 waiver."""

    match = _CHECK_249_WAIVER_RE.search(line)
    if not match:
        return False
    rationale = match.group(1).strip()
    if not rationale:
        return False
    if rationale in _CHECK_249_WAIVER_PLACEHOLDER_LITERALS:
        return False
    return True


def _check_249_string_literal_is_misleading(literal: str) -> str | None:
    """Return the matched device token if ``literal`` looks like a misleading
    device-named auth-eval output path, else None.

    Detection criteria (all required):
    1. Contains an auth-eval context token (`contest_auth_eval`,
       `auth_eval_result`, etc.)
    2. Contains a `_<device>` suffix immediately before `.json` / `_work` / end
       (e.g. `contest_auth_eval_cuda.json`, `something_cpu_work`)

    Returns the matched device token (cuda / cpu / mps) or None.
    """

    # Cheap context check first.
    has_context = any(
        ctx in literal for ctx in _CHECK_249_AUTH_EVAL_CONTEXT_TOKENS
    )
    if not has_context:
        return None
    # Look for `_<device>.json` or `_<device>_work` or `_<device>` at end.
    for token in _CHECK_249_DEVICE_TOKENS:
        for suffix in (f"_{token}.json", f"_{token}_work", f"_{token}"):
            if literal.endswith(suffix):
                # Confirm not an inner false positive (require token boundary).
                # A literal like 'contest_auth_eval_cuda.json' should match
                # but 'contest_auth_eval_cudacake.json' should not.
                if suffix.endswith(".json") or suffix.endswith("_work"):
                    return token
                # Bare `_<device>` only matches if it's the final segment.
                idx = literal.rfind(f"_{token}")
                if idx >= 0 and idx + len(f"_{token}") == len(literal):
                    return token
    return None


def _check_249_collect_violations_in_file(
    path: Path, repo_root: Path
) -> list[str]:
    """Walk ``path``'s AST + return a list of violation messages."""

    violations: list[str] = []
    try:
        source = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return violations
    if not any(ctx in source for ctx in _CHECK_249_AUTH_EVAL_CONTEXT_TOKENS):
        return violations
    if not any(f"_{token}" in source for token in _CHECK_249_DEVICE_TOKENS):
        return violations
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return violations
    source_lines = source.splitlines()
    try:
        rel = str(path.relative_to(repo_root)).replace("\\", "/")
    except ValueError:
        rel = str(path)
    for node in ast.walk(tree):
        if not isinstance(node, ast.Constant):
            continue
        if not isinstance(node.value, str):
            continue
        token = _check_249_string_literal_is_misleading(node.value)
        if token is None:
            continue
        # Check same-line waiver on the line containing this literal.
        lineno = getattr(node, "lineno", 0)
        if 1 <= lineno <= len(source_lines):
            if _check_249_line_has_waiver(source_lines[lineno - 1]):
                continue
        violations.append(
            f"{rel}:{lineno}: hardcoded device token "
            f"'_{token}' in auth-eval path literal "
            f"{node.value!r} — derive from auth_eval_device "
            "or add same-line `# DEVICE_NAMED_DIR_OK:<rationale>` "
            "waiver. See Catalog #249."
        )
    return violations


def _check_249_iter_in_scope_files(repo_root: Path):
    """Iterate over .py files in scope for Catalog #249."""

    scan_dirs = ("src/tac", "tools", "experiments", "scripts")
    source_index = _current_source_index(repo_root)
    if source_index is not None:
        context_paths = set(
            source_index.files_containing_substrings(
                scan_dirs,
                pattern="*.py",
                substrings=_CHECK_249_AUTH_EVAL_CONTEXT_TOKENS,
                require_all=False,
            )
        )
        device_paths = set(
            source_index.files_containing_substrings(
                scan_dirs,
                pattern="*.py",
                substrings=tuple(f"_{token}" for token in _CHECK_249_DEVICE_TOKENS),
                require_all=False,
            )
        )
        for path in sorted(context_paths.intersection(device_paths)):
            if _check_249_path_in_scope(path, repo_root):
                yield path
        return

    rg_paths = _rg_python_files_matching_regex(
        repo_root,
        scan_dirs,
        r"contest_auth_eval|auth_eval_result|auth_eval_json|auth_eval_path",
    )
    if rg_paths is not None:
        for path in rg_paths:
            if _check_249_path_in_scope(path, repo_root):
                yield path
        return

    for sub in scan_dirs:
        sub_root = repo_root / sub
        if not sub_root.exists():
            continue
        for path in sub_root.rglob("*.py"):
            if _check_249_path_in_scope(path, repo_root):
                yield path


def check_no_misleading_device_named_output_directories(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #249 — refuse hardcoded device tokens in auth-eval output paths.

    Per CLAUDE.md "Apples-to-apples evidence discipline" + "Forbidden
    component-aliasing for baselines" non-negotiables: an artifact filename or
    directory name MUST NOT make a device claim its contents cannot honor.

    Bug class anchor: Z3 v2 FULL Modal A100 dispatch 2026-05-15. Trainer
    hardcoded `result_json_path = out_dir / "contest_auth_eval_cuda.json"`;
    Modal dispatcher injected AUTH_EVAL_DEVICE=cpu; CPU eval result landed in
    `contest_auth_eval_cuda.json` + `contest_auth_eval_cuda_work/`. Parent
    agent quoted "0.19869 [contest-CUDA T4]" from the FILENAME despite the
    metadata saying CPU. Paired re-eval revealed true CUDA = 0.2317.

    The runtime sister fix in `src/tac/substrates/_shared/smoke_auth_eval_gate.
    py::_redirect_output_json_to_match_device` auto-rewrites mismatched
    filenames at runtime + emits a loud `[phantom-score-fix]` warning. This
    STRICT preflight gate is the structural complement: it refuses NEW
    hardcoded device tokens in source code so future trainers don't regrow
    the bug class at a different surface.

    Sister of Catalog #127 (custody validator) + Catalog #221 (auth_eval
    result fail-closed) + Catalog #226 (canonical helper enforcement).
    """

    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    files = list(_check_249_iter_in_scope_files(root))
    violations: list[str] = []
    for path in files:
        violations.extend(_check_249_collect_violations_in_file(path, root))

    if verbose:
        if violations:
            print(
                f"  [catalog-249] WARN: {len(violations)} hardcoded "
                f"device-named auth-eval path(s) across "
                f"{len(files)} scanned file(s) (strict={strict})"
            )
        else:
            print(
                f"  [catalog-249] OK ({len(files)} file(s) scanned)"
            )

    if violations and strict:
        msg = (
            f"check_no_misleading_device_named_output_directories: "
            f"{len(violations)} hardcoded device-named auth-eval "
            f"path(s) (Catalog #249 — phantom-score directory class "
            f"permanent fix; Z3 v2 anchor 2026-05-15); first 3:\n  "
            + "\n  ".join(violations[:3])
        )
        raise PreflightError(msg)
    return violations


# ----------------------------------------------------------------------------
# Catalog #228 — check_substrate_trainer_consumes_f3_cache_when_flag_declared
#
# F3-BACKPORT-WAVE-V2 op-routable #5 (2026-05-14). Bug class: a substrate
# trainer under ``experiments/train_substrate_*.py`` declares the RESERVED
# ``--enable-gt-scorer-cache`` Tier-1 optimization flag (Catalog #151
# manifest entry) but does NOT actually consume the cache primitive in its
# hot loop (``gt_cache.lookup(`` + ``gt_pose_batch=`` kwarg threading).
#
# Empirical anchor: predecessor F3-BACKPORT-WAVE-V2 wired the contract into
# 10 substrate trainers
# (`feedback_f3_backport_wave_v2_eleven_trainers_landed_20260514.md`).
# Without a STRICT preflight gate, a future trainer refactor could silently
# remove the wire-in (replace canonical
# `_build_optimized_training_context` with manual `loss_fn(...)`); the
# regression would not surface until a future Modal/Lightning smoke
# timeout on contest-resolution training.
#
# The gate delegates classification to the canonical helper
# ``tools/check_f3_trainer_actionable.py`` (which already encodes the full
# verdict taxonomy: ALREADY_WIRED / D1_SEGNET_SIDECAR / FULL_MAIN_STUB /
# Z3_V1_RATE_ONLY / SMOKE_SYNTHETIC / NEEDS_SUBSTRATE_F3_WIRE_IN). Only the
# explicit ``NEEDS_F3_BACKPORT`` and ``NEEDS_F3_BACKPORT_PLUS_TIER1_FLAGS``
# verdicts are gate violations — every other verdict is a structurally
# legitimate non-actionable state (substrate-side blocker / synthetic
# scorer / SegNet-only sidecar / stub-state).
#
# Per CLAUDE.md "Strict-flip atomicity rule" + the predecessor F3-V2
# landing memo: 17 trainers are ALREADY_WIRED at landing time; the gate
# inherits a 0 live count for trainers that DECLARE-AND-CONSUME the F3
# contract.
#
# Sister of Catalog #172 (`check_substrate_trainers_declare_autocast_fp16_
# support`), #178 (TF32), #179 (torch.compile), #180 (no_grad) — same
# pattern of "substrate-trainer engineering hygiene gate" applied to a
# different Tier-1 primitive (F3 GTScorerCache instead of autocast / TF32
# / torch.compile / no_grad).
#
# Memory: feedback_f3_backport_wave_v2_eleven_trainers_landed_20260514.md
# + feedback_prompt_premise_verification_before_edit_pattern_20260514.md.
# ----------------------------------------------------------------------------

# Canonical helper's recognized "ACTIONABLE violation" verdict tokens —
# any trainer that classifies into one of these has declared the F3 flag
# AND has a real PoseNet hot loop AND has a substrate-side wire-in but
# is missing the trainer-side wire-in. These are the only refusal
# verdicts; the other verdicts (ALREADY_WIRED / D1_SEGNET_SIDECAR /
# Z3_V1_RATE_ONLY / FULL_MAIN_STUB / SMOKE_SYNTHETIC_SCORERS_FULL_STUB /
# NEEDS_SUBSTRATE_F3_WIRE_IN / RESERVED_FLAG_BUT_NO_SCORER_HOT_LOOP /
# RESERVED_FLAG_NOT_CONSUMED / UNKNOWN_STATE_INVESTIGATE / NO_TRAINER_FILE)
# are structurally legitimate non-actionable states (substrate-side
# blocker / stub / synthetic / sidecar) and not refused.
_CHECK_228_ACTIONABLE_VIOLATION_VERDICTS = frozenset(
    {
        "NEEDS_F3_BACKPORT",
        "NEEDS_F3_BACKPORT_PLUS_TIER1_FLAGS",
    }
)

# Same-line waiver on the trainer file's argparse flag-declaration line.
# Placeholder ``<reason>`` literal is rejected so the docstring above
# cannot self-waive.
_CHECK_228_WAIVER_RE = re.compile(
    r"#\s*F3_CACHE_CONSUMPTION_WAIVED:\s*(?!<reason>)\S+"
)

_CHECK_228_TRAINER_GLOB = "train_substrate_*.py"


def _check_228_load_classifier() -> object | None:
    """Lazy-import the canonical F3-actionable classifier so the gate
    delegates to the single source of truth.
    """
    try:
        import importlib.util as _ilu

        path = REPO_ROOT / "tools" / "check_f3_trainer_actionable.py"
        if not path.is_file():
            return None
        spec = _ilu.spec_from_file_location(
            "_pact_check_228_f3_classifier", path
        )
        if spec is None or spec.loader is None:
            return None
        module = _ilu.module_from_spec(spec)
        spec.loader.exec_module(module)
        return module
    except Exception:
        return None


def _check_228_trainer_has_waiver(path: Path) -> bool:
    """Return True if the trainer file carries the same-line F3 waiver
    on any argparse flag-declaration line referencing
    ``--enable-gt-scorer-cache``.
    """
    try:
        text = path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return False
    for line in text.splitlines():
        if "enable-gt-scorer-cache" in line or "enable_gt_scorer_cache" in line:
            if _CHECK_228_WAIVER_RE.search(line):
                return True
    return False


def check_substrate_trainer_consumes_f3_cache_when_flag_declared(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #228 — refuse substrate trainers that declare the RESERVED
    ``--enable-gt-scorer-cache`` Tier-1 optimization flag but do NOT
    actually consume the GTScorerCache primitive in their hot loop.

    Per F3-BACKPORT-WAVE-V2 op-routable #5
    (`feedback_f3_backport_wave_v2_eleven_trainers_landed_20260514.md`).
    Delegates verdict classification to the canonical helper at
    ``tools/check_f3_trainer_actionable.py`` so the gate and the
    operator-facing reproducer stay in lock-step.

    Same-line waiver: ``# F3_CACHE_CONSUMPTION_WAIVED:<reason>`` on the
    argparse flag-declaration line. Placeholder ``<reason>`` literal is
    rejected.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    classifier = _check_228_load_classifier()
    if classifier is None:
        if verbose:
            print(
                "  [f3-cache-consumption] OK "
                "(canonical classifier tools/check_f3_trainer_actionable.py "
                "not found; gate is no-op)"
            )
        return []
    experiments_dir = root / "experiments"
    if not experiments_dir.is_dir():
        if verbose:
            print(
                "  [f3-cache-consumption] OK "
                "(no experiments dir; 0 trainer(s) scanned)"
            )
        return []
    violations: list[str] = []
    scanned = 0
    for path in sorted(experiments_dir.glob(_CHECK_228_TRAINER_GLOB)):
        rel = str(path.relative_to(root))
        scanned += 1
        trainer_id = path.stem.replace("train_substrate_", "")
        try:
            verdict_row = classifier._classify(trainer_id)
        except Exception as exc:
            violations.append(
                f"{rel}: classifier raised {exc!s} for trainer_id={trainer_id}"
            )
            continue
        verdict = str(verdict_row.get("verdict", ""))
        if verdict not in _CHECK_228_ACTIONABLE_VIOLATION_VERDICTS:
            continue
        if _check_228_trainer_has_waiver(path):
            continue
        violations.append(
            f"{rel}: trainer declares `--enable-gt-scorer-cache` but does "
            f"NOT consume the GTScorerCache primitive (verdict={verdict}); "
            "expected `gt_cache.lookup(` + `gt_pose_batch=` threading in "
            "the hot loop per canonical helper "
            "tools/check_f3_trainer_actionable.py. Either backport the "
            "wire-in OR carry a same-line "
            "`# F3_CACHE_CONSUMPTION_WAIVED:<reason>` waiver on the "
            "argparse flag-declaration line. Catalog #228 + "
            "feedback_f3_backport_wave_v2_eleven_trainers_landed_20260514.md."
        )
    if verbose:
        if violations:
            print(
                f"  [f3-cache-consumption] {len(violations)} "
                f"violation(s) across {scanned} substrate trainer(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [f3-cache-consumption] OK "
                f"({scanned} substrate trainer(s); all flag-declared "
                f"trainers also consume the cache or are non-actionable)"
            )
    if violations and strict:
        raise PreflightError(
            "check_substrate_trainer_consumes_f3_cache_when_flag_declared "
            f"found {len(violations)} violation(s). Catalog #228 closes "
            "F3-BACKPORT-WAVE-V2 op-routable #5; the canonical helper at "
            "tools/check_f3_trainer_actionable.py is the verdict authority:"
            "\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# check_substrate_trainers_use_canonical_optimization_helpers
#
# General sibling of Catalog #228. #228 protects the F3 GTScorerCache
# consumption path after a trainer has declared that specific flag. This gate
# catches the broader orphan from the 2026-05-14 optimization-helper directive:
# substrate trainers should either build the canonical
# ``build_optimized_training_context`` bundle, use a direct
# ``tac.training_optimization`` helper, or carry an explicit comment waiver.
# Initial wire-in is WARN-ONLY because the live count is nonzero; the gate is
# the canonical source of truth for the backfill list.
# ----------------------------------------------------------------------------


def check_substrate_trainers_use_canonical_optimization_helpers(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Report trainers missing canonical optimization-helper consumption.

    Acceptance is AST-based and comment-waiver based; docstrings and copied
    examples do not satisfy the contract.
    """

    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    try:
        from tac.trainer_optimization_helper_audit import (
            audit_trainer_optimization_helpers,
        )
    except Exception as exc:  # pragma: no cover - defensive import guard
        violations = [f"could not import trainer optimization helper audit: {exc!s}"]
    else:
        audit = audit_trainer_optimization_helpers(root)
        violations = list(audit.violations)
        if verbose:
            print(
                "  [trainer-optimization-helpers] "
                f"scanned={audit.scanned_trainers} "
                f"accepted={audit.accepted_trainers} "
                f"missing={audit.missing_trainers} "
                f"waived={audit.waived_trainers}"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")

    if violations and strict:
        raise PreflightError(
            "check_substrate_trainers_use_canonical_optimization_helpers "
            f"found {len(violations)} trainer(s) missing canonical "
            "optimization-helper usage or an explicit waiver. Backfill "
            "`build_optimized_training_context`, a direct "
            "`tac.training_optimization` helper call, or add "
            "`# OPTIMIZATION_HELPERS_WAIVED:<reason>`:\n  "
            + "\n  ".join(v[:300] for v in violations[:8])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #229 — check_subagent_landing_includes_premise_verification_evidence
#
# Premise-verification-before-edit pattern self-protection (2026-05-14).
# Bug class: subagent landing memos that claim N file/trainer/substrate
# edits without an accompanying empirical verdict table OR reproducer
# script path. Per
# `feedback_prompt_premise_verification_before_edit_pattern_20260514.md`,
# the F3-BACKPORT-WAVE empirically falsified the parent prompt's
# "7 trainers need backport" claim (0/7 actionable) via reproducer
# BEFORE any edit. Without this gate, future bulk-edit subagents will
# apply edits based on parent assertions without verification.
#
# Scope: ~/.claude/projects/.../memory/feedback_*_landed_<YYYYMMDD>.md
# where YYYYMMDD >= 20260514. Detection: memo body claims ">= 3 bulk
# edits" (e.g., "10 trainers wired", "5 substrates rewritten",
# "13 recipes backfilled") AND lacks BOTH (a) a verdict table
# (markdown table headers like "| trainer_id |" / "| verdict |" /
# "verdict_table" / "actionable") AND (b) a reproducer script path
# token (".omx/tmp/" / "_reproducer.py" / "tools/check_").
#
# Same-line waiver: ``# PREMISE_VERIFICATION_WAIVED:<reason>`` on a
# single body line for memos that legitimately don't apply the pattern
# (e.g., infrastructure landings with no file-list claims). Placeholder
# ``<reason>`` rejected.
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
# rule" — the legacy memo backfill is large and the operator will route
# strict-flip after the backfill sweep clears live count to 0.
#
# Sister of Catalog #125 (`check_subagent_landing_has_solver_wire_in`)
# + Catalog #126 (`check_lane_pre_registered_before_work_starts`) +
# Catalog #206 (`check_subagent_dispatches_use_checkpoint_discipline`).
# Together they form the four-corner discipline gate for subagent
# landings: solver wire-in + lane registry + checkpoint discipline +
# premise verification.
#
# Memory: feedback_prompt_premise_verification_before_edit_pattern_20260514.md
# + feedback_f3_backport_wave_v2_eleven_trainers_landed_20260514.md.
# ----------------------------------------------------------------------------

# Cutoff: only memos dated 2026-05-14 or later are in scope. Earlier
# memos are legacy and predate the canonical pattern.
_CHECK_229_DATE_CUTOFF = "20260514"

# Regex to detect bulk-edit claims in memo body. Matches phrases like
# "10 trainers wired", "5 substrates rewritten", "13 recipes backfilled".
_CHECK_229_BULK_EDIT_RE = re.compile(
    r"\b(\d+)\s+(?:trainers?|substrates?|files?|recipes?|wrappers?|"
    r"checks?|gates?)\s+"
    r"(?:edited|wired|rewritten|backported|patched|landed|added|"
    r"refactored|extracted|created)",
    re.IGNORECASE,
)

# Tokens that count as a verdict table OR reproducer-script path
# (either is sufficient to satisfy the gate).
_CHECK_229_VERDICT_TABLE_TOKENS = (
    "| trainer_id |",
    "| trainer |",
    "| verdict |",
    "| Trainer |",
    "| Verdict |",
    "verdict_table",
    "actionable",
    "Actionable",
    "ACTIONABLE",
    "empirical verdict",
    "Empirical verdict",
    "verdict table",
    "Verdict table",
)
_CHECK_229_REPRODUCER_PATH_TOKENS = (
    ".omx/tmp/",
    "_reproducer.py",
    "tools/check_",
)
_CHECK_229_WAIVER_RE = re.compile(
    r"#\s*PREMISE_VERIFICATION_WAIVED:\s*(?!<reason>)\S+"
)
_CHECK_229_FILE_WAIVER_RE = re.compile(
    r"#\s*PREMISE_VERIFICATION_WAIVED_FILE:\s*(?!<reason>)\S+"
)

# Memo filename pattern for landing memos.
_CHECK_229_MEMO_GLOB = "feedback_*_landed_*.md"


def _check_229_memo_dir(repo_root: Path) -> Path | None:
    """Resolve the canonical memory directory. The directory lives outside
    the repo (in ``~/.claude/projects/<project>/memory/``) so we discover
    it relative to the operator's home directory. Returns None if absent.
    """
    try:
        home = Path.home()
    except Exception:
        return None
    memory_dir = (
        home / ".claude" / "projects"
        / "-Users-adpena-Projects-pact" / "memory"
    )
    if memory_dir.is_dir():
        return memory_dir
    return None


def _check_229_memo_date_suffix(path: Path) -> str | None:
    """Extract the date suffix YYYYMMDD from a landing memo filename.
    Returns None if not parseable.
    """
    name = path.stem  # e.g. feedback_xyz_landed_20260514
    match = re.search(r"_(\d{8})$", name)
    if not match:
        return None
    return match.group(1)


def check_subagent_landing_includes_premise_verification_evidence(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #229 — refuse subagent landing memos that claim >=3 bulk
    edits without an empirical verdict table or reproducer-script path.

    Per `feedback_prompt_premise_verification_before_edit_pattern_20260514.md`.
    Initial wire-in is warn-only; strict-flip pending operator-routed
    backfill sweep.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    memo_dir = _check_229_memo_dir(root)
    if memo_dir is None:
        if verbose:
            print(
                "  [premise-verification] OK "
                "(memory dir not present; 0 memos scanned)"
            )
        return []
    violations: list[str] = []
    scanned = 0
    skipped_pre_cutoff = 0
    for memo in sorted(memo_dir.glob(_CHECK_229_MEMO_GLOB)):
        date_suffix = _check_229_memo_date_suffix(memo)
        if date_suffix is None:
            continue
        if date_suffix < _CHECK_229_DATE_CUTOFF:
            skipped_pre_cutoff += 1
            continue
        try:
            text = memo.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        scanned += 1
        # File-level waiver
        if _CHECK_229_FILE_WAIVER_RE.search(text):
            continue
        # Per-line waiver
        if _CHECK_229_WAIVER_RE.search(text):
            continue
        # Count bulk-edit claims
        total_edits = sum(
            int(m.group(1)) for m in _CHECK_229_BULK_EDIT_RE.finditer(text)
        )
        if total_edits < 3:
            continue
        # Acceptance: verdict-table token OR reproducer-path token in body
        has_verdict_table = any(
            tok in text for tok in _CHECK_229_VERDICT_TABLE_TOKENS
        )
        has_reproducer_path = any(
            tok in text for tok in _CHECK_229_REPRODUCER_PATH_TOKENS
        )
        if has_verdict_table or has_reproducer_path:
            continue
        violations.append(
            f"{memo.name}: landing memo claims {total_edits} bulk edits "
            "without an empirical verdict table OR reproducer-script "
            "path. Per CLAUDE.md premise-verification-before-edit "
            "pattern, add a verdict table OR cite the reproducer at "
            ".omx/tmp/<lane_id>_reproducer.py / tools/check_<lane>_*.py "
            "OR carry a same-line `# PREMISE_VERIFICATION_WAIVED:<reason>` "
            "waiver. Catalog #229 + "
            "feedback_prompt_premise_verification_before_edit_pattern_20260514.md."
        )
    if verbose:
        if violations:
            print(
                f"  [premise-verification] {len(violations)} "
                f"violation(s) across {scanned} memo(s) "
                f"(skipped_pre_cutoff={skipped_pre_cutoff}):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [premise-verification] OK "
                f"({scanned} memo(s) scanned, "
                f"{skipped_pre_cutoff} legacy pre-cutoff exempt)"
            )
    if violations and strict:
        raise PreflightError(
            "check_subagent_landing_includes_premise_verification_evidence "
            f"found {len(violations)} violation(s). Catalog #229 closes "
            "the premise-verification-before-edit pattern self-protection:"
            "\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #230 — check_bulk_rewrite_respects_sister_subagent_ownership_map
#
# Editor-vs-editor collision self-protection (2026-05-14). Bug class:
# bulk-edit operations (SPDX header sweep / mass refactor / wide-edit /
# bulk-rewrite) in subagent commit messages that do NOT reference the
# recursive R2 ownership map / disjoint-scope declaration / sister-subagent
# territory. Per
# `feedback_editor_vs_editor_collision_patterns_in_parallel_waves_20260514.md`,
# the F3-GTSCORERCACHE-WIRE-IN landing observed transient working-tree
# wipes when OSS-RELEASE subagent's SPDX sweep captured F3's in-flight
# substrate files. Without this gate, future parallel waves with
# multiple editor subagents will silently revert sister-subagent edits.
#
# Scope: last 50 commits whose commit message body mentions a bulk-op
# token (SPDX header sweep / SPDX sweep / bulk rewrite / mass refactor /
# bulk import / scope sweep / bulk-edit / wide-edit). For each such
# commit, the body MUST reference the ownership map OR a recursive R2
# disjoint-scope marker. Acceptance: any of ownership map / disjoint
# scope / sister-subagent / OWNS: / scope isolated / path-prefix
# exclusion / recursive R2.
#
# Same-line waiver: ``# BULK_REWRITE_OWNERSHIP_WAIVED:<reason>`` on a
# body line; placeholder rejected. The commit serializer log
# (`.omx/state/commit-serializer.log`) is consulted so only TRUE
# subagent commits are in scope; operator-direct commits are exempt
# (operator owns the global scope by definition).
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
# rule" — legacy bulk-edit commits predate the pattern; strict-flip
# pending operator-routed backfill.
#
# Sister of Catalog #117 (`check_subagent_commit_serializer_uses_lock`)
# + Catalog #157 (`check_commit_serializer_pre_lock_hash_against_head`)
# + Catalog #216 (`check_commit_serializer_post_stage_hash`). Together
# they extinct the commit-vs-edit collision class at four surfaces:
# commit-time-pre-pre-lock (#157) + commit-time-staged (#216) +
# commit-time-lock-arbitration (#117) + edit-time-bulk-op (#230).
#
# Memory: feedback_editor_vs_editor_collision_patterns_in_parallel_waves_20260514.md.
# ----------------------------------------------------------------------------

# Bulk-operation tokens detected in commit message bodies (case-insensitive
# substring search). Each token represents a high-risk wide-scope edit
# that could capture sister-subagent files.
_CHECK_230_BULK_OP_TOKENS = (
    "spdx header sweep",
    "spdx sweep",
    "bulk rewrite",
    "mass refactor",
    "bulk import",
    "scope sweep",
    "bulk-edit",
    "wide-edit",
    "bulk-rewrite",
)

# Ownership-map / disjoint-scope tokens that satisfy the gate.
_CHECK_230_OWNERSHIP_MAP_TOKENS = (
    "ownership map",
    "disjoint scope",
    "sister-subagent",
    "sister subagent",
    "OWNS:",
    "owns:",
    "scope isolated",
    "path-prefix exclusion",
    "recursive R2",
    "recursive r2",
    "R2 ownership",
)

_CHECK_230_WAIVER_RE = re.compile(
    r"#\s*BULK_REWRITE_OWNERSHIP_WAIVED:\s*(?!<reason>)\S+"
)


def _check_230_load_serializer_shas(
    repo_root: Path, last_n_commits: int
) -> set[str]:
    """Load the set of subagent commit SHAs from the canonical commit
    serializer log. Returns short-SHA prefixes for matching against
    git log output.
    """
    log_path = repo_root / ".omx" / "state" / "commit-serializer.log"
    if not log_path.is_file():
        return set()
    shas: set[str] = set()
    try:
        for line in log_path.read_text(encoding="utf-8").splitlines():
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                continue
            sha = row.get("commit_sha") or row.get("sha")
            if isinstance(sha, str) and sha:
                shas.add(sha[:9])
    except OSError:
        return set()
    return shas


def _check_230_iter_recent_commits(
    repo_root: Path, last_n_commits: int
) -> list[tuple[str, str]]:
    """Return [(sha, body)] for the last N commits."""
    try:
        out = subprocess.run(
            ["git", "log", f"-{last_n_commits}", "--format=%H%n%B%n---END---"],
            cwd=str(repo_root),
            capture_output=True,
            text=True,
            timeout=15,
        )
    except (OSError, subprocess.TimeoutExpired):
        return []
    if out.returncode != 0:
        return []
    entries: list[tuple[str, str]] = []
    for chunk in out.stdout.split("---END---"):
        chunk = chunk.strip()
        if not chunk:
            continue
        lines = chunk.split("\n", 1)
        sha = lines[0].strip()
        body = lines[1] if len(lines) > 1 else ""
        entries.append((sha, body))
    return entries


def check_bulk_rewrite_respects_sister_subagent_ownership_map(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
    last_n_commits: int = 50,
) -> list[str]:
    """Catalog #230 — refuse bulk-rewrite subagent commits that do NOT
    reference the sister-subagent ownership map / disjoint-scope marker.

    Per `feedback_editor_vs_editor_collision_patterns_in_parallel_waves_20260514.md`.
    Initial wire-in is warn-only; strict-flip pending operator-routed
    backfill.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    serializer_prefixes = _check_230_load_serializer_shas(root, last_n_commits)
    if not serializer_prefixes:
        if verbose:
            print(
                "  [bulk-rewrite-ownership] OK "
                "(no subagent commits in serializer log)"
            )
        return []
    violations: list[str] = []
    scanned = 0
    for sha, body in _check_230_iter_recent_commits(root, last_n_commits):
        if sha[:9] not in serializer_prefixes:
            continue
        body_lower = body.lower()
        bulk_op = next(
            (tok for tok in _CHECK_230_BULK_OP_TOKENS if tok in body_lower),
            None,
        )
        if bulk_op is None:
            continue
        scanned += 1
        # Same-line waiver
        if _CHECK_230_WAIVER_RE.search(body):
            continue
        # Acceptance: ownership-map token in body (case-insensitive)
        respects = any(
            tok.lower() in body_lower for tok in _CHECK_230_OWNERSHIP_MAP_TOKENS
        )
        if respects:
            continue
        violations.append(
            f"commit {sha[:10]}: subagent bulk-op commit (token={bulk_op!r}) "
            "without sister-subagent ownership-map reference. Per CLAUDE.md "
            "+ editor-vs-editor-collision memo, declare the disjoint-scope "
            "boundary in the commit body (recursive R2 / OWNS: <subtree> / "
            "sister-subagent / path-prefix exclusion) OR carry a "
            "`# BULK_REWRITE_OWNERSHIP_WAIVED:<reason>` waiver. "
            "Catalog #230 + "
            "feedback_editor_vs_editor_collision_patterns_in_parallel_waves_20260514.md."
        )
    if verbose:
        if violations:
            print(
                f"  [bulk-rewrite-ownership] {len(violations)} "
                f"violation(s) across {scanned} subagent bulk-op commit(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:240]}")
        else:
            print(
                f"  [bulk-rewrite-ownership] OK "
                f"({scanned} subagent bulk-op commit(s) scanned)"
            )
    if violations and strict:
        raise PreflightError(
            "check_bulk_rewrite_respects_sister_subagent_ownership_map "
            f"found {len(violations)} violation(s). Catalog #230 closes "
            "the editor-vs-editor collision class self-protection:"
            "\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ----------------------------------------------------------------------------
# Catalog #231 — check_review_gate_hook_uses_retry_helper
#
# DuckDB-lock-fix self-protection (2026-05-14, lane
# `lane_duckdb_lock_fix_review_gate_hook_20260514` op-routable #1).
# Bug class: any future revision of ``tools/review_gate_hook.py`` that
# replaces the canonical retry helper ``review_tracker._connect_duckdb``
# with a bare ``duckdb.connect()`` call would re-introduce the
# 80-300s commit stall observed empirically in F3-GTSCORERCACHE +
# CATALOG-226-REFACTOR waves.
#
# The canonical fix routes the hook through:
# 1. ``review_tracker._connect_duckdb`` (with retry_seconds=1.5 budget)
# 2. ``review_tracker.load_entities_from_json_snapshot`` (JSON fallback)
# 3. ``review_tracker._is_duckdb_lock_error`` (predicate)
#
# Per `feedback_duckdb_lock_fix_review_gate_hook_landed_20260514.md` op
# decision #1 (RECOMMENDED YES). Without this gate, a future contributor
# (or sister subagent refactoring the hook) could silently regress the
# fix.
#
# Detection: parse ``tools/review_gate_hook.py`` with AST and check that
# (a) at least ONE canonical retry-helper token is imported or
# referenced, AND (b) NO bare ``duckdb.connect()`` Call node appears
# OUTSIDE docstrings/comments. The AST-walk distinguishes docstring
# mentions (string literals) from real Call expressions.
#
# Same-line waiver: ``# REVIEW_GATE_BARE_DUCKDB_OK:<reason>`` on the
# bare-connect line; placeholder rejected.
#
# STRICT-from-byte-one per CLAUDE.md "Bugs must be permanently fixed
# AND self-protected against" non-negotiable + "Strict-flip atomicity
# rule" — live count at landing: 0 (the canonical fix is already
# present in tools/review_gate_hook.py per the source landing memo).
#
# Sister of Catalog #131 (`check_no_bare_writes_to_shared_state`) +
# Catalog #138 (`check_state_writers_strict_load_for_mutating_path`) +
# Catalog #128 (`check_continual_learning_writes_use_lock`). Together
# they extinct the bare-state-IO bug class across .omx/state writes
# (#131), .omx/state strict loads (#138), continual-learning writes
# (#128), and review-tracker reads (#231).
#
# Memory: feedback_duckdb_lock_fix_review_gate_hook_landed_20260514.md.
# ----------------------------------------------------------------------------

# Canonical retry-helper tokens. The hook must import or reference at
# least one to satisfy the gate.
_CHECK_231_CANONICAL_HELPER_TOKENS = (
    "_connect_duckdb",
    "connect_duckdb_with_retry",
    "load_entities_from_json_snapshot",
    "_is_duckdb_lock_error",
)

# Same-line waiver on a bare duckdb.connect Call line.
_CHECK_231_WAIVER_RE = re.compile(
    r"#\s*REVIEW_GATE_BARE_DUCKDB_OK:\s*(?!<reason>)\S+"
)


def _check_231_collect_bare_duckdb_connects(
    src: str,
) -> list[tuple[int, str]]:
    """Walk the AST of the review-gate hook source and collect
    ``duckdb.connect(...)`` Call nodes. Returns list of (lineno, source_line)
    pairs. Docstrings and string literals are excluded by AST construction
    (only Call nodes are inspected).

    The canonical helper ``_connect_duckdb`` function may itself call
    ``duckdb.connect(...)`` inside its body — we accept Call nodes that
    appear INSIDE the canonical helper function definition by name.
    """
    try:
        tree = ast.parse(src)
    except SyntaxError:
        return []
    source_lines = src.splitlines()
    bare_calls: list[tuple[int, str]] = []

    class _Visitor(ast.NodeVisitor):
        def __init__(self) -> None:
            # Track enclosing function name (so we can exempt the canonical
            # helper itself).
            self._enclosing_func: list[str] = []

        def visit_FunctionDef(self, node: ast.FunctionDef) -> None:
            self._enclosing_func.append(node.name)
            try:
                self.generic_visit(node)
            finally:
                self._enclosing_func.pop()

        def visit_AsyncFunctionDef(
            self, node: ast.AsyncFunctionDef
        ) -> None:
            self._enclosing_func.append(node.name)
            try:
                self.generic_visit(node)
            finally:
                self._enclosing_func.pop()

        def visit_Call(self, node: ast.Call) -> None:
            func = node.func
            if (
                isinstance(func, ast.Attribute)
                and func.attr == "connect"
                and isinstance(func.value, ast.Name)
                and func.value.id == "duckdb"
            ):
                # Exempt if inside the canonical helper itself (which
                # legitimately wraps duckdb.connect with retry).
                if self._enclosing_func and any(
                    tok in name for tok in _CHECK_231_CANONICAL_HELPER_TOKENS
                    for name in self._enclosing_func
                ):
                    pass
                else:
                    lineno = node.lineno
                    line = (
                        source_lines[lineno - 1]
                        if 0 <= lineno - 1 < len(source_lines)
                        else ""
                    )
                    bare_calls.append((lineno, line))
            self.generic_visit(node)

    _Visitor().visit(tree)
    return bare_calls


def check_review_gate_hook_uses_retry_helper(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #231 — refuse any future ``tools/review_gate_hook.py``
    revision that re-introduces a bare ``duckdb.connect()`` call outside
    the canonical retry helper.

    Per `feedback_duckdb_lock_fix_review_gate_hook_landed_20260514.md`
    operator decision #1 (RECOMMENDED YES). STRICT-from-byte-one;
    live count at landing: 0.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    hook_path = root / "tools" / "review_gate_hook.py"
    if not hook_path.is_file():
        if verbose:
            print(
                "  [review-gate-retry-helper] OK "
                "(tools/review_gate_hook.py absent; 0 scanned)"
            )
        return []
    try:
        text = hook_path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        return [f"tools/review_gate_hook.py: read error {exc!s}"]
    violations: list[str] = []
    # Requirement (a): at least one canonical retry-helper token
    has_canonical_token = any(
        tok in text for tok in _CHECK_231_CANONICAL_HELPER_TOKENS
    )
    if not has_canonical_token:
        violations.append(
            "tools/review_gate_hook.py: does not import or reference any "
            "canonical retry-helper token ("
            + ", ".join(_CHECK_231_CANONICAL_HELPER_TOKENS)
            + "). Per Catalog #231, route the hook through "
            "`review_tracker._connect_duckdb` + JSON-snapshot fallback. "
            "Memory: "
            "feedback_duckdb_lock_fix_review_gate_hook_landed_20260514.md."
        )
    # Requirement (b): no bare duckdb.connect Call outside canonical
    # helper. Use AST to distinguish docstring mentions from real Calls.
    bare_calls = _check_231_collect_bare_duckdb_connects(text)
    for lineno, line in bare_calls:
        if _CHECK_231_WAIVER_RE.search(line):
            continue
        violations.append(
            f"tools/review_gate_hook.py:{lineno}: bare `duckdb.connect(...)` "
            "Call detected; expected routing through canonical retry helper "
            "`review_tracker._connect_duckdb` per Catalog #231. Either "
            "delegate to the canonical helper OR carry a same-line "
            "`# REVIEW_GATE_BARE_DUCKDB_OK:<reason>` waiver. Memory: "
            "feedback_duckdb_lock_fix_review_gate_hook_landed_20260514.md."
        )
    if verbose:
        if violations:
            print(
                f"  [review-gate-retry-helper] {len(violations)} "
                f"violation(s) in tools/review_gate_hook.py:"
            )
            for v in violations[:5]:
                print(f"    - {v[:240]}")
        else:
            print(
                "  [review-gate-retry-helper] OK "
                "(canonical retry helper used; no bare duckdb.connect calls)"
            )
    if violations and strict:
        raise PreflightError(
            "check_review_gate_hook_uses_retry_helper "
            f"found {len(violations)} violation(s). Catalog #231 closes "
            "DuckDB-lock-fix op decision #1 self-protection:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


# ---------------------------------------------------------------------------
# Catalog #241 + #242 — META layer substrate contract gates
# (META-LAYER-SUBSTRATE-CONTRACT-AUTO-WIRE-SUBAGENT, 2026-05-15).
# Memory: feedback_meta_layer_substrate_contract_landed_20260515.md
# Design: .omx/research/substrate_meta_layer_design_20260515.md
# ---------------------------------------------------------------------------

# Tokens accepted to mark a substrate trainer as legacy-pre-META-layer.
# Same-line on the file's first ~20 lines (filename comment block / module
# docstring). Placeholder ``<rationale>`` literal is rejected so the gate
# cannot self-waive.
_CHECK_241_LEGACY_TOKEN = "LEGACY_SUBSTRATE_PRE_META_LAYER:"
_CHECK_241_DECORATOR_TOKEN = "@register_substrate"
_CHECK_241_REGISTERED_SUBSTRATE_IMPORT_TOKEN = ".registered_substrate import"
_CHECK_241_HEADER_LOOKBACK_LINES = 25


def check_substrate_uses_register_decorator_or_explicitly_legacy_tagged(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #241 — refuse ``experiments/train_substrate_*.py`` that neither
    use ``@register_substrate(...)`` NOR carry a same-line waiver
    ``# LEGACY_SUBSTRATE_PRE_META_LAYER:<rationale>`` in the file header.

    Initial wire-in is WARN-ONLY (31 legacy substrates exist at landing;
    migration is a follow-up wave per `.omx/research/substrate_meta_layer_design_20260515.md`
    § 6). Strict-flip planned alongside the migration's final commit per
    CLAUDE.md "Strict-flip atomicity rule".

    Per CLAUDE.md "Forbidden premature KILL": legacy substrates that don't yet
    use the decorator are TAGGED-PENDING-MIGRATION via the waiver, not killed.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    base = root / "experiments"
    if not base.is_dir():
        if verbose:
            print("  [substrate-decorator-or-legacy] OK (no experiments dir; 0 scanned)")
        return []
    violations: list[str] = []
    scanned = 0
    for path in sorted(base.glob("train_substrate_*.py")):
        scanned += 1
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            violations.append(f"{path}: read error {exc!s}")
            continue
        if _CHECK_241_DECORATOR_TOKEN in text:
            continue
        if _CHECK_241_REGISTERED_SUBSTRATE_IMPORT_TOKEN in text:
            continue
        # Header-only waiver scan (first ~25 lines).
        header = "\n".join(text.split("\n")[: _CHECK_241_HEADER_LOOKBACK_LINES])
        # Reject placeholder ``<rationale>`` literal.
        if _CHECK_241_LEGACY_TOKEN in header:
            # Find the token and check its rationale isn't the placeholder.
            idx = header.find(_CHECK_241_LEGACY_TOKEN)
            rationale = header[idx + len(_CHECK_241_LEGACY_TOKEN) :].split("\n", 1)[0].strip()
            if rationale and rationale != "<rationale>":
                continue
            violations.append(
                f"{path}: carries '{_CHECK_241_LEGACY_TOKEN}' but rationale is empty or "
                "placeholder '<rationale>'. Provide a concrete reason (e.g. "
                "'pre-2026-05-15 migration backlog item #N')."
            )
            continue
        violations.append(
            f"{path}: substrate trainer does not use @register_substrate(...) "
            "AND does not carry a same-line "
            f"'# {_CHECK_241_LEGACY_TOKEN}<rationale>' waiver in its first "
            f"{_CHECK_241_HEADER_LOOKBACK_LINES} lines. Per Catalog #241, every "
            "substrate trainer must declare its META contract via "
            "``@register_substrate(SubstrateContract(...))`` in-file, import a "
            "package-side ``registered_substrate`` module, or be explicitly "
            "tagged as legacy-pending-migration."
        )
    if verbose:
        print(
            f"  [substrate-decorator-or-legacy] scanned {scanned}; "
            f"{len(violations)} violations"
        )
    if violations and strict:
        raise PreflightError(
            "check_substrate_uses_register_decorator_or_explicitly_legacy_tagged "
            f"found {len(violations)} violation(s). Catalog #241 enforces META "
            "layer adoption per `.omx/research/substrate_meta_layer_design_20260515.md`:\n  "
            + "\n  ".join(v[:300] for v in violations[:5])
        )
    return violations


def check_register_substrate_contract_fields_canonical(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #242 — every file that uses ``@register_substrate(...)`` MUST
    register a contract that validates against ``SubstrateContract``.

    The check imports ``tac.substrate_registry`` and inspects the in-memory
    ``_REGISTERED_SUBSTRATES`` dict. Contracts that fail validation surface
    here as preflight errors (in addition to the import-time error). This is
    defense-in-depth: the import-time error is the primary surface; this gate
    catches a registered-but-corrupted contract that may have escaped initial
    validation through an out-of-band mutation.

    STRICT-from-byte-one. Live count at landing: 0 (only the
    ``example_template`` uses the decorator, and its contract is clean).
    """
    # Lazy import to avoid circular dep at preflight.py import time.
    try:
        import importlib

        from tac.substrate_registry import (
            example_template as _example_template,  # noqa: F401  (force registration)
            validate_all_registered,
        )
    except ImportError as exc:
        if verbose:
            print(f"  [substrate-contract-fields] skipped (import failed: {exc})")
        return []
    root = Path(repo_root or REPO_ROOT)
    substrate_root = root / "src" / "tac" / "substrates"
    import_errors: list[str] = []
    if substrate_root.is_dir():
        for path in sorted(substrate_root.glob("*/registered_substrate.py")):
            package = path.parent.name
            module_name = f"tac.substrates.{package}.registered_substrate"
            try:
                importlib.import_module(module_name)
            except Exception as exc:  # pragma: no cover - exercised in live preflight
                import_errors.append(f"{module_name}: import failed: {exc!r}")
    errors = validate_all_registered()
    errors.extend(import_errors)
    if verbose:
        print(
            "  [substrate-contract-fields] validated "
            f"{len(errors)} error(s) across registered substrates"
        )
    if errors and strict:
        raise PreflightError(
            "check_register_substrate_contract_fields_canonical "
            f"found {len(errors)} contract validation error(s). Catalog #242 "
            "enforces SubstrateContract field-level invariants:\n  "
            + "\n  ".join(e[:300] for e in errors[:5])
        )
    return errors


# ----------------------------------------------------------------------------
# Catalog #248 — check_no_stash_pop_conflict_markers_in_canonical_files
#
# GRAND-COUNCIL-MULTI-SISTER-MERGE-RESOLUTION self-protection (2026-05-15).
# Bug class: parallel sister subagents using ``git stash push`` + ``git stash
# pop`` workflows to coordinate edits can leave residual ``<<<<<<< Updated
# upstream`` / ``======= `` / ``>>>>>>> Stashed changes`` (or HEAD-form
# ``<<<<<<< HEAD``) conflict markers in canonical source files when the pop
# encounters a 3-way merge conflict and the operator/sister silently moves
# on without resolving. The empirical anchor is the 79-UU-file pile-up at
# 2026-05-15 caused by 3+ parallel sister subagents (PAIRED-DISPATCH-SKIP /
# ORPHAN-SIGNAL-AUDIT / 8-AXIS-SWEEP) all stashing-and-popping concurrently.
# Conflict markers are syntactically invalid in every supported file type
# (Python / shell / JSON / YAML / Markdown all break) and slipping them into
# main is a hard rebuild-required incident.
#
# Sister of:
# - Catalog #117 (`check_subagent_commit_serializer_uses_lock`) — last-50-
#   commit serializer-usage gate.
# - Catalog #157 (`check_commit_serializer_pre_lock_hash_against_head`) —
#   commit-swap pre-pre-lock race detector.
# - Catalog #174 (`check_subagent_commit_serializer_always_uses_expected_content_sha256`)
#   — mandates `--expected-content-sha256` so sibling-edit detection is
#   symmetric.
# - Catalog #230 (`check_bulk_rewrite_respects_sister_subagent_ownership_map`)
#   — extincts the editor-vs-editor collision class at the bulk-rewrite
#   surface; #248 extincts the residual artifact at the file content surface.
# Together the four close the multi-sister stash-pop race bug-class meta-
# surface: edit-time (#230) + commit-time-pre-pre-lock (#157) + commit-time-
# lock-arbitration (#117 + #174) + post-resolution-residual-marker (#248).
#
# STRICT-from-byte-one per CLAUDE.md "Bugs must be permanently fixed AND
# self-protected against" + "Strict-flip atomicity rule". Live count at
# landing: 0 (the multi-sister race resolution lands in the same commit
# batch).
# ----------------------------------------------------------------------------

# Conflict marker prefixes per Git's documented convention. Match at column
# 0 (line-anchored) only. ``=======`` is excluded by itself because it is a
# common token in ASCII-art docstrings / divider lines; we require the start
# OR end marker pair to be present.
_CHECK_248_CONFLICT_MARKER_PREFIXES = (
    "<<<<<<< Updated upstream",
    "<<<<<<< HEAD",
    "<<<<<<< ours",
    ">>>>>>> Stashed changes",
    ">>>>>>> theirs",
)
# Generic ``>>>>>>> `` (any branch suffix) catches non-canonical stash-pop
# residuals. We use a regex anchored at line start with exactly 7 ``>`` and a
# trailing space to avoid clobbering shell-prompt-like text.
_CHECK_248_GENERIC_END_MARKER_RE = re.compile(r"^>>>>>>> \S")
_CHECK_248_GENERIC_START_MARKER_RE = re.compile(r"^<<<<<<< \S")
# Per-line ``# CONFLICT_MARKER_INTENTIONAL_OK:<rationale>`` waiver for the
# rare case where a file legitimately documents conflict-marker text (e.g.
# this file's own catalog block, a tutorial, a test fixture). Placeholder
# ``<rationale>`` literal rejected so the gate's docstring example cannot
# self-waive.
_CHECK_248_WAIVER_TOKEN = "# CONFLICT_MARKER_INTENTIONAL_OK:"
_CHECK_248_WAIVER_PLACEHOLDER_REJECT = (
    "# CONFLICT_MARKER_INTENTIONAL_OK:<rationale>",
    "# CONFLICT_MARKER_INTENTIONAL_OK:<reason>",
)
_CHECK_248_SCAN_DIRS = (
    "src",
    "tools",
    "scripts",
    "experiments",
    "submissions",
    "tests",
    "configs",
    "docs",
    "reports",
    ".omx",
    ".ralph",
    ".agents",
    "runtime-rs",
    "cuda",
    "jax",
    "mojo",
)
_CHECK_248_SCAN_EXTENSIONS = (
    ".py",
    ".sh",
    ".json",
    ".jsonl",
    ".yaml",
    ".yml",
    ".md",
    ".txt",
    ".cfg",
    ".toml",
    ".rs",
    ".cu",
    ".cuh",
)
_CHECK_248_EXCLUDED_PATH_MARKERS = (
    "experiments/results/",
    "_intake_",
    ".omx/oss_export/",
    "vendored/",
    "build/lib/",
    "reports/raw/",
    ".venv/",
    "__pycache__/",
    "node_modules/",
    ".git/",
    "upstream/",  # pinned upstream snapshot per CLAUDE.md mutation frontier
)
_CHECK_248_SELF_EXEMPT_FILES = frozenset(
    {
        "src/tac/preflight.py",  # carries the marker literals in its own gate
        "src/tac/tests/test_check_248_no_stash_pop_conflict_markers.py",  # fixtures
    }
)


def check_no_stash_pop_conflict_markers_in_canonical_files(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #248 — refuse any state of the repo that contains residual git
    conflict markers (``<<<<<<< Updated upstream`` / ``<<<<<<< HEAD`` /
    ``>>>>>>> Stashed changes`` / ``>>>>>>> <branch>``) in canonical source
    files.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
    non-negotiable + "Strict-flip atomicity rule" — live count at landing: 0
    (the GRAND-COUNCIL-MULTI-SISTER-MERGE-RESOLUTION resolution lands in the
    same commit batch).

    Bug class anchor: 2026-05-15 multi-sister stash-pop race produced 79 UU
    files including 14 with residual conflict markers across ``src/tac/``,
    ``experiments/``, ``submissions/``, ``tools/``, ``reports/``. Slipping
    even one residual marker into main breaks every importer / parser /
    consumer of that file because the marker syntax is universally invalid.
    """
    repo_root = repo_root or Path.cwd()
    if isinstance(repo_root, str):
        repo_root = Path(repo_root)
    violations: list[str] = []

    for scan_dir in _CHECK_248_SCAN_DIRS:
        scan_path = repo_root / scan_dir
        if not scan_path.exists():
            continue
        for path in scan_path.rglob("*"):
            if not path.is_file():
                continue
            if path.suffix not in _CHECK_248_SCAN_EXTENSIONS:
                continue
            rel = path.relative_to(repo_root).as_posix()
            if any(m in rel for m in _CHECK_248_EXCLUDED_PATH_MARKERS):
                continue
            if rel in _CHECK_248_SELF_EXEMPT_FILES:
                continue
            try:
                text = path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            for lineno, line in enumerate(text.splitlines(), start=1):
                marker_kind: str | None = None
                if any(line.startswith(p) for p in _CHECK_248_CONFLICT_MARKER_PREFIXES):
                    marker_kind = "literal"
                elif _CHECK_248_GENERIC_END_MARKER_RE.match(
                    line
                ) or _CHECK_248_GENERIC_START_MARKER_RE.match(line):
                    marker_kind = "generic"
                if marker_kind is None:
                    continue
                # Same-line waiver check. Placeholder rejection.
                stripped = line.rstrip()
                if _CHECK_248_WAIVER_TOKEN in stripped and not any(
                    p in stripped for p in _CHECK_248_WAIVER_PLACEHOLDER_REJECT
                ):
                    # waiver carries a real rationale; skip
                    continue
                violations.append(
                    f"{rel}:{lineno}: residual git conflict marker "
                    f"({marker_kind}) — '{line[:80]}' "
                    f"(Catalog #248: GRAND-COUNCIL-MULTI-SISTER-MERGE-"
                    f"RESOLUTION self-protect)"
                )

    if verbose:
        print(
            f"  [no-stash-pop-conflict-markers] scanned, "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            "check_no_stash_pop_conflict_markers_in_canonical_files found "
            f"{len(violations)} residual git conflict marker(s) (Catalog "
            "#248 — multi-sister stash-pop race self-protect):\n  "
            + "\n  ".join(v[:300] for v in violations[:10])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #250-255 — Rudin-Daubechies autopilot ranker self-protection
# (RUDIN-DAUBECHIES-AUTOPILOT-FULL-IMPLEMENTATION-WAVELET-RASHOMON-FALLING-
# RULE-LIST-CONTINUAL-LEARNING-20260515)
# ─────────────────────────────────────────────────────────────────────────
