def _check_287b_strip_code_fences_and_html_comments(text: str) -> str:
    """Return text with triple-backtick fences and HTML comments masked.

    The masking replaces the content with newlines so line numbers and
    offset arithmetic remain stable; only the in-prose `tac.X` citations
    are scanned.
    """
    out: list[str] = []
    in_fence = False
    in_html = False
    for line in text.splitlines():
        stripped = line.lstrip()
        # HTML comment opens / closes can span multiple lines
        if not in_fence:
            if not in_html and "<!--" in line:
                idx = line.index("<!--")
                head = line[:idx]
                rest = line[idx + 4:]
                if "-->" in rest:
                    # single-line HTML comment
                    end_idx = rest.index("-->")
                    tail = rest[end_idx + 3:]
                    line = head + " " * (4 + end_idx + 3) + tail
                else:
                    in_html = True
                    line = head + " " * (len(line) - idx)
            elif in_html:
                if "-->" in line:
                    end_idx = line.index("-->")
                    line = " " * (end_idx + 3) + line[end_idx + 3:]
                    in_html = False
                else:
                    line = " " * len(line)
        # Triple-backtick fence open/close
        if stripped.startswith("```"):
            in_fence = not in_fence
            out.append(" " * len(line))
            continue
        if in_fence:
            out.append(" " * len(line))
            continue
        out.append(line)
    return "\n".join(out)


def _check_287b_extract_two_component_prefix(dotted: str) -> str | None:
    """Return ``tac.X`` for any ``tac.X[.Y...]`` dotted path; else None."""
    parts = dotted.split(".")
    if len(parts) < 2 or parts[0] != "tac":
        return None
    return f"{parts[0]}.{parts[1]}"


def _check_287b_module_is_importable(name: str) -> bool:
    """Return True iff ``importlib.util.find_spec(name)`` returns a spec."""
    import importlib.util as _iu
    try:
        spec = _iu.find_spec(name)
    except (ModuleNotFoundError, ImportError, ValueError, AttributeError):
        return False
    return spec is not None


def _check_287b_module_has_attr(
    module_name: str,
    attr_name: str,
    attr_cache: dict[tuple[str, str], bool] | None = None,
) -> bool:
    """Return True iff ``module_name`` imports and exposes ``attr_name``."""
    key = (module_name, attr_name)
    if attr_cache is not None and key in attr_cache:
        return attr_cache[key]
    try:
        module = importlib.import_module(module_name)
    except Exception:
        result = False
    else:
        result = hasattr(module, attr_name)
    if attr_cache is not None:
        attr_cache[key] = result
    return result


def _check_287b_authority_claim_line(line: str) -> bool:
    """Return True for active authority language that file waivers must not hide."""
    return bool(_CHECK_287B_AUTHORITY_CLAIM_RE.search(line))


def _check_287b_authority_dotted_reference_ok(
    dotted: str,
    importable_cache: dict[str, bool],
    attr_cache: dict[tuple[str, str], bool] | None = None,
) -> bool:
    """Return True when an authority-line dotted citation has importable backing.

    Whole-file proposal waivers are intentionally weak evidence. If such a
    file also uses active authority language, the citation must either name an
    importable module path directly or name a real attribute on an importable
    parent module. This preserves legitimate references such as
    ``tac.council_continual_learning.append_council_anchor`` while refusing
    parent-module-only false authority such as ``tac.unified_action.S_total``.
    """
    if dotted not in importable_cache:
        importable_cache[dotted] = _check_287b_module_is_importable(dotted)
    if importable_cache[dotted]:
        return True
    parts = dotted.split(".")
    if len(parts) <= 2:
        return False
    parent = ".".join(parts[:-1])
    if parent not in importable_cache:
        importable_cache[parent] = _check_287b_module_is_importable(parent)
    if not importable_cache[parent]:
        return False
    terminal = parts[-1]
    if not terminal[:1].isupper() and not _CHECK_287B_CALLABLE_TERMINAL_RE.match(terminal):
        return False
    return _check_287b_module_has_attr(parent, terminal, attr_cache)


def _check_287b_line_sha256(line: str) -> str:
    """Return an exact content fingerprint for a waiver-manifest line."""
    return hashlib.sha256(line.encode("utf-8")).hexdigest()


def _check_287b_load_waiver_manifest(
    root: Path,
) -> dict[tuple[str, int, str], str | None]:
    """Load exact append-only waiver entries for historical research prose.

    The ledger lets Catalog #287-v2 respect `.omx/research` historical
    provenance: old dated memos stay byte-preserved, while waiver authority
    lives in a tracked append-only state file. Each waiver is exact to
    `(relpath, line, dotted)` and, when present, the line SHA-256.
    """
    path = root / _CHECK_287B_WAIVER_MANIFEST_REL
    waivers: dict[tuple[str, int, str], str | None] = {}
    try:
        lines = path.read_text(encoding="utf-8").splitlines()
    except OSError:
        return waivers
    for raw in lines:
        if not raw.strip():
            continue
        try:
            row = json.loads(raw)
        except json.JSONDecodeError:
            continue
        if not isinstance(row, dict):
            continue
        if row.get("schema_version") != _CHECK_287B_WAIVER_SCHEMA:
            continue
        relpath = row.get("relpath")
        line = row.get("line")
        dotted = row.get("dotted")
        rationale = str(row.get("rationale", "")).strip()
        if not isinstance(relpath, str) or not isinstance(dotted, str):
            continue
        if not isinstance(line, int) or line <= 0:
            continue
        if _is_placeholder_gate_waiver_rationale(
            rationale,
            _CHECK_287B_WAIVER_PLACEHOLDERS,
        ):
            continue
        line_sha = row.get("line_sha256")
        if line_sha is not None and not (
            isinstance(line_sha, str)
            and len(line_sha) == 64
            and all(c in "0123456789abcdef" for c in line_sha.lower())
        ):
            continue
        waivers[(relpath, line, dotted)] = line_sha
    return waivers


def _check_287b_manifest_waives(
    waivers: Mapping[tuple[str, int, str], str | None],
    relpath: str,
    line_no: int,
    dotted: str,
    line_text: str,
) -> bool:
    """Return True for an exact manifest waiver whose optional line hash matches."""
    line_sha = waivers.get((relpath, line_no, dotted))
    if (relpath, line_no, dotted) not in waivers:
        return False
    if line_sha is None:
        return True
    return _check_287b_line_sha256(line_text) == line_sha


def _check_287b_file_waived(text: str) -> bool:
    """File-level waiver `PHANTOM_NAME_DESIGN_PROPOSAL_OK_FILE` in first 30 lines."""
    head_lines = text.splitlines()[:30]
    for line in head_lines:
        m = _CHECK_287B_FILE_WAIVER_RE.search(line)
        if m:
            rationale = m.group(1).strip()
            if not _is_placeholder_gate_waiver_rationale(
                rationale,
                _CHECK_287B_WAIVER_PLACEHOLDERS,
            ):
                return True
    return False


def _check_287b_line_waived(line: str) -> bool:
    """Same-line waiver via either PHANTOM_NAME_INTENTIONAL_OK or
    DESIGN_PROPOSAL_NOT_YET_IMPLEMENTED. Placeholder rationale rejected.
    """
    for regex in (
        _CHECK_287B_INLINE_WAIVER_PHANTOM_RE,
        _CHECK_287B_INLINE_WAIVER_PROPOSAL_RE,
    ):
        m = regex.search(line)
        if m:
            rationale = m.group(1).strip()
            if not _is_placeholder_gate_waiver_rationale(
                rationale,
                _CHECK_287B_WAIVER_PLACEHOLDERS,
            ):
                return True
    return False


def _check_287b_scan_research_memos(
    root: Path,
    *,
    scan_memory: bool = False,
) -> list[str]:
    """Sub-scope B implementation — scan `.omx/research/*.md` for phantom
    `tac.X` citations. Returns list of violation strings.

    Memory files (`~/.claude/projects/-Users-adpena-Projects-pact/memory/
    feedback_*.md`) excluded by default per OSS-hermeticity. Opt-in via
    `scan_memory=True` for operator-side audits.
    """
    violations: list[str] = []
    research_dir = root / ".omx" / "research"
    targets: list[Path] = []
    if research_dir.is_dir():
        targets.extend(research_dir.rglob("*.md"))
    if scan_memory:
        memory_dir = Path.home() / ".claude" / "projects" / "-Users-adpena-Projects-pact" / "memory"
        if memory_dir.is_dir():
            targets.extend(memory_dir.glob("feedback_*.md"))
    # Cache module-importability decisions across the whole scan for speed.
    importable_cache: dict[str, bool] = {}
    attr_cache: dict[tuple[str, str], bool] = {}
    manifest_waivers = _check_287b_load_waiver_manifest(root)
    for path in targets:
        try:
            rel = path.relative_to(root).as_posix()
        except ValueError:
            # path is outside repo root (e.g., memory file in $HOME)
            rel = str(path)
        # Self-exempt: design memos + test fixtures contain verbatim
        # phantom citations.
        if any(rel.endswith(suffix) for suffix in _CHECK_287B_SELF_EXEMPT_SUFFIXES):
            continue
        # Design memos describing this scope-extension itself.
        if "catalog_287_scope_extension_to_research_md_phantom_api_design" in rel:
            continue
        if any(marker in rel for marker in _CHECK_287B_EXCLUDED_PATH_MARKERS):
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        file_waived = _check_287b_file_waived(text)
        masked = _check_287b_strip_code_fences_and_html_comments(text)
        for i, line in enumerate(masked.splitlines()):
            # Per-line waiver short-circuit
            if _check_287b_line_waived(line):
                continue
            file_waiver_allows_line = file_waived and not _check_287b_authority_claim_line(line)
            if file_waiver_allows_line:
                continue
            for match in _CHECK_287B_TAC_MODULE_NAME_RE.finditer(line):
                dotted = match.group(0)
                if _check_287b_manifest_waives(
                    manifest_waivers,
                    rel,
                    i + 1,
                    dotted,
                    line,
                ):
                    continue
                if file_waived:
                    if _check_287b_authority_dotted_reference_ok(
                        dotted,
                        importable_cache,
                        attr_cache,
                    ):
                        continue
                    violations.append(
                        f"{rel}:{i + 1}: file-level proposal waiver cannot "
                        f"mask active authority claim `{dotted}` — full "
                        "dotted path is not importable. Cite the actual "
                        "importable canonical name or add a same-line "
                        "`# DESIGN_PROPOSAL_NOT_YET_IMPLEMENTED:<rationale>` "
                        "/ `# PHANTOM_NAME_INTENTIONAL_OK:<rationale>` waiver "
                        "if the line is historical/proposal prose."
                    )
                    continue
                prefix = _check_287b_extract_two_component_prefix(dotted)
                if prefix is None:
                    continue
                if prefix not in importable_cache:
                    importable_cache[prefix] = (
                        _check_287b_module_is_importable(prefix)
                    )
                if importable_cache[prefix]:
                    continue
                violations.append(
                    f"{rel}:{i + 1}: phantom `tac.X` citation `{dotted}` "
                    f"— 2-component prefix `{prefix}` is not importable. "
                    "Per CLAUDE.md 'Bugs must be permanently fixed AND "
                    "self-protected against' + Catalog #287 scope-"
                    "extension (META-PHANTOM-API-STRUCTURAL-EXTINCTION). "
                    "Acceptance: (a) cite the actual importable canonical "
                    "name; (b) same-line waiver `# PHANTOM_NAME_"
                    "INTENTIONAL_OK:<rationale>`; (c) same-line waiver "
                    "`# DESIGN_PROPOSAL_NOT_YET_IMPLEMENTED:<rationale>` "
                    "for proposals; (d) file-level waiver `# PHANTOM_NAME"
                    "_DESIGN_PROPOSAL_OK_FILE:<rationale>` in first 30 "
                    "lines for whole-file proposal memos."
                )
                # one violation per (line, dotted) is enough; keep scanning
                # other dotted citations on the same line for completeness
    return violations


def check_no_docstring_overstatement_without_evidence_tag(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
    scan_research_memos: bool = True,
    scan_memory_files: bool = False,
) -> list[str]:
    """Catalog #287 - GAP-4a docstring-overstatement evidence-tag gate
    + Catalog #287-B SCOPE-EXTENSION 2026-05-18 phantom-API in research
    memos.

    **Sub-scope A** (original): scans ``src/tac/**/*.py`` for percentage /
    multiplier overstatement patterns without an adjacent
    ``[empirical:<artifact>]`` / ``[contest-CUDA]`` / ``[prediction]`` /
    ``[advisory only]`` axis tag within ±5 lines. Per CLAUDE.md "Forbidden
    empirical-claim-without-evidence-tag (the docstring-overstatement
    trap)" forbidden pattern + OMNIBUS GAP-4a.

    Same-line waiver (sub-scope A): ``# DOCSTRING_PERCENT_CLAIM_OK:
    <rationale>`` (placeholder ``<rationale>`` / ``<reason>`` literals
    rejected).

    **Sub-scope B** (2026-05-18 scope-extension): scans
    ``.omx/research/**/*.md`` for ``tac.X[.Y...]`` module-name citations
    and refuses any whose 2-component prefix ``tac.X`` is not importable
    via ``importlib.util.find_spec()``. Acceptance: (a) cite the actual
    importable name; (b) same-line waiver ``# PHANTOM_NAME_INTENTIONAL_OK:
    <rationale>``; (c) same-line waiver
    ``# DESIGN_PROPOSAL_NOT_YET_IMPLEMENTED:<rationale>`` for proposed
    helpers; (d) file-level waiver ``# PHANTOM_NAME_DESIGN_PROPOSAL_OK_
    FILE:<rationale>`` in first 30 lines for whole-file proposal memos.
    File-level waivers do not suppress active authority lines such as
    landed/wired/grep-verified claims; those lines must cite an actually
    importable dotted path or carry a same-line waiver. Placeholder rationales
    rejected. Memory files opt-in via ``scan_memory_files=True`` (default OFF
    for OSS hermeticity per Catalog #290/#291/#292 sister design).

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected
    against" non-negotiable + operator decision E.1 2026-05-18 +
    grand council T3 finding #5 PROCEED. 17 cumulative META-audit
    instances of phantom-API citations established the bug class is
    structural.

    Self-exempt: ``src/tac/preflight.py`` (regex literals + this
    docstring), ``src/tac/tests/test_check_287_phantom_api_research_md_
    extension.py`` (verbatim violation samples), the 15th-instance source
    memo, and design memos matching
    ``catalog_287_scope_extension_to_research_md_phantom_api_design*``.

    Strict-flipped 2026-05-19 after source evidence-tag backfill,
    canonical-name correction, proposal-waiver backfill, and file-level
    waiver hardening for active authority lines.

    Memory: ``feedback_phase_2_land_5_gap_gates_omnibus_followon_landed_
    20260515.md`` (original) + ``feedback_catalog_287_scope_extended_to_
    research_md_phantom_api_landed_20260518.md`` (scope-extension).
    Lane: ``lane_meta_phantom_api_structural_extinction_catalog_287_
    scope_extend_20260518``.
    """
    root = Path(repo_root or REPO_ROOT)
    violations: list[str] = []

    # Sub-scope A — original src/tac/**/*.py docstring scan
    src_dir = root / "src" / "tac"
    if src_dir.is_dir():
        self_exempt = {root / "src" / "tac" / "preflight.py"}
        for path in src_dir.rglob("*.py"):
            if path in self_exempt:
                continue
            rel = path.relative_to(root).as_posix()
            if any(marker in rel for marker in _CHECK_287_EXCLUDED_PATH_MARKERS):
                continue
            try:
                text = path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            lines = text.splitlines()
            for i, line in enumerate(lines):
                for pat in _CHECK_287_OVERSTATEMENT_PATTERNS:
                    if pat.search(line):
                        # Same-line waiver?
                        waiver_match = _CHECK_287_WAIVER_RE.search(line)
                        if waiver_match:
                            rationale = waiver_match.group(1).strip()
                            if not _is_placeholder_gate_waiver_rationale(
                                rationale,
                                _CHECK_287_WAIVER_PLACEHOLDERS,
                            ):
                                continue
                        # Adjacent evidence tag (±5 lines)?
                        lo = max(0, i - 5)
                        hi = min(len(lines), i + 6)
                        window = "\n".join(lines[lo:hi])
                        if any(tag in window for tag in _CHECK_287_EVIDENCE_TAG_PATTERNS):
                            continue
                        violations.append(
                            f"{path.relative_to(root)}:{i + 1}: empirical claim "
                            f"`{line.strip()[:120]}` lacks adjacent evidence tag "
                            "([empirical:<path>] / [contest-CUDA] / [prediction] "
                            "/ [advisory only]) per CLAUDE.md 'Forbidden empirical-"
                            "claim-without-evidence-tag' + Catalog #287. Same-line "
                            "waiver: `# DOCSTRING_PERCENT_CLAIM_OK:<rationale>`."
                        )
                        break  # one violation per line is enough

    # Sub-scope B — 2026-05-18 scope-extension: research memo phantom-API scan
    if scan_research_memos:
        violations.extend(
            _check_287b_scan_research_memos(root, scan_memory=scan_memory_files)
        )

    if verbose:
        if violations:
            print(
                f"  [check_no_docstring_overstatement_without_evidence_tag] "
                f"{len(violations)} violation(s) (warn-only initially)"
            )
        else:
            print(
                "  [check_no_docstring_overstatement_without_evidence_tag] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_no_docstring_overstatement_without_evidence_tag found "
            f"{len(violations)} violation(s). Per CLAUDE.md 'Forbidden "
            "empirical-claim-without-evidence-tag' forbidden pattern + "
            "Catalog #287 (OMNIBUS GAP-4a) + Catalog #287-B scope-extension "
            "(META-PHANTOM-API-STRUCTURAL-EXTINCTION 2026-05-18). Every "
            "percentage / multiplier claim MUST carry an adjacent evidence "
            "tag; every `tac.X` citation in `.omx/research/*.md` MUST be "
            "an importable module OR carry the canonical waiver.\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #288 - check_uv_torch_install_has_driver_version_pin
#
# OMNIBUS-BUG-CLASS-AUDIT GAP-4b (2026-05-15) uv-torch driver-pin gate per
# CLAUDE.md "Forbidden uv torch install without driver-version pin (the
# cu13-vs-cu124 trap)" forbidden pattern.
#
# Bug class: `uv pip install torch` / `uv add torch` / `uv run --with torch`
# (no local-version suffix) defaults to the LATEST CUDA wheel from PyPI
# (currently `+cu13`). On a Vast.ai host with NVIDIA driver < 580 (CUDA 12.x),
# the cu13 wheel will FAIL `torch.cuda.init()` and silently fall back to CPU
# - every score becomes `[advisory only]` per the MPS-falsification rule.
#
# Anchor: 2026-05-01 instance 35957332 silently ran inflate on CPU for 5 min
# before detection. Memory:
# `feedback_vast_cuda_driver_too_old_silent_cpu_fallback_20260501.md`.
# ============================================================================

_CHECK_288_UV_TORCH_PATTERNS: tuple[re.Pattern, ...] = (
    re.compile(r"\buv\s+pip\s+install\s+torch(?!\+cu\d{2,3})(?!\+cpu)"),
    re.compile(r"\buv\s+add\s+torch(?!\+cu\d{2,3})(?!\+cpu)"),
    re.compile(r"\buv\s+run\s+--with\s+torch(?!\+cu\d{2,3})(?!\+cpu)"),
)
_CHECK_288_INDEX_OPT_OUT_TOKENS: tuple[str, ...] = (
    "--index https://download.pytorch.org/whl/cu",
    "--index-url https://download.pytorch.org/whl/cu",
    "--extra-index-url https://download.pytorch.org/whl/cu",
    "INFLATE_TORCH_SPEC",
    "UV_EXTRA_INDEX_URL=https://download.pytorch.org/whl/cu",
    "torch==2.5.1+cu",
    "torch==2.6.0+cu",
)
_CHECK_288_WAIVER_RE = re.compile(
    r"#\s*UV_TORCH_DRIVER_PIN_OK\s*:\s*([^\s][^\n#]{0,200})"
)
_CHECK_288_WAIVER_PLACEHOLDERS = frozenset(("<rationale>", "<reason>", ""))
_CHECK_288_EXCLUDED_PATH_MARKERS: tuple[str, ...] = (
    "experiments/results/",
    "_intake_",
    ".omx/oss_export/",
    "vendored",
    "build/lib/",
    "reports/raw/",
    "/tests/",
    "/test_",
    ".venv/",
    "__pycache__/",
)


def check_uv_torch_install_has_driver_version_pin(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #288 - GAP-4b uv-torch driver-version pin gate.

    Scans ``*.sh`` + ``*.yml`` + ``Dockerfile`` files under ``scripts/``,
    ``tools/``, ``experiments/`` for ``uv pip install torch`` / ``uv add
    torch`` / ``uv run --with torch`` invocations missing a local-version
    suffix (``+cu124`` / ``+cu118`` / ``+cpu``) or an explicit
    ``--index https://download.pytorch.org/whl/cuXXX`` flag.

    Per CLAUDE.md "Forbidden uv torch install without driver-version pin
    (the cu13-vs-cu124 trap)" forbidden pattern + OMNIBUS GAP-4b.

    Same-line waiver: ``# UV_TORCH_DRIVER_PIN_OK:<rationale>`` (placeholder
    ``<rationale>`` / ``<reason>`` literals rejected). Self-exempt:
    ``src/tac/preflight.py`` (carries the regex literals).

    STRICT-from-byte-one per CLAUDE.md "Strict-flip atomicity rule" — live
    count at landing: 0 (the canonical wrapper
    ``scripts/remote_archive_only_eval.sh:88-95`` already auto-pins).

    Memory: ``feedback_phase_2_land_5_gap_gates_omnibus_followon_landed_20260515.md``.
    Lane: ``lane_phase_2_land_5_gap_gates_20260515``.
    """
    root = Path(repo_root or REPO_ROOT)
    self_exempt = {root / "src" / "tac" / "preflight.py"}
    scan_dirs = ("scripts", "tools", "experiments")
    file_globs = ("*.sh", "*.yml", "*.yaml", "Dockerfile")
    violations: list[str] = []
    for scan_dir in scan_dirs:
        d = root / scan_dir
        if not d.is_dir():
            continue
        for glob in file_globs:
            for path in d.rglob(glob):
                if path in self_exempt:
                    continue
                rel = path.relative_to(root).as_posix()
                if any(marker in rel for marker in _CHECK_288_EXCLUDED_PATH_MARKERS):
                    continue
                try:
                    text = path.read_text(encoding="utf-8", errors="replace")
                except OSError:
                    continue
                # Quick filter: must contain `uv` and `torch`
                if "uv" not in text or "torch" not in text:
                    continue
                # File-level opt-out tokens (centralized pin via env-var, etc.)
                if any(tok in text for tok in _CHECK_288_INDEX_OPT_OUT_TOKENS):
                    continue
                lines = text.splitlines()
                for i, line in enumerate(lines):
                    for pat in _CHECK_288_UV_TORCH_PATTERNS:
                        if pat.search(line):
                            # Same-line waiver?
                            waiver_match = _CHECK_288_WAIVER_RE.search(line)
                            if waiver_match:
                                rationale = waiver_match.group(1).strip()
                                if not _is_placeholder_gate_waiver_rationale(
                                    rationale,
                                    _CHECK_288_WAIVER_PLACEHOLDERS,
                                ):
                                    break
                            # Inline cu suffix on same line?
                            if "+cu" in line or "+cpu" in line:
                                break
                            violations.append(
                                f"{path.relative_to(root)}:{i + 1}: unpinned "
                                f"`{line.strip()[:120]}` per CLAUDE.md "
                                "'Forbidden uv torch install without driver-"
                                "version pin (cu13-vs-cu124 trap)' + Catalog "
                                "#288. Fix: add `+cu124` local-version suffix "
                                "OR set `INFLATE_TORCH_SPEC=torch==2.5.1+cu124` "
                                "+ `UV_EXTRA_INDEX_URL=https://download.pytorch."
                                "org/whl/cu124` per "
                                "scripts/remote_archive_only_eval.sh:88-95. "
                                "Same-line waiver: `# UV_TORCH_DRIVER_PIN_OK:"
                                "<rationale>`."
                            )
                            break
    if verbose:
        if violations:
            print(
                f"  [check_uv_torch_install_has_driver_version_pin] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_uv_torch_install_has_driver_version_pin] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_uv_torch_install_has_driver_version_pin found "
            f"{len(violations)} violation(s). Per CLAUDE.md 'Forbidden uv "
            "torch install without driver-version pin (cu13-vs-cu124 trap)' "
            "forbidden pattern + Catalog #288 (OMNIBUS GAP-4b). Unpinned "
            "torch installs silently fall back to CPU on driver < 580; "
            "every score becomes [advisory only].\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #289 - check_serializer_log_no_dropped_expected_content_sha_retry_pattern
#
# OMNIBUS-BUG-CLASS-AUDIT GAP-5 (2026-05-15) commit-serializer drop-flag-and-
# retry detection per WAVE-D `feedback_commit_swap_incident_2c957c31e_
# forensic_analysis_landed_20260515.md` recommendation. META-meta-meta sister
# of Catalog #117/#157/#174.
#
# Bug class: even with #117 (serializer usage) + #157 (pre-pre-lock hash) +
# #174 (--expected-content-sha256 mandatory), the AGENT-RESPONSE failure mode
# remained: when the serializer refuses with rc=4 (mismatch), the agent could
# DROP the `--expected-content-sha256` flag on retry and silently absorb the
# sister's edits under the wrong commit body. This gate scans the
# `.omx/state/commit-serializer.log` JSONL for the WAVE-D 2c957c31e signature
# and refuses repository state where the pattern recurs.
#
# Sister of Catalog #117 (last-50-commit serializer usage), #157 (pre-pre-lock
# hash), #174 (--expected-content-sha256 mandatory), #216 (post-stage hash
# doc-only, now promoted to callable function). Together they extinct the
# commit-swap class at 4 surfaces: edit-time + pre-pre-lock + lock-arbitration
# + agent-response retry pattern.
# ============================================================================

_CHECK_289_LOG_RELPATH = (".omx", "state", "commit-serializer.log")
_CHECK_289_DROP_RETRY_WINDOW_SECONDS = 600  # 10 minutes per WAVE-D guidance
_CHECK_289_DISCIPLINE_CUTOFF_UTC = "2026-05-15T22:00:00Z"


def _check_289_parse_iso(s: str) -> float | None:
    """Best-effort ISO-8601 parser; returns None on bad input."""
    try:
        from datetime import datetime
        if s.endswith("Z"):
            s = s[:-1] + "+00:00"
        return datetime.fromisoformat(s).timestamp()
    except Exception:
        return None


def check_serializer_log_no_dropped_expected_content_sha_retry_pattern(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #289 - GAP-5 commit-serializer drop-flag-and-retry detection.

    Scans ``.omx/state/commit-serializer.log`` (JSONL append-only per Catalog
    #131 sister discipline) for the WAVE-D 2c957c31e signature: same
    ``message_head`` has ≥1 ``outcome=expected_content_sha_mismatch`` event
    followed by an ``outcome=committed`` event WITHOUT ``expected_content_sha_diffs``
    field within the next ~10-minute window.

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
    + WAVE-D forensic recommendation. Sister of Catalog #117/#157/#174/#216.

    Cutoff filter: only events at-or-after ``2026-05-15T22:00:00Z`` are
    scanned per CLAUDE.md "Strict-flip atomicity rule" — pre-cutoff legacy
    events are exempt as the discipline window had not opened.

    STRICT-from-byte-one per the same non-negotiable. Live count at landing:
    0 (no post-cutoff drop-flag-retry events expected; PHASE-1 + PHASE-2
    landings will use the canonical pattern).

    Memory: ``feedback_phase_2_land_5_gap_gates_omnibus_followon_landed_20260515.md``.
    Lane: ``lane_phase_2_land_5_gap_gates_20260515``.
    """
    root = Path(repo_root or REPO_ROOT)
    log_path = root.joinpath(*_CHECK_289_LOG_RELPATH)
    if not log_path.is_file():
        return []
    cutoff_ts = _check_289_parse_iso(_CHECK_289_DISCIPLINE_CUTOFF_UTC)
    if cutoff_ts is None:
        return []
    try:
        with log_path.open("r", encoding="utf-8", errors="replace") as fh:
            rows = []
            for line in fh:
                line = line.strip()
                if not line:
                    continue
                try:
                    rows.append(json.loads(line))
                except (json.JSONDecodeError, ValueError):
                    continue
    except OSError:
        return []

    # Group events by message_head, sort by started_at_utc; detect mismatch
    # followed by committed within window WITHOUT diffs field.
    by_head: dict[str, list[dict]] = {}
    for r in rows:
        if not isinstance(r, dict):
            continue
        head = r.get("message_head")
        if not isinstance(head, str):
            continue
        ts_str = r.get("started_at_utc", "")
        if not isinstance(ts_str, str):
            continue
        ts = _check_289_parse_iso(ts_str)
        if ts is None or ts < cutoff_ts:
            continue
        r["_ts"] = ts
        by_head.setdefault(head, []).append(r)

    violations: list[str] = []
    for head, events in by_head.items():
        events.sort(key=lambda x: x.get("_ts", 0.0))
        # Find mismatch then look for committed within window without diffs
        for i, ev in enumerate(events):
            if ev.get("outcome") != "expected_content_sha_mismatch":
                continue
            mismatch_ts = ev["_ts"]
            mismatch_files = ev.get("files", [])
            for j in range(i + 1, len(events)):
                later = events[j]
                if later["_ts"] - mismatch_ts > _CHECK_289_DROP_RETRY_WINDOW_SECONDS:
                    break
                if later.get("outcome") != "committed":
                    continue
                # Check overlap of files
                later_files = later.get("files", [])
                overlap = set(mismatch_files) & set(later_files)
                if not overlap:
                    continue
                # The committed retry MUST carry expected_content_sha256_present=True
                # (the new GAP-5 log field) if it re-passed the flag (correct
                # pattern). If field is False or absent AND nfiles >= 3, it's
                # the WAVE-D drop-flag pattern. Pre-GAP-5 events without the
                # field are EXEMPT (legacy logging schema; cutoff handles).
                if later.get("expected_content_sha256_present") is True:
                    continue  # correct re-pass per GAP-5 log
                if "expected_content_sha256_present" not in later:
                    continue  # pre-GAP-5 schema; exempt
                if len(later_files) < 3:
                    continue  # small commit, less risky
                violations.append(
                    f"commit-serializer.log: message_head=`{head[:80]}` had "
                    f"outcome=expected_content_sha_mismatch at {ev.get('started_at_utc')} "
                    f"followed by outcome=committed at {later.get('started_at_utc')} "
                    f"(nfiles={len(later_files)}) WITHOUT expected_content_sha_diffs "
                    "field — WAVE-D drop-flag-and-retry pattern (Catalog #289). "
                    "Fix: re-snapshot post-edit sha + re-pass --expected-content-"
                    "sha256 on retry per CLAUDE.md docstring-corrected canonical "
                    "contract; NEVER drop the flag."
                )
                break

    if verbose:
        if violations:
            print(
                f"  [check_serializer_log_no_dropped_expected_content_sha_retry_pattern] "
                f"{len(violations)} drop-flag-retry pattern(s)"
            )
        else:
            print(
                "  [check_serializer_log_no_dropped_expected_content_sha_retry_pattern] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_serializer_log_no_dropped_expected_content_sha_retry_pattern "
            f"found {len(violations)} drop-flag-retry pattern(s). Per CLAUDE.md "
            "'Bugs must be permanently fixed AND self-protected against' + "
            "Catalog #289 (OMNIBUS GAP-5 META-meta-meta sister of "
            "#117/#157/#174). The agent-response failure mode (DROP the "
            "--expected-content-sha256 flag on rc=4 retry) is the WAVE-D "
            "2c957c31e root cause; this gate refuses repository state where "
            "the pattern recurs.\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #290 - check_substrate_design_memo_has_canonical_vs_unique_decision_section
#
# KNOWLEDGE-PRESERVATION-WAVE 2026-05-15 self-protection per operator NON-
# NEGOTIABLE *"Save related memory and knowledge and instructions to prevent
# and make us smarter than ever and more capable and rigorous"* + retrospective
# *"this has been a huge problem since the beginning of the competition and
# prevented us from actually building original implementations because you
# didn't understand me and didn't understand the domain and problem space well
# enough at the time but we learned from PR 95 and just learned the same lesson
# again but across the entire contest and submission"*.
#
# Anchor memos:
#   - feedback_canonical_share_when_serves_unique_when_suppresses_standing_directive_20260515.md
#   - feedback_pr95_lesson_now_at_meta_level_unique_and_complete_per_method_default_20260515.md
#   - feedback_assumptions_challenge_audit_break_out_local_minima_landed_20260515.md
#
# Refuses repo-local `.omx/research/*_design_<YYYYMMDD>.md` memos, plus
# external memory memos only when ``memory_dir=...`` is passed explicitly, whose
# filename matches one of:
#   - ``feedback_*substrate*scaffold*landed_<YYYYMMDD>.md``
#   - ``feedback_nscs<N>_landed_<YYYYMMDD>.md``
#   - ``feedback_*substrate*v[0-9]+*landed_<YYYYMMDD>.md``
# AND whose date suffix is >= 2026-05-15 (this directive's date), AND whose
# body does NOT contain the literal section header
# ``## Canonical-vs-unique decision per layer`` (case-insensitive).
#
# Bug class: pre-rule, NEW substrate scaffolds inherited canonical helpers +
# META layer + shared engineering scaffold by default. Variance between
# substrates was the variance of the 10% NOT shared. The 0.196-0.199 cluster
# was what the SHARED 90% produced — a flat plateau encoded by my reflex
# toward canonical-helper-share. Per the new "UNIQUE-AND-COMPLETE-PER-METHOD"
# CLAUDE.md non-negotiable, every substrate scaffold design memo MUST document
# explicit per-layer canonical-vs-unique decisions so a reviewer can audit
# whether the substrate's optimal score path was suppressed by reflex
# canonicalization. The literal section header is the single structural
# requirement; the section's body content is the operator-facing audit
# surface.
#
# Acceptance: pre-cutoff memos exempt by date filter; post-cutoff memos with
# the literal section header pass; post-cutoff substrate scaffold memos
# without the header are flagged. Memos that are neither substrate-scaffold
# nor NSCS naming are out-of-scope by filename filter. External memory is
# opt-in so clean clones and CI see the same default result as the operator
# machine.
#
# WARN-ONLY initially per CLAUDE.md "Strict-flip atomicity rule" — the live
# count at landing is likely > 0 because 4 in-flight + just-completed
# scaffolds (STC-DASHER + ATW-CODEC + WUNDERKIND-G1-ENTROPY + U-DIE-KL) plus
# any sister-subagent NSCS scaffolds may be missing the section header.
# Strict-flip planned after the next backfill wave.
#
# Sister of:
#   - Catalog #220 (substrate L1 scaffold operational mechanism declaration —
#     same META class at the runtime-effect surface; #290 catches the
#     design-memo-discipline surface)
#   - Catalog #229 (premise-verification-before-edit — same per-memo
#     discipline pattern at the verification surface)
#   - Catalog #241 (substrate META layer contract — encodes the canonical
#     fields; #290 forces the design memo to document why each canonical
#     was adopted vs forked)
# ============================================================================

# Cutoff date suffix; memos dated before this are exempt.
_CHECK_290_CUTOFF_DATE_SUFFIX_INT = 20260515

# Literal section header (case-insensitive substring match).
_CHECK_290_REQUIRED_SECTION_HEADER = "## canonical-vs-unique decision per layer"

# Filename patterns scoping which memos are subject to this gate.
# Matches: feedback_*substrate*scaffold*landed_<YYYYMMDD>.md
#          feedback_nscs<digits>_landed_<YYYYMMDD>.md
#          feedback_*substrate*v<digits>*landed_<YYYYMMDD>.md
_CHECK_290_SUBSTRATE_SCAFFOLD_FILENAME_RE = re.compile(
    r"^feedback_.*substrate.*scaffold.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_290_NSCS_FILENAME_RE = re.compile(
    r"^feedback_nscs\d+.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_290_SUBSTRATE_V_N_FILENAME_RE = re.compile(
    r"^feedback_.*substrate.*_v\d+.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_290_RESEARCH_DESIGN_FILENAME_RE = re.compile(
    r"^.*_design_(\d{8})\.md$",
    re.IGNORECASE,
)


def _check_290_in_scope(filename: str) -> int | None:
    """Return parsed YYYYMMDD int if the filename is in-scope, else None."""
    for regex in (
        _CHECK_290_SUBSTRATE_SCAFFOLD_FILENAME_RE,
        _CHECK_290_NSCS_FILENAME_RE,
        _CHECK_290_SUBSTRATE_V_N_FILENAME_RE,
        _CHECK_290_RESEARCH_DESIGN_FILENAME_RE,
    ):
        m = regex.match(filename)
        if m:
            try:
                return int(m.group(1))
            except (TypeError, ValueError):
                return None
    return None


def _check_290_default_memory_dir() -> Path | None:
    """No external memory scan by default.

    Catalog #290 is a repository preflight gate; clean clones and CI must see
    the same result as the operator machine. Pass ``memory_dir=...`` explicitly
    when auditing local Claude memory.
    """
    return None


def _check_290_default_research_dir(repo_root: Path | str | None = None) -> Path:
    """Default in-repo research design-memo directory."""
    root = Path(repo_root or REPO_ROOT).resolve()
    return root / ".omx" / "research"


def check_substrate_design_memo_has_canonical_vs_unique_decision_section(
    *,
    memory_dir: Path | str | None = None,
    research_dir: Path | str | None = None,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #290 — refuse substrate scaffold landing memos missing the
    canonical-vs-unique decision section.

    Per CLAUDE.md "UNIQUE-AND-COMPLETE-PER-METHOD operating mode" non-
    negotiable. Every substrate scaffold landing memo dated >= 2026-05-15 MUST
    contain the literal section header
    ``## Canonical-vs-unique decision per layer`` (case-insensitive) so the
    operator and future agents can audit which canonical helpers were adopted
    vs forked AND why. The historical mistake (operator's retrospective): the
    reflex toward canonicalization was the structural cause of the 0.1928
    cluster.

    Acceptance:
    - Pre-cutoff memos (date < 2026-05-15) are exempt by date filter.
    - In-scope memos with the literal header pass.
    - In-scope memos without the header are flagged.
    - In-repo ``.omx/research/*_design_<YYYYMMDD>.md`` memos are in scope:
      those are the active design surface subagents land before memory
      rollups exist.
    - External memory memos are scanned only when ``memory_dir`` is passed
      explicitly; default behavior is clone-stable and repo-local.

    Sister of Catalog #220 (substrate L1 operational mechanism) + Catalog
    #229 (premise-verification-before-edit) + Catalog #241 (substrate META
    layer contract).

    Memory: ``feedback_knowledge_preservation_pr95_meta_level_lesson_landed_20260515.md``.
    Lane: ``lane_knowledge_preservation_pr95_meta_level_lesson_20260515``.
    """
    if memory_dir is None:
        memory_target = _check_290_default_memory_dir()
    elif isinstance(memory_dir, str):
        memory_target = Path(memory_dir)
    else:
        memory_target = memory_dir
    if research_dir is None:
        research_target = _check_290_default_research_dir(repo_root)
    elif isinstance(research_dir, str):
        research_target = Path(research_dir)
    else:
        research_target = research_dir

    violations: list[str] = []
    seen_dirs: set[Path] = set()
    target_surfaces: list[tuple[Path, str]] = []
    if memory_target is not None:
        target_surfaces.append((memory_target, "memory"))
    target_surfaces.append((research_target, "research"))
    for target, surface in target_surfaces:
        try:
            resolved_target = target.resolve()
        except OSError:
            resolved_target = target
        if resolved_target in seen_dirs:
            continue
        seen_dirs.add(resolved_target)
        if not target.is_dir():
            continue
        try:
            candidates = sorted(target.iterdir())
        except OSError:
            continue
        for entry in candidates:
            if not entry.is_file():
                continue
            date_int = _check_290_in_scope(entry.name)
            if date_int is None:
                continue  # filename not in scope
            if date_int < _CHECK_290_CUTOFF_DATE_SUFFIX_INT:
                continue  # pre-cutoff memos exempt
            try:
                body = entry.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if _CHECK_290_REQUIRED_SECTION_HEADER in body.lower():
                continue
            try:
                rel = entry.relative_to(Path(repo_root or REPO_ROOT).resolve())
            except ValueError:
                rel = entry
            violations.append(
                f"{rel}: {surface} design/substrate memo dated {date_int} is "
                "missing the required '## Canonical-vs-unique decision per layer' "
                "section header (case-insensitive). Per CLAUDE.md "
                "'UNIQUE-AND-COMPLETE-PER-METHOD operating mode' non-negotiable: "
                "every substrate or codec design memo dated >= 2026-05-15 MUST "
                "document per-layer canonical-vs-unique decisions so a reviewer "
                "can audit whether the substrate's optimal score path was "
                "suppressed by reflex canonicalization."
            )

    if verbose:
        if violations:
            print(
                f"  [check_substrate_design_memo_has_canonical_vs_unique_decision_section] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_substrate_design_memo_has_canonical_vs_unique_decision_section] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_substrate_design_memo_has_canonical_vs_unique_decision_section "
            f"found {len(violations)} substrate scaffold memo(s) missing the "
            "required '## Canonical-vs-unique decision per layer' section. "
            "Per CLAUDE.md 'UNIQUE-AND-COMPLETE-PER-METHOD operating mode' + "
            "'Bugs must be permanently fixed AND self-protected against' "
            "non-negotiables. Catalog #290 (KNOWLEDGE-PRESERVATION-WAVE; "
            "sister of Catalog #220 + #229 + #241).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #291 - check_session_has_recent_meta_assumption_review
#
# L5-STAIRCASE-V2-AND-ADVERSARIAL-APPARATUS-STRUCTURAL-FIXES 2026-05-15
# self-protection per Adversarial-apparatus retrospective
# (`feedback_adversarial_review_apparatus_blind_to_shared_assumption_failure_meta_meta_meta_meta_20260515.md`)
# Fix 3.
#
# Anchor: NOT A SINGLE existing review apparatus (10+ codex reviews / multiple
# grand councils / skunkworks councils / 3-clean-pass / 270+ STRICT preflight
# gates / META-meta gates #118/#159/#176/#185 / Contrarian role) ever caught
# the canonicalization-by-default reflex suppressing substrate-optimal
# engineering across the entire contest. Operator catalysis was required.
# Structural cause: every existing review type operates WITHIN shared
# assumptions; none has explicit mandate to interrogate the BACKDROP.
#
# Mandate: every session must run a META-ASSUMPTION ADVERSARIAL REVIEW
# periodically (every 50 landings OR every 7 days, whichever first). Output:
# enumerate shared assumptions across recent work; per-assumption "if
# violated, what would change?"; identify highest-EV violations; queue for
# next dispatch wave.
#
# This gate scans the repo-local `.omx/research` directory by default for the
# most-recent META-ASSUMPTION review / assumptions-challenge audit artifact
# (external operator memory can still be audited by passing memory_dir
# explicitly). Refuses any state where
# (a) more than 7 days have elapsed since the most-recent META-ASSUMPTION
# review OR (b) more than 50 subagent landings (counted from
# `.omx/state/commit-serializer.log` events with outcome=committed) have
# occurred since the most-recent META-ASSUMPTION review.
#
# WARN-ONLY initially per CLAUDE.md "Strict-flip atomicity rule" — live
# count at landing: 0 because today's ASSUMPTIONS-CHALLENGE-AUDIT is the
# first instance + most-recent. Strict-flip atomic with the first cycle
# completion (i.e. when a future session actually triggers the recurring
# protocol).
#
# Sister of:
#   - Catalog #229 (premise-verification-before-edit; same per-discipline
#     pattern at the verification surface; #291 is at the META-ASSUMPTION
#     periodic surface)
#   - Catalog #185 (LIVE_COUNT drift between CLAUDE.md text and gate
#     empirical state; same drift-prevention pattern)
#   - Catalog #290 (substrate scaffold canonical-vs-unique discipline; #290
#     enforces per-design-memo while #291 enforces per-session)
# ============================================================================

# Gate triggers strict refusal when EITHER condition is met. Both serve as
# orthogonal canaries: time-based catches sessions that touch many files
# without committing; landings-based catches high-velocity sessions that
# could otherwise drift far from the last review even within 7 days.
_CHECK_291_MAX_DAYS_SINCE_LAST_REVIEW = 7
_CHECK_291_MAX_LANDINGS_SINCE_LAST_REVIEW = 50

# Filename patterns matching valid META-ASSUMPTION review memos.
_CHECK_291_REVIEW_FILENAME_RE = re.compile(
    r"^(?:feedback_)?(?:.*meta_assumption.*review.*|"
    r".*assumptions_challenge_audit.*).*?(\d{8}).*\.(?:md|json)$",
    re.IGNORECASE,
)

# Memo body must contain at least one of these tokens to count as a real
# META-ASSUMPTION review (prevents an empty placeholder file from satisfying
# the gate). Mirrors the canonical 18-assumption matrix vocabulary.
_CHECK_291_REVIEW_BODY_TOKENS: tuple[str, ...] = (
    "shared assumption",
    "shared assumptions",
    "shared_assumption",
    "shared_assumptions",
    "assumption-violation",
    "assumption violation",
    "if violated",
    "META-ASSUMPTION",
    "meta-assumption",
    "ASSUMPTIONS-CHALLENGE-AUDIT",
)


def _check_291_default_memory_dir(repo_root: Path | str | None = None) -> Path:
    """Default to repo-local research artifacts for OSS-hermetic preflight.

    External Claude memory is machine-local state. Pass ``memory_dir=...``
    explicitly when auditing it, but do not make clean clones depend on it.
    """
    root = Path(repo_root or REPO_ROOT).resolve()
    return root / ".omx" / "research"


def _check_291_parse_date_suffix(suffix: str) -> tuple[int, int, int] | None:
    """Parse YYYYMMDD into (Y, M, D); return None on malformed."""
    if len(suffix) != 8:
        return None
    try:
        year = int(suffix[0:4])
        month = int(suffix[4:6])
        day = int(suffix[6:8])
    except ValueError:
        return None
    if not (1 <= month <= 12 and 1 <= day <= 31):
        return None
    return (year, month, day)


def _check_291_find_most_recent_review(memory_dir: Path) -> tuple[Path, tuple[int, int, int]] | None:
    """Return (path, (Y, M, D)) of the most-recent in-scope review memo, or None.

    A memo counts only if its filename matches the regex AND its body
    contains at least one canonical META-ASSUMPTION review token (prevents
    placeholder-file gaming).
    """
    if not memory_dir.is_dir():
        return None
    best: tuple[Path, tuple[int, int, int]] | None = None
    try:
        candidates = sorted(memory_dir.iterdir())
    except OSError:
        return None
    for entry in candidates:
        if not entry.is_file():
            continue
        m = _CHECK_291_REVIEW_FILENAME_RE.match(entry.name)
        if not m:
            continue
        date_tuple = _check_291_parse_date_suffix(m.group(1))
        if date_tuple is None:
            continue
        try:
            body = entry.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        body_lower = body.lower()
        if not any(tok.lower() in body_lower for tok in _CHECK_291_REVIEW_BODY_TOKENS):
            continue  # placeholder file w/ matching name but no real content
        if best is None or date_tuple > best[1]:
            best = (entry, date_tuple)
    return best


def _check_291_count_subagent_landings_since(
    serializer_log: Path, since_iso_utc: str
) -> int:
    """Count `outcome=committed` events in commit-serializer.log whose
    ``written_at_utc`` (or ``started_at_utc`` fallback) is strictly after
    ``since_iso_utc`` (an ISO-8601 UTC timestamp). Returns 0 on missing /
    unreadable log (fail-OPEN; the time-since-last canary still fires).

    The strictly-after semantics deliberately excludes the review memo's
    own creation event and any sister-subagent commits in the same
    session-batch, so the cadence cannot trip on its own landing.
    """
    if not serializer_log.is_file():
        return 0
    count = 0
    try:
        for line in serializer_log.read_text(encoding="utf-8", errors="replace").splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                continue
            if not isinstance(row, dict):
                continue
            outcome = row.get("outcome")
            if outcome != "committed":
                continue
            written = row.get("written_at_utc") or row.get("started_at_utc") or ""
            if not isinstance(written, str):
                continue
            # Compare lexicographically on ISO-8601 (works because ISO-8601
            # sorts in calendar order). Strictly greater so the review memo's
            # own session-batch is not counted against itself.
            if written > since_iso_utc:
                count += 1
    except OSError:
        return 0
    return count


def check_session_has_recent_meta_assumption_review(
    *,
    memory_dir: Path | str | None = None,
    serializer_log: Path | str | None = None,
    repo_root: Path | str | None = None,
    now_utc: "_dt.datetime | None" = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #291 — refuse sessions that have drifted past the recurring
    META-ASSUMPTION ADVERSARIAL REVIEW cadence.

    Per CLAUDE.md "META-ASSUMPTION ADVERSARIAL REVIEW" non-negotiable:
    every session must run the periodic META-ASSUMPTION review (every 7
    days OR every 50 subagent landings, whichever first). The review
    enumerates shared assumptions across recent work; per assumption asks
    "if violated, what would change?"; identifies highest-EV violations;
    queues for next dispatch wave.

    Bug class: the structural blindness of EVERY existing review apparatus
    (codex / grand council / skunkworks / 3-clean-pass / 270+ STRICT
    preflight gates / META-meta-meta gates #118/#159/#176/#185 / Contrarian
    veto) to canonicalization-by-default suppression. The 0.196-0.199
    cluster across all substrates IS the empirical cost. Operator catalysis
    was required to surface this; the gate is the structural protection so
    future sessions do not repeat the blindness.

    Acceptance: a recent in-scope review/audit artifact exists in repo-local
    `.omx/research` by default, or in an explicitly passed `memory_dir`, AND
    (i) its date is within the last 7 days AND (ii) fewer than 50 subagent
    landings have occurred since its mtime.

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
    because today's ASSUMPTIONS-CHALLENGE-AUDIT is the FIRST instance and
    is by definition recent — live count at landing: 0. Strict-flip atomic
    with the first cycle completion.

    Sister of Catalog #229 (premise-verification-before-edit) + Catalog
    #185 (LIVE_COUNT drift) + Catalog #290 (substrate scaffold canonical-
    vs-unique discipline).

    Memory:
    ``feedback_l5_staircase_v2_and_adversarial_apparatus_structural_fixes_landed_20260515.md``.
    """
    if memory_dir is None:
        memory_target = _check_291_default_memory_dir(repo_root)
    elif isinstance(memory_dir, str):
        memory_target = Path(memory_dir)
    else:
        memory_target = memory_dir

    if serializer_log is None:
        log_target = Path(repo_root or REPO_ROOT) / ".omx" / "state" / "commit-serializer.log"
    elif isinstance(serializer_log, str):
        log_target = Path(serializer_log)
    else:
        log_target = serializer_log

    if now_utc is None:
        now_utc_resolved = _dt.datetime.now(_dt.timezone.utc)
    elif now_utc.tzinfo is None:
        now_utc_resolved = now_utc.replace(tzinfo=_dt.timezone.utc)
    else:
        now_utc_resolved = now_utc

    most_recent = _check_291_find_most_recent_review(memory_target)
    violations: list[str] = []

    if most_recent is None:
        violations.append(
            f"{memory_target}: no META-ASSUMPTION ADVERSARIAL REVIEW memo found "
            "matching `feedback_*meta_assumption*review*.md` OR "
            "`feedback_assumptions_challenge_audit_*.md` with canonical body "
            "tokens. Per CLAUDE.md 'META-ASSUMPTION ADVERSARIAL REVIEW' non-"
            "negotiable: every session must run the periodic review (every 7 "
            "days OR every 50 subagent landings, whichever first)."
        )
    else:
        memo_path, (y, m, d) = most_recent
        # Time-since-last is measured in DAYS at calendar precision (the
        # filename date suffix); landings-since-last is measured strictly
        # after the memo file's mtime so the gate cannot trip on its own
        # landing batch.
        try:
            review_date = _dt.datetime(y, m, d, tzinfo=_dt.timezone.utc)
        except ValueError:
            review_date = None
        try:
            mtime_iso = _dt.datetime.fromtimestamp(
                memo_path.stat().st_mtime, _dt.timezone.utc
            ).isoformat()
        except OSError:
            mtime_iso = f"{y:04d}-{m:02d}-{d:02d}T23:59:59+00:00"
        if review_date is not None:
            days_elapsed = (now_utc_resolved - review_date).days
            if days_elapsed > _CHECK_291_MAX_DAYS_SINCE_LAST_REVIEW:
                violations.append(
                    f"{memo_path.name}: most-recent META-ASSUMPTION ADVERSARIAL "
                    f"REVIEW is {days_elapsed} days old (max "
                    f"{_CHECK_291_MAX_DAYS_SINCE_LAST_REVIEW} per CLAUDE.md "
                    "'META-ASSUMPTION ADVERSARIAL REVIEW' non-negotiable cadence)."
                )
            landings = _check_291_count_subagent_landings_since(log_target, mtime_iso)
            if landings > _CHECK_291_MAX_LANDINGS_SINCE_LAST_REVIEW:
                violations.append(
                    f"{memo_path.name}: {landings} subagent landings have occurred "
                    f"since the most-recent META-ASSUMPTION ADVERSARIAL REVIEW "
                    f"(max {_CHECK_291_MAX_LANDINGS_SINCE_LAST_REVIEW} per "
                    "CLAUDE.md 'META-ASSUMPTION ADVERSARIAL REVIEW' non-negotiable "
                    "cadence; fan-out velocity exceeded the assumption-drift "
                    "guardrail)."
                )

    if verbose:
        if violations:
            print(
                f"  [check_session_has_recent_meta_assumption_review] "
                f"{len(violations)} violation(s)"
            )
        else:
            print("  [check_session_has_recent_meta_assumption_review] OK")
    if violations and strict:
        raise PreflightError(
            "check_session_has_recent_meta_assumption_review found "
            f"{len(violations)} META-ASSUMPTION review cadence violation(s). "
            "Per CLAUDE.md 'META-ASSUMPTION ADVERSARIAL REVIEW' non-negotiable + "
            "'Bugs must be permanently fixed AND self-protected against'. "
            "Catalog #291 (L5-STAIRCASE-V2-AND-ADVERSARIAL-APPARATUS-STRUCTURAL-"
            "FIXES; sister of Catalog #185 + #229 + #290).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #292 - check_grand_council_deliberation_has_explicit_assumption_statements
#
# OR2-GRAND-COUNCIL-PER-ROUND-ASSUMPTION-STATEMENT-DISCIPLINE 2026-05-15
# self-protection per Fix 7 of the Adversarial-apparatus retrospective
# (`feedback_adversarial_review_apparatus_blind_to_shared_assumption_failure_meta_meta_meta_meta_20260515.md`).
#
# Anchor: Catalog #291 enforces the periodic META-ASSUMPTION ADVERSARIAL
# REVIEW at the SESSION-LEVEL surface (every 7 days OR every 50 landings).
# But the structural blindness can recur WITHIN a single grand council
# deliberation that operates inside an unexamined assumption backdrop. Fix 7
# binds the discipline at the per-DELIBERATION-PER-ROUND surface: every
# council member, every round, must explicitly state "the shared assumption
# I am operating within for this design is X", and the Assumption-Adversary
# must evaluate X for HARD-EARNED vs CARGO-CULTED classification.
#
# Bug class: a grand council can fan out a clean Catalog #291 cadence (the
# session has a recent META-ASSUMPTION review) AND still produce an
# assumption-bound deliberation if individual members never surface their
# operating-within assumptions. The 0.196-0.199 cluster is the empirical
# cost of pre-2026-05-15 deliberations that reached consensus without
# per-member assumption-statement discipline.
#
# This gate scans `~/.claude/projects/-Users-adpena-Projects-pact/memory`
# (or any explicitly-passed `memory_dir`) for council deliberation memos
# matching `feedback_*council*.md` whose date suffix is >= the 2026-05-15
# cutoff (exempts legacy memos pre-Fix-7) and refuses any memo lacking the
# canonical per-round explicit-assumption-statement vocabulary AND the
# Assumption-Adversary evaluation block. Repo-local `.omx/research`
# council/symposium memos are also scanned so clean clones and CI see the
# same default result.
#
# Acceptance:
#   - Memo body contains a per-member operating-within phrase
#     (`operating within`, `shared assumption I am`, `the assumption I am`,
#     `the shared assumption`, `assumption I am operating within`) — at
#     least once per memo, OR
#   - Memo body contains `Assumption-Adversary` evaluation block (verifies
#     HARD-EARNED vs CARGO-CULTED classification was performed).
#   - Same-line `# COUNCIL_ASSUMPTION_STATEMENT_WAIVED:<rationale>` waiver
#     in the memo body honored for the rare deliberate text-only deferred
#     case (placeholder `<rationale>` / `<reason>` literals rejected so the
#     gate's docstring example cannot self-waive).
#
# WARN-ONLY initially per CLAUDE.md "Strict-flip atomicity rule" — live
# count at landing is likely > 0 because pre-2026-05-15 council memos may
# lack the discipline tokens; the date cutoff exempts them, but recent
# memos that landed before THIS gate's text amendment to "Council conduct"
# may still drift. Strict-flip planned after the next backfill wave once
# in-flight sister memos all carry the per-member tokens.
#
# Sister of:
#   - Catalog #291 (META-ASSUMPTION cadence — session-level cousin; #292
#     enforces per-deliberation discipline where #291 enforces per-session
#     cadence)
#   - Catalog #229 (premise-verification-before-edit — same per-discipline
#     pattern at the verification surface)
#   - Catalog #290 (substrate scaffold canonical-vs-unique discipline —
#     same per-memo discipline pattern at the substrate-design surface)
#   - Catalog #185 (CLAUDE.md catalog-text-vs-empirical-state drift — META-
#     meta-meta protection for this entry's claimed live count)
# ============================================================================

# Cutoff date suffix; council memos dated before this are exempt by date
# filter (legacy memos pre-Fix-7 cannot be expected to carry the new
# discipline tokens).
_CHECK_292_CUTOFF_DATE_SUFFIX_INT = 20260515

# Filename patterns matching council deliberation memos in scope.
# Matches:
#   feedback_*council*landed_<YYYYMMDD>.md
#   feedback_*grand_council*<YYYYMMDD>.md
#   feedback_*skunkworks_council*<YYYYMMDD>.md
#   feedback_*reunion*symposium*<YYYYMMDD>.md  (grand reunion symposium counts)
_CHECK_292_COUNCIL_FILENAME_RE = re.compile(
    r"^feedback_.*(?:grand_council|skunkworks_council|council|reunion.*symposium)"
    r".*?(\d{8}).*\.md$",
    re.IGNORECASE,
)

# Tokens that indicate per-member explicit assumption-statement discipline.
# A council memo passes if ANY of these tokens appears in the body. The
# tokens were derived from Fix 7 verbatim: "the shared assumption I am
# operating within for this design is X".
_CHECK_292_OPERATING_WITHIN_TOKENS: tuple[str, ...] = (
    "operating within",
    "shared assumption i am",
    "the assumption i am",
    "the shared assumption",
    "assumption i am operating within",
    "shared-assumption i am",
    "shared assumption for this",
    "my operating assumption",
    "operating assumption for this",
)

# Sister token-set: Assumption-Adversary evaluation block. A memo that
# performs explicit HARD-EARNED vs CARGO-CULTED classification per
# assumption is also accepted (the discipline is observable even if
# individual operating-within phrases are absent in the surface text).
_CHECK_292_ASSUMPTION_ADVERSARY_TOKENS: tuple[str, ...] = (
    "assumption-adversary",
    "assumption adversary",
    "hard-earned vs cargo-culted",
    "hard_earned vs cargo_culted",
    "hard earned vs cargo culted",
    "cargo-culted",
    "cargo_culted",
)

_CHECK_292_WAIVER_PATTERN = re.compile(
    r"#\s*COUNCIL_ASSUMPTION_STATEMENT_WAIVED\s*:\s*([^\s][^\n#]{0,200})"
)
_CHECK_292_WAIVER_PLACEHOLDERS = frozenset((
    "<rationale>",
    "<reason>",
    "",
))


def _check_292_parse_date_suffix(suffix: str) -> int | None:
    """Parse YYYYMMDD into a calendar-sortable int; return None on malformed."""
    if len(suffix) != 8:
        return None
    try:
        year = int(suffix[0:4])
        month = int(suffix[4:6])
        day = int(suffix[6:8])
    except ValueError:
        return None
    if not (1 <= month <= 12 and 1 <= day <= 31):
        return None
    return year * 10000 + month * 100 + day


def _check_292_has_waiver(body: str) -> bool:
    """Same-line waiver respected when rationale is non-placeholder."""
    for m in _CHECK_292_WAIVER_PATTERN.finditer(body):
        rationale = m.group(1).strip().lower()
        if rationale not in _CHECK_292_WAIVER_PLACEHOLDERS:
            return True
    return False


def _check_292_default_memory_dir() -> Path | None:
    """No external memory scan by default.

    Catalog #292 is a repository preflight gate; clean clones and CI must
    see the same default result as the operator machine. Pass
    ``memory_dir=...`` explicitly when auditing local Claude memory.
    """
    return None


def _check_292_default_research_dir(repo_root: Path | str | None = None) -> Path:
    """Default in-repo research council/symposium memo directory."""
    root = Path(repo_root or REPO_ROOT).resolve()
    return root / ".omx" / "research"


def check_grand_council_deliberation_has_explicit_assumption_statements(
    *,
    memory_dir: Path | str | None = None,
    research_dir: Path | str | None = None,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #292 — refuse grand council deliberation memos missing the
    per-round explicit-assumption-statement discipline.

    Per CLAUDE.md "Council conduct" Fix-7 amendment + "META-ASSUMPTION
    ADVERSARIAL REVIEW" non-negotiable. Every council deliberation memo
    dated >= 2026-05-15 MUST carry one of:

      1. A per-member operating-within phrase (e.g. "the shared assumption
         I am operating within for this design is X"), OR
      2. An Assumption-Adversary evaluation block (verifies HARD-EARNED vs
         CARGO-CULTED classification per round), OR
      3. A same-line ``# COUNCIL_ASSUMPTION_STATEMENT_WAIVED:<rationale>``
         waiver with non-placeholder rationale.

    Bug class: Catalog #291 enforces the periodic META-ASSUMPTION review
    cadence at the SESSION-LEVEL surface, but a council can still produce
    assumption-bound deliberation outputs WITHIN a clean cadence if no
    individual member surfaces their operating-within assumption. The
    0.196-0.199 cluster is the empirical cost of pre-Fix-7 deliberations
    that reached consensus without per-member assumption-statement
    discipline. The Assumption-Adversary council role (CLAUDE.md "Council
    conduct" sextet pact) is the runtime mechanism; this gate is the
    structural protection that refuses council memos lacking the
    discipline tokens.

    Acceptance:
      - Pre-cutoff memos (date < 2026-05-15) are exempt by date filter.
      - Post-cutoff council memos with operating-within phrase pass.
      - Post-cutoff council memos with Assumption-Adversary evaluation
        block pass.
      - Post-cutoff council memos with same-line waiver + non-placeholder
        rationale pass.
      - In-repo ``.omx/research/*council*.md`` and ``*symposium*.md`` are
        in scope.
      - External memory memos are scanned only when ``memory_dir`` is
        passed explicitly; default behavior is clone-stable and repo-local.

    Sister of Catalog #291 (session-level cadence) + Catalog #229 (premise
    verification) + Catalog #290 (substrate canonical-vs-unique discipline)
    + Catalog #185 (META-meta-meta CLAUDE.md drift detector).

    Memory:
    ``feedback_or2_grand_council_per_round_assumption_statement_discipline_landed_20260515.md``.

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
    rule" because pre-Fix-7 council memos may lack the discipline tokens
    even when dated >= cutoff (the cutoff was chosen TODAY; same-day
    legacy memos predating the Fix-7 amendment exist). Strict-flip planned
    after the next backfill wave clears in-flight sisters.
    """
    if memory_dir is None:
        memory_target = _check_292_default_memory_dir()
    elif isinstance(memory_dir, str):
        memory_target = Path(memory_dir)
    else:
        memory_target = memory_dir
    if research_dir is None:
        research_target = _check_292_default_research_dir(repo_root)
    elif isinstance(research_dir, str):
        research_target = Path(research_dir)
    else:
        research_target = research_dir

    violations: list[str] = []
    seen_dirs: set[Path] = set()
    target_surfaces: list[tuple[Path, str]] = []
    if memory_target is not None:
        target_surfaces.append((memory_target, "memory"))
    target_surfaces.append((research_target, "research"))

    for target, surface in target_surfaces:
        try:
            resolved_target = target.resolve()
        except OSError:
            resolved_target = target
        if resolved_target in seen_dirs:
            continue
        seen_dirs.add(resolved_target)
        if not target.is_dir():
            continue
        try:
            candidates = sorted(target.iterdir())
        except OSError:
            continue
        for entry in candidates:
            if not entry.is_file():
                continue
            m = _CHECK_292_COUNCIL_FILENAME_RE.match(entry.name)
            if not m:
                continue
            date_int = _check_292_parse_date_suffix(m.group(1))
            if date_int is None:
                continue
            if date_int < _CHECK_292_CUTOFF_DATE_SUFFIX_INT:
                continue
            try:
                body = entry.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            body_lower = body.lower()
            if any(tok in body_lower for tok in _CHECK_292_OPERATING_WITHIN_TOKENS):
                continue
            if any(tok in body_lower for tok in _CHECK_292_ASSUMPTION_ADVERSARY_TOKENS):
                continue
            if _check_292_has_waiver(body):
                continue
            try:
                rel = entry.relative_to(Path(repo_root or REPO_ROOT).resolve())
            except ValueError:
                rel = entry
            violations.append(
                f"{rel}: {surface} council memo dated {date_int} is missing the "
                "required per-round explicit-assumption-statement discipline. Per "
                "CLAUDE.md 'Council conduct' Fix-7 amendment + 'META-ASSUMPTION "
                "ADVERSARIAL REVIEW' non-negotiable: every council deliberation "
                "memo dated >= 2026-05-15 MUST carry one of (a) per-member "
                "operating-within phrase (e.g. 'the shared assumption I am "
                "operating within for this design is X'), (b) Assumption-Adversary "
                "evaluation block (HARD-EARNED vs CARGO-CULTED classification), "
                "or (c) same-line `# COUNCIL_ASSUMPTION_STATEMENT_WAIVED:"
                "<rationale>` waiver with non-placeholder rationale."
            )

    if verbose:
        if violations:
            print(
                f"  [check_grand_council_deliberation_has_explicit_assumption_statements] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_grand_council_deliberation_has_explicit_assumption_statements] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_grand_council_deliberation_has_explicit_assumption_statements "
            f"found {len(violations)} council deliberation memo(s) missing the "
            "per-round explicit-assumption-statement discipline. Per CLAUDE.md "
            "'Council conduct' Fix-7 amendment + 'META-ASSUMPTION ADVERSARIAL "
            "REVIEW' non-negotiable + 'Bugs must be permanently fixed AND self-"
            "protected against'. Catalog #292 (OR2-GRAND-COUNCIL-PER-ROUND-"
            "ASSUMPTION-STATEMENT-DISCIPLINE; sister of Catalog #185 + #229 + "
            "#290 + #291).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #293 - check_cathedral_literature_anchors_have_source_scope
#
# Cathedral/autopilot source-fidelity self-protection 2026-05-16. Sister of the
# Cathedral literature-anchor scope hardening that added explicit
# ``source_supports`` / ``paper_claim_scope`` / ``pact_must_prove`` /
# ``decode_complexity_evidence`` fields to the substrate composition matrix.
#
# Bug class: a Cathedral row can carry a persuasive ``literature_anchor`` and a
# predicted score band while silently dropping the boundary between (a) what the
# cited paper actually supports and (b) what Pact still must prove on byte-closed
# contest archives. That turns source citations into false authority and can
# steer the autopilot toward unsupported score-lowering claims. The guard keeps
# literature anchors as hypothesis provenance, not promotion evidence.
#
# STRICT-from-byte-one: live count is 0 because the source-scope fields landed
# before this gate. Future anchored rows must carry the complete scope contract
# in both the canonical inventory and serialized Pareto rows.
# ============================================================================

from tac.optimization.literature_source_scope import (  # noqa: E402
    LITERATURE_SOURCE_SCOPE_EMPTY_MARKERS,
    LITERATURE_SOURCE_SCOPE_REQUIRED_FIELDS,
    literature_source_scope_row_get,
    literature_source_scope_violation_message,
    non_placeholder_literature_source_text,
)

_CHECK_293_REQUIRED_SCOPE_FIELDS = LITERATURE_SOURCE_SCOPE_REQUIRED_FIELDS
_CHECK_293_EMPTY_SCOPE_MARKERS = LITERATURE_SOURCE_SCOPE_EMPTY_MARKERS


def _check_293_row_get(row: object, field: str) -> object:
    return literature_source_scope_row_get(row, field)


def _check_293_non_placeholder_text(value: object) -> bool:
    return non_placeholder_literature_source_text(value)


def _check_293_source_scope_violations(
    *,
    substrate_rows: Iterable[object],
    pareto_rows: Iterable[object],
) -> list[str]:
    """Return rows whose literature anchor lacks source-fidelity scope fields."""

    violations: list[str] = []
    for surface, rows in (
        ("canonical_substrate_inventory", substrate_rows),
        ("serialized_pareto_rows", pareto_rows),
    ):
        for row in rows:
            violation = literature_source_scope_violation_message(
                surface=surface,
                row=row,
            )
            if violation:
                violations.append(violation)
    return violations


def check_cathedral_literature_anchors_have_source_scope(
    *,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #293 — require source-fidelity scope on literature-anchored
    Cathedral/autopilot rows.

    The guard checks both:

    - the canonical substrate inventory rows; and
    - the serialized Pareto rows consumed by autopilot/reporting surfaces.

    This keeps paper citations from being used as false score authority. A
    literature anchor is allowed only when the row also records what the source
    supports, the source's claim scope, what Pact still must prove empirically,
    and decode-complexity evidence.
    """

    _ = repo_root  # Signature kept consistent with other preflight gates.
    try:
        from tac.optimization.substrate_composition_matrix import (
            canonical_substrate_inventory,
            per_substrate_pareto_rows,
            serialize_pareto_rows,
        )

        substrate_rows = canonical_substrate_inventory()
        pareto_rows = serialize_pareto_rows(per_substrate_pareto_rows())
    except Exception as exc:
        violations = [
            "could not build Cathedral substrate composition rows for literature "
            f"source-scope validation: {type(exc).__name__}: {exc}"
        ]
    else:
        violations = _check_293_source_scope_violations(
            substrate_rows=substrate_rows,
            pareto_rows=pareto_rows,
        )

    if verbose:
        if violations:
            print(
                "  [check_cathedral_literature_anchors_have_source_scope] "
                f"{len(violations)} violation(s)"
            )
        else:
            print("  [check_cathedral_literature_anchors_have_source_scope] OK")
    if violations and strict:
        raise PreflightError(
            "check_cathedral_literature_anchors_have_source_scope found "
            f"{len(violations)} Cathedral/autopilot literature-anchor source-scope "
            "violation(s). Per CLAUDE.md source-fidelity and paper-readiness "
            "discipline, literature anchors are hypothesis provenance, not score "
            "authority. Catalog #293 (sister of Catalog #291/#292 and the "
            "Cathedral literature-anchor scope hardening).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #284 - check_nightly_catalog_gate_regression_workflow_canonical_use
#
# PHASE-3-CONTINUOUS-REGRESSION-CI-NIGHTLY-WORKFLOW 2026-05-15 self-protection
# per OMNIBUS-BUG-CLASS-AUDIT GAP-3 + operator standing directive 2026-05-15
# *"fix all bug classes and meta bugs and all versions permanently and self
# protect against them"*.
#
# Refuses any state of `.github/workflows/nightly_catalog_gate_regression.yml`
# that does not invoke the canonical helper
# `tools/run_nightly_catalog_gate_regression.py`. Sister of Catalog #245
# (canonical-use ledger-discipline pattern) + Catalog #117/#157/#174 (commit-
# machinery canonical-use family). Without this gate a future workflow edit
# could silently bypass the helper (and thus the META-meta drift detectors at
# Catalogs #118/#159/#176/#185), breaking the daily green/red signal that the
# operator depends on for <24h drift detection.
#
# STRICT-from-byte-one per CLAUDE.md "Strict-flip atomicity rule" — landing
# commit batch ships the canonical helper + the workflow file + this gate
# together, driving live count to 0.
# ============================================================================

_CHECK_284_WORKFLOW_RELPATH: tuple[str, ...] = (
    ".github",
    "workflows",
    "nightly_catalog_gate_regression.yml",
)
_CHECK_284_CANONICAL_HELPER_TOKEN = "tools/run_nightly_catalog_gate_regression.py"
_CHECK_284_WAIVER_PATTERN = re.compile(
    r"#\s*NIGHTLY_CATALOG_GATE_REGRESSION_OK\s*:\s*([^\s][^\n#]{0,200})"
)
_CHECK_284_WAIVER_PLACEHOLDERS = frozenset(("<rationale>", "<reason>", ""))


def check_nightly_catalog_gate_regression_workflow_canonical_use(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #284 — nightly catalog-gate regression workflow MUST route
    through the canonical helper.

    Refuses ``.github/workflows/nightly_catalog_gate_regression.yml`` whose
    body does NOT contain the canonical helper invocation token
    ``tools/run_nightly_catalog_gate_regression.py``. Acceptance: file-level
    waiver ``# NIGHTLY_CATALOG_GATE_REGRESSION_OK:<rationale>`` in the first
    25 lines (placeholder ``<rationale>`` / ``<reason>`` literals rejected so
    the docstring example cannot self-waive).

    Per CLAUDE.md "Bugs must be permanently fixed AND self-protected against"
    + OMNIBUS-BUG-CLASS-AUDIT GAP-3: the canonical helper invokes the META-
    meta drift detectors at Catalogs #118 / #159 / #176 / #185 in-process and
    emits the per-day status JSON under ``.omx/state/`` that is the operator's
    daily green/red signal. A future workflow edit that bypasses the helper
    (e.g. inlining a different test invocation) would silently skip drift
    detection — this gate refuses that regression structurally.

    If the workflow file does not exist (e.g. clean checkout in tests), the
    gate is a no-op. STRICT-from-byte-one per CLAUDE.md "Strict-flip atomicity
    rule" — live count at landing: 0 (the canonical helper + workflow ship
    in the same commit batch).

    Memory:
    ``feedback_phase_3_continuous_regression_ci_nightly_workflow_landed_20260515.md``.
    """
    root = Path(repo_root or REPO_ROOT)
    workflow = root.joinpath(*_CHECK_284_WORKFLOW_RELPATH)
    if not workflow.is_file():
        if verbose:
            try:
                rel = workflow.relative_to(root)
            except ValueError:
                rel = workflow
            print(
                "  [check_nightly_catalog_gate_regression_workflow_canonical_use] "
                f"{rel} not present; skipping"
            )
        return []
    try:
        text = workflow.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        if verbose:
            print(
                "  [check_nightly_catalog_gate_regression_workflow_canonical_use] "
                f"unreadable: {exc}"
            )
        return []

    # File-level waiver: scan first ~25 lines for the marker.
    head = "\n".join(text.splitlines()[:25])
    waiver_match = _CHECK_284_WAIVER_PATTERN.search(head)
    if waiver_match is not None:
        rationale = waiver_match.group(1).strip()
        if rationale and rationale not in _CHECK_284_WAIVER_PLACEHOLDERS:
            return []

    if _CHECK_284_CANONICAL_HELPER_TOKEN in text:
        return []

    try:
        rel = workflow.relative_to(root)
    except ValueError:
        rel = workflow
    violation = (
        f"{rel}: nightly catalog-gate regression workflow does NOT invoke "
        f"the canonical helper `{_CHECK_284_CANONICAL_HELPER_TOKEN}`. Per "
        "Catalog #284 every modification to this workflow MUST route through "
        "the canonical helper so the META-meta drift detectors at Catalogs "
        "#118/#159/#176/#185 fire in-process and the per-day status JSON "
        "lands under .omx/state/. Add the canonical invocation OR carry a "
        "file-level `# NIGHTLY_CATALOG_GATE_REGRESSION_OK:<rationale>` "
        "waiver in the first 25 lines."
    )
    violations = [violation]
    if verbose:
        print(
            "  [check_nightly_catalog_gate_regression_workflow_canonical_use] "
            f"{len(violations)} violation(s)"
        )
    if strict:
        raise PreflightError(
            "check_nightly_catalog_gate_regression_workflow_canonical_use "
            f"found {len(violations)} violation(s). Per CLAUDE.md 'Bugs "
            "must be permanently fixed AND self-protected against' + "
            "OMNIBUS-BUG-CLASS-AUDIT GAP-3 (Catalog #284): the nightly "
            "regression workflow MUST route through the canonical helper "
            "`tools/run_nightly_catalog_gate_regression.py`.\n  "
            + "\n  ".join(v[:600] for v in violations[:5])
        )
    return violations


