# Cutoff date suffix; memos dated before this are exempt.
_CHECK_294_CUTOFF_DATE_SUFFIX_INT = 20260515

# Literal section header (case-insensitive substring match).
_CHECK_294_REQUIRED_SECTION_HEADER = "## 9-dimension success checklist evidence"

# Filename patterns scoping which memos are subject to this gate.
_CHECK_294_SUBSTRATE_FILENAME_RE = re.compile(
    r"^feedback_.*substrate.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_294_SCAFFOLD_FILENAME_RE = re.compile(
    r"^feedback_.*scaffold.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_294_NSCS_FILENAME_RE = re.compile(
    r"^feedback_nscs\d+.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_294_STACK_OF_STACKS_FILENAME_RE = re.compile(
    r"^feedback_.*stack_of_stacks.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_294_COMPOSITION_FILENAME_RE = re.compile(
    r"^feedback_.*composition.*landed_(\d{8})\.md$",
    re.IGNORECASE,
)
_CHECK_294_RESEARCH_DESIGN_FILENAME_RE = re.compile(
    r"^.*_design_(\d{8})\.md$",
    re.IGNORECASE,
)

# Same-line waiver pattern: `# 9_DIM_CHECKLIST_EVIDENCE_WAIVED:<rationale>`.
_CHECK_294_WAIVER_PATTERN = re.compile(
    r"#\s*9_DIM_CHECKLIST_EVIDENCE_WAIVED\s*:\s*([^\s][^\n#]{0,200})"
)
_CHECK_294_WAIVER_PLACEHOLDERS = frozenset(("<rationale>", "<reason>", ""))


def _check_294_in_scope(filename: str) -> int | None:
    """Return parsed YYYYMMDD int if the filename is in-scope, else None."""
    for regex in (
        _CHECK_294_SUBSTRATE_FILENAME_RE,
        _CHECK_294_SCAFFOLD_FILENAME_RE,
        _CHECK_294_NSCS_FILENAME_RE,
        _CHECK_294_STACK_OF_STACKS_FILENAME_RE,
        _CHECK_294_COMPOSITION_FILENAME_RE,
        _CHECK_294_RESEARCH_DESIGN_FILENAME_RE,
    ):
        m = regex.match(filename)
        if m:
            try:
                return int(m.group(1))
            except (TypeError, ValueError):
                return None
    return None


def _check_294_waiver_present(body: str) -> bool:
    """Return True if a non-placeholder `9_DIM_CHECKLIST_EVIDENCE_WAIVED:<rationale>`
    appears anywhere in the body."""
    match = _CHECK_294_WAIVER_PATTERN.search(body)
    if match is None:
        return False
    rationale = match.group(1).strip()
    if not rationale:
        return False
    if rationale in _CHECK_294_WAIVER_PLACEHOLDERS:
        return False
    return True


def _check_294_default_memory_dir() -> Path | None:
    """No external memory scan by default.

    Catalog #294 is a repository preflight gate; clean clones and CI must see
    the same result as the operator machine. Pass ``memory_dir=...`` explicitly
    when auditing local Claude memory.
    """
    return None


def _check_294_default_research_dir(repo_root: Path | str | None = None) -> Path:
    """Default in-repo research design-memo directory."""
    root = Path(repo_root or REPO_ROOT).resolve()
    return root / ".omx" / "research"


def check_substrate_landing_memo_has_9_dim_checklist_evidence_section(
    *,
    memory_dir: Path | str | None = None,
    research_dir: Path | str | None = None,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #294 — refuse substrate landing + stack-of-stacks composition
    memos missing the ``## 9-dimension success checklist evidence`` section.

    Per the operator standing directive 2026-05-15 (
    ``feedback_9_dimension_success_checklist_per_substrate_and_stack_of_stacks_standing_directive_20260515.md``):
    every substrate landing memo AND every stack-of-stacks composition memo
    dated >= 2026-05-15 MUST document evidence across all 9 success
    dimensions:

    (1) UNIQUENESS (class-shift not within-class)
    (2) BEAUTY + ELEGANCE (PR101-style 30-sec-reviewable)
    (3) DISTINCTNESS (explicitly different from sisters)
    (4) RIGOR (premise verification + adversarial review + assumption
        classification + empirical anchor)
    (5) OPTIMIZATION PER TECHNIQUE (substrate-optimal engineering — also
        checked by sister Catalog #290 at the design-memo surface)
    (6) STACK-OF-STACKS-COMPOSABILITY (orthogonal axes + additive ΔS)
    (7) DETERMINISTIC REPRODUCIBILITY (byte-stable + seed-pinned)
    (8) EXTREME OPTIMIZATION + PERFORMANCE
    (9) OPTIMAL MINIMAL CONTEST SCORE (binding objective)

    Missing evidence on ANY dimension = landing INVALID. The literal section
    header is the single structural requirement; the section body content is
    the operator-facing audit surface (per-dimension evidence + cite-source
    per dimension).

    Acceptance:
    - Pre-cutoff memos (date < 2026-05-15) are exempt by date filter.
    - In-scope memos with the literal header pass.
    - In-scope memos with a non-placeholder
      ``# 9_DIM_CHECKLIST_EVIDENCE_WAIVED:<rationale>`` waiver pass.
    - In-scope memos without the header AND without the waiver are flagged.
    - In-repo ``.omx/research/*_design_<YYYYMMDD>.md`` memos are in scope
      (active design surface where subagents land before memory rollups
      exist).
    - External memory memos are scanned only when ``memory_dir`` is passed
      explicitly; default behavior is clone-stable and repo-local
      (OSS-hermetic per sister Catalog #290 / #291 / #292).

    Sister of Catalog #290 (covers Dimension 5 specifically; #294 covers
    Dimensions 1-4 + 6-9 via the unified section header) + Catalog #291
    (per-session cadence companion) + Catalog #292 (per-council-deliberation
    companion).

    Memory: ``feedback_catalog_294_9_dim_checklist_evidence_section_landed_20260515.md``.
    Lane: ``lane_catalog_294_9_dim_checklist_evidence_section_20260515``.
    """
    if memory_dir is None:
        memory_target = _check_294_default_memory_dir()
    elif isinstance(memory_dir, str):
        memory_target = Path(memory_dir)
    else:
        memory_target = memory_dir
    if research_dir is None:
        research_target = _check_294_default_research_dir(repo_root)
    elif isinstance(research_dir, str):
        research_target = Path(research_dir)
    else:
        research_target = research_dir

    violations: list[str] = []
    seen_dirs: set[Path] = set()
    target_surfaces: list[tuple[Path, str]] = []
    if memory_target is not None:
        target_surfaces.append((memory_target, "memory"))
    target_surfaces.append((research_target, "research"))
    for target, surface in target_surfaces:
        try:
            resolved_target = target.resolve()
        except OSError:
            resolved_target = target
        if resolved_target in seen_dirs:
            continue
        seen_dirs.add(resolved_target)
        if not target.is_dir():
            continue
        try:
            candidates = sorted(target.iterdir())
        except OSError:
            continue
        for entry in candidates:
            if not entry.is_file():
                continue
            date_int = _check_294_in_scope(entry.name)
            if date_int is None:
                continue  # filename not in scope
            if date_int < _CHECK_294_CUTOFF_DATE_SUFFIX_INT:
                continue  # pre-cutoff memos exempt
            try:
                body = entry.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Acceptance path 1: literal section header (case-insensitive).
            if _CHECK_294_REQUIRED_SECTION_HEADER in body.lower():
                continue
            # Acceptance path 2: same-line waiver with non-placeholder rationale.
            if _check_294_waiver_present(body):
                continue
            try:
                rel = entry.relative_to(Path(repo_root or REPO_ROOT).resolve())
            except ValueError:
                rel = entry
            violations.append(
                f"{rel}: {surface} substrate/composition landing memo dated "
                f"{date_int} is missing the required "
                "'## 9-dimension success checklist evidence' section header "
                "(case-insensitive). Per the operator standing directive "
                "2026-05-15: every substrate landing AND every stack-of-stacks "
                "composition memo dated >= 2026-05-15 MUST document evidence "
                "across all 9 dimensions (UNIQUENESS / BEAUTY+ELEGANCE / "
                "DISTINCTNESS / RIGOR / OPTIMIZATION PER TECHNIQUE / "
                "STACK-OF-STACKS-COMPOSABILITY / DETERMINISTIC REPRODUCIBILITY "
                "/ EXTREME OPTIMIZATION+PERFORMANCE / OPTIMAL MINIMAL CONTEST "
                "SCORE). Either add the section header OR carry a same-line "
                "`# 9_DIM_CHECKLIST_EVIDENCE_WAIVED:<rationale>` waiver."
            )

    if verbose:
        if violations:
            print(
                "  [check_substrate_landing_memo_has_9_dim_checklist_evidence_section] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_substrate_landing_memo_has_9_dim_checklist_evidence_section] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_substrate_landing_memo_has_9_dim_checklist_evidence_section "
            f"found {len(violations)} substrate/composition landing memo(s) "
            "missing the required '## 9-dimension success checklist evidence' "
            "section. Per the operator standing directive 2026-05-15 + "
            "CLAUDE.md 'Bugs must be permanently fixed AND self-protected "
            "against' non-negotiable. Catalog #294 (sister of Catalog #290 "
            "Dimension 5 + Catalog #291 per-session cadence + Catalog #292 "
            "per-deliberation discipline).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #295 - check_submission_inflate_works_with_empty_pythonpath
# ============================================================================
# Empirical anchor 2026-05-16: NSCS06 v5 Modal dispatch
# fc-01KRQMAQ7V41AFYMJH5HRK9P10 failed at runtime because
# submissions/nscs06_carmack_hotz_strip_everything/inflate.py used the
# PYTHONPATH-shim pattern
#
#     sys.path.insert(0, str(HERE / "src"))
#     from tac.substrates.nscs06_carmack_hotz_strip_everything.inflate ...
#
# which worked during local development (the operator's working tree had
# the repo `src/` resolvable on sys.path) but FAILED on the Modal worker
# because the `src/tac/...` tree was never vendored into the submission
# directory. The Modal worker mount only saw the submission_dir contents,
# not the repo `src/`, so the `from tac...` import raised
# ModuleNotFoundError before any inflate work could happen. The v6 fix
# (commit 90bca47ff) vendored the codec package alongside as
# `submission/_nscs06_codec/` and removed the PYTHONPATH shim.
#
# Per CLAUDE.md HNeRV parity discipline lesson 9 (Runtime closure): "Run
# the exact contest inflate.sh signature in a clean environment BEFORE
# dispatch. Dependency closure failures (missing brotli, wrong wrapper
# signatures, hidden sidecars, local paths, CPU/CUDA mismatches) are
# runtime blockers, not method negatives." A PYTHONPATH shim that resolves
# only on the operator's local tree is the same bug class as a hidden
# sidecar -- the submission is not self-contained.
#
# This gate scans every `submissions/*/inflate.py` (excluding the pinned
# upstream `submissions/exact_current/` per CLAUDE.md mutation frontier)
# and refuses any file that:
#   1. Calls sys.path.insert(...) AND imports `from tac....` / `import tac....`
#      WITHOUT the imported package being vendored as a sibling directory
#      of inflate.py (e.g. NSCS06 v6 ships `submissions/<id>/_nscs06_codec/`
#      OR the NSCS01 pattern would require `submissions/<id>/src/tac/...`).
#   2. Calls sys.path.insert(...) pointing OUTSIDE the submission directory
#      tree (e.g. sibling submission's src/, repo root, $HOME) without an
#      explicit declared dependency manifest.
#
# Acceptance:
#   (a) No sys.path.insert at all (the canonical NSCS06 v6 pattern with
#       vendored sibling package + direct import).
#   (b) sys.path.insert resolves entirely WITHIN the submission directory
#       tree AND every `from tac....` import resolves to a vendored sibling
#       directory (e.g. `submissions/<id>/src/tac/<...>/`).
#   (c) sys.path.insert(HERE / "src") AND no `from tac.` imports (the
#       NSCS06 v6 pattern of vendoring non-tac codec packages alongside).
#   (d) Same-line waiver `# SUBMISSION_PYTHONPATH_SHIM_OK:<rationale>`
#       on the sys.path.insert line (placeholder `<rationale>` / `<reason>`
#       literal rejected).
#
# Sister of Catalog #205 (`check_inflate_py_uses_canonical_select_inflate_device`)
# scoped to the same `submissions/*/inflate.py` surface (Catalog #205 catches
# inline device-fork; Catalog #295 catches PYTHONPATH-shim self-containment
# violations).
# ============================================================================


_CHECK_295_WAIVER_TOKEN = "SUBMISSION_PYTHONPATH_SHIM_OK:"
_CHECK_295_WAIVER_PLACEHOLDERS = ("<rationale>", "<reason>")


def _check_295_iter_target_files(repo_root: Path) -> list[Path]:
    """List every ``submissions/*/inflate.py`` under repo_root.

    Excludes ``submissions/exact_current/`` since CLAUDE.md mutation
    frontier marks the pinned upstream snapshot as off-limits without
    explicit human approval.
    """

    submissions_root = repo_root / "submissions"
    if not submissions_root.is_dir():
        return []
    targets: list[Path] = []
    for child in sorted(submissions_root.iterdir()):
        if not child.is_dir():
            continue
        if child.name == "exact_current":
            continue
        if "_intake_" in child.name:
            continue
        candidate = child / "inflate.py"
        if candidate.is_file():
            targets.append(candidate)
    return targets


def _check_295_collect_sys_path_inserts(
    tree: ast.AST,
) -> list[tuple[int, ast.AST]]:
    """Return (lineno, argument-AST) tuples for every ``sys.path.insert(...)`` call.

    AST-aware so docstring/comment mentions of the literal text are NOT
    flagged.
    """
    out: list[tuple[int, ast.AST]] = []
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        func = node.func
        if not isinstance(func, ast.Attribute):
            continue
        if func.attr != "insert":
            continue
        value = func.value
        # Match `sys.path.insert(...)`
        if (
            isinstance(value, ast.Attribute)
            and value.attr == "path"
            and isinstance(value.value, ast.Name)
            and value.value.id == "sys"
            and len(node.args) >= 2
        ):
            out.append((node.lineno, node.args[1]))
    return out


def _check_295_collect_tac_imports(tree: ast.AST) -> list[tuple[int, str]]:
    """Return (lineno, dotted-name) tuples for every ``from tac.*`` or ``import tac.*``.

    AST-aware so docstring/comment mentions are NOT flagged.
    """
    out: list[tuple[int, str]] = []
    for node in ast.walk(tree):
        if isinstance(node, ast.ImportFrom):
            if node.module and (node.module == "tac" or node.module.startswith("tac.")):
                out.append((node.lineno, node.module))
        elif isinstance(node, ast.Import):
            for alias in node.names:
                if alias.name == "tac" or alias.name.startswith("tac."):
                    out.append((node.lineno, alias.name))
    return out


def _check_295_line_has_waiver(line: str) -> bool:
    """Return True if ``line`` carries the canonical same-line waiver.

    Placeholder literals are rejected so the gate's own documentation
    example cannot self-waive a real violation.
    """
    if _CHECK_295_WAIVER_TOKEN not in line:
        return False
    idx = line.find(_CHECK_295_WAIVER_TOKEN)
    tail = line[idx + len(_CHECK_295_WAIVER_TOKEN):].strip()
    if not tail:
        return False
    for placeholder in _CHECK_295_WAIVER_PLACEHOLDERS:
        if tail.startswith(placeholder):
            return False
    return True


def _check_295_tac_module_is_vendored(
    submission_dir: Path, dotted_module: str
) -> bool:
    """Check whether ``dotted_module`` (e.g. ``tac.foo.bar``) is vendored
    inside ``submission_dir`` as a real importable package tree.

    Searches the standard vendoring locations:
      - ``<submission_dir>/<dotted-path-as-dirs>.py``
      - ``<submission_dir>/<dotted-path-as-dirs>/__init__.py``
      - ``<submission_dir>/src/<dotted-path-as-dirs>.py``
      - ``<submission_dir>/src/<dotted-path-as-dirs>/__init__.py``
    """
    parts = dotted_module.split(".")
    for prefix in (submission_dir, submission_dir / "src"):
        # Try the top-level package path (parts[0]) for an importable form.
        # We accept either `<prefix>/tac/__init__.py` or `<prefix>/tac.py`.
        top_pkg = prefix / parts[0]
        top_mod = prefix / f"{parts[0]}.py"
        if top_pkg.is_dir() and (top_pkg / "__init__.py").is_file():
            return True
        if top_mod.is_file():
            return True
    return False


def _check_295_collect_module_level_assignments(
    tree: ast.AST,
) -> dict[str, ast.AST]:
    """Return {name: value_AST} for every module-level ``Name = <expr>``.

    Used to trace `SRC_DIR = HERE / "src"` style indirection so the
    insert-target check can follow one level of variable binding.
    Walks only the top-level body; nested function/class assigns are
    out of scope (a submission inflate.py with deep nesting is a code
    smell of its own).
    """
    bindings: dict[str, ast.AST] = {}
    if not isinstance(tree, ast.Module):
        return bindings
    for node in tree.body:
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name):
                    bindings[target.id] = node.value
        elif isinstance(node, ast.AnnAssign):
            if isinstance(node.target, ast.Name) and node.value is not None:
                bindings[node.target.id] = node.value
    return bindings


def _check_295_path_insert_target_inside_submission(
    arg_node: ast.AST,
    submission_dir: Path,
    bindings: dict[str, ast.AST] | None = None,
) -> bool:
    """Heuristic: does the sys.path.insert argument resolve INSIDE submission_dir?

    Accepts the canonical patterns:
        sys.path.insert(0, str(HERE))
        sys.path.insert(0, str(HERE / "src"))
        sys.path.insert(0, str(SRC_DIR))      # if SRC_DIR = HERE / "..."
        sys.path.insert(0, str(vendored_src)) # if vendored_src = HERE / "..."

    Rejects (returns False) patterns pointing to sibling submission or
    outside the submission tree (e.g. ``HERE.parent / "apogee_intN" / "src"``
    or ``HERE.parent.parent / "src"``).

    One-level variable indirection is followed via ``bindings`` so the
    canonical ``SRC_DIR = HERE / "src"`` pattern is accepted. Multi-level
    chains and dynamic expressions remain conservatively rejected.
    """
    # Unwrap str(...) call
    if isinstance(arg_node, ast.Call):
        if (
            isinstance(arg_node.func, ast.Name)
            and arg_node.func.id == "str"
            and len(arg_node.args) >= 1
        ):
            arg_node = arg_node.args[0]

    def _expr_uses_parent_traversal(node: ast.AST) -> bool:
        """Detect HERE.parent / ... / HERE.parent.parent / ... chains."""
        for sub in ast.walk(node):
            if isinstance(sub, ast.Attribute) and sub.attr == "parent":
                return True
        return False

    def _expr_anchored_at_here(node: ast.AST) -> bool:
        """Detect HERE-anchored expressions: bare HERE or HERE / "subdir" / ..."""
        for sub in ast.walk(node):
            if isinstance(sub, ast.Name) and sub.id in {"HERE", "SUBMISSION_DIR"}:
                return True
        return False

    if _expr_uses_parent_traversal(arg_node):
        return False  # points outside submission_dir

    if _expr_anchored_at_here(arg_node):
        return True

    # One-level variable indirection: SRC_DIR = HERE / "src"
    if bindings is not None and isinstance(arg_node, ast.Name):
        bound = bindings.get(arg_node.id)
        if bound is not None:
            # Recurse one level (no bindings to prevent infinite loops).
            if _expr_uses_parent_traversal(bound):
                return False
            if _expr_anchored_at_here(bound):
                return True

    return False


def _scan_inflate_for_pythonpath_shim_self_contained(
    path: Path, repo_root: Path
) -> list[str]:
    """Find PYTHONPATH-shim self-containment violations in one inflate.py.

    Returns one violation string per offending file (zero or one). Empty
    list means the file is self-contained per the acceptance cascade.
    """
    rel = path.relative_to(repo_root) if path.is_absolute() else path
    submission_dir = path.parent
    try:
        text = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []
    try:
        tree = ast.parse(text, filename=str(path))
    except SyntaxError:
        return []

    text_lines = text.splitlines()
    inserts = _check_295_collect_sys_path_inserts(tree)
    tac_imports = _check_295_collect_tac_imports(tree)
    bindings = _check_295_collect_module_level_assignments(tree)

    # Acceptance path (a): No sys.path.insert at all = canonical
    # NSCS06-v6-style or simple inflate without any path manipulation.
    if not inserts:
        # But: if there are `from tac....` imports without a path insert,
        # the submission is implicitly depending on the operator's working
        # tree -- the NSCS06 v5 bug class. Refuse UNLESS the import line
        # carries the canonical waiver (research-only adapter use case).
        if tac_imports:
            # Check each unvendored tac.* import for the canonical waiver
            # OR for the import being vendored alongside (e.g. via
            # submissions/<id>/src/tac/* + sister cwd manipulation by the
            # inflate.sh wrapper). The waiver-respect path supports the
            # function-scoped lazy-import pattern used by research adapters
            # like submissions/magic_codec_pr106_r2/inflate.py which the
            # audit ledger explicitly designates as the LAB-only dispatch
            # acceptance shape (sibling submission + operator working tree
            # both mounted; non-promotable per its docstring).
            unwaived: list[tuple[int, str]] = []
            for lineno, module_name in tac_imports:
                line_text = (
                    text_lines[lineno - 1]
                    if 0 < lineno <= len(text_lines)
                    else ""
                )
                if _check_295_line_has_waiver(line_text):
                    continue
                if _check_295_tac_module_is_vendored(submission_dir, module_name):
                    continue
                unwaived.append((lineno, module_name))
            if not unwaived:
                return []
            first_import_line = unwaived[0][0]
            return [
                f"{rel}:{first_import_line}: imports `from tac.*` / "
                f"`import tac.*` WITHOUT any vendored `tac` package "
                f"alongside inflate.py and WITHOUT any sys.path.insert. "
                f"Per the NSCS06 v5 bug class (Modal dispatch "
                f"fc-01KRQMAQ7V41AFYMJH5HRK9P10 ModuleNotFoundError on "
                f"the worker): a submission `inflate.py` MUST be "
                f"self-contained. Either vendor the codec package "
                f"alongside as `submissions/{submission_dir.name}/"
                f"_<id>_codec/` (NSCS06 v6 pattern @ commit 90bca47ff) "
                f"OR add same-line "
                f"`# SUBMISSION_PYTHONPATH_SHIM_OK:<rationale>` waiver "
                f"on the offending `from tac.*` import line."
            ]
        return []

    # If we have inserts but NO `from tac.*` imports, the inserts are
    # harmless -- the submission vendors its codec under a non-tac name
    # (e.g. `submissions/<id>/src/codec.py` + `model.py`, NSCS06-v6-style).
    # Verify the waiver isn't masking a real violation.
    if not tac_imports:
        # Still verify any insert's target is inside the submission tree.
        # If an insert points OUTSIDE the submission (e.g. sibling
        # submission's src/), that's a fragile dependency requiring
        # explicit declaration via waiver.
        for lineno, arg in inserts:
            line_text = text_lines[lineno - 1] if 0 < lineno <= len(text_lines) else ""
            if _check_295_line_has_waiver(line_text):
                continue
            if not _check_295_path_insert_target_inside_submission(
                arg, submission_dir, bindings=bindings,
            ):
                return [
                    f"{rel}:{lineno}: `sys.path.insert(...)` points OUTSIDE "
                    f"the submission directory `{submission_dir.name}/` "
                    f"(detected `HERE.parent / ...` traversal OR unresolved "
                    f"variable). Per the NSCS06 v5 bug class: a submission "
                    f"MUST be self-contained. Either vendor required code "
                    f"alongside inflate.py (NSCS06 v6 pattern @ commit "
                    f"90bca47ff) OR add same-line "
                    f"`# SUBMISSION_PYTHONPATH_SHIM_OK:<rationale>` "
                    f"waiver declaring the required sibling submission."
                ]
        return []

    # We have BOTH sys.path.insert AND `from tac.*` imports. This is the
    # NSCS06 v5 / NSCS01 pattern. The submission MUST vendor the imported
    # `tac.*` packages alongside, OR carry a waiver.
    for lineno, arg in inserts:
        line_text = text_lines[lineno - 1] if 0 < lineno <= len(text_lines) else ""
        if _check_295_line_has_waiver(line_text):
            # Waived -- skip violation for THIS insert.
            return []

    # Check each `from tac.*` import: is the top-level `tac` package
    # vendored as `<submission_dir>/tac/` or `<submission_dir>/src/tac/`?
    unvendored: list[str] = []
    for lineno, module_name in tac_imports:
        if not _check_295_tac_module_is_vendored(submission_dir, module_name):
            unvendored.append(f"line {lineno}: `{module_name}`")

    if unvendored:
        return [
            f"{rel}: PYTHONPATH-shim pattern (sys.path.insert + "
            f"`from tac.*` imports) BUT `tac` package is NOT vendored "
            f"alongside inflate.py. Imports requiring vendoring: "
            f"{', '.join(unvendored[:3])}. This is the NSCS06 v5 bug "
            f"class (Modal dispatch fc-01KRQMAQ7V41AFYMJH5HRK9P10 "
            f"ModuleNotFoundError on the worker because the repo `src/` "
            f"was never copied into the submission). Fix: vendor the "
            f"codec package alongside as `submissions/"
            f"{submission_dir.name}/<vendored-name>/__init__.py + ...` "
            f"(NSCS06 v6 pattern @ commit 90bca47ff) AND remove the "
            f"`from tac.*` imports in favor of direct relative imports "
            f"of the vendored package. OR add same-line "
            f"`# SUBMISSION_PYTHONPATH_SHIM_OK:<rationale>` waiver on "
            f"the sys.path.insert(...) line declaring the dependency "
            f"is intentional (e.g. NSCS01-style fail-closed-at-runtime "
            f"research surface)."
        ]

    return []


def check_submission_inflate_works_with_empty_pythonpath(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #295 - refuse PYTHONPATH-shim submissions that depend on the
    operator's working tree to import `tac.*` at runtime.

    Empirical anchor 2026-05-16: NSCS06 v5 Modal dispatch
    ``fc-01KRQMAQ7V41AFYMJH5HRK9P10`` failed at runtime because
    ``submissions/nscs06_carmack_hotz_strip_everything/inflate.py`` used
    the PYTHONPATH-shim pattern
    ``sys.path.insert(0, str(HERE / "src"))`` then
    ``from tac.substrates.nscs06_carmack_hotz_strip_everything.inflate ...``
    which worked during local development (the operator's working tree
    had the repo ``src/`` resolvable on sys.path) but FAILED on the Modal
    worker because the ``src/tac/...`` tree was never vendored into the
    submission directory. The v6 fix (commit ``90bca47ff``) vendored the
    codec package alongside as ``submissions/<id>/_nscs06_codec/`` and
    removed the PYTHONPATH shim.

    Per CLAUDE.md HNeRV parity discipline lesson 9 (Runtime closure): a
    submission ``inflate.py`` MUST be self-contained. A PYTHONPATH shim
    that resolves only on the operator's local tree is the same bug
    class as a hidden sidecar.

    Sister of Catalog #205 (``check_inflate_py_uses_canonical_select_inflate_device``)
    scoped to the same ``submissions/*/inflate.py`` surface (Catalog #205
    catches inline device-fork; Catalog #295 catches PYTHONPATH-shim
    self-containment violations).

    Memory: ``feedback_catalog_295_submission_inflate_empty_pythonpath_strict_gate_landed_20260516.md``.
    Lane: ``lane_check_submission_inflate_empty_pythonpath_strict_gate_20260516``.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    targets = _check_295_iter_target_files(root)
    violations: list[str] = []
    for path in targets:
        violations.extend(
            _scan_inflate_for_pythonpath_shim_self_contained(path, root)
        )

    if verbose:
        if violations:
            print(
                f"  [check_submission_inflate_works_with_empty_pythonpath] "
                f"{len(violations)} violation(s) across {len(targets)} "
                "submissions/inflate.py file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:280]}")
        else:
            print(
                f"  [check_submission_inflate_works_with_empty_pythonpath] OK "
                f"({len(targets)} submissions/inflate.py file(s) scanned, "
                "0 violation(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_submission_inflate_works_with_empty_pythonpath found "
            f"{len(violations)} violation(s). Per the NSCS06 v5 bug class "
            "anchor (Modal dispatch fc-01KRQMAQ7V41AFYMJH5HRK9P10 "
            "ModuleNotFoundError because submission was not self-contained): "
            "submission `inflate.py` files MUST vendor required code "
            "alongside (NSCS06 v6 pattern @ commit 90bca47ff) OR carry an "
            "explicit `# SUBMISSION_PYTHONPATH_SHIM_OK:<rationale>` "
            "waiver:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #328 - check_submission_inflate_py_under_loc_budget
# ============================================================================
# The 2026-05-18 inflate.py extreme-compression symposium resolved a subtle
# authority problem: compressing Python source does NOT improve contest score
# because the scorer charges `archive.zip` bytes, not runtime source bytes.
# Source size still matters as a review/runtime-closure constraint. This gate
# keeps direct `submissions/*/inflate.py` files small enough to audit and nudges
# large runtimes toward reusable helpers or explicit waivers.
# ============================================================================


def check_submission_inflate_py_under_loc_budget(
    *,
    repo_root: Path | None = None,
    max_lines: int = 200,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #328 - flag direct submission ``inflate.py`` files over budget.

    This is deliberately not score evidence. The contest rate term charges
    archive bytes. The budget exists to prevent source-review opacity, hidden
    dependency creep, and cargo-culted "compress inflate.py" score claims.
    """

    from tac.submission_inflate_loc_budget import (
        scan_submission_inflate_py_loc_budget,
    )

    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    findings = scan_submission_inflate_py_loc_budget(
        root,
        max_lines=max_lines,
    )
    violations = [finding.format() for finding in findings]
    hard_count = sum(1 for finding in findings if finding.budget_tier == "hard_budget")
    default_count = sum(1 for finding in findings if finding.budget_tier == "default_budget")

    if verbose:
        if violations:
            print(
                f"  [check_submission_inflate_py_under_loc_budget] "
                f"{len(violations)} finding(s): {hard_count} over hard "
                f"{max_lines}-line budget, {default_count} over default "
                "100-line review target (warn-only until cleanup):"
            )
            for violation in violations[:10]:
                print(f"    - {violation[:280]}")
        else:
            print(
                f"  [check_submission_inflate_py_under_loc_budget] OK "
                f"(all direct submissions/inflate.py files <= {max_lines} lines)"
            )

    if violations and strict:
        raise PreflightError(
            "check_submission_inflate_py_under_loc_budget found "
            f"{len(violations)} direct submission inflate.py file(s) over "
            f"{max_lines} physical lines per Catalog #328. This is a "
            "review/runtime-closure guard, not a score claim: the contest "
            "charges archive.zip bytes. Extract reusable runtime helpers, "
            "remove dead source, or add an explicit "
            "`# INFLATE_PY_LOC_BUDGET_OK:<rationale>` waiver in the first "
            "40 lines for a source-faithful exception:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #296 - check_substrate_predicted_band_has_dykstra_feasibility_check
# ============================================================================
# Empirical anchors 2026-05-16 from
# .omx/research/meta_assumption_backfill_audit_all_staircase_substrates_20260516.md
# + grand_council_symposium_nscs06_carmack_hotz_falsification_redesign_multipath_20260516.md
# + commit 4292c8ce2 (symposium) + commit b0a7ff474 (META-assumption audit):
#
#   - NSCS06: predicted score band ~[0.10, 0.20] from first-principles
#     5-move composition. Empirical Modal v6 dispatch: 105.15 -- 553x
#     OUTSIDE the predicted band. The cargo-cult was assuming 5 design
#     moves compose additively under contest rate+distortion polytope
#     constraints WITHOUT a Dykstra-feasibility intersection check.
#   - D1: 1.18x OUTSIDE predicted band (polytope-interior overlay
#     deferred to L2 INTEGRATION while rate-axis cost landed).
#   - C6 MDL-IBPS: predicted [0.11, 0.16] from MDL + IB composition
#     without Dykstra-feasibility check that the two constraints
#     actually intersect at a feasible contest-polytope point.
#   - Time-Traveler L5: predicted band from 5-design-move composition
#     without Dykstra-feasibility check that the 5 moves jointly
#     project into the contest's feasible region.
#
# Per CLAUDE.md "Meta-Lagrangian/Pareto solver - NON-NEGOTIABLE":
# "Prefer solvable math over arbitrary sweeps. New knobs must be
# grounded in entropy/MDL, Fisher/Hessian/Jacobian or Frechet
# sensitivity, Dykstra/ADMM feasibility, Bayesian experimental design,
# optimal transport/camera geometry..."
#
# Per CLAUDE.md "Council conduct": Dykstra co-leads the inner quintet
# pact specifically because alternating-projections feasibility IS the
# arbiter of whether a multi-constraint composition is achievable
# rather than just predicted.
#
# Sister of Catalog #290 (canonical-vs-unique decision per layer),
# Catalog #229 (premise verification before edit), Catalog #292
# (per-deliberation assumption surfacing), Catalog #294 (9-dimension
# success checklist evidence).
# ============================================================================


_CHECK_296_WAIVER_TOKEN = "PREDICTED_BAND_VIBES_OK:"
_CHECK_296_WAIVER_PLACEHOLDERS = ("<rationale>", "<reason>")

# Section headers that trigger the gate (case-insensitive substring).
# NOTE: Δ.lower() == δ in Python, so both the lowercased form AND the
# original uppercase form are listed so that header detection survives
# the case-fold step regardless of which Greek letter the author used.
_CHECK_296_TRIGGER_HEADERS = (
    "## predicted δs band",
    "## predicted delta s band",
    "## predicted score band",
    "## predicted band",
)

_CHECK_296_DYKSTRA_TOKENS = (
    "dykstra",
    "convex feasibility",
    "alternating projection",
    "alternating-projection",
    "intersection of constraints",
    "intersection-of-constraints",
)

_CHECK_296_FIRST_PRINCIPLES_TOKENS = (
    "shannon",
    "r(d)",
    "rate-distortion",
    "mdl",
    "minimum description length",
    "tishby",
    "daubechies",
    "mallat",
    "wyner",
    "wyner-ziv",
    "atick-redlich",
    "atick redlich",
    "rao-ballard",
    "rao ballard",
)

_CHECK_296_PROBE_DISAMBIGUATOR_REGEX = re.compile(
    r"tools/probe_[a-z0-9_]+_disambiguator\.py",
    re.IGNORECASE,
)


def _check_296_iter_design_memos(repo_root: Path) -> list[Path]:
    """List every ``.omx/research/*_design_<YYYYMMDD>.md`` under repo_root."""
    research_root = repo_root / ".omx" / "research"
    if not research_root.is_dir():
        return []
    pattern = re.compile(r"_design_(\d{8})\.md$")
    targets: list[Path] = []
    for entry in sorted(research_root.iterdir()):
        if not entry.is_file():
            continue
        if pattern.search(entry.name):
            targets.append(entry)
    return targets


def _check_296_line_has_waiver(line: str) -> bool:
    """Return True if ``line`` carries the canonical same-line waiver.

    Placeholder literals (``<rationale>``, ``<reason>``) are rejected so
    the gate's own documentation example cannot self-waive a real
    violation. Bare-no-rationale and pure-HTML-marker rationales are
    also rejected (we strip ``-->`` and trailing whitespace and require
    the remaining text to be a substantive (>=4 char) rationale token).
    """
    if _CHECK_296_WAIVER_TOKEN not in line:
        return False
    idx = line.find(_CHECK_296_WAIVER_TOKEN)
    tail = line[idx + len(_CHECK_296_WAIVER_TOKEN):]
    # Strip trailing HTML comment close and whitespace so a `-->`
    # immediately after the colon is treated as "no rationale provided".
    tail = tail.rstrip()
    if tail.endswith("-->"):
        tail = tail[:-3].rstrip()
    tail = tail.strip()
    if not tail:
        return False
    # Reject placeholder literals.
    for placeholder in _CHECK_296_WAIVER_PLACEHOLDERS:
        if tail.startswith(placeholder):
            return False
    # Require a substantive rationale token (>=4 chars).
    if len(tail) < 4:
        return False
    return True


def _check_296_body_has_acceptance_token(
    body_lower: str, body_original: str
) -> bool:
    """Check whether the memo body satisfies the (a)/(b)/(c) acceptance cascade."""
    for tok in _CHECK_296_DYKSTRA_TOKENS:
        if tok in body_lower:
            return True
    for tok in _CHECK_296_FIRST_PRINCIPLES_TOKENS:
        if tok in body_lower:
            return True
    if _CHECK_296_PROBE_DISAMBIGUATOR_REGEX.search(body_original):
        return True
    return False


def _scan_design_memo_for_predicted_band_dykstra(
    path: Path, repo_root: Path
) -> list[str]:
    """Find predicted-band-without-Dykstra-feasibility violations in one memo."""
    rel = path.relative_to(repo_root) if path.is_absolute() else path
    try:
        text = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []

    body_lower = text.lower()
    trigger_found = False
    trigger_line_no = 0
    text_lines = text.splitlines()
    for i, line in enumerate(text_lines, start=1):
        line_lower = line.lower()
        for header in _CHECK_296_TRIGGER_HEADERS:
            if header in line_lower:
                if _check_296_line_has_waiver(line):
                    return []
                trigger_found = True
                trigger_line_no = i
                break
        if trigger_found:
            break

    if not trigger_found:
        return []

    if _check_296_body_has_acceptance_token(body_lower, text):
        return []

    return [
        f"{rel}:{trigger_line_no}: design memo contains a "
        f"`## Predicted ΔS band` (or sister) section header but lacks "
        f"ANY of: (a) Dykstra-feasibility token (dykstra / convex "
        f"feasibility / alternating projection / intersection of "
        f"constraints), (b) first-principles citation (Shannon / R(D) "
        f"/ MDL / Tishby / Daubechies / Mallat / Wyner / "
        f"Atick-Redlich / Rao-Ballard), (c) sister probe-disambiguator "
        f"path (tools/probe_*_disambiguator.py). Per CLAUDE.md "
        f"\"Meta-Lagrangian/Pareto solver - NON-NEGOTIABLE\" + "
        f"\"Council conduct\" (Dykstra co-leads quintet pact). "
        f"Empirical anchor: NSCS06 v6 dispatch landed 105.15 vs "
        f"predicted [0.10, 0.20] band -- 553x OUTSIDE band -- because "
        f"5-move composition was assumed additive without Dykstra-"
        f"feasibility intersection check (symposium commit 4292c8ce2; "
        f"META-assumption audit commit b0a7ff474). Either add the "
        f"Dykstra-feasibility section / first-principles citation / "
        f"probe-disambiguator path OR carry same-line "
        f"`# PREDICTED_BAND_VIBES_OK:<rationale>` waiver on the "
        f"`## Predicted ΔS band` header line."
    ]


def check_substrate_predicted_band_has_dykstra_feasibility_check(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #296 - refuse substrate design memos with predicted ΔS bands
    that lack a Dykstra-feasibility intersection check, first-principles
    citation, or sister probe-disambiguator path.

    Empirical anchors 2026-05-16: NSCS06 v6 dispatch landed 105.15 vs
    predicted [0.10, 0.20] (553x OUTSIDE band) because 5-move composition
    was assumed additive under contest polytope constraints WITHOUT a
    Dykstra-feasibility intersection check. D1 1.18x OUTSIDE band. C6
    MDL-IBPS + Time-Traveler L5 carry similar cargo-cult-prediction risk.

    Per CLAUDE.md "Meta-Lagrangian/Pareto solver - NON-NEGOTIABLE" +
    "Council conduct" (Dykstra co-leads the inner quintet pact).

    Sister of Catalog #290, #229, #292, #294.

    Memory: ``feedback_catalog_296_substrate_predicted_band_dykstra_feasibility_landed_20260516.md``.
    Lane: ``lane_catalog_296_297_metacargocult_strict_gates_20260516``.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    targets = _check_296_iter_design_memos(root)
    violations: list[str] = []
    for path in targets:
        violations.extend(
            _scan_design_memo_for_predicted_band_dykstra(path, root)
        )

    if verbose:
        if violations:
            print(
                f"  [check_substrate_predicted_band_has_dykstra_feasibility_check] "
                f"{len(violations)} violation(s) across {len(targets)} "
                "design memo(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:280]}")
        else:
            print(
                f"  [check_substrate_predicted_band_has_dykstra_feasibility_check] "
                f"OK ({len(targets)} design memo(s) scanned, 0 violation(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_substrate_predicted_band_has_dykstra_feasibility_check "
            f"found {len(violations)} substrate design memo(s) with "
            "`## Predicted ΔS band` sections that lack Dykstra-"
            "feasibility / first-principles citation / probe-"
            "disambiguator path. Per CLAUDE.md \"Meta-Lagrangian/Pareto "
            "solver - NON-NEGOTIABLE\" + \"Council conduct\" + "
            "Catalog #296 (META-CARGO-CULT meta-assumption audit). "
            "Empirical anchor: NSCS06 v6 dispatch landed 105.15 vs "
            "predicted [0.10, 0.20] (553x OUTSIDE band). Symposium "
            "commit 4292c8ce2; META-assumption audit commit b0a7ff474.\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #297 - check_substrate_signal_axis_destruction_has_reversibility_probe
# ============================================================================
# Empirical anchors 2026-05-16:
#
#   - NSCS06 Y=R=G=B grayscale-to-RGB replication at compress time:
#     trainer collapsed RGB chroma to Y luma and reconstructed R=G=B=Y
#     at inflate; segnet score landed seg=64.59 because SegNet's
#     stride-2 stem cannot recover the destroyed chroma signal.
#   - NSCS06 np.roll global translation cargo-cult: inflate-time
#     reconstruction applied global translation under assumption that
#     PoseNet is translation-invariant; pose=149.03 empirical proof
#     that pose is NOT invariant.
#   - Z3-G1 empty hyperprior_weights_int8 slots: archive emitted with
#     `hyperprior_weights_int8 = b""` + `w_hat_int8 = b""`; auth-eval
#     reproduced Z3 v2 baseline 0.19869 to 5 decimals (silent baseline
#     reproduction proof that empty-slot bytes never affect score).
#
# Per CLAUDE.md "Apples-to-apples evidence discipline" + "Bit-level
# deconstruction and entropy discipline" + Catalog #220 (substrate L1+
# byte-addition operational mechanism) + Catalog #139 (no-op detector)
# + Catalog #105 (no-op provenance): every transform that mutates
# archive bytes MUST be paired with a proof that the mutation actually
# affects the score, not just an assumption.
#
# This gate scans `src/tac/substrates/*/` directory tree AND
# `experiments/train_substrate_*.py` files for forbidden signal-axis-
# destruction tokens (Y=R=G=B, grayscale_to_rgb(...duplicate),
# frame.mean(...color), rgb_grey = (r+g+b)/3, single_channel_only,
# _grayscale_to_rgb, _drop_chroma).
#
# Acceptance cascade per file:
#   (a) Sister probe file exists: ``tools/probe_<substrate>_reversibility*.py``.
#   (b) Same-line waiver ``# SIGNAL_AXIS_DESTRUCTION_REVERSIBLE_PROBE_OK:<rationale>``.
#   (c) Enclosing function name contains ``_compress_time_only`` marker.
#
# Sister of Catalog #220, #272, #139, #105.
# ============================================================================


_CHECK_297_WAIVER_TOKEN = "SIGNAL_AXIS_DESTRUCTION_REVERSIBLE_PROBE_OK:"
_CHECK_297_WAIVER_PLACEHOLDERS = ("<rationale>", "<reason>")
_CHECK_297_COMPRESS_TIME_ONLY_MARKER = "_compress_time_only"

_CHECK_297_DESTRUCTION_PATTERNS = (
    re.compile(r"\bY\s*=\s*R\s*=\s*G\s*=\s*B\b"),
    re.compile(r"\bR\s*=\s*G\s*=\s*B\s*=\s*Y\b"),
    re.compile(r"grayscale_to_rgb\s*\([^)]*duplicate", re.IGNORECASE),
    re.compile(r"\bframe\.mean\s*\([^)]*\bcolor", re.IGNORECASE),
    re.compile(r"rgb_grey\s*=\s*\(\s*r\s*\+\s*g\s*\+\s*b\s*\)\s*/\s*3"),
    re.compile(r"\bsingle_channel_only\b"),
    re.compile(r"\b_grayscale_to_rgb\b"),
    re.compile(r"\b_drop_chroma\b"),
)


def _check_297_iter_target_files(repo_root: Path) -> list[Path]:
    """List every target file the gate scans.

    Includes:
      - src/tac/substrates/<id>/<any>.py
      - experiments/train_substrate_*.py
    Excludes test files, vendored intake clones, and generated artifacts.
    """
    targets: list[Path] = []

    substrates_root = repo_root / "src" / "tac" / "substrates"
    if substrates_root.is_dir():
        for entry in sorted(substrates_root.rglob("*.py")):
            rel = entry.relative_to(repo_root).as_posix()
            if "/tests/" in rel or "/test_" in rel:
                continue
            if "_intake_" in rel or "/build/lib/" in rel:
                continue
            if "/.omx/oss_export/" in rel:
                continue
            if entry.name.startswith("test_"):
                continue
            targets.append(entry)

    experiments_root = repo_root / "experiments"
    if experiments_root.is_dir():
        for entry in sorted(experiments_root.iterdir()):
            if not entry.is_file():
                continue
            if not entry.name.startswith("train_substrate_"):
                continue
            if not entry.name.endswith(".py"):
                continue
            rel = entry.relative_to(repo_root).as_posix()
            if "_intake_" in rel:
                continue
            targets.append(entry)

    return targets


def _check_297_line_has_waiver(line: str) -> bool:
    """Return True if ``line`` carries the canonical same-line waiver.

    Placeholder literals are rejected so the gate's own documentation
    example cannot self-waive a real violation.
    """
    if _CHECK_297_WAIVER_TOKEN not in line:
        return False
    idx = line.find(_CHECK_297_WAIVER_TOKEN)
    tail = line[idx + len(_CHECK_297_WAIVER_TOKEN):].strip()
    if not tail:
        return False
    for placeholder in _CHECK_297_WAIVER_PLACEHOLDERS:
        if tail.startswith(placeholder):
            return False
    return True


def _check_297_substrate_id_from_path(
    path: Path, repo_root: Path
) -> str | None:
    """Derive the substrate id from a target file's path.

    For ``src/tac/substrates/<id>/...``, returns ``<id>``.
    For ``experiments/train_substrate_<id>.py``, returns ``<id>``.
    """
    rel_parts = (
        path.relative_to(repo_root).parts if path.is_absolute() else path.parts
    )
    if len(rel_parts) >= 4 and rel_parts[:3] == ("src", "tac", "substrates"):
        return rel_parts[3]
    if (
        len(rel_parts) == 2
        and rel_parts[0] == "experiments"
        and rel_parts[1].startswith("train_substrate_")
        and rel_parts[1].endswith(".py")
    ):
        return rel_parts[1][len("train_substrate_"):-len(".py")]
    return None


def _check_297_sister_probe_exists(
    repo_root: Path, substrate_id: str
) -> bool:
    """Return True if a sister reversibility probe exists.

    Canonical pattern: ``tools/probe_<substrate_id>_reversibility*.py``.
    """
    tools_root = repo_root / "tools"
    if not tools_root.is_dir():
        return False
    prefix = f"probe_{substrate_id}_reversibility"
    for entry in tools_root.iterdir():
        if not entry.is_file():
            continue
        if not entry.name.endswith(".py"):
            continue
        if entry.name.startswith(prefix):
            return True
    return False


def _check_297_line_in_compress_time_only_function(
    text_lines: list[str], lineno: int
) -> bool:
    """Heuristic: is the line at ``lineno`` inside a function whose name
    contains ``_compress_time_only``?
    """
    if lineno < 1 or lineno > len(text_lines):
        return False
    target_line = text_lines[lineno - 1]
    target_indent = len(target_line) - len(target_line.lstrip())
    if target_indent == 0:
        return False

    def_pattern = re.compile(
        r"^(\s*)(?:async\s+)?def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\("
    )
    for i in range(lineno - 2, -1, -1):
        line = text_lines[i]
        if not line.strip():
            continue
        m = def_pattern.match(line)
        if not m:
            continue
        def_indent = len(m.group(1))
        if def_indent < target_indent:
            func_name = m.group(2)
            return _CHECK_297_COMPRESS_TIME_ONLY_MARKER in func_name
    return False


def _scan_file_for_signal_axis_destruction(
    path: Path, repo_root: Path
) -> list[str]:
    """Find signal-axis-destruction-without-reversibility-probe violations."""
    rel = path.relative_to(repo_root) if path.is_absolute() else path
    try:
        text = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []

    text_lines = text.splitlines()
    if not text_lines:
        return []

    hits: list[tuple[int, str, str]] = []
    for lineno, line in enumerate(text_lines, start=1):
        # Skip pure comment lines so docstring/comment mentions are not flagged.
        stripped = line.lstrip()
        if stripped.startswith("#"):
            continue
        for pattern in _CHECK_297_DESTRUCTION_PATTERNS:
            m = pattern.search(line)
            if m:
                hits.append((lineno, line, pattern.pattern))
                break

    if not hits:
        return []

    substrate_id = _check_297_substrate_id_from_path(path, repo_root)
    probe_exists = False
    if substrate_id is not None:
        probe_exists = _check_297_sister_probe_exists(repo_root, substrate_id)

    violations: list[str] = []
    for lineno, line, matched_pat in hits:
        if _check_297_line_has_waiver(line):
            continue
        if probe_exists:
            continue
        if _check_297_line_in_compress_time_only_function(text_lines, lineno):
            continue
        snippet = line.strip()[:160]
        violations.append(
            f"{rel}:{lineno}: signal-axis-destruction token detected "
            f"(pattern `{matched_pat}`, line: `{snippet}`) WITHOUT "
            f"sister reversibility probe at "
            f"`tools/probe_{substrate_id or '<substrate-id>'}_reversibility*.py` "
            f"AND WITHOUT same-line "
            f"`# SIGNAL_AXIS_DESTRUCTION_REVERSIBLE_PROBE_OK:<rationale>` "
            f"waiver AND not inside a `_compress_time_only`-named "
            f"function. Per CLAUDE.md \"Apples-to-apples evidence "
            f"discipline\" + Catalog #220 + Catalog #272. Empirical "
            f"anchors: NSCS06 Y=R=G=B chroma replication (seg=64.59), "
            f"NSCS06 np.roll global translation (pose=149.03), Z3-G1 "
            f"empty hyperprior slots (silent 0.19869 baseline). "
            f"Symposium commit 4292c8ce2; META-assumption audit commit "
            f"b0a7ff474. Either add a sister probe file, the same-"
            f"line waiver with rationale, or move the destruction "
            f"into a `_compress_time_only` function."
        )
    return violations


def check_substrate_signal_axis_destruction_has_reversibility_probe(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #297 - refuse substrate trainers / codec modules that destroy
    a signal axis (chroma drop / grayscale replication / explicit
    single-channel marker) without a paired reversibility probe.

    Empirical anchors 2026-05-16: NSCS06 Y=R=G=B chroma replication
    (seg=64.59), NSCS06 np.roll global translation (pose=149.03), Z3-G1
    empty hyperprior_weights_int8 slots (silent 0.19869 baseline
    reproduction proof that empty slots never affect score).

    Per CLAUDE.md "Apples-to-apples evidence discipline" + "Bit-level
    deconstruction and entropy discipline".

    Sister of Catalog #220 (substrate L1+ byte-addition operational
    mechanism), Catalog #272 (distinguishing-feature integration
    contract), Catalog #139 (packet compiler no-op detector), Catalog
    #105 (no-op provenance).

    Memory: ``feedback_catalog_297_substrate_signal_axis_destruction_reversibility_landed_20260516.md``.
    Lane: ``lane_catalog_296_297_metacargocult_strict_gates_20260516``.
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    targets = _check_297_iter_target_files(root)
    violations: list[str] = []
    for path in targets:
        violations.extend(_scan_file_for_signal_axis_destruction(path, root))

    if verbose:
        if violations:
            print(
                f"  [check_substrate_signal_axis_destruction_has_reversibility_probe] "
                f"{len(violations)} violation(s) across {len(targets)} "
                "substrate file(s):"
            )
            for v in violations[:10]:
                print(f"    - {v[:280]}")
        else:
            print(
                f"  [check_substrate_signal_axis_destruction_has_reversibility_probe] "
                f"OK ({len(targets)} substrate file(s) scanned, 0 violation(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_substrate_signal_axis_destruction_has_reversibility_probe "
            f"found {len(violations)} signal-axis-destruction violation(s) "
            "without paired reversibility probe. Per CLAUDE.md \"Apples-"
            "to-apples evidence discipline\" + Catalog #220 + Catalog "
            "#272 + Catalog #297 (META-CARGO-CULT META-CC-2). Empirical "
            "anchors: NSCS06 Y=R=G=B (seg=64.59), NSCS06 np.roll "
            "(pose=149.03), Z3-G1 empty slots (0.19869 silent baseline). "
            "Symposium commit 4292c8ce2; META-assumption audit commit "
            "b0a7ff474.\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #298 — check_substrate_lane_l1_scaffold_not_stale_dispatch
#
# PREMORTEM-CONSOLIDATION-WAVE 2026-05-16 self-protection per CLAUDE.md
# "Substrate retirement discipline" non-negotiable + the 12-month premortem
# (`.omx/research/12_month_frustration_premortem_and_recommendations_
# 20260516.md` Category E + Section 3 #1).
#
# Bug class: L1 SCAFFOLD substrate lanes accumulate in the registry
# without dispatch, polluting the cathedral autopilot ranker surface and
# creating decision overload. The premortem projects 200+ stale L1
# substrates by 2027-05-16 at current cadence.
#
# Refuses any in-scope L1 substrate lane in `.omx/state/lane_registry.json`
# with `impl_complete=true` that has no `lane_maturity.py mark` activity
# AND no `successful_dispatch` posterior anchor in the last
# `_CHECK_298_STALENESS_DAYS` days UNLESS one of the opt-outs applies:
#
#   (a) advance to L2+ (real-archive empirical or contest-CUDA gate
#       satisfied; the lane is no longer L1)
#   (b) declare `research_only=true` (or target_modes includes
#       `research_only` / `research_substrate`) with reactivation
#       criteria pinned in notes
#   (c) declare `lane_class=substrate_engineering` (or
#       `research_substrate`)
#   (d) declare `archived=true` (top-level field) OR
#       `lane_state=archived` token in notes
#   (e) same-line `# RETIREMENT_DISCIPLINE_WAIVED:<rationale>` waiver in
#       lane notes / evidence (placeholder `<rationale>` literal rejected)
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
# rule" because the operator-routed backfill sweep of existing stale
# L1 lanes is itself the strict-flip atomic. Strict-flip planned once
# the sweep drives count to 0.
#
# Sister of Catalog #220 (L1 scaffold operational mechanism declaration)
# + Catalog #272 (distinguishing-feature integration contract) + Catalog
# #233 (L1->L2 promotion canonical 4-gate). Together they extinct the
# "L1 SCAFFOLD substrate accumulates indefinitely" failure mode.
# ============================================================================

_CHECK_298_STALENESS_DAYS = 30

# Substrate id-substring set mirroring Catalog #220 / #272 in-scope tokens.
_CHECK_298_IN_SCOPE_ID_SUBSTRINGS: tuple[str, ...] = (
    "substrate_",
    "_substrate_",
    "_polytope_",
    "_sidecar_",
    "_overlay_",
    "yucr_",
    "d1_segnet",
    "d2_",
    "d4_",
    "lane_a1_",
    "_hnerv_",
    "_nerv_",
    "_lora_",
    "wavelet_residual",
    "siren_residual",
    "coord_mlp_residual",
    "nscs",
    "balle_",
    "cool_chic",
    "_c3_",
    "vq_vae",
    "self_compress",
)

_CHECK_298_OPT_OUT_RESEARCH_TOKENS: tuple[str, ...] = (
    "research_only=true",
    "research_only:true",
    "research-only=true",
)

_CHECK_298_OPT_OUT_SUBSTRATE_ENG_TOKENS: tuple[str, ...] = (
    "lane_class=substrate_engineering",
    "lane_class:substrate_engineering",
    "lane_class: substrate_engineering",
    "substrate_engineering_exception",
)

_CHECK_298_OPT_OUT_ARCHIVED_TOKENS: tuple[str, ...] = (
    "archived=true",
    "lane_state=archived",
    "terminal_verdict",
)

_CHECK_298_WAIVER_RE = re.compile(
    r"#\s*RETIREMENT_DISCIPLINE_WAIVED\s*:\s*(?P<reason>[^\n#]+)"
)

_CHECK_298_PLACEHOLDER_RATIONALES = ("<rationale>", "<reason>", "")


def _check_298_lane_in_scope(lane_id: str) -> bool:
    lane_id_lower = lane_id.lower()
    return any(
        tok in lane_id_lower
        for tok in _CHECK_298_IN_SCOPE_ID_SUBSTRINGS
    )


def _check_298_collect_lane_text(lane: dict) -> str:
    parts: list[str] = []
    notes = lane.get("notes", "")
    if isinstance(notes, str):
        parts.append(notes)
    gates = lane.get("gates", {})
    if isinstance(gates, dict):
        for gate_obj in gates.values():
            if isinstance(gate_obj, dict):
                ev = gate_obj.get("evidence", "")
                if isinstance(ev, str):
                    parts.append(ev)
    return "\n".join(parts).lower()


def _check_298_lane_opt_out(lane: dict, text: str) -> str | None:
    if lane.get("research_only") is True:
        return "research_only=true"
    if lane.get("archived") is True:
        return "archived=true"
    if lane.get("lane_class") in (
        "substrate_engineering", "research_substrate"
    ):
        return f"lane_class={lane['lane_class']}"
    target_modes = lane.get("target_modes", [])
    if isinstance(target_modes, list):
        for tm in target_modes:
            if isinstance(tm, str) and tm.lower() in (
                "research_substrate", "research_only"
            ):
                return f"target_modes={tm}"
    for tok in _CHECK_298_OPT_OUT_RESEARCH_TOKENS:
        if tok in text:
            return tok
    for tok in _CHECK_298_OPT_OUT_SUBSTRATE_ENG_TOKENS:
        if tok in text:
            return tok
    for tok in _CHECK_298_OPT_OUT_ARCHIVED_TOKENS:
        if tok in text:
            return tok
    return None


def _check_298_waiver_present(text: str) -> bool:
    for m in _CHECK_298_WAIVER_RE.finditer(text):
        reason = m.group("reason").strip().lower()
        if reason and reason not in _CHECK_298_PLACEHOLDER_RATIONALES:
            return True
    return False


def _check_298_lane_recent_mark_age_days(
    lane_id: str,
    audit_log_path: Path,
    now_ts: float,
) -> float | None:
    """Linear scan over audit log; returns the freshest mark-age in
    days for the lane, or None if no entries found."""
    from datetime import datetime as _dt, timezone as _tz
    if not audit_log_path.is_file():
        return None
    most_recent_ts: float | None = None
    try:
        for line in audit_log_path.read_text(encoding="utf-8").splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                continue
            args = row.get("args", {})
            if not isinstance(args, dict):
                continue
            audit_lane = args.get("lane_id") or args.get("id")
            if audit_lane != lane_id:
                continue
            ts = row.get("timestamp", "")
            if not isinstance(ts, str):
                continue
            try:
                cleaned = ts.rstrip("Z").split("+")[0]
                dt = _dt.fromisoformat(cleaned)
                dt_ts = dt.replace(tzinfo=_tz.utc).timestamp()
            except (ValueError, AttributeError):
                continue
            if most_recent_ts is None or dt_ts > most_recent_ts:
                most_recent_ts = dt_ts
    except OSError:
        return None
    if most_recent_ts is None:
        return None
    return (now_ts - most_recent_ts) / 86400.0


def check_substrate_lane_l1_scaffold_not_stale_dispatch(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #298 — refuse stale L1 SCAFFOLD substrate lanes.

    Per CLAUDE.md "Substrate retirement discipline" non-negotiable:
    every substrate at L1+ for >30 days without dispatch MUST either
    advance to L2+, declare `research_only=true` with reactivation
    criteria, OR be moved to archived state with terminal verdict.

    See module docstring for the full opt-out cascade and the
    `# RETIREMENT_DISCIPLINE_WAIVED:<rationale>` same-line waiver.

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-lane diagnostic.

    Returns:
        List of violation messages (one per stale L1 substrate lane).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    registry_path = root / ".omx" / "state" / "lane_registry.json"
    audit_log_path = root / ".omx" / "state" / "lane_maturity_audit.log"
    if not registry_path.is_file():
        if verbose:
            print("  [catalog-298] OK (no lane_registry.json)")
        return violations

    try:
        registry = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if verbose:
            print(f"  [catalog-298] WARN registry read error: {exc}")
        return violations

    lanes = registry.get("lanes")
    if not isinstance(lanes, list):
        if verbose:
            print("  [catalog-298] OK (registry has no lanes list)")
        return violations

    import time as _time
    now_ts = _time.time()
    scanned = 0
    opted_out = 0
    active_marks = 0

    for lane in lanes:
        if not isinstance(lane, dict):
            continue
        lane_id = str(lane.get("id", ""))
        if not lane_id or not _check_298_lane_in_scope(lane_id):
            continue
        level = int(lane.get("level", 0) or 0)
        if level != 1:
            # L0 lanes have not landed code yet; L2+ have empirical
            # evidence (out of scope for retirement discipline).
            continue
        gates = lane.get("gates", {})
        if not isinstance(gates, dict):
            continue
        impl_gate = gates.get("impl_complete", {})
        if not (isinstance(impl_gate, dict)
                and impl_gate.get("status") is True):
            # Not yet impl_complete; no retirement pressure.
            continue
        scanned += 1
        text = _check_298_collect_lane_text(lane)

        opt_out = _check_298_lane_opt_out(lane, text)
        if opt_out:
            opted_out += 1
            if verbose:
                print(
                    f"  [catalog-298] OK lane={lane_id} L{level} "
                    f"opt_out={opt_out!r}"
                )
            continue

        if _check_298_waiver_present(text):
            if verbose:
                print(
                    f"  [catalog-298] WAIVED lane={lane_id} L{level}"
                )
            continue

        mark_age = _check_298_lane_recent_mark_age_days(
            lane_id, audit_log_path, now_ts
        )
        if mark_age is not None and mark_age <= _CHECK_298_STALENESS_DAYS:
            active_marks += 1
            if verbose:
                print(
                    f"  [catalog-298] OK lane={lane_id} L{level} "
                    f"recent_mark_age_days={mark_age:.1f}"
                )
            continue

        violations.append(
            f"lane {lane_id!r} (L{level}) is in-scope L1 substrate "
            f"with impl_complete=true but no `lane_maturity.py mark` "
            f"activity in the last {_CHECK_298_STALENESS_DAYS} days "
            f"(most_recent_mark_age_days={mark_age}). Per CLAUDE.md "
            "\"Substrate retirement discipline\" non-negotiable, this "
            "lane MUST satisfy one of: "
            "(a) advance to L2+ via dispatch + empirical anchor, "
            "(b) declare `research_only=true` with reactivation "
            "criteria via `python tools/lane_maturity.py mark "
            f"{lane_id} --gate <gate> --evidence <ref>`, "
            "(c) declare `lane_class=substrate_engineering`, "
            "(d) move to archived state with terminal verdict, OR "
            "(e) carry a same-line "
            "`# RETIREMENT_DISCIPLINE_WAIVED:<rationale>` waiver in "
            "lane notes/evidence. Run "
            "`tools/audit_stale_l1_substrates.py` for the canonical "
            "operator-facing decision queue."
        )

    if verbose:
        print(
            f"  [catalog-298] scanned_l1_impl_complete={scanned} "
            f"opted_out={opted_out} active_marks={active_marks} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            "check_substrate_lane_l1_scaffold_not_stale_dispatch found "
            f"{len(violations)} L1 substrate lane(s) stale > "
            f"{_CHECK_298_STALENESS_DAYS} days without dispatch or "
            "explicit opt-out. Per CLAUDE.md \"Substrate retirement "
            "discipline\" + premortem #1 (Category E). Run "
            "`.venv/bin/python tools/audit_stale_l1_substrates.py "
            "--only-stale` for the decision queue:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #315 — check_substrate_at_optimal_form_before_paid_dispatch
#
# META-FRAMING-CORRECTION 2026-05-17 self-protection per operator directive
# of the same date.
#
# The structural failure this gate prevents:
#   Empirically dispatching substrates at LIFTED-TRAINER form (basic
#   implementation that passes tests + has PR95-paradigm tokens) when the
#   sextet / grand council returned ``PROCEED_WITH_REVISIONS`` and the
#   substrate has not been iterated to OPTIMAL FORM (cargo-cult-unwind
#   methodology applied + 9-dim checklist satisfied + sextet returned
#   PROCEED-unconditional). Per operator standing directives
#   (UNIQUE-AND-COMPLETE-PER-METHOD + 9-dim checklist + PR95-at-META +
#   HNeRV parity discipline + cargo-cult unwind methodology), substrate
#   dispatch must happen at OPTIMAL FORM, not at the first
#   ``impl_complete=true`` waypoint.
#
# Empirical anchors (this session):
#   - NSCS06 v6 -> v7 = 44% score improvement (105.15 -> 58.89) via
#     cargo-cult-unwind methodology. The ONLY substrate that got iterated
#     to optimal form before the next paid dispatch wave.
#   - 4-of-5 distinguishing-feature dispatch failures this session
#     (Wunderkind G1 v2 reducer / ATW v2 D4 cooperative-receiver /
#     Z6 FiLM ego-motion / NSCS01 nullspace-split / NSCS06 v8 Path B)
#     were empirically tested at LIFTED-TRAINER form, falsifying
#     specific implementations not the novel concepts.
#   - Operator's UNIQUE-AND-COMPLETE-PER-METHOD directive (Catalog #290)
#     + 9-dim checklist (Catalog #294) + cargo-cult audit (Catalog #303)
#     + observability surface (Catalog #305) are enforced at DESIGN-MEMO
#     surface but BYPASSED at IMPLEMENTATION + DISPATCH surface.
#
# How the gate detects the bug class:
#   For every in-scope substrate lane in ``.omx/state/lane_registry.json``
#   at L1+ with ``impl_complete=true``, the gate scans
#   ``.omx/state/council_deliberation_posterior.jsonl`` for the latest
#   council deliberation that names this substrate via the canonical
#   ``deferred_substrate_id`` field. If the latest verdict is
#   ``PROCEED_WITH_REVISIONS`` AND no later ``PROCEED`` anchor (without
#   revisions) supersedes it AND the lane has no opt-out, the gate
#   refuses.
#
# Acceptance cascade (any ONE suffices):
#   (a) Substrate has a sextet PROCEED-unconditional anchor that is
#       chronologically LATER than the most-recent
#       PROCEED_WITH_REVISIONS anchor for the same substrate
#       (iteration landed; council re-approved).
#   (b) ``research_only=true`` declared per CLAUDE.md "Substrate
#       scaffolds MUST be COMPLETE or RESEARCH-ONLY" non-negotiable
#       (top-level field OR notes-token OR target_modes contains
#       ``research_only`` / ``research_substrate``).
#   (c) ``lane_class=substrate_engineering`` declared (top-level field
#       OR notes-token) per HNeRV parity discipline L7 (substrate
#       engineering exceeds bolt-on size budget; not yet contest-
#       dispatch eligible).
#   (d) ``archived=true`` (top-level field OR notes-token
#       ``lane_state=archived`` / ``terminal_verdict``) per CLAUDE.md
#       "Forbidden premature KILL" — archived state is dormant-with-
#       reactivation, NOT kill.
#   (e) Same-line waiver
#       ``# OPTIMAL_FORM_DISPATCH_OK:<rationale>`` in lane notes /
#       evidence (placeholder ``<rationale>`` / ``<reason>`` literals
#       REJECTED so the gate's docstring example cannot self-waive).
#
# Sister gates:
#   - Catalog #220 — substrate L1+ scaffold operational mechanism
#   - Catalog #272 — distinguishing-feature integration contract
#   - Catalog #233 — L1->L2 promotion canonical 4-gate
#   - Catalog #298 — substrate L1 not stale dispatch (retirement
#     discipline; #315 is the iteration-discipline complement: #298
#     prevents staleness, #315 prevents premature dispatch)
#   - Catalog #294 — 9-dim success checklist (design-memo surface)
#   - Catalog #303 — cargo-cult audit section (design-memo surface)
#   - Catalog #305 — observability surface (design-memo surface)
#   - Catalog #300 — council deliberation v2 frontmatter
#
# Together they extinct the canonical failure: design-memo discipline
# (#290 + #294 + #303 + #305) is enforced at the memo surface, but the
# IMPLEMENTATION + COUNCIL + DISPATCH chain has no structural gate
# binding the council verdict back to the dispatch decision. Catalog
# #315 closes that surface.
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
# rule" — live count at landing is expected >0 because multiple
# substrates have PROCEED_WITH_REVISIONS anchors WITHOUT follow-on
# iteration anchors (Wunderkind G1 v2, ATW v2 D4 cooperative-receiver,
# Z6 v1 FiLM, NSCS01 v1 head0-capacity, NSCS03 v1 default-config).
# Strict-flip pending the substrate-iteration wave that lands either
# follow-on PROCEED-unconditional council anchors OR
# ``research_only=true`` opt-out on the affected lanes.
# ============================================================================

_CHECK_315_IN_SCOPE_ID_SUBSTRINGS: tuple[str, ...] = (
    "substrate_",
    "_substrate_",
    "_polytope_",
    "_sidecar_",
    "_overlay_",
    "yucr_",
    "d1_segnet",
    "d2_",
    "d4_",
    "lane_a1_",
    "_hnerv_",
    "_nerv_",
    "_lora_",
    "wavelet_residual",
    "siren_residual",
    "coord_mlp_residual",
    "nscs",
    "balle_",
    "cool_chic",
    "_c3_",
    "vq_vae",
    "self_compress",
    "time_traveler",
    "wunderkind",
    "atw_",
    "z6_",
    "z7_",
    "z8_",
    # FIX-WAVE-R1 F1 closure 2026-05-17: keep C6 IBPS + MDL-IBPS
    # dispatch lanes in Catalog #315 scope. The join fallback below
    # handles the malformed historical C6 council row whose
    # deferred_substrate_id was null.
    "c6_",
    "_c6_",
    "mdl_ibps",
    "_mdl_ibps",
)

_CHECK_315_NULL_DEFERRED_SUBSTRATE_ID_BACKFILLS: dict[str, str] = {
    # FIX-WAVE-R1 F1 closure 2026-05-17. The C6 IBPS sextet row was
    # emitted with deferred_substrate_id=null while its prose claimed
    # Catalog #315 satisfaction. Rewriting live append-only state would
    # risk trampling concurrent operator writes, so the guard carries a
    # narrow historical backfill keyed by immutable deliberation_id.
    "council_c6_ibps_phase_2_sextet_for_dispatch_unlock_20260517": (
        "c6_e4_mdl_ibps_substrate"
    ),
}

_CHECK_315_OPT_OUT_RESEARCH_TOKENS: tuple[str, ...] = (
    "research_only=true",
    "research_only:true",
    "research-only=true",
)

_CHECK_315_OPT_OUT_SUBSTRATE_ENG_TOKENS: tuple[str, ...] = (
    "lane_class=substrate_engineering",
    "lane_class:substrate_engineering",
    "lane_class: substrate_engineering",
    "substrate_engineering_exception",
)

_CHECK_315_OPT_OUT_ARCHIVED_TOKENS: tuple[str, ...] = (
    "archived=true",
    "lane_state=archived",
    "terminal_verdict",
)

_CHECK_315_WAIVER_RE = re.compile(
    r"#\s*OPTIMAL_FORM_DISPATCH_OK\s*:\s*(?P<reason>[^\n#]+)",
    re.IGNORECASE,
)

_CHECK_315_PLACEHOLDER_RATIONALES = ("<rationale>", "<reason>", "")


def _check_315_lane_in_scope(lane_id: str) -> bool:
    lane_id_lower = lane_id.lower()
    if any(
        tok in lane_id_lower
        for tok in (
            "_council",
            "sextet_council",
            "grand_council",
            "phase_2_sextet_council",
            "fix_wave",
        )
    ):
        return False
    return any(
        tok in lane_id_lower
        for tok in _CHECK_315_IN_SCOPE_ID_SUBSTRINGS
    )


def _check_315_collect_lane_text(lane: dict) -> str:
    parts: list[str] = []
    notes = lane.get("notes", "")
    if isinstance(notes, str):
        parts.append(notes)
    gates = lane.get("gates", {})
    if isinstance(gates, dict):
        for gate_obj in gates.values():
            if isinstance(gate_obj, dict):
                ev = gate_obj.get("evidence", "")
                if isinstance(ev, str):
                    parts.append(ev)
    return "\n".join(parts).lower()


def _check_315_lane_opt_out(lane: dict, text: str) -> str | None:
    if lane.get("research_only") is True:
        return "research_only=true"
    if lane.get("archived") is True:
        return "archived=true"
    if lane.get("lane_class") in (
        "substrate_engineering", "research_substrate"
    ):
        return f"lane_class={lane['lane_class']}"
    target_modes = lane.get("target_modes", [])
    if isinstance(target_modes, list):
        for tm in target_modes:
            if isinstance(tm, str) and tm.lower() in (
                "research_substrate", "research_only"
            ):
                return f"target_modes={tm}"
    for tok in _CHECK_315_OPT_OUT_RESEARCH_TOKENS:
        if tok in text:
            return tok
    for tok in _CHECK_315_OPT_OUT_SUBSTRATE_ENG_TOKENS:
        if tok in text:
            return tok
    for tok in _CHECK_315_OPT_OUT_ARCHIVED_TOKENS:
        if tok in text:
            return tok
    return None


def _check_315_waiver_present(text: str) -> bool:
    for m in _CHECK_315_WAIVER_RE.finditer(text):
        reason = m.group("reason").strip().lower()
        if reason and reason not in _CHECK_315_PLACEHOLDER_RATIONALES:
            return True
    return False


def _check_315_parse_iso_utc(value: str) -> float | None:
    """Best-effort parse of an ISO-8601 UTC timestamp to a POSIX
    seconds-since-epoch float. Returns None on parse failure."""
    from datetime import datetime as _dt, timezone as _tz
    if not isinstance(value, str) or not value:
        return None
    try:
        cleaned = value.rstrip("Z").split("+")[0]
        dt = _dt.fromisoformat(cleaned)
        return dt.replace(tzinfo=_tz.utc).timestamp()
    except (ValueError, AttributeError):
        return None


def _check_315_build_council_verdict_map(
    posterior_path: Path,
) -> dict[str, dict]:
    """Returns a map of substrate_id -> latest council deliberation
    record (the row with the most-recent ``written_at_utc``).

    Records without a ``deferred_substrate_id`` field cannot be joined
    back to a lane and are excluded. This is the canonical substrate
    -> council-verdict join surface per the council posterior schema.
    """
    latest_by_substrate: dict[str, dict] = {}
    latest_ts_by_substrate: dict[str, float] = {}
    if not posterior_path.is_file():
        return latest_by_substrate
    try:
        for line in posterior_path.read_text(encoding="utf-8").splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                continue
            substrate_id = row.get("deferred_substrate_id")
            if not isinstance(substrate_id, str) or not substrate_id:
                deliberation_id = row.get("deliberation_id")
                if isinstance(deliberation_id, str):
                    substrate_id = (
                        _CHECK_315_NULL_DEFERRED_SUBSTRATE_ID_BACKFILLS.get(
                            deliberation_id
                        )
                    )
            if not isinstance(substrate_id, str) or not substrate_id:
                continue
            ts_str = row.get("written_at_utc", "")
            ts = _check_315_parse_iso_utc(ts_str) or 0.0
            prior_ts = latest_ts_by_substrate.get(substrate_id)
            if prior_ts is None or ts > prior_ts:
                latest_ts_by_substrate[substrate_id] = ts
                latest_by_substrate[substrate_id] = row
    except OSError:
        return latest_by_substrate
    return latest_by_substrate


# v2 (codex review fix 2026-05-17): canonical substrate-family tokens used
# for fuzzy ID join. Posterior surface IDs (e.g.
# ``nscs01_nullspace_split_renderer_v1_head0_capacity_surface``) and lane
# IDs (e.g. ``lane_nscs01_nullspace_split_renderer_20260515``) rarely match
# exactly. The exact-ID join from v1 silently missed every revised-council
# lane on the live repo. Family-token overlap recovers them.
_CHECK_315_SUBSTRATE_FAMILY_TOKENS: tuple[str, ...] = (
    "nscs01", "nscs02", "nscs03", "nscs04", "nscs05", "nscs06",
    "z3_g1", "z3_balle", "z4", "z5", "z6", "z7", "z8",
    "c6",
    "c6_e4",
    "c6_e4_mdl_ibps",
    "mdl_ibps",
    "atw_codec",
    "wunderkind_g1",
    "tishby_ib_pure",
    "rudin",
    "darts_supernet",
)


def _check_315_extract_family_tokens(id_str: str) -> frozenset[str]:
    """Returns the set of canonical substrate-family tokens present in an
    ID string. Used to fuzzy-match posterior ``deferred_substrate_id``
    surface names against lane registry IDs when exact join fails.
    """
    if not isinstance(id_str, str) or not id_str:
        return frozenset()
    normalized = re.sub(r"[^a-z0-9]+", "_", id_str.lower()).strip("_")
    haystack = f"_{normalized}_"
    hits: set[str] = set()
    for tok in _CHECK_315_SUBSTRATE_FAMILY_TOKENS:
        normalized_tok = re.sub(r"[^a-z0-9]+", "_", tok.lower()).strip("_")
        if normalized_tok and f"_{normalized_tok}_" in haystack:
            hits.add(tok)
    return frozenset(hits)


def _check_315_substrate_ids_for_lane(lane: dict) -> tuple[str, ...]:
    """Returns the set of substrate_id strings that may identify this
    lane in the council posterior. The lane.id itself is the primary
    key; additional aliases may live in lane.notes (e.g. the v1 surface
    name documented in council deliberations)."""
    ids: list[str] = []
    lane_id = str(lane.get("id", ""))
    if lane_id:
        ids.append(lane_id)
    # Some council anchors use the alias surface name, not the
    # full registry id. Allow lookup by alias if the lane declares
    # one. The alias field is OPT-IN; missing alias is fine.
    alias = lane.get("substrate_alias")
    if isinstance(alias, str) and alias:
        ids.append(alias)
    aliases = lane.get("substrate_aliases")
    if isinstance(aliases, list):
        for a in aliases:
            if isinstance(a, str) and a:
                ids.append(a)
    return tuple(ids)


def _check_315_lookup_latest_verdict(
    lane: dict,
    verdict_map: dict[str, dict],
) -> dict | None:
    """Returns the latest council deliberation record that names this
    lane (any of its substrate_ids OR a posterior surface_id that
    shares a canonical substrate-family token), or None if no anchor
    exists.

    v2 (codex review fix 2026-05-17): added family-token fallback after
    exact-ID join failed silently on every revised-council lane in the
    live repo (NSCS01/NSCS03/Z6/Wunderkind/Tishby all used `_v1_*_surface`
    surface IDs that did not match any lane ID exactly).
    """
    candidate: dict | None = None
    candidate_ts: float = -1.0
    # Pass 1: exact ID join (primary path; preserves prior behavior)
    for sid in _check_315_substrate_ids_for_lane(lane):
        row = verdict_map.get(sid)
        if row is None:
            continue
        ts = _check_315_parse_iso_utc(row.get("written_at_utc", "")) or 0.0
        if ts > candidate_ts:
            candidate_ts = ts
            candidate = row
    if candidate is not None:
        return candidate
    # Pass 2: family-token fuzzy match (codex review v2 fallback). Only
    # fires when exact join produced nothing. Requires non-empty token
    # overlap between lane and posterior surface ID.
    lane_tokens = _check_315_extract_family_tokens(str(lane.get("id", "")))
    if not lane_tokens:
        return None
    for sid, row in verdict_map.items():
        sid_tokens = _check_315_extract_family_tokens(sid)
        if not sid_tokens or not (lane_tokens & sid_tokens):
            continue
        ts = _check_315_parse_iso_utc(row.get("written_at_utc", "")) or 0.0
        if ts > candidate_ts:
            candidate_ts = ts
            candidate = row
    return candidate


def check_substrate_at_optimal_form_before_paid_dispatch(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #315 — refuse substrate dispatch at LIFTED-TRAINER form
    when sextet council returned PROCEED_WITH_REVISIONS.

    Per operator directive 2026-05-17 (META-FRAMING-CORRECTION):
    substrates MUST be iterated to OPTIMAL FORM (cargo-cult-unwind
    methodology applied + 9-dim checklist satisfied + sextet returned
    PROCEED-unconditional) BEFORE paid empirical dispatch. The 4-of-5
    distinguishing-feature failures this session falsified SPECIFIC
    IMPLEMENTATIONS at lifted-trainer form rather than novel concepts.

    See the module-level Catalog #315 docstring above for the full
    acceptance cascade and the
    ``# OPTIMAL_FORM_DISPATCH_OK:<rationale>`` same-line waiver.

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-lane diagnostic.

    Returns:
        List of violation messages (one per lane at lifted-trainer
        form with outstanding council revisions).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    registry_path = root / ".omx" / "state" / "lane_registry.json"
    posterior_path = (
        root / ".omx" / "state" / "council_deliberation_posterior.jsonl"
    )
    # v2 (codex review fix 2026-05-17): in STRICT mode, treat missing or
    # unreadable control-plane state as a paid-dispatch blocker. Codex's
    # finding: "absence of the registry/posterior is not evidence that
    # every substrate is at optimal form; it is loss of the very state
    # needed to prove safety. Under recovery, partial checkout, or JSON
    # corruption, strict preflight can silently drop this guard before
    # provider spend."
    if not registry_path.is_file():
        if strict:
            raise PreflightError(
                "check_substrate_at_optimal_form_before_paid_dispatch "
                "(Catalog #315 v2 fail-closed): lane_registry.json "
                "is MISSING. Strict mode REQUIRES the lane registry to "
                "prove substrate-form readiness; missing state is NOT "
                "evidence of safety. Restore the registry or run in "
                "non-strict mode for exploratory calls."
            )
        if verbose:
            print("  [catalog-315] WARN (no lane_registry.json; non-strict)")
        return violations
    try:
        registry = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError) as exc:
        if strict:
            raise PreflightError(
                "check_substrate_at_optimal_form_before_paid_dispatch "
                "(Catalog #315 v2 fail-closed): lane_registry.json is "
                f"UNREADABLE/CORRUPT ({exc}). Strict mode REQUIRES a "
                "valid lane registry; refusing paid dispatch."
            )
        if verbose:
            print(f"  [catalog-315] WARN registry read error: {exc}")
        return violations

    lanes = registry.get("lanes")
    if not isinstance(lanes, list):
        if strict:
            raise PreflightError(
                "check_substrate_at_optimal_form_before_paid_dispatch "
                "(Catalog #315 v2 fail-closed): lane_registry.json has "
                "no 'lanes' list. Refusing paid dispatch."
            )
        if verbose:
            print("  [catalog-315] WARN (registry has no lanes list)")
        return violations

    if not posterior_path.is_file():
        if strict:
            raise PreflightError(
                "check_substrate_at_optimal_form_before_paid_dispatch "
                "(Catalog #315 v2 fail-closed): "
                "council_deliberation_posterior.jsonl is MISSING. "
                "Strict mode REQUIRES the council posterior to prove "
                "substrate-form readiness; missing state is NOT "
                "evidence of safety."
            )
        if verbose:
            print(
                "  [catalog-315] WARN "
                "(no council_deliberation_posterior.jsonl; non-strict)"
            )
        return violations

    verdict_map = _check_315_build_council_verdict_map(posterior_path)
    if not verdict_map:
        if strict:
            raise PreflightError(
                "check_substrate_at_optimal_form_before_paid_dispatch "
                "(Catalog #315 v2 fail-closed): council posterior has "
                "no deferred_substrate_id anchors. Strict mode REQUIRES "
                "council deliberations to prove substrate-form readiness."
            )
        if verbose:
            print(
                "  [catalog-315] WARN "
                "(no deferred_substrate_id anchors in posterior)"
            )
        return violations

    scanned = 0
    opted_out = 0
    proceed_unconditional = 0
    no_council_anchor = 0

    for lane in lanes:
        if not isinstance(lane, dict):
            continue
        lane_id = str(lane.get("id", ""))
        if not lane_id or not _check_315_lane_in_scope(lane_id):
            continue
        level = int(lane.get("level", 0) or 0)
        if level < 1:
            continue
        gates = lane.get("gates", {})
        if not isinstance(gates, dict):
            continue
        impl_gate = gates.get("impl_complete", {})
        if not (
            isinstance(impl_gate, dict)
            and impl_gate.get("status") is True
        ):
            continue
        scanned += 1
        text = _check_315_collect_lane_text(lane)

        opt_out = _check_315_lane_opt_out(lane, text)
        if opt_out:
            opted_out += 1
            if verbose:
                print(
                    f"  [catalog-315] OK lane={lane_id} L{level} "
                    f"opt_out={opt_out!r}"
                )
            continue

        if _check_315_waiver_present(text):
            if verbose:
                print(
                    f"  [catalog-315] WAIVED lane={lane_id} L{level}"
                )
            continue

        latest = _check_315_lookup_latest_verdict(lane, verdict_map)
        if latest is None:
            # No council anchor exists for this substrate after exact-ID
            # join and family-token fallback. Catalog #315 is specifically
            # the council-verdict-binding surface; it must not become a
            # broad retroactive "all historical substrate lanes need
            # council rows" migration gate. Sister gates cover lanes with
            # missing design/promotion evidence. This gate only blocks
            # when a joinable council anchor exists and is not a positive
            # PROCEED.
            no_council_anchor += 1
            if verbose:
                print(
                    f"  [catalog-315] WARN lane={lane_id} L{level} "
                    "no_council_anchor (covered by sister gates)"
                )
            continue

        verdict = latest.get("council_verdict", "")
        # v2 (codex review fix 2026-05-17): POSITIVE PROCEED requirement.
        # Codex's HIGH finding: v1 accepted any verdict !=
        # 'PROCEED_WITH_REVISIONS' as dispatch-safe, including DEFER /
        # REFUSE / ESCALATE_TO_HIGHER_TIER / missing / unknown. For a
        # paid-dispatch BLOCKER the hard requirement is POSITIVE
        # authorization, not absence of one specific negation.
        _POSITIVE_PROCEED_VERDICTS = {"PROCEED", "PROCEED_UNCONDITIONAL"}
        if verdict in _POSITIVE_PROCEED_VERDICTS:
            proceed_unconditional += 1
            if verbose:
                print(
                    f"  [catalog-315] OK lane={lane_id} L{level} "
                    f"latest_verdict={verdict!r} (positive PROCEED)"
                )
            continue

        deliberation_id = latest.get("deliberation_id", "<unknown>")
        verdict_ts_str = latest.get("written_at_utc", "<unknown>")
        # Classify non-PROCEED verdicts for dispatch-blocker rationale.
        if verdict == "PROCEED_WITH_REVISIONS":
            verdict_class = "iteration_pending"
        elif verdict in ("DEFER_PENDING_EVIDENCE", "DEFER", "REFUSE"):
            verdict_class = "dormant_pending_redeliberation"
        elif verdict.startswith("ESCALATE"):
            verdict_class = "escalated_no_authorization"
        elif not verdict:
            verdict_class = "missing_verdict"
        else:
            verdict_class = "unknown_non_proceed_verdict"
        violations.append(
            f"lane {lane_id!r} (L{level}) is in-scope substrate lane "
            f"with impl_complete=true but the latest council "
            f"deliberation ({deliberation_id!r} at {verdict_ts_str}) "
            f"returned council_verdict={verdict!r} "
            f"(blocker class: {verdict_class}) AND no follow-on "
            "POSITIVE PROCEED anchor supersedes it. Per CLAUDE.md "
            "\"Substrate MUST be at OPTIMAL FORM before paid empirical "
            "dispatch\" v2 fail-closed: this lane MUST satisfy one of: "
            "(a) land iteration subagent commits applying the council "
            "revisions + re-trigger sextet/grand-council deliberation "
            "that returns POSITIVE PROCEED per the canonical iteration "
            "methodology (NSCS06 v6->v7 pattern), "
            "(b) declare `research_only=true` with reactivation "
            "criteria, "
            "(c) declare `lane_class=substrate_engineering`, "
            "(d) move to archived state with terminal verdict, OR "
            "(e) carry a same-line "
            "`# OPTIMAL_FORM_DISPATCH_OK:<rationale>` waiver in lane "
            "notes/evidence (rationale must be a real string)."
        )

    if verbose:
        print(
            f"  [catalog-315] scanned={scanned} "
            f"opted_out={opted_out} "
            f"latest_proceed_unconditional={proceed_unconditional} "
            f"no_council_anchor={no_council_anchor} "
            f"violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            "check_substrate_at_optimal_form_before_paid_dispatch "
            f"found {len(violations)} substrate lane(s) at LIFTED-"
            "TRAINER form with outstanding sextet/grand-council "
            "PROCEED_WITH_REVISIONS verdicts. Per CLAUDE.md "
            "\"Substrate MUST be at OPTIMAL FORM before paid "
            "empirical dispatch\" non-negotiable, every such lane "
            "must land iteration commits + receive a follow-on "
            "PROCEED-unconditional council anchor BEFORE any paid "
            "Modal/Lightning/Vast.ai dispatch. Canonical iteration "
            "methodology: NSCS06 v6->v7 (105.15 -> 58.89, 44% "
            "improvement in ONE iteration via cargo-cult unwinds). "
            "Affected lanes:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #299 — check_catalog_quota_under_400
#
# PREMORTEM-CONSOLIDATION-WAVE 2026-05-16 self-protection per CLAUDE.md
# "Gate consolidation discipline" non-negotiable + the 12-month premortem
# (`.omx/research/12_month_frustration_premortem_and_recommendations_
# 20260516.md` Category A + Section 3 #5).
#
# Bug class: every bug surface gets a new STRICT preflight gate. At the
# current cadence (~5-10 new gates/week) the catalog # crosses 500 by
# Q4 2026 and 700+ by 2027-05-16. preflight.py swells past 100K LOC.
# Operator-authorize harness's 30-second budget breaks. New gates get
# added but reviewed only by their author. META-meta phantom-row
# incidents become the rule.
#
# Refuses any state of `src/tac/preflight.py` where a STRICT preflight
# callsite (function name pattern `check_*` invoked at strict=True in
# `preflight_all()` body) has catalog # > 400 without a `# CATALOG_
# QUOTA_EXCEEDED_OK:<rationale>` waiver in `CLAUDE.md` (file-level
# waiver in first 200 lines per the discipline section).
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
# rule" — the current catalog # is ~300 so the quota is not yet
# binding. Strict-flip planned when catalog # approaches 400 (so the
# operator gets the explicit "stop and consolidate" pause at the
# right moment).
#
# Sister of Catalog #118 (no duplicate numbers) + Catalog #159
# (catalog text matches strict value) + Catalog #176 (strict callsites
# have CLAUDE.md row) + Catalog #185 (LIVE_COUNT drift detection) +
# Catalog #186 (catalog claim committed via serializer). Together they
# extinct the catalog # drift / phantom-row / exhaustion failure modes
# at FIVE surfaces: number uniqueness (#118) + text-strict parity
# (#159) + callsite-has-row (#176) + live-count drift (#185) +
# claim-transactional (#186) + quota brake (#299).
# ============================================================================

_CHECK_299_CATALOG_QUOTA = 400
_CHECK_299_STRICT_CALLSITE_RE = re.compile(
    r"^\s*check_([a-z0-9_]+)\(\s*$", re.MULTILINE,
)
_CHECK_299_CATALOG_NUM_RE = re.compile(
    r"#\s*Catalog\s+#(\d+)", re.IGNORECASE,
)
_CHECK_299_WAIVER_RE = re.compile(
    r"#\s*CATALOG_QUOTA_EXCEEDED_OK\s*:\s*(?P<reason>[^\n#]+)"
)


def check_catalog_quota_under_400(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #299 — refuse new STRICT gates with catalog # > 400.

    Per CLAUDE.md "Gate consolidation discipline" non-negotiable: no
    new STRICT preflight gate may be claimed past Catalog #400 without
    one of:
      (a) retirement of an existing strict gate (mark DEPRECATED +
          remove after 30 days),
      (b) operator-explicit `# CATALOG_QUOTA_EXCEEDED_OK:<rationale>`
          waiver in CLAUDE.md (first 200 lines),
      (c) the new gate REPLACES an existing strict gate.

    Triggers an explicit "stop and consolidate" pause: review the
    existing 295+ gates for retirement candidates BEFORE adding the
    new one.

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print scan summary.

    Returns:
        List of violation messages (one per over-quota strict callsite).
    """
    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    violations: list[str] = []

    # The waiver lives in CLAUDE.md (per the discipline section).
    claude_md_path = root / "CLAUDE.md"
    waived = False
    if claude_md_path.is_file():
        try:
            head = "\n".join(
                claude_md_path.read_text(
                    encoding="utf-8", errors="replace"
                ).splitlines()[:200]
            )
        except OSError:
            head = ""
        for m in _CHECK_299_WAIVER_RE.finditer(head):
            reason = m.group("reason").strip().lower()
            if reason and reason not in (
                "<rationale>", "<reason>", ""
            ):
                waived = True
                break

    if waived:
        if verbose:
            print(
                "  [catalog-299] WAIVED (CLAUDE.md file-level waiver "
                "`# CATALOG_QUOTA_EXCEEDED_OK:<rationale>` present)"
            )
        return violations

    # Parse the catalog table from CLAUDE.md to determine which catalog
    # #s are currently registered.
    registered_nums: set[int] = set()
    if claude_md_path.is_file():
        try:
            md_text = claude_md_path.read_text(
                encoding="utf-8", errors="replace"
            )
        except OSError:
            md_text = ""
        for line in md_text.splitlines():
            m = re.match(r"^(\d+)\.\s+`check_", line)
            if m:
                try:
                    registered_nums.add(int(m.group(1)))
                except ValueError:
                    pass

    over_quota = sorted(n for n in registered_nums if n > _CHECK_299_CATALOG_QUOTA)
    if not over_quota:
        if verbose:
            registered_max = max(registered_nums) if registered_nums else 0
            print(
                f"  [catalog-299] OK (max registered catalog # = "
                f"{registered_max}; quota = {_CHECK_299_CATALOG_QUOTA})"
            )
        return violations

    for cat_num in over_quota:
        violations.append(
            f"CLAUDE.md catalog table contains entry for Catalog "
            f"#{cat_num} which exceeds the quota of "
            f"#{_CHECK_299_CATALOG_QUOTA}. Per CLAUDE.md \"Gate "
            "consolidation discipline\" non-negotiable + premortem #5 "
            "(Category A): new STRICT preflight gates past the quota "
            "MUST EITHER (a) retire an existing strict gate (mark "
            "DEPRECATED + remove after 30 days), (b) carry a file-"
            "level `# CATALOG_QUOTA_EXCEEDED_OK:<rationale>` waiver "
            "in CLAUDE.md first 200 lines, OR (c) REPLACE an existing "
            "strict gate (delete the old entry). Action: stop adding "
            "new gates and consolidate existing 295+ for retirement "
            "candidates BEFORE the next claim."
        )

    if verbose:
        print(
            f"  [catalog-299] registered_max="
            f"{max(registered_nums) if registered_nums else 0} "
            f"over_quota={len(over_quota)} violations={len(violations)}"
        )

    if violations and strict:
        raise PreflightError(
            "check_catalog_quota_under_400 found "
            f"{len(violations)} catalog entries above the "
            f"#{_CHECK_299_CATALOG_QUOTA} quota. Per CLAUDE.md \"Gate "
            "consolidation discipline\" non-negotiable: stop adding "
            "STRICT preflight gates and consolidate the existing "
            "catalog. Add a file-level `# CATALOG_QUOTA_EXCEEDED_OK:"
            "<rationale>` waiver in CLAUDE.md first 200 lines OR "
            "retire / replace existing gates:\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #300 - check_council_deliberation_declares_tier_in_frontmatter
#
# COUNCIL-HIERARCHY-V2 self-protection 2026-05-16 (operator-approved 4-tier
# protocol with maximum-signal preservation + continual-learning wire-in
# meta-principles per `feedback_council_hierarchy_v2_landed_20260516.md`).
#
# Anchor: Catalog #292 enforces per-DELIBERATION assumption surfacing for
# all council memos dated >= 2026-05-15. The COUNCIL-HIERARCHY-V2 landing
# extends the discipline with a 4-tier protocol (T1 Working Group / T2
# Inner-Skunkworks / T3 Full Grand Council / T4 Symposium) so that quorum
# rules, tie-break rules, recusal triggers, elevation triggers, and the
# operator-attention budget per tier are all explicit. Without a TIER
# declaration in the council memo frontmatter, downstream consumers (the
# continual-learning posterior, the Rashomon ensemble, the audit cadence
# tool) cannot route the deliberation through the correct sub-flow.
#
# Refuses any post-cutoff council memo lacking the v2 frontmatter fields.
# Required fields (per the v2 spec):
#   - council_tier             — one of T1/T2/T3/T4
#   - council_attendees        — list of named members
#   - council_quorum_met       — boolean per quorum rules
#   - council_verdict          — one of PROCEED / PROCEED_WITH_REVISIONS /
#                                DEFER_PENDING_EVIDENCE / REFUSE /
#                                ESCALATE_TO_OPERATOR / ESCALATE_TO_HIGHER_TIER
#   - council_dissent          — list (may be empty); verbatim minority opinions
#   - council_decisions_recorded — list (may be empty); op-routables emitted
#
# T2+ memos additionally require:
#   - council_assumption_adversary_verdict — list (≥1 entry)
#
# Acceptance:
#   - Pre-cutoff memos (date < 2026-05-16T18:00:00Z) are exempt by date filter
#     (Catalog #292 still applies to those; #300 is the v2 extension).
#   - Post-cutoff memos with all required frontmatter fields pass.
#   - Same-line `# COUNCIL_TIER_FRONTMATTER_WAIVED:<rationale>` waiver in
#     the memo body honored (placeholder `<rationale>` / `<reason>` rejected).
#
# WARN-ONLY at landing per "Strict-flip atomicity rule" — no post-cutoff
# council memos exist at landing time. Strict-flip planned after 5 council
# deliberations land in v2 format.
#
# Sister of:
#   - Catalog #291 (META-ASSUMPTION cadence — session-level cousin)
#   - Catalog #292 (per-deliberation assumption surfacing — body-level cousin)
#   - Catalog #229 (premise-verification-before-edit pattern)
#   - Catalog #290 (substrate canonical-vs-unique discipline — same OSS-hermetic
#     design pattern)
#   - Catalog #185 (CLAUDE.md catalog text vs empirical state drift)
# ============================================================================

# Cutoff cutoff UTC instant; memos written before this are exempt by date
# filter (Catalog #292 still applies for the body-level discipline).
_CHECK_300_CUTOFF_DATE_SUFFIX_INT = 20260516

# Filename patterns matching council deliberation memos in scope. Extends
# Catalog #292's regex to ALSO match council memos in `.omx/research/` that
# don't carry the `feedback_` prefix (e.g.
# `grand_council_symposium_<topic>_<YYYYMMDD>.md` lives in repo-local
# research with no feedback_ prefix; Claude memory memos use the
# `feedback_*council*<date>.md` convention).
_CHECK_300_COUNCIL_FILENAME_RE = re.compile(
    r"^(?:feedback_)?.*(?:grand_council|skunkworks_council|council|reunion.*symposium)"
    r".*?(\d{8}).*\.md$",
    re.IGNORECASE,
)

# Required v2 frontmatter field names (case-sensitive; checked as
# `<field>:` substring in the memo body, matching standard YAML
# frontmatter syntax).
_CHECK_300_REQUIRED_FIELDS: tuple[str, ...] = (
    "council_tier",
    "council_attendees",
    "council_quorum_met",
    "council_verdict",
    "council_dissent",
    "council_decisions_recorded",
)

# T2+ additionally requires this field (assumption-adversary classification
# per Catalog #292's HARD-EARNED vs CARGO-CULTED discipline).
_CHECK_300_T2_PLUS_REQUIRED_FIELD = "council_assumption_adversary_verdict"

# T2+ mission-alignment fields per CLAUDE.md "Mission alignment —
# non-negotiable" subsection (operator binding standing directive 2026-05-16
# per `feedback_council_apparatus_in_service_of_innovation_rigor_optimization_score_lowering_20260516.md`).
# These extend the T2+ required set with the 3 mission-alignment frontmatter
# fields. council_override_rationale is REQUIRED only when
# council_override_invoked is true (paired-field validation below).
_CHECK_300_T2_PLUS_MISSION_REQUIRED_FIELDS: tuple[str, ...] = (
    "council_predicted_mission_contribution",
    "council_override_invoked",
)

# Valid values for council_predicted_mission_contribution per the canonical
# enum at tac.council_continual_learning.VALID_MISSION_CONTRIBUTIONS. Kept
# in lock-step with that enum so a future migration to a new category is
# caught at both the helper-construction surface AND the frontmatter
# inspection surface.
_CHECK_300_VALID_MISSION_CONTRIBUTIONS: frozenset[str] = frozenset({
    "frontier_breaking",
    "frontier_protecting",
    "rigor_overhead",
    "apparatus_maintenance",
    "mission_questioned",
})

# Recognized tier values for `council_tier:`.
_CHECK_300_VALID_TIERS: frozenset[str] = frozenset({"T1", "T2", "T3", "T4"})

_CHECK_300_WAIVER_PATTERN = re.compile(
    r"#\s*COUNCIL_TIER_FRONTMATTER_WAIVED\s*:\s*([^\s][^\n#]{0,200})"
)
_CHECK_300_WAIVER_PLACEHOLDERS = frozenset(("<rationale>", "<reason>", ""))


def _check_300_parse_date_suffix(suffix: str) -> int | None:
    """Parse YYYYMMDD into a sortable int; return None on malformed."""
    if len(suffix) != 8:
        return None
    try:
        year = int(suffix[0:4])
        month = int(suffix[4:6])
        day = int(suffix[6:8])
    except ValueError:
        return None
    if not (1 <= month <= 12 and 1 <= day <= 31):
        return None
    return year * 10000 + month * 100 + day


def _check_300_has_waiver(body: str) -> bool:
    for m in _CHECK_300_WAIVER_PATTERN.finditer(body):
        rationale = m.group(1).strip().lower()
        if rationale not in _CHECK_300_WAIVER_PLACEHOLDERS:
            return True
    return False


def _check_300_extract_tier(body: str) -> str | None:
    """Extract the value of `council_tier:` from the memo body.

    Tolerates leading whitespace, quoted values, and inline values.
    Returns the first match; if no value or unrecognized value, returns
    None (caller treats as missing).
    """
    m = re.search(
        r"council_tier\s*:\s*['\"]?(T[1234])['\"]?",
        body,
        re.IGNORECASE,
    )
    if not m:
        return None
    tier = m.group(1).upper()
    if tier in _CHECK_300_VALID_TIERS:
        return tier
    return None


def _check_300_default_research_dir(repo_root: Path | str | None = None) -> Path:
    root = Path(repo_root or REPO_ROOT).resolve()
    return root / ".omx" / "research"


def _check_300_extract_mission_contribution(body: str) -> str | None:
    """Extract the value of `council_predicted_mission_contribution:` from the memo body.

    Tolerates leading whitespace and optionally-quoted values. Returns the
    first match if the value is in :data:`_CHECK_300_VALID_MISSION_CONTRIBUTIONS`;
    None otherwise (caller treats as missing or malformed).
    """
    m = re.search(
        r"council_predicted_mission_contribution\s*:\s*['\"]?([a-z_]+)['\"]?",
        body,
        re.IGNORECASE,
    )
    if not m:
        return None
    value = m.group(1).lower()
    if value in _CHECK_300_VALID_MISSION_CONTRIBUTIONS:
        return value
    return None


def _check_300_extract_override_invoked(body: str) -> bool | None:
    """Extract the value of `council_override_invoked:` from the memo body.

    Returns True / False on canonical YAML boolean values; None when the
    field is missing or malformed (caller treats as missing).
    """
    m = re.search(
        r"council_override_invoked\s*:\s*['\"]?(true|false|yes|no)['\"]?",
        body,
        re.IGNORECASE,
    )
    if not m:
        return None
    value = m.group(1).lower()
    if value in ("true", "yes"):
        return True
    if value in ("false", "no"):
        return False
    return None


def _check_300_has_override_rationale(body: str) -> bool:
    """Return True when `council_override_rationale:` field is present with non-empty value.

    A bare `council_override_rationale:` (no value) OR
    `council_override_rationale: null` does NOT count as present.
    """
    m = re.search(
        r"council_override_rationale\s*:\s*['\"]?([^\n\r]+?)['\"]?\s*(?:#|$)",
        body,
        re.IGNORECASE | re.MULTILINE,
    )
    if not m:
        return False
    value = m.group(1).strip().strip("'\"").lower()
    if not value or value in ("null", "none", "~"):
        return False
    return True


def check_council_deliberation_declares_tier_in_frontmatter(
    *,
    memory_dir: Path | str | None = None,
    research_dir: Path | str | None = None,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #300 — refuse council memos missing the v2 4-tier frontmatter.

    Per CLAUDE.md "Council hierarchy: 4-tier protocol" non-negotiable +
    COUNCIL-HIERARCHY-V2 landing 2026-05-16. Every council deliberation
    memo dated >= 2026-05-16 MUST carry the v2 frontmatter fields so
    downstream consumers (continual-learning posterior, Rashomon
    ensemble, cadence audit tool) can route the deliberation through
    the correct sub-flow.

    Required v2 frontmatter (all tiers):
      - council_tier (one of T1/T2/T3/T4)
      - council_attendees
      - council_quorum_met
      - council_verdict
      - council_dissent
      - council_decisions_recorded

    T2+ additionally:
      - council_assumption_adversary_verdict

    Acceptance:
      - Pre-cutoff memos (date < 20260516) exempt by date filter
        (Catalog #292 still applies).
      - Post-cutoff memos with all required fields pass.
      - Same-line `# COUNCIL_TIER_FRONTMATTER_WAIVED:<rationale>`
        waiver with non-placeholder rationale.

    Sister of Catalog #291 (session-level cadence), #292 (body-level
    assumption surfacing), #229 (premise verification), #290 (substrate
    canonical-vs-unique), #185 (META-meta drift detector).

    Memory: ``feedback_council_hierarchy_v2_landed_20260516.md``.

    Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
    rule"; live count at landing is 0. Strict-flip planned after 5
    deliberations land in v2 format.
    """
    if memory_dir is None:
        memory_target = None
    elif isinstance(memory_dir, str):
        memory_target = Path(memory_dir)
    else:
        memory_target = memory_dir
    if research_dir is None:
        research_target = _check_300_default_research_dir(repo_root)
    elif isinstance(research_dir, str):
        research_target = Path(research_dir)
    else:
        research_target = research_dir

    violations: list[str] = []
    seen_dirs: set[Path] = set()
    target_surfaces: list[tuple[Path, str]] = []
    if memory_target is not None:
        target_surfaces.append((memory_target, "memory"))
    target_surfaces.append((research_target, "research"))

    for target, surface in target_surfaces:
        try:
            resolved_target = target.resolve()
        except OSError:
            resolved_target = target
        if resolved_target in seen_dirs:
            continue
        seen_dirs.add(resolved_target)
        if not target.is_dir():
            continue
        try:
            candidates = sorted(target.iterdir())
        except OSError:
            continue
        for entry in candidates:
            if not entry.is_file():
                continue
            m = _CHECK_300_COUNCIL_FILENAME_RE.match(entry.name)
            if not m:
                continue
            date_int = _check_300_parse_date_suffix(m.group(1))
            if date_int is None:
                continue
            if date_int < _CHECK_300_CUTOFF_DATE_SUFFIX_INT:
                continue
            try:
                body = entry.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if _check_300_has_waiver(body):
                continue
            # Collect missing required fields.
            missing: list[str] = []
            for field in _CHECK_300_REQUIRED_FIELDS:
                if f"{field}:" not in body:
                    missing.append(field)
            # T2+ additionally requires the assumption-adversary verdict.
            tier = _check_300_extract_tier(body)
            if tier in ("T2", "T3", "T4"):
                if f"{_CHECK_300_T2_PLUS_REQUIRED_FIELD}:" not in body:
                    missing.append(_CHECK_300_T2_PLUS_REQUIRED_FIELD)
                # Mission-alignment field presence (operator binding directive
                # 2026-05-16). Required for T2+ per CLAUDE.md "Mission
                # alignment — non-negotiable" subsection of "Council
                # hierarchy: 4-tier protocol".
                for mission_field in _CHECK_300_T2_PLUS_MISSION_REQUIRED_FIELDS:
                    if f"{mission_field}:" not in body:
                        missing.append(mission_field)
                # Mission-contribution VALUE validation (must be one of the
                # canonical enum values). If field present but value
                # malformed, treat as missing-with-bad-value annotation.
                if f"council_predicted_mission_contribution:" in body:
                    mc = _check_300_extract_mission_contribution(body)
                    if mc is None:
                        missing.append(
                            "council_predicted_mission_contribution (value must be one of "
                            f"{sorted(_CHECK_300_VALID_MISSION_CONTRIBUTIONS)})"
                        )
                # Override-rationale paired-field validation: when
                # council_override_invoked=true, council_override_rationale
                # is REQUIRED (verbatim operator quote per operational
                # consequence 1).
                if f"council_override_invoked:" in body:
                    override = _check_300_extract_override_invoked(body)
                    if override is True and not _check_300_has_override_rationale(body):
                        missing.append(
                            "council_override_rationale (REQUIRED when "
                            "council_override_invoked: true per CLAUDE.md "
                            "'Mission alignment — non-negotiable' operational "
                            "consequence 1)"
                        )
            # Tier itself: if council_tier is missing OR invalid, treat as
            # missing (the field name might be present but value malformed).
            if tier is None and "council_tier" not in [
                f for f in _CHECK_300_REQUIRED_FIELDS if f not in missing
            ]:
                # council_tier: substring is present but value is unrecognized.
                missing.append("council_tier (value must be one of T1/T2/T3/T4)")
            if not missing:
                continue
            try:
                rel = entry.relative_to(Path(repo_root or REPO_ROOT).resolve())
            except ValueError:
                rel = entry
            violations.append(
                f"{rel}: {surface} council memo dated {date_int} is missing the "
                f"v2 4-tier frontmatter field(s): {sorted(set(missing))}. Per "
                "CLAUDE.md 'Council hierarchy: 4-tier protocol' non-negotiable + "
                "COUNCIL-HIERARCHY-V2 landing 2026-05-16 + 'Mission alignment "
                "— non-negotiable' subsection (operator binding standing "
                "directive 2026-05-16): every council deliberation memo "
                "dated >= 2026-05-16 MUST declare council_tier (T1/T2/T3/T4) "
                "+ council_attendees + council_quorum_met + council_verdict "
                "+ council_dissent + council_decisions_recorded (T2+ "
                "additionally requires council_assumption_adversary_verdict "
                "per Catalog #292 + Fix 7, AND council_predicted_mission_"
                "contribution + council_override_invoked per the mission-"
                "alignment binding directive; council_override_rationale is "
                "REQUIRED when council_override_invoked: true). Add the "
                "frontmatter fields OR add a same-line `# COUNCIL_TIER_"
                "FRONTMATTER_WAIVED:<rationale>` waiver with non-placeholder "
                "rationale."
            )

    if verbose:
        if violations:
            print(
                f"  [check_council_deliberation_declares_tier_in_frontmatter] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_council_deliberation_declares_tier_in_frontmatter] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_council_deliberation_declares_tier_in_frontmatter "
            f"found {len(violations)} council deliberation memo(s) missing "
            "the v2 4-tier frontmatter. Per CLAUDE.md 'Council hierarchy: "
            "4-tier protocol' non-negotiable + 'Bugs must be permanently "
            "fixed AND self-protected against'. Catalog #300 (COUNCIL-"
            "HIERARCHY-V2; sister of Catalog #291 + #292 + #229 + #290 + "
            "#185).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #301 - check_kill_memos_have_substrate_compatibility_evidence
#
# PERMANENT-FIX-AND-SELF-PROTECT-ALL 2026-05-16 self-protection per operator
# NON-NEGOTIABLE *"must permanently fix and self protect against all"* + the
# resurrection audit memo `.omx/research/resurrection_audit_20260516.md`
# (commit d0c347f1f). Pattern B = Substrate-mismatch-as-class-kill attribution:
# kill memos that attribute "TECHNIQUE FALSIFIED" / "TECHNIQUE KILLED" when
# the actual root cause was substrate-class incompatibility (e.g., the
# technique was tested against an incompatible archive grammar, not its
# native substrate). PR101 CompressAI / PR106 Lanes #05+#06 / PR107
# lossy_coarsening anchors documented in the resurrection audit.
#
# Per CLAUDE.md "KILL/FALSIFIED memory verdicts - NON-NEGOTIABLE,
# HIGHEST EMPHASIS" + "Forbidden premature KILL without research
# exhaustion (the kill-too-fast trap)" FORBIDDEN pattern. Default
# verdict for one-config failure is DEFERRED-pending-research, NOT
# KILLED. KILL/FALSIFIED memos MUST carry evidence of substrate-class
# compatibility checking so the kill is not silently a substrate-
# mismatch attribution error.
#
# Refuses repo-local `.omx/research/*killed*.md` + `.omx/research/*falsified*.md`
# files dated >= 2026-05-16 (cutoff exempts pre-audit legacy verdicts pending
# the operator-routed resurrection sweep) AND `.omx/research/*deferred*.md`
# memos containing "TECHNIQUE FALSIFIED" / "TECHNIQUE KILLED" claims that
# lack ANY of:
#   (a) Compatible-substrate-tested token: "verified against compatible
#       substrate", "tested against compatible substrate",
#       "archive_grammar_compatible", "class_preserved",
#       "compatible_substrate_verified".
#   (b) Substrate-mismatch-considered token: "substrate mismatch ruled out",
#       "substrate-mismatch ruled out", "substrate compatibility verified",
#       "substrate class verified", "resurrection_audit_classified".
#   (c) Same-line waiver `# SUBSTRATE_MISMATCH_ATTRIBUTION_OK:<rationale>`
#       on the FALSIFIED/KILLED claim line (placeholder rejected).
#
# Sister of: Catalog #220 (substrate L1 scaffold operational mechanism)
# + Catalog #233 (L1-to-L2 promotion canonical 4-gate) + Catalog #298
# (substrate retirement discipline 30-day). Catalog #233 covers
# promotion-time substrate-class evidence; #301 covers retirement-time
# substrate-class evidence. Together they close the substrate-class-
# attribution surface bidirectionally.
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity
# rule" because the resurrection audit (commit d0c347f1f) catalogs 4-6
# legacy kill memos still needing substrate-compatibility backfill;
# strict-flip planned after operator-routed sweep clears the backlog.
# ============================================================================


_CHECK_301_CUTOFF_DATE_SUFFIX_INT = 20260516
_CHECK_301_WAIVER_TOKEN = "SUBSTRATE_MISMATCH_ATTRIBUTION_OK:"
_CHECK_301_WAIVER_PLACEHOLDERS = ("<rationale>", "<reason>")

_CHECK_301_KILL_CLAIM_PATTERNS = (
    re.compile(r"\btechnique\s+falsified\b", re.IGNORECASE),
    re.compile(r"\btechnique\s+killed\b", re.IGNORECASE),
    re.compile(r"\btechnique\s+is\s+falsified\b", re.IGNORECASE),
    re.compile(r"\btechnique\s+is\s+killed\b", re.IGNORECASE),
    re.compile(r"\bmethod\s+falsified\b", re.IGNORECASE),
    re.compile(r"\bmethod\s+killed\b", re.IGNORECASE),
)

_CHECK_301_COMPATIBILITY_TOKENS = (
    "verified against compatible substrate",
    "tested against compatible substrate",
    "archive_grammar_compatible",
    "class_preserved",
    "class preserved",
    "compatible_substrate_verified",
    "compatible substrate verified",
    "substrate mismatch ruled out",
    "substrate-mismatch ruled out",
    "substrate compatibility verified",
    "substrate-compatibility verified",
    "substrate class verified",
    "substrate-class verified",
    "resurrection_audit_classified",
    "resurrection audit classified",
)

_CHECK_301_FILENAME_RE = re.compile(
    r"^.*(killed|falsified|deferred).*?(\d{8})\.md$",
    re.IGNORECASE,
)


def _check_301_line_has_waiver(line: str) -> bool:
    """Return True if ``line`` carries the canonical same-line waiver."""
    if _CHECK_301_WAIVER_TOKEN not in line:
        return False
    idx = line.find(_CHECK_301_WAIVER_TOKEN)
    tail = line[idx + len(_CHECK_301_WAIVER_TOKEN):].strip()
    if tail.endswith("-->"):
        tail = tail[:-3].rstrip()
    if not tail:
        return False
    for placeholder in _CHECK_301_WAIVER_PLACEHOLDERS:
        if tail.startswith(placeholder):
            return False
    if len(tail) < 4:
        return False
    return True


def _check_301_body_has_compatibility_token(body_lower: str) -> bool:
    for tok in _CHECK_301_COMPATIBILITY_TOKENS:
        if tok in body_lower:
            return True
    return False


def check_kill_memos_have_substrate_compatibility_evidence(
    *,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #301 — refuse KILL/FALSIFIED memos lacking substrate-
    compatibility evidence.

    Per CLAUDE.md "KILL/FALSIFIED memory verdicts" non-negotiable +
    "Forbidden premature KILL without research exhaustion" FORBIDDEN
    pattern. KILL conversion requires evidence the technique was tested
    against a compatible substrate, not silently against an incompatible
    archive grammar. Sister of Catalog #220 + #233 + #298.

    Memory: ``feedback_permanent_fix_self_protect_all_today_bug_classes_landed_20260516.md``.
    Lane: ``lane_permanent_fix_self_protect_all_20260516``.
    """
    root = Path(repo_root or REPO_ROOT)
    research_root = root / ".omx" / "research"
    if not research_root.is_dir():
        return []

    violations: list[str] = []
    try:
        candidates = sorted(research_root.iterdir())
    except OSError:
        return []

    for entry in candidates:
        if not entry.is_file() or not entry.name.endswith(".md"):
            continue
        m = _CHECK_301_FILENAME_RE.match(entry.name)
        if not m:
            continue
        try:
            date_int = int(m.group(2))
        except (TypeError, ValueError):
            continue
        if date_int < _CHECK_301_CUTOFF_DATE_SUFFIX_INT:
            continue  # pre-cutoff legacy memos exempt
        try:
            text = entry.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        body_lower = text.lower()
        # Find KILL/FALSIFIED claim
        text_lines = text.splitlines()
        for i, line in enumerate(text_lines, start=1):
            claim_hit = None
            for pat in _CHECK_301_KILL_CLAIM_PATTERNS:
                if pat.search(line):
                    claim_hit = pat.pattern
                    break
            if not claim_hit:
                continue
            if _check_301_line_has_waiver(line):
                # waiver on the claim line short-circuits this file's violations
                claim_hit = None
                break
            # claim found without same-line waiver — check body for compatibility token
            if _check_301_body_has_compatibility_token(body_lower):
                claim_hit = None
                break
            try:
                rel = entry.relative_to(root)
            except ValueError:
                rel = entry
            violations.append(
                f"{rel}:{i}: KILL/FALSIFIED memo dated {date_int} contains "
                f"technique-kill/falsified claim but lacks substrate-class "
                f"compatibility evidence. Add ANY of: (a) compatible-substrate-"
                f"tested token (verified against compatible substrate / "
                f"archive_grammar_compatible / class_preserved / "
                f"compatible_substrate_verified), (b) substrate-mismatch-"
                f"considered token (substrate mismatch ruled out / "
                f"resurrection_audit_classified), OR (c) same-line waiver "
                f"`# SUBSTRATE_MISMATCH_ATTRIBUTION_OK:<rationale>` on the "
                f"FALSIFIED/KILLED claim line. Per CLAUDE.md \"KILL/FALSIFIED "
                f"memory verdicts\" non-negotiable + \"Forbidden premature "
                f"KILL without research exhaustion\" FORBIDDEN pattern + the "
                f"resurrection audit (commit d0c347f1f) Pattern B = "
                f"Substrate-mismatch-as-class-kill attribution. Catalog "
                f"#301 (sister of #220 / #233 / #298)."
            )
            break  # one violation per file is sufficient

    if verbose:
        if violations:
            print(
                f"  [check_kill_memos_have_substrate_compatibility_evidence] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_kill_memos_have_substrate_compatibility_evidence] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_kill_memos_have_substrate_compatibility_evidence found "
            f"{len(violations)} KILL/FALSIFIED memo(s) lacking substrate-"
            "class compatibility evidence. Per CLAUDE.md \"KILL/FALSIFIED "
            "memory verdicts\" non-negotiable + \"Forbidden premature KILL "
            "without research exhaustion\" FORBIDDEN pattern + resurrection "
            "audit commit d0c347f1f Pattern B. Catalog #301 (sister of "
            "#220 / #233 / #298).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #302 - check_sister_subagent_scope_overlap_via_checkpoint_jsonl
#
# PERMANENT-FIX-AND-SELF-PROTECT-ALL 2026-05-16 META-meta self-protection
# per operator NON-NEGOTIABLE + my own near-miss 30 min before landing
# (sister `a8970e367aaa5df99` killed before edit-time collision;
# `a50a92694ac22c9f5` was in flight on same CLAUDE.md + src/tac/preflight.py
# scope). Bug class: parent agent dispatches a new subagent whose declared
# `files_touched` overlaps with the `files_touched` of an in-flight subagent
# whose checkpoint is `status: in_progress` and was written within the last
# 60 minutes. Without structural detection, this relies on manual TaskStop
# after-the-fact, which is what produced the near-miss.
#
# Per CLAUDE.md "Subagent coherence-by-default" non-negotiable + Catalog
# #230 (bulk-rewrite-respects-sister-subagent-ownership-map) — Catalog
# #230 covers the COMMIT-MESSAGE surface; Catalog #302 covers the
# IN-FLIGHT-CHECKPOINT surface (a tighter window).
#
# Scans `.omx/state/subagent_progress.jsonl` for in-flight subagent rows
# (status=in_progress, written within last 60 minutes) and refuses any
# state where 2+ DIFFERENT subagent IDs share at least 1 file in
# `files_touched`. Default-exempts files that are commonly multi-subagent
# (`.omx/state/modal_call_id_ledger.jsonl`, `.omx/state/active_lane_dispatch_claims.md`,
# `MEMORY.md`, etc.). Same-line waiver on the LAST subagent's `notes`
# field: `# SISTER_SUBAGENT_SCOPE_OVERLAP_OK:<rationale>` (placeholder
# rejected so the gate's own example cannot self-waive).
#
# Sister of: Catalog #117 (subagent commit serializer must be used) +
# Catalog #157 (commit-swap pre-pre-lock hash) + Catalog #174
# (--expected-content-sha256 mandatory) + Catalog #206 (subagent
# crash-resume discipline) + Catalog #230 (bulk-rewrite ownership map).
# Together they extinct the multi-subagent edit/commit collision class
# at SIX surfaces: edit-time-checkpoint (#302) + edit-time-bulk-op
# (#230) + commit-time-pre-pre-lock (#157) + commit-time-staged (#216)
# + commit-time-lock-arbitration (#117) + post-resolution-residual-
# marker (#248).
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
# — live count at landing: 0 (no in-flight subagent collisions; sister
# wave just landed clean). Strict-flip pending one full session-cycle
# observation that the gate stays clean.
# ============================================================================


_CHECK_302_WAIVER_TOKEN = "SISTER_SUBAGENT_SCOPE_OVERLAP_OK:"
_CHECK_302_WAIVER_PLACEHOLDERS = ("<rationale>", "<reason>")
_CHECK_302_IN_FLIGHT_WINDOW_SECONDS = 60 * 60  # 60 minutes

# Files exempt from collision detection (commonly multi-subagent state).
_CHECK_302_EXEMPT_FILES = frozenset({
    ".omx/state/modal_call_id_ledger.jsonl",
    ".omx/state/active_lane_dispatch_claims.md",
    ".omx/state/commit-serializer.log",
    ".omx/state/catalog-claim.log",
    ".omx/state/subagent_progress.jsonl",
    ".omx/state/lane_registry.json",
    ".omx/state/lane_maturity_audit.log",
    ".omx/state/continual_learning_posterior.jsonl",
    ".omx/state/cost_band_posterior.jsonl",
    "MEMORY.md",
})


def _check_302_parse_iso_utc(ts: str):
    """Parse an ISO-UTC timestamp; return datetime or None on parse failure."""
    try:
        if ts.endswith("Z"):
            ts = ts[:-1] + "+00:00"
        return _dt.datetime.fromisoformat(ts)
    except (TypeError, ValueError):
        return None


def _check_302_line_has_waiver(notes: str) -> bool:
    if not isinstance(notes, str):
        return False
    if _CHECK_302_WAIVER_TOKEN not in notes:
        return False
    idx = notes.find(_CHECK_302_WAIVER_TOKEN)
    tail = notes[idx + len(_CHECK_302_WAIVER_TOKEN):].strip()
    if not tail:
        return False
    for placeholder in _CHECK_302_WAIVER_PLACEHOLDERS:
        if tail.startswith(placeholder):
            return False
    return len(tail) >= 4


def check_sister_subagent_scope_overlap_via_checkpoint_jsonl(
    *,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
    now_utc=None,
) -> list[str]:
    """Catalog #302 — refuse repo state with 2+ in-flight subagents whose
    declared `files_touched` overlap.

    Per CLAUDE.md "Subagent coherence-by-default" non-negotiable + sister
    Catalog #230 (bulk-rewrite ownership map; commit-message surface).
    Catalog #302 closes the edit-time-checkpoint surface that #230 does
    not cover.

    Memory: ``feedback_permanent_fix_self_protect_all_today_bug_classes_landed_20260516.md``.
    Lane: ``lane_permanent_fix_self_protect_all_20260516``.
    """
    import json as _json

    root = Path(repo_root or REPO_ROOT)
    jsonl_path = root / ".omx" / "state" / "subagent_progress.jsonl"
    if not jsonl_path.is_file():
        return []

    if now_utc is None:
        now_utc = _dt.datetime.now(_dt.timezone.utc)

    # Read all entries; keep only the LATEST row per subagent_id.
    latest_per_subagent: dict[str, dict] = {}
    try:
        with jsonl_path.open("r", encoding="utf-8") as fh:
            for raw in fh:
                raw = raw.strip()
                if not raw:
                    continue
                try:
                    row = _json.loads(raw)
                except (ValueError, _json.JSONDecodeError):
                    continue
                if not isinstance(row, dict):
                    continue
                sid = row.get("subagent_id")
                if not isinstance(sid, str) or not sid:
                    continue
                latest_per_subagent[sid] = row
    except OSError:
        return []

    # Filter to in-flight subagents within the 60-min window.
    in_flight: list[dict] = []
    for sid, row in latest_per_subagent.items():
        status = row.get("status")
        if status != "in_progress":
            continue
        written_at = row.get("written_at_utc")
        if not isinstance(written_at, str):
            continue
        ts = _check_302_parse_iso_utc(written_at)
        if ts is None:
            continue
        try:
            delta = (now_utc - ts).total_seconds()
        except (TypeError, ValueError):
            continue
        if delta < 0 or delta > _CHECK_302_IN_FLIGHT_WINDOW_SECONDS:
            continue
        in_flight.append(row)

    if len(in_flight) < 2:
        return []

    # Detect file overlap pairwise.
    violations: list[str] = []
    for i in range(len(in_flight)):
        for j in range(i + 1, len(in_flight)):
            a = in_flight[i]
            b = in_flight[j]
            a_files = a.get("files_touched") or []
            b_files = b.get("files_touched") or []
            if not isinstance(a_files, list) or not isinstance(b_files, list):
                continue
            a_set = {f for f in a_files if isinstance(f, str) and f not in _CHECK_302_EXEMPT_FILES}
            b_set = {f for f in b_files if isinstance(f, str) and f not in _CHECK_302_EXEMPT_FILES}
            overlap = a_set & b_set
            if not overlap:
                continue
            # Check waiver on either subagent's notes
            if _check_302_line_has_waiver(a.get("notes", "")):
                continue
            if _check_302_line_has_waiver(b.get("notes", "")):
                continue
            a_id = a.get("subagent_id", "?")
            b_id = b.get("subagent_id", "?")
            overlap_str = ", ".join(sorted(overlap)[:5])
            violations.append(
                f"in-flight subagent collision: {a_id} <-> {b_id} share "
                f"file(s) {{ {overlap_str} }} in files_touched. Both are "
                f"status=in_progress within the last 60 minutes. Per "
                f"CLAUDE.md \"Subagent coherence-by-default\" non-"
                f"negotiable + Catalog #230 sister gate. Resolve via "
                f"manual TaskStop on the older subagent OR add the "
                f"newer subagent's notes field with "
                f"`# SISTER_SUBAGENT_SCOPE_OVERLAP_OK:<rationale>` waiver."
            )

    if verbose:
        if violations:
            print(
                f"  [check_sister_subagent_scope_overlap_via_checkpoint_jsonl] "
                f"{len(violations)} collision(s)"
            )
        else:
            print(
                "  [check_sister_subagent_scope_overlap_via_checkpoint_jsonl] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_sister_subagent_scope_overlap_via_checkpoint_jsonl found "
            f"{len(violations)} in-flight subagent collision(s). Per CLAUDE.md "
            "\"Subagent coherence-by-default\" non-negotiable + Catalog "
            "#302 (sister of #117 / #157 / #174 / #206 / #230 / #248).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


