# Catalog #357 - check_cathedral_consumer_tier_b_declares_canonical_contract
# 2026-05-20 lane_wave_1_dim_6_dual_tier_consumer_architecture_foundation_20260520.
#
# DUAL-TIER ARCHITECTURE PER CATHEDRAL-SMARTER-DESIGN-MEMO DIMENSION 6:
# Resolves the operator-mental-model gap surfaced by WIRE-IN-RIGOR audit
# (44+ cathedral consumers fire per loop iteration but per Catalog #341 ALL
# return predicted_delta_adjustment=0.0). The dual-tier system makes the
# Tier A observability-only vs Tier B score-contributing distinction
# STRUCTURAL rather than tribal-knowledge.
#
# SCOPE: scans every package under src/tac/cathedral_consumers/ that
# declares ``CONSUMER_TIER = ConsumerTier.TIER_B_SCORE_CONTRIBUTING`` at
# module level. Tier A consumers (default; omit CONSUMER_TIER OR set to
# TIER_A_OBSERVABILITY_ONLY) are out of scope (covered by sister Catalog
# #341 routing-markers gate).
#
# ACCEPTANCE: Tier B consumers MUST satisfy ALL of:
#   1. Import ``ConsumerTier`` from ``tac.cathedral.consumer_contract``
#      (required for the class-level declaration to resolve).
#   2. Body contains the literal token ``TIER_B_SCORE_CONTRIBUTING``
#      (declares tier intent).
#   3. Body contains ``provenance`` substring (Catalog #323 canonical
#      Provenance must be threaded into every contribution return value).
#   4. Body contains ``promotable`` substring AND ``False`` (Tier B
#      contributes to RANKING but NEVER to PROMOTION; promotable=False
#      preserved per CLAUDE.md "Submission auth eval — BOTH CPU AND CUDA").
#   5. Body does NOT contain ``axis_tag="[predicted]"`` /
#      ``axis_tag='[predicted]'`` / ``'axis_tag': '[predicted]'`` /
#      ``"axis_tag": "[predicted]"`` (Tier B requires empirically-grounded
#      axis token; ``[predicted]`` is Tier A semantics).
#
# WAIVER: file-level ``# CATHEDRAL_CONSUMER_TIER_B_DEFERRED_OK:<rationale>``
# in __init__.py first 60 lines (placeholder ``<rationale>`` / ``<reason>``
# / rationales <4 chars rejected per Catalog #287 sister discipline so the
# gate's docstring example cannot self-waive). Reserved for Tier B
# consumers in scaffold state awaiting Phase 2 wire-in per Dim 6 Step 6.5.
#
# Sister of Catalog #341 (Tier A routing-markers; #357 is the Tier B
# sister extension), Catalog #335 (canonical Protocol contract), Catalog
# #323 (canonical Provenance umbrella), Catalog #356 (Tier B per-axis
# decomposition prerequisite), Catalog #287 (placeholder-rationale
# rejection), Catalog #125 (6-hook wire-in non-negotiable), Catalog #176
# (META-meta: STRICT callsites have CLAUDE.md row), Catalog #185
# (META-meta-meta: Live count: 0 verified empirically).
#
# Together they extinct the Tier-B-without-canonical-contract bug class
# STRUCTURALLY at FIVE surfaces: canonical Protocol (#335) + Tier A
# routing-markers (#341) + Tier B contract (#357) + per-axis Provenance
# (#356) + canonical Provenance umbrella (#323).
#
# STRICT-from-byte-one per CLAUDE.md "Bugs must be permanently fixed AND
# self-protected against" + "Strict-flip atomicity rule" — live count at
# landing: 0 (no Tier B consumers exist yet; the gate fires structurally
# the moment a Tier B consumer lands without the canonical contract).

_CHECK_357_CONSUMER_DIR_RELPATH = "src/tac/cathedral_consumers"
_CHECK_357_EXEMPT_SUBDIRS: frozenset[str] = frozenset({"__pycache__", "tests"})

# In-scope token: presence in __init__.py marks the consumer as Tier B.
_CHECK_357_TIER_B_INSCOPE_TOKEN = "TIER_B_SCORE_CONTRIBUTING"

# Required tokens for Tier B canonical contract compliance.
_CHECK_357_TIER_B_REQUIRED_PROVENANCE_TOKEN = "provenance"
_CHECK_357_TIER_B_REQUIRED_PROMOTABLE_TOKEN = "promotable"
_CHECK_357_TIER_B_REQUIRED_FALSE_TOKEN = "False"
_CHECK_357_TIER_B_REQUIRED_IMPORT_TOKEN = "ConsumerTier"

# Forbidden axis_tag forms (Tier B requires non-[predicted] empirical axis).
_CHECK_357_TIER_B_FORBIDDEN_PREDICTED_AXIS_FORMS: tuple[str, ...] = (
    'axis_tag="[predicted]"',
    "axis_tag='[predicted]'",
    '"axis_tag": "[predicted]"',
    "'axis_tag': '[predicted]'",
)

_CHECK_357_WAIVER_PATTERN = re.compile(
    r"# CATHEDRAL_CONSUMER_TIER_B_DEFERRED_OK:(.+?)(?:$|#)", re.MULTILINE
)
_CHECK_357_WAIVER_LOOKBACK_LINES = 60


def _check_357_consumer_is_tier_b(body: str) -> bool:
    """Return True iff body has a module-level assignment of the form
    ``CONSUMER_TIER = ... TIER_B_SCORE_CONTRIBUTING ...`` (or sister
    annotated form).

    AST-based detection per Catalog #168 (sister gate for the same
    Assign-vs-AnnAssign META-class). Substring detection alone would
    false-positive on docstring mentions of the canonical promotion path
    (e.g. ``"Add CONSUMER_TIER = ConsumerTier.TIER_B_SCORE_CONTRIBUTING"``
    in a docstring documenting the promotion path).

    Returns False on syntax errors (defensive; the operator-facing #335
    canonical-contract gate handles broken consumers; #357 silently
    skips them rather than crash).
    """
    try:
        tree = ast.parse(body)
    except SyntaxError:
        return False

    for node in tree.body:
        # Handle both ``CONSUMER_TIER = ...`` (Assign) and
        # ``CONSUMER_TIER: ConsumerTier = ...`` (AnnAssign) per Catalog #168.
        targets: list[ast.expr] = []
        value: ast.expr | None = None
        if isinstance(node, ast.Assign):
            targets = list(node.targets)
            value = node.value
        elif isinstance(node, ast.AnnAssign):
            targets = [node.target] if node.target is not None else []
            value = node.value

        if value is None:
            continue

        for tgt in targets:
            if isinstance(tgt, ast.Name) and tgt.id == "CONSUMER_TIER":
                # Walk the RHS expression looking for TIER_B_SCORE_CONTRIBUTING.
                for sub in ast.walk(value):
                    if isinstance(sub, ast.Attribute):
                        if sub.attr == _CHECK_357_TIER_B_INSCOPE_TOKEN:
                            return True
                    elif isinstance(sub, ast.Name):
                        if sub.id == _CHECK_357_TIER_B_INSCOPE_TOKEN:
                            return True
                # CONSUMER_TIER assignment found but doesn't reference Tier B.
                # Stop scanning further; this consumer is Tier A.
                return False
    return False


def _check_357_extract_waiver_rationale(body: str) -> str | None:
    """Return the non-placeholder waiver rationale if present in the first
    60 lines, else None.

    Per Catalog #287 sister discipline: placeholder rationales
    (``<rationale>`` / ``<reason>`` / ``rationale`` / ``reason`` literals,
    empty, or <4 chars) reject the waiver so the gate's docstring example
    cannot self-waive.
    """
    # Restrict scan to first 60 lines.
    lines = body.split("\n", _CHECK_357_WAIVER_LOOKBACK_LINES + 1)
    head = "\n".join(lines[:_CHECK_357_WAIVER_LOOKBACK_LINES])
    m = _CHECK_357_WAIVER_PATTERN.search(head)
    if not m:
        return None
    rationale = m.group(1).strip().rstrip(":").strip()
    low = rationale.lower()
    if low in ("<rationale>", "<reason>", "rationale", "reason", ""):
        return None
    if len(rationale) < 4:
        return None
    return rationale


def _check_357_find_violations(body: str) -> list[str]:
    """Return list of canonical-contract violations for a Tier B consumer body."""
    violations: list[str] = []
    # (1) Import token
    if _CHECK_357_TIER_B_REQUIRED_IMPORT_TOKEN not in body:
        violations.append(
            f"missing import of '{_CHECK_357_TIER_B_REQUIRED_IMPORT_TOKEN}' "
            "(required to resolve CONSUMER_TIER declaration)"
        )
    # (3) provenance present
    if _CHECK_357_TIER_B_REQUIRED_PROVENANCE_TOKEN not in body:
        violations.append(
            f"missing '{_CHECK_357_TIER_B_REQUIRED_PROVENANCE_TOKEN}' field "
            "(Tier B contributions MUST carry canonical Provenance per "
            "Catalog #323)"
        )
    # (4) promotable AND False present
    if _CHECK_357_TIER_B_REQUIRED_PROMOTABLE_TOKEN not in body:
        violations.append(
            f"missing '{_CHECK_357_TIER_B_REQUIRED_PROMOTABLE_TOKEN}' field "
            "(Tier B contributions MUST carry promotable=False per CLAUDE.md "
            '"Submission auth eval — BOTH CPU AND CUDA")'
        )
    elif _CHECK_357_TIER_B_REQUIRED_FALSE_TOKEN not in body:
        violations.append(
            "'promotable' present but no 'False' literal found; Tier B "
            "MUST carry promotable=False"
        )
    # (5) Forbidden axis_tag="[predicted]" forms
    for forbidden in _CHECK_357_TIER_B_FORBIDDEN_PREDICTED_AXIS_FORMS:
        if forbidden in body:
            violations.append(
                f"forbidden axis_tag form: {forbidden!r}. Tier B requires "
                'empirically-grounded axis token (NOT "[predicted]"). If '
                "signal is speculative, declare CONSUMER_TIER = "
                "ConsumerTier.TIER_A_OBSERVABILITY_ONLY instead."
            )
            break
    return violations


def check_cathedral_consumer_tier_b_declares_canonical_contract(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
) -> list[str]:
    """Catalog #357 — Tier B cathedral consumers declare the canonical
    score-contributing contract.

    Sister extension of Catalog #341 per CATHEDRAL-SMARTER-DESIGN-MEMO Dim
    6 Step 6.3. Tier A consumers (default; Catalog #341 routing-markers
    apply) are out of scope. Tier B consumers (those declaring
    ``CONSUMER_TIER = ConsumerTier.TIER_B_SCORE_CONTRIBUTING``) MUST
    satisfy the canonical contract: import ConsumerTier, carry provenance
    + promotable=False, and use an empirically-grounded axis_tag (not
    ``[predicted]``).

    Bug class: a Tier B consumer that omits canonical Provenance OR
    ``promotable=False`` OR uses ``[predicted]`` axis_tag silently leaks
    score predictions into the autopilot ranker without the structural
    protection that the markers were designed to provide. The dual-tier
    architecture's safety relies on Tier B carrying empirical grounding;
    without this gate, a Tier B label would be cosmetic.

    SCOPE: ``src/tac/cathedral_consumers/*/__init__.py`` containing the
    ``TIER_B_SCORE_CONTRIBUTING`` token.

    ACCEPTANCE per Dim 6 Step 6.3:
      1. Import of ``ConsumerTier``
      2. ``provenance`` field threaded through contribution returns
      3. ``promotable=False`` preserved
      4. NO ``axis_tag="[predicted]"`` (use canonical contest or
         diagnostic axis instead)

    WAIVER: file-level
    ``# CATHEDRAL_CONSUMER_TIER_B_DEFERRED_OK:<rationale>`` in __init__.py
    first 60 lines for Tier B scaffolds awaiting Phase 2 wire-in. Per
    Catalog #287 sister discipline placeholder rationales rejected so the
    gate's docstring example cannot self-waive.

    STRICT-from-byte-one per CLAUDE.md "Strict-flip atomicity rule" —
    live count at landing: 0 (no Tier B consumers exist yet; the dual-
    tier landing in this commit batch is foundation-only).
    """
    root = Path(repo_root).resolve() if repo_root is not None else REPO_ROOT
    consumer_dir = root / _CHECK_357_CONSUMER_DIR_RELPATH
    all_violations: list[str] = []

    if not consumer_dir.is_dir():
        if verbose:
            print(
                f"  [cathedral-consumer-tier-b] {_CHECK_357_CONSUMER_DIR_RELPATH} "
                "not present, skipping"
            )
        return all_violations

    for sub in sorted(consumer_dir.iterdir()):
        if not sub.is_dir():
            continue
        if sub.name in _CHECK_357_EXEMPT_SUBDIRS:
            continue
        if sub.name.startswith("_"):
            # Reference packages exempt (e.g. _example_consumer).
            continue
        init_path = sub / "__init__.py"
        if not init_path.exists():
            continue

        try:
            body = init_path.read_text(encoding="utf-8")
        except OSError as exc:
            if verbose:
                print(
                    f"  [cathedral-consumer-tier-b] SKIP {sub.name} "
                    f"(read failed: {exc})"
                )
            continue

        # In-scope check: must have ACTUAL module-level CONSUMER_TIER
        # assignment to ConsumerTier.TIER_B_SCORE_CONTRIBUTING (AST-based
        # per Catalog #168 to avoid false-positives on docstring mentions
        # of the canonical promotion path).
        if not _check_357_consumer_is_tier_b(body):
            continue

        # Waiver check (waiver short-circuits validation).
        if _check_357_extract_waiver_rationale(body) is not None:
            continue

        # Canonical-contract check.
        violations = _check_357_find_violations(body)
        if violations:
            rel = str(init_path.relative_to(root))
            for v in violations:
                all_violations.append(
                    f"{rel}: Tier B canonical contract violation: {v}. "
                    "Per Catalog #357 (DUAL-TIER ARCHITECTURE Dim 6 Step 6.3) "
                    "every Tier B cathedral consumer MUST satisfy the canonical "
                    "score-contributing contract (import ConsumerTier + carry "
                    "provenance + promotable=False + use empirically-grounded "
                    'axis_tag != "[predicted]"). Either fix the violation, '
                    "downgrade to TIER_A_OBSERVABILITY_ONLY, OR add "
                    "`# CATHEDRAL_CONSUMER_TIER_B_DEFERRED_OK:<rationale>` "
                    "file-level waiver in __init__.py first 60 lines "
                    "(placeholder rationale rejected; rationale ≥4 chars)."
                )

    if verbose:
        if all_violations:
            print(
                f"  [cathedral-consumer-tier-b] {len(all_violations)} violation(s)"
            )
        else:
            print(
                "  [cathedral-consumer-tier-b] OK (all Tier B consumers, if "
                "any, carry the canonical score-contributing contract)"
            )
    if all_violations and strict:
        raise PreflightError(
            "check_cathedral_consumer_tier_b_declares_canonical_contract "
            f"found {len(all_violations)} violation(s) per Catalog #357 "
            "(DUAL-TIER ARCHITECTURE Dim 6 Step 6.3).\n  "
            + "\n  ".join(v[:500] for v in all_violations[:5])
        )
    return all_violations


# Catalog #318 - check_master_gradient_raw_byte_authority_not_landed
# 2026-05-17 lane_l5_rule6_master_gradient_raw_byte_authority_guard.
# Raw byte/bit finite differences over contest ZIP archives and entropy-coded
# payloads are blocked by ``tac.master_gradient_feasibility``. This source
# guard catches the next failure layer: a helper that *names* itself as master
# gradient authority while exposing raw archive-byte tensors or byte-index
# projection APIs. Valid master-gradient routing is a packet-valid
# ``CandidateModificationSpec`` / grammar-aware operator response row that
# rebuilds packet metadata and proves inflate + byte consumption.

_CHECK_318_TARGET_FILES: tuple[str, ...] = (
    "src/tac/master_gradient.py",
    "tools/extract_master_gradient.py",
    "tools/cathedral_autopilot_autonomous_loop.py",
)
_CHECK_318_FORBIDDEN_PATTERNS: tuple[tuple[str, str], ...] = (
    ("finite_difference_bit_flip", "raw_bit_or_byte_finite_difference_method"),
    ("(N_archive_bytes, 3)", "raw_archive_byte_response_tensor"),
    ("(N_bytes, 3)", "raw_byte_response_tensor"),
    ("gradient_array_path", "raw_gradient_sidecar_path"),
    ("byte_modifications: Mapping[int, float]", "raw_byte_modification_api"),
    ("predict_delta_s(byte_modifications", "raw_byte_delta_projection_api"),
    ("latest_anchor_for_archive", "archive_sha_anchor_presence_rerank"),
)
_CHECK_318_REQUIRED_OPERATOR_TOKENS: tuple[str, ...] = (
    "CandidateModificationSpec",
    "grammar_aware_operator",
)
_CHECK_318_WAIVER_PATTERN = re.compile(
    r"MASTER_GRADIENT_RAW_AUTHORITY_OK\s*:\s*(.+?)(?:$|#)",
    re.MULTILINE,
)


def _check_318_source_has_waiver(source: str) -> bool:
    """Return True iff source carries a non-placeholder explicit waiver."""
    header = "\n".join(source.splitlines()[:80])
    m = _CHECK_318_WAIVER_PATTERN.search(header)
    if not m:
        return False
    rationale = m.group(1).strip().rstrip(":").strip()
    if not rationale:
        return False
    if rationale.lower() in ("<rationale>", "<reason>"):
        return False
    return True


def check_master_gradient_raw_byte_authority_not_landed(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
) -> list[str]:
    """Catalog #318 — block raw archive-byte master-gradient authority.

    This is intentionally a source tripwire, not a score-analysis tool. The
    allowed master-gradient route is already expressed by
    ``tac.master_gradient_feasibility`` and
    ``tac.master_gradient_operator_plan``: packet-valid mutation operators
    with explicit packet proofs and no score/promotion authority. This check
    refuses the authority-bearing WIP surface that reintroduces raw
    ``(N_archive_bytes, 3)`` gradients or byte-index delta projections.

    Same-header waiver in the first 80 lines:
    ``# MASTER_GRADIENT_RAW_AUTHORITY_OK:<rationale>``. Placeholder rationale
    strings are rejected.
    """
    root = Path(repo_root).resolve() if repo_root is not None else REPO_ROOT
    violations: list[str] = []

    for rel_path in _CHECK_318_TARGET_FILES:
        path = root / rel_path
        if not path.is_file():
            continue
        try:
            source = path.read_text(encoding="utf-8")
        except OSError as exc:
            if verbose:
                print(
                    "  [check_master_gradient_raw_byte_authority_not_landed] "
                    f"SKIP {rel_path} (read failed: {exc})"
                )
            continue
        if _check_318_source_has_waiver(source):
            continue

        hits = [
            label
            for token, label in _CHECK_318_FORBIDDEN_PATTERNS
            if token in source
        ]
        if not hits:
            continue
        has_valid_route_tokens = all(
            token in source for token in _CHECK_318_REQUIRED_OPERATOR_TOKENS
        )
        if has_valid_route_tokens and "finite_difference_bit_flip" not in source:
            continue
        violations.append(
            f"{rel_path} exposes authority-bearing raw master-gradient pattern(s) "
            f"{hits}. Per Catalog #318 and the May 17 L5/Rule #6 rebaseline, "
            "raw archive-byte / bit finite differences over ZIP plus entropy-coded "
            "packets are not score derivatives. Replace this with a typed "
            "`CandidateModificationSpec` / `grammar_aware_operator` response-row "
            "interface that rebuilds ZIP metadata/CRC and proves inflate + "
            "byte-consumption closure, or add "
            "`# MASTER_GRADIENT_RAW_AUTHORITY_OK:<rationale>` in the first 80 "
            "lines for a deliberately diagnostic, non-authority artifact."
        )

    if verbose:
        if violations:
            print(
                "  [check_master_gradient_raw_byte_authority_not_landed] "
                f"{len(violations)} violation(s)"
            )
        else:
            print("  [check_master_gradient_raw_byte_authority_not_landed] OK")
    if violations and strict:
        raise PreflightError(
            "check_master_gradient_raw_byte_authority_not_landed found "
            f"{len(violations)} raw-byte master-gradient authority issue(s) "
            "per Catalog #318.\n  "
            + "\n  ".join(v[:500] for v in violations[:5])
        )
    return violations


# Catalog #327 - check_master_gradient_contest_axis_requires_authoritative_custody
# 2026-05-18 codex_t3_synthesis_adversarial_review_master_gradient_axis_guard.
# Refuse effective append-only master-gradient anchors whose contest-axis label
# contradicts their hardware/method/pair-count custody. This complements #318:
# #318 blocks raw-byte source authority; #327 blocks stale live-state authority.


def check_master_gradient_contest_axis_requires_authoritative_custody(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
) -> list[str]:
    """Catalog #327 — contest-axis master-gradient rows need real custody."""
    from tac.master_gradient import (
        MASTER_GRADIENT_LEDGER_PATH,
        load_anchors_lenient,
        unresolved_contest_axis_authority_violations,
    )

    root = Path(repo_root).resolve() if repo_root is not None else REPO_ROOT
    violations: list[str] = []
    source_contracts = {
        "src/tac/master_gradient_consumers.py": "is_authoritative_axis_anchor",
        "src/tac/empirical_per_x_optimal_codec_planner/per_byte_strategy.py": "is_authoritative_axis_anchor",
        "src/tac/canonical_duckdb/per_byte_sensitivity_ext.py": "is_authoritative_axis_anchor",
        "tools/cathedral_autopilot_autonomous_loop.py": (
            "latest_rejected_contest_axis_anchor_for_archive"
        ),
    }
    autopilot_rank_contract_tokens = {
        "require_score_weighted_custody=True",
        "_sidecar_has_full_pair_gradient_custody",
        "top_k_score_weighted_with_axis_breakdown",
    }
    for rel_path, required_token in source_contracts.items():
        path = root / rel_path
        if not path.exists():
            continue
        try:
            source = path.read_text(encoding="utf-8")
        except OSError:
            continue
        if required_token not in source:
            violations.append(
                f"{rel_path} does not contain required Catalog #327 authority "
                f"filter token {required_token!r}. Master-gradient consumers "
                "that read .omx/state/master_gradient_anchors.jsonl must route "
                "through tac.master_gradient authority filtering so diagnostic "
                "per-pair/aggregate signals stay useful for training, compress "
                "time, and guarded inflate-time planning without becoming false "
                "contest-CPU/contest-CUDA authority."
            )
        if rel_path == "tools/cathedral_autopilot_autonomous_loop.py":
            missing_rank_tokens = sorted(
                token for token in autopilot_rank_contract_tokens if token not in source
            )
            if missing_rank_tokens:
                violations.append(
                    f"{rel_path} missing canonical Cathedral master-gradient "
                    f"ranking custody token(s): {missing_rank_tokens}. Catalog #327 "
                    "requires Venn/atlas ranking influence to flow only through "
                    "score-weighted counts, full 600-pair per-byte gradient custody, "
                    "and active-panel contest-axis matching."
                )

    ledger = root / MASTER_GRADIENT_LEDGER_PATH
    if not ledger.exists():
        if verbose:
            print(
                "  [check_master_gradient_contest_axis_requires_authoritative_custody] "
                "OK (no ledger)"
            )
    else:
        rows = load_anchors_lenient(ledger)
        for row, reason in unresolved_contest_axis_authority_violations(rows):
            archive = str(row.get("archive_sha256", "<missing>"))
            archive_short = archive[:16] if len(archive) > 16 else archive
            violations.append(
                f"{MASTER_GRADIENT_LEDGER_PATH} archive={archive_short} "
                f"measurement_utc={row.get('measurement_utc', '<missing>')} "
                f"measurement_axis={row.get('measurement_axis', '<missing>')} "
                f"measurement_hardware={row.get('measurement_hardware', '<missing>')} "
                f"measurement_method={row.get('measurement_method', '<missing>')} "
                f"n_pairs_used={row.get('n_pairs_used', '<missing>')} "
                f"n_pairs_total={row.get('n_pairs_total', '<missing>')} is not an "
                f"authoritative contest-axis master-gradient anchor: {reason}. "
                "Append a newer diagnostic/advisory correction row for the same archive "
                "or regenerate the anchor under matching contest hardware, full pair "
                "custody, and exact axis labels before consumers treat it as contest "
                "authority."
            )

    if verbose:
        if violations:
            print(
                "  [check_master_gradient_contest_axis_requires_authoritative_custody] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_master_gradient_contest_axis_requires_authoritative_custody] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_master_gradient_contest_axis_requires_authoritative_custody "
            f"found {len(violations)} unresolved contest-axis custody issue(s) "
            "per Catalog #327.\n  "
            + "\n  ".join(v[:500] for v in violations[:5])
        )
    return violations


# Catalog #319 — check_substrate_wyner_ziv_reweight_has_deliverability_proof
# 2026-05-17 lane_q2_q3_batched_catalog_319_gate_plus_autopilot_reweight_v2_20260517.
# Refuse any autopilot HIGH_PAIR_INVARIANT reward path that does not consult
# the per-archive DeliverabilityProof artifact emitted by
# ``tac.wyner_ziv_deliverability.proof_builder``. Venn classification alone
# is a planning signal; it is not contest deliverability proof.


_VENN_REWEIGHT_DELIVERABILITY_WAIVER = "VENN_REWEIGHT_DELIVERABILITY_OK:"


def _line_has_valid_venn_deliverability_waiver(line: str) -> bool:
    if _VENN_REWEIGHT_DELIVERABILITY_WAIVER not in line:
        return False
    reason = line.split(_VENN_REWEIGHT_DELIVERABILITY_WAIVER, 1)[1].strip()
    if not reason:
        return False
    lowered = reason.lower()
    return "<rationale>" not in lowered and "<reason>" not in lowered


def check_substrate_wyner_ziv_reweight_has_deliverability_proof(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #319 — positive Wyner-Ziv rewards require deliverability proof.

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-source diagnostic.

    Returns:
        List of violation messages (one per dispatch wrapper that applies
        the HIGH_PAIR_INVARIANT reward branch without consulting a proof).
    """
    root = Path(repo_root) if repo_root is not None else REPO_ROOT
    target = root / "tools" / "cathedral_autopilot_autonomous_loop.py"
    if not target.exists():
        return []
    try:
        text = target.read_text(encoding="utf-8")
    except OSError as exc:
        violations = [f"{target}: could not read autopilot source for Catalog #319: {exc}"]
        if strict:
            raise PreflightError(
                "check_substrate_wyner_ziv_reweight_has_deliverability_proof found "
                f"{len(violations)} violation(s):\n" + "\n".join(violations)
            )
        return violations

    lines = text.splitlines()
    has_valid_waiver = any(
        _line_has_valid_venn_deliverability_waiver(line) for line in lines
    )
    has_placeholder_waiver = any(
        _VENN_REWEIGHT_DELIVERABILITY_WAIVER in line
        and not _line_has_valid_venn_deliverability_waiver(line)
        for line in lines
    )
    violations: list[str] = []
    if has_placeholder_waiver:
        violations.append(
            f"{target}: Catalog #319 waiver uses empty/placeholder rationale; "
            f"use `{_VENN_REWEIGHT_DELIVERABILITY_WAIVER}<specific reason>`."
        )

    high_invariant_branch = (
        "pair_invariant_frac >= _VENN_REWEIGHT_HIGH_PAIR_INVARIANT_THRESHOLD"
        in text
    )
    if high_invariant_branch and not has_valid_waiver:
        required_tokens = (
            "load_deliverability_proof_for_archive",
            "verify_deliverability_proof_contest_compliance",
            "_venn_deliverability_reward_factor_for_archive",
        )
        missing = [token for token in required_tokens if token not in text]
        if missing:
            violations.append(
                f"{target}: Catalog #319 violation: HIGH_PAIR_INVARIANT reward "
                f"branch does not consult DeliverabilityProof surface; missing "
                f"{', '.join(missing)}."
            )
    for lineno, line in enumerate(lines, start=1):
        if "_VENN_REWEIGHT_HIGH_PAIR_INVARIANT_DELTA_FACTOR" in line and not (
            _line_has_valid_venn_deliverability_waiver(line)
        ):
            violations.append(
                f"{target}:{lineno}: Catalog #319 violation: blanket "
                "HIGH_PAIR_INVARIANT delta factor is forbidden; use a "
                "DeliverabilityProof-weighted factor instead."
            )

    if verbose:
        if violations:
            print("  [check_substrate_wyner_ziv_reweight_has_deliverability_proof]")
            for v in violations:
                print(f"    - {v}")
        else:
            print("  [check_substrate_wyner_ziv_reweight_has_deliverability_proof] OK")
    if violations and strict:
        raise PreflightError(
            "check_substrate_wyner_ziv_reweight_has_deliverability_proof found "
            f"{len(violations)} violation(s):\n" + "\n".join(violations)
        )
    return violations


