def check_no_autopilot_adjustment_derived_from_phantom_provenance_composition_alpha(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #322 — refuse substrate_composition_matrix.json entries whose
    pair_key contains a Catalog #321 phantom-provenance token.

    Phantom-provenance tokens are the 3 candidates Catalog #321 rejected as
    REJECTED_RESEARCH_SIDECAR:
      - ``pr101_state_dict``
      - ``pr106_state_dict``
      - ``posenet_class_sensitivity``

    Any pair_key in ``entries`` whose lowercased form contains one of these
    tokens is refused unless the entry's most-recent row carries a
    ``# PHANTOM_PROVENANCE_OK:<rationale>`` waiver in the row's
    ``validation_reason`` OR ``_phantom_provenance_waiver`` field with a
    non-placeholder rationale of at least 4 characters.

    Also scans the canonical `pairwise_alpha_*.json` artifacts under
    `.omx/state/wyner_ziv_deliverability/` for top-level `candidates_probed`
    arrays containing phantom-provenance tokens — those artifacts emit
    α values that would silently feed
    `apply_substrate_composition_matrix_to_candidates` if surfaced into the
    canonical matrix.

    Args:
        repo_root: Optional override; defaults to ``REPO_ROOT``.
        strict: If True, raise :class:`PreflightError` on any violation.
        verbose: If True, print per-artifact diagnostic.

    Returns:
        List of violation messages, one per offending pair key / artifact.
    """
    root = Path(repo_root) if repo_root is not None else REPO_ROOT
    violations: list[str] = []

    # Surface 1: canonical substrate composition matrix
    matrix_path = root / ".omx" / "state" / "substrate_composition_matrix.json"
    if matrix_path.is_file():
        try:
            raw = matrix_path.read_text(encoding="utf-8")
            payload = json.loads(raw)
        except (OSError, json.JSONDecodeError) as exc:
            violations.append(
                f"{matrix_path}: Catalog #322 could not parse matrix JSON: {exc}"
            )
        else:
            if isinstance(payload, dict):
                entries = payload.get("entries", {})
                if isinstance(entries, dict):
                    for pair_key, rows in entries.items():
                        key_lower = str(pair_key).lower()
                        offending = [
                            t for t in _CATALOG_322_PHANTOM_PROVENANCE_TOKENS
                            if t in key_lower
                        ]
                        if not offending:
                            continue
                        # Check for per-row waiver in the most-recent row.
                        latest_row = {}
                        if isinstance(rows, list) and rows:
                            latest_row = max(
                                (r for r in rows if isinstance(r, dict)),
                                key=lambda r: r.get("written_at_utc", ""),
                                default={},
                            )
                        row_waiver_text = (
                            str(latest_row.get("validation_reason") or "")
                            + " "
                            + str(latest_row.get("_phantom_provenance_waiver") or "")
                        )
                        if _check_322_waiver_has_valid_rationale(row_waiver_text):
                            continue
                        violations.append(
                            f"{matrix_path}::entries[{pair_key!r}]: "
                            f"Catalog #322 violation: pair_key contains phantom-"
                            f"provenance token(s) {offending} per Catalog #321 "
                            "REJECTED_RESEARCH_SIDECAR. The α value feeds the "
                            "autopilot v2 cascade (adjust_predicted_delta_for_"
                            "composition_alpha_v2) and would corrupt dispatch "
                            "ranking. Fix: revert via the canonical helper "
                            "`tac.optimization.substrate_composition_matrix."
                            "revert_phantom_source_rows()` OR add inline "
                            "`# PHANTOM_PROVENANCE_OK:<rationale>` waiver in "
                            "the row's `_phantom_provenance_waiver` field."
                        )

    # Surface 2: pairwise_alpha probe artifacts that could promote phantom α
    # into the canonical matrix surface.
    wz_dir = root / ".omx" / "state" / "wyner_ziv_deliverability"
    if wz_dir.is_dir():
        for path in sorted(wz_dir.glob("pairwise_alpha_*.json")):
            try:
                raw = path.read_text(encoding="utf-8")
                payload = json.loads(raw)
            except (OSError, json.JSONDecodeError) as exc:
                violations.append(
                    f"{path}: Catalog #322 could not parse pairwise_alpha: {exc}"
                )
                continue
            if not isinstance(payload, dict):
                continue
            # The probe records the candidate set as `candidates_probed` or
            # similar arrays + the pair_results dict; either surface flags.
            text = json.dumps(payload).lower()
            offending = [
                t for t in _CATALOG_322_PHANTOM_PROVENANCE_TOKENS
                if t in text
            ]
            if not offending:
                continue
            row_waiver_text = (
                str(payload.get("validation_reason") or "")
                + " "
                + str(payload.get("_phantom_provenance_waiver") or "")
            )
            if _check_322_waiver_has_valid_rationale(row_waiver_text):
                continue
            violations.append(
                f"{path}: Catalog #322 violation: pairwise_alpha artifact "
                f"references phantom-provenance candidate(s) {offending} per "
                "Catalog #321 REJECTED_RESEARCH_SIDECAR. These α values must "
                "NOT be promoted into the canonical substrate composition "
                "matrix. Fix: re-run the probe against VALIDATED_CONTEST_MEMBER "
                "archive members only (per Option B sweep landed 2026-05-17), "
                "OR add a top-level `_phantom_provenance_waiver` field with "
                "`# PHANTOM_PROVENANCE_OK:<rationale>` if this is a deliberate "
                "diagnostic-only artifact."
            )

    if verbose:
        if violations:
            print(
                "  [check_no_autopilot_adjustment_derived_from_phantom_"
                "provenance_composition_alpha]"
            )
            for v in violations:
                print(f"    - {v}")
        else:
            print(
                "  [check_no_autopilot_adjustment_derived_from_phantom_"
                "provenance_composition_alpha] OK"
            )

    if violations and strict:
        raise PreflightError(
            "check_no_autopilot_adjustment_derived_from_phantom_provenance_"
            f"composition_alpha found {len(violations)} violation(s):\n"
            + "\n".join(violations)
        )
    return violations


# =============================================================================
# Catalog #323 — check_no_score_claim_without_canonical_provenance
# =============================================================================
# META-class umbrella gate (2026-05-17) per operator NON-NEGOTIABLE *"We need
# to fix the provenance issue for all and fix it permanently and canonically
# and make it easy"*.
#
# Subsumes 5 sister gates (#287 docstring-overstatement / #249 misleading-
# directory-name / #319 autopilot-venn-reweight / #321 research-sidecar /
# #823 byte-identity artifact) by enforcing the canonical Provenance
# contract at the persisted-artifact-row surface.
#
# Scans .omx/state/*.json + .omx/state/*.jsonl + experiments/results/
# build_manifest.json + experiments/results/auth_eval_*.json + sister
# canonical persisted artifacts. For each row with a score-claiming key
# WITHOUT a `provenance: {...}` sub-object validated via
# `validate_provenance`, refuses.
#
# Companion canonical helper: tac.provenance package (~1100 LOC across 4
# files); canonical audit tool: tools/audit_provenance_compliance.py.
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
# because legacy artifacts carry baseline violations (188 at landing per
# audit_provenance_compliance.py sweep). Strict-flip pending operator-
# routed backfill sweep that drives violations to 0.
#
# Sister gates KEPT as defense-in-depth (they remain strict at their own
# surface); #323 is the umbrella that catches what sister gates miss.

_CHECK_323_SCORE_CLAIM_KEYS: tuple[str, ...] = (
    "score",
    "score_value",
    "contest_score",
    "final_score",
    "predicted_score",
    "canonical_score",
    "canonical_score_recomputed",
    "canonical_score_contest_cuda",
    "canonical_score_contest_cpu",
    "score_recomputed",
    "score_recomputed_from_components",
    "score_recomputed_from_contest_components",
    "score_recomputed_from_public_components",
    "score_contest_cuda",
    "score_contest_cpu",
    "contest_cuda_score_recomputed",
    "contest_cpu_score_recomputed",
    "empirical_score",
    "diagnostic_cpu_score",
    "deliverable_score_savings_estimate",
    "deliverable_savings",
    "composition_alpha",
    "alpha",
    "alpha_savings_ratio_form",
    "savings",
    "delta_s",
    "delta_score",
    "score_savings",
    "auth_eval_score",
    "auth_eval_recomputed_score",
    "score_recomputed_from_auth_eval",
    "recomputed_score",
)

_CHECK_323_SCAN_PATTERNS: tuple[str, ...] = (
    ".omx/state/**/*.json",
    ".omx/state/**/*.jsonl",
    "experiments/results/**/build_manifest.json",
    "experiments/results/**/auth_eval_*.json",
    "experiments/results/**/contest_auth_eval_*.json",
    "experiments/results/**/optimal_plan_*.json",
    "submissions/*/dual_eval_adjudicated.json",
)

_CHECK_323_EXCLUDE_MARKERS: tuple[str, ...] = (
    "/.venv/",
    "/__pycache__/",
    "/node_modules/",
    "/.git/",
    "/build/lib/",
    "_intake_",  # vendored PR intake clones (Catalog #109)
    "/.omx/oss_export/",
    "/vendored/",
    "/reports/raw/",
    "/.omx/state/archive/",
    "/.omx/state/quarantine",
)

_CHECK_323_WAIVER_RE = re.compile(
    r"#\s*PROVENANCE_CANONICAL_WAIVED:\s*(?P<rationale>.+?)\s*$"
)


def _check_323_waiver_has_valid_rationale(text: str) -> bool:
    """Return True only for an explicit non-placeholder Catalog #323 waiver."""
    m = _CHECK_323_WAIVER_RE.search(text)
    if not m:
        return False
    rationale = (m.group("rationale") or "").strip()
    if not rationale:
        return False
    if rationale in ("<rationale>", "<reason>"):
        return False
    return len(rationale) >= 3


def check_no_score_claim_without_canonical_provenance(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
    max_artifacts_to_scan: int = 10000,
) -> list[str]:
    """STRICT preflight gate Catalog #323 — canonical Provenance umbrella.

    Refuses persisted score-claiming artifact rows that lack a canonical
    `provenance` sub-object (or have an invalid one).

    Args:
        strict: If True, raise PreflightError when violations found.
        verbose: If True, print per-violation detail.
        repo_root: Repo root path; defaults to the repo enclosing this file.
        max_artifacts_to_scan: Safety cap (default 10k).

    Returns:
        List of violation descriptions (empty if clean).

    Raises:
        PreflightError: if strict and violations non-empty.
    """
    import json as _json

    if verbose:
        print("  [check_no_score_claim_without_canonical_provenance]")

    root = Path(repo_root) if repo_root else Path(__file__).resolve().parent.parent.parent

    violations: list[str] = []
    seen: set[Path] = set()
    scanned = 0

    for pattern in _CHECK_323_SCAN_PATTERNS:
        for path in root.glob(pattern):
            if path in seen:
                continue
            s = str(path)
            if any(m in s for m in _CHECK_323_EXCLUDE_MARKERS):
                continue
            if not path.is_file():
                continue
            seen.add(path)
            scanned += 1
            if scanned > max_artifacts_to_scan:
                break

            try:
                raw = path.read_text()
            except (OSError, UnicodeDecodeError):
                continue

            if not raw.strip():
                continue

            # File-level waiver check (first 30 lines). Only comment-style
            # header lines count here; JSON string values are handled by the
            # per-row waiver check below so placeholders cannot masquerade as
            # file-level waiver comments.
            header_waiver_lines = [
                line
                for line in raw.splitlines()[:30]
                if line.lstrip().startswith("#")
                and "PROVENANCE_CANONICAL_WAIVED:" in line
            ]
            if header_waiver_lines:
                if any(
                    _check_323_waiver_has_valid_rationale(line)
                    for line in header_waiver_lines
                ):
                    continue

            # Parse rows
            rows: list[dict] = []
            if path.suffix == ".jsonl":
                for line in raw.splitlines():
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        obj = _json.loads(line)
                        if isinstance(obj, dict):
                            rows.append(obj)
                    except _json.JSONDecodeError:
                        continue
            else:
                try:
                    obj = _json.loads(raw)
                except _json.JSONDecodeError:
                    continue
                if isinstance(obj, dict):
                    rows.append(obj)
                elif isinstance(obj, list):
                    for item in obj:
                        if isinstance(item, dict):
                            rows.append(item)

            for row_idx, row in enumerate(rows):
                score_keys = [k for k in _CHECK_323_SCORE_CLAIM_KEYS if k in row]
                if not score_keys:
                    continue
                # Per-row waiver
                if any(
                    isinstance(v, str)
                    and _check_323_waiver_has_valid_rationale(v)
                    for v in row.values()
                ):
                    continue

                if "provenance" not in row:
                    rel = path.relative_to(root) if root in path.parents or root == path.parent else path
                    violations.append(
                        f"{rel} row {row_idx}: score-claim keys {score_keys}"
                        f" but no 'provenance' sub-object (Catalog #323)"
                    )
                    continue

                prov_dict = row["provenance"]
                if not isinstance(prov_dict, dict):
                    rel = path.relative_to(root) if root in path.parents or root == path.parent else path
                    violations.append(
                        f"{rel} row {row_idx}: 'provenance' is not a dict"
                        f" (type={type(prov_dict).__name__})"
                    )
                    continue

                # Reconstruct + validate
                try:
                    from tac.provenance import audit_score_claim_dict
                    valid, blockers = audit_score_claim_dict(row)
                    if not valid:
                        rel = path.relative_to(root) if root in path.parents or root == path.parent else path
                        blocker_summary = "; ".join(blockers[:3])
                        violations.append(
                            f"{rel} row {row_idx}: invalid Provenance:"
                            f" {blocker_summary}"
                        )
                except Exception as exc:
                    rel = path.relative_to(root) if root in path.parents or root == path.parent else path
                    violations.append(
                        f"{rel} row {row_idx}: validator raised: {exc!r}"
                    )

        if scanned > max_artifacts_to_scan:
            break

    if violations:
        if verbose:
            print(
                f"  [check_no_score_claim_without_canonical_provenance] {len(violations)} violation(s)"
            )
            for v in violations[:5]:
                print(f"    - {v}")
    else:
        if verbose:
            print(
                "  [check_no_score_claim_without_canonical_provenance] OK"
            )

    if violations and strict:
        raise PreflightError(
            "check_no_score_claim_without_canonical_provenance (Catalog #323)"
            f" found {len(violations)} violation(s); persisted score-claim"
            " artifacts MUST carry a canonical 'provenance' sub-object per"
            " tac.provenance contract. See"
            " docs/provenance_canonical_usage.md or run"
            " tools/audit_provenance_compliance.py --summary for the"
            " operator-facing report.\n\nFirst 10 violations:\n"
            + "\n".join(violations[:10])
        )
    return violations


def _preflight_cli_main() -> None:
    import argparse
    parser = argparse.ArgumentParser(
        description=(
            "Preflight pipeline validator - fast developer scope by default; "
            "explicit release scope for exhaustive custody sweeps"
        )
    )
    parser.add_argument("--renderer", type=str, default=None,
                        help="Optional renderer .bin/.pt for artifact check")
    parser.add_argument("--masks", type=str, default=None)
    parser.add_argument("--poses", type=str, default=None)
    parser.add_argument("--archive", type=str, default=None)
    parser.add_argument("--no-codebase", action="store_true",
                        help="Skip codebase / arity / profiles / filenames / arch_consistency")
    parser.add_argument("--profile", type=str, default=None,
                        help="Profile name for training-input validation")
    parser.add_argument("--tto-frames", type=str, default=None)
    parser.add_argument("--gt-poses", type=str, default=None)
    parser.add_argument(
        "--scope",
        choices=("all", "dev", "release"),
        default="dev",
        help=(
            "dev (default) runs the bounded strict developer gate; all runs "
            "the canonical exhaustive preflight_all release/custody gate; "
            "release is an alias for all. Use --scope all|release with "
            "--allow-slow-preflight before release, dispatch, or frontier "
            "claims."
        ),
    )
    parser.add_argument(
        "--timeout-s",
        type=float,
        default=DEFAULT_PREFLIGHT_CLI_TIMEOUT_S,
        help=(
            "Wall-clock budget for the normal developer preflight CLI. "
            f"Default: {DEFAULT_PREFLIGHT_CLI_TIMEOUT_S:g}s."
        ),
    )
    parser.add_argument(
        "--allow-slow-preflight",
        action="store_true",
        help=(
            "Explicit release/custody override: disable the normal 30s "
            "developer timeout. Do not use for routine edit/green loops."
        ),
    )
    parser.add_argument(
        "--timings-json",
        type=Path,
        default=None,
        help=(
            "Write a JSON timing profile for this tac.preflight CLI run. "
            "Useful for keeping the dev scope under 30s and finding "
            "broad-scan regressions."
        ),
    )
    args = parser.parse_args()

    status = "passed"
    error_type = ""
    error = ""
    exit_code = 0
    timeout_s: float | None = None
    runner = preflight_developer
    cli_started = time.perf_counter()
    recorder: _PreflightCliTimingRecorder | None = None
    try:
        # R38 fixed the old artifact-only CLI by routing through
        # preflight_all. Catalog #145 was later superseded by the 2026-05-09
        # DX budget ratchet: the routine CLI must stay bounded and fail
        # inside 30s if it regresses. Exhaustive release/custody sweeps are
        # still explicit via `--scope all|release --allow-slow-preflight`.
        profile_arch = None
        if args.profile:
            from tac.profiles import PROFILES
            if args.profile not in PROFILES:
                print(f"Unknown profile: {args.profile}", file=sys.stderr)
                sys.exit(2)
            profile_arch = PROFILES[args.profile]
        timeout_s = _preflight_cli_timeout_seconds(
            timeout_s=args.timeout_s,
            allow_slow_preflight=args.allow_slow_preflight,
        )
        scope_explicit = any(
            arg == "--scope" or arg.startswith("--scope=")
            for arg in sys.argv[1:]
        )
        if args.scope == "dev" and scope_explicit:
            print(
                "\nWARNING: --scope dev runs the fast developer-only gate; "
                "release/custody checks are SKIPPED. Run with --scope all "
                "--allow-slow-preflight before any release, dispatch, or "
                "frontier-claim. (catalog #145)\n",
                file=sys.stderr,
            )
        # The CLI adds a hard DX budget: routine preflight must be fast, or
        # fail loudly and force profiling instead of silently taxing every edit.
        runner = preflight_developer if args.scope == "dev" else preflight_all
        recorder = _PreflightCliTimingRecorder(scope=args.scope, runner=runner)
        runner_kwargs = {
            "profile_name": args.profile,
            "profile_arch": profile_arch,
            "tto_frames_path": args.tto_frames,
            "gt_poses_path": args.gt_poses,
            "masks_path": args.masks,
            "renderer_path": args.renderer,
            "archive_path": args.archive,
            "check_codebase": not args.no_codebase,
            "verbose": True,
        }
        # The CLI already owns the user-facing timeout and timing JSON. Avoid
        # a nested recorder/timer so parallel checks pay one instrumentation
        # layer while direct library calls still get the 30s DX crash budget by
        # default.
        runner_kwargs["wall_clock_budget_s"] = None
        with recorder, _preflight_timeout_after(timeout_s):
            runner(**runner_kwargs)
        print("\nPREFLIGHT PASSED")
    except (PreflightError, ArityViolation, FilenameContractError,
            CodebaseDriftError, LoaderFormatSafetyError) as e:
        status = "failed"
        error_type = type(e).__name__
        if isinstance(e, PreflightTimeoutError) and recorder is not None:
            raw_error = str(e)
            if "Slowest preflight checks recorded before failure:" in raw_error:
                error = raw_error
            else:
                budget = (
                    DEFAULT_PREFLIGHT_CLI_TIMEOUT_S
                    if timeout_s is None
                    else timeout_s
                )
                error = _preflight_budget_error_message(
                    scope=args.scope,
                    budget_s=budget,
                    elapsed_s=time.perf_counter() - cli_started,
                    step_rows=recorder.rows(),
                    cause=raw_error,
                )
        else:
            error = str(e)
        exit_code = 1
        print(f"\nPREFLIGHT FAILED: {error}", file=sys.stderr)
    finally:
        if args.timings_json is not None:
            payload = _build_preflight_cli_timing_payload(
                scope=args.scope,
                status=status,
                wall_elapsed_s=time.perf_counter() - cli_started,
                timeout_s=timeout_s,
                allow_slow_preflight=args.allow_slow_preflight,
                check_codebase=not args.no_codebase,
                step_rows=recorder.rows() if recorder is not None else [],
                error_type=error_type,
                error=error,
            )
            _write_preflight_cli_timing_json(args.timings_json, payload)
            stream = sys.stderr if exit_code else sys.stdout
            print(f"Timing profile JSON: {args.timings_json}", file=stream)
    sys.exit(exit_code)


# =========================================================================
# Catalog #324 — PREDICTED_BAND POST-TRAINING TIER-C VALIDATION REQUIRED
# =========================================================================
# Per operator NON-NEGOTIABLE 2026-05-17 META-FIX Catalog #324.
# Empirical bug class anchor: C6 IBPS 22× miss
# (call_id fc-01KRW353MJJ9A6QW8H99QWZEMH, 2026-05-17). Sister #835's
# Assumption-Adversary verbatim WARNED; #836 empirically falsified.
# Sister of Catalog #321 / #322 / #323 phantom-score family at the
# predicted_band sub-surface.

_CHECK_324_RECIPE_GLOB: str = ".omx/operator_authorize_recipes/*.yaml"


def check_no_predicted_band_without_post_training_tier_c_validation(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
) -> list[str]:
    """STRICT preflight gate Catalog #324 — predicted_band post-training Tier-C validation.

    Refuses any substrate recipe at
    ``.omx/operator_authorize_recipes/*.yaml`` that declares a
    ``predicted_band`` field WITHOUT one of: (a)
    ``predicted_band_validation_status: validated_post_training`` +
    post-training Tier-C density artifact path; (b)
    ``predicted_band_validation_status: pending_post_training`` +
    reactivation criteria; (c) ``research_only: true`` (explicit
    non-promotable); (d) same-line
    ``# PREDICTED_BAND_RANDOM_INIT_OK:<rationale>`` waiver
    (placeholder rejected).

    Bug class anchor: 2026-05-17 C6 IBPS recipe declared
    ``predicted_band: [0.113, 0.163]`` derived from random-init Tier-C
    density 2.67e-5; actual 50ep smoke landed 3.04 (22× outside upper).
    Sister #835's recipe-fix sextet Assumption-Adversary verbatim
    flagged the prediction as CARGO-CULTED ("post-smoke Tier-C
    re-confirmation REQUIRED"). Sister #836 empirically falsified.

    Args:
        strict: If True, raise PreflightError when violations found.
        verbose: If True, print per-violation detail.
        repo_root: Repo root path; defaults to the repo enclosing this file.

    Returns:
        List of violation descriptions (empty if clean).

    Raises:
        PreflightError: if strict and violations non-empty.
    """
    if verbose:
        print("  [check_no_predicted_band_without_post_training_tier_c_validation]")

    try:
        from tac.optimization.tier_c_density_post_training_validator import (
            validate_recipe_predicted_band,
        )
    except ImportError as exc:
        # Fail-closed on canonical helper missing per CLAUDE.md "Bugs must be
        # permanently fixed AND self-protected against" sister Catalog #279.
        msg = (
            f"[Catalog #324] FATAL: canonical helper "
            f"`tac.optimization.tier_c_density_post_training_validator` "
            f"unavailable: {exc}"
        )
        if strict:
            raise PreflightError(msg)
        return [msg]

    root = Path(repo_root) if repo_root else Path(__file__).resolve().parent.parent.parent
    recipe_dir = root / ".omx" / "operator_authorize_recipes"
    if not recipe_dir.is_dir():
        return []

    violations: list[str] = []
    for recipe_path in sorted(recipe_dir.glob("*.yaml")):
        verdict = validate_recipe_predicted_band(recipe_path)
        if not verdict.is_valid:
            blockers_text = "; ".join(verdict.blockers) if verdict.blockers else "(no blocker recorded)"
            violations.append(
                f"[Catalog #324] {recipe_path.name}: "
                f"status={verdict.validation_status} — {blockers_text}"
            )
            if verbose:
                print(f"    VIOLATION: {recipe_path.name} ({verdict.validation_status})")

    if violations and strict:
        msg = (
            f"Catalog #324 (predicted_band post-training Tier-C validation): "
            f"{len(violations)} recipe violations. "
            f"Per CLAUDE.md NON-NEGOTIABLE 'Substrate MUST be at OPTIMAL FORM "
            f"before paid empirical dispatch' + META-FIX 2026-05-17 (C6 IBPS "
            f"22× miss anchor): every predicted_band MUST attest to whether "
            f"Tier-C density was measured pre-training (random-init) or "
            f"post-training. Run `.venv/bin/python "
            f"tools/audit_predicted_band_provenance.py` for the full report. "
            f"First violation: {violations[0]}"
        )
        raise PreflightError(msg)

    return violations


# =========================================================================
# Catalog #325 — PER-SUBSTRATE OPTIMAL FORM via grand council symposium
# =========================================================================
# Per operator standing directive 2026-05-17/18 verbatim:
#   "all candidates including c6 ibps may need further optimization and
#    iteration and review and audit and individual extreme passion and
#    detail and effort and adversarial grand council symposiums"
#
# Bug class anchor: 2026-05-17 C6 IBPS Phase 2 sextet PROCEED-unconditional
# unlocked dispatch -> empirical 3.04 vs predicted [0.113, 0.163] = 22x miss
# revealed META-layer audits (Catalog #303 + #294 + #305 + #296 + #324) at
# design-memo + recipe-emit surfaces CAN surface bug classes but CANNOT
# adjudicate per-substrate idiosyncratic cargo-culted assumptions without
# dedicated per-substrate council symposium.
#
# Sister of Catalog #315 (parent OPTIMAL FORM iteration-discipline; #325 is
# per-substrate symposium-evidence sub-surface) + Catalog #324 (recipe-emit
# surface) + Catalog #303/#294/#305/#296 (design-memo surfaces) + Catalog
# #292/#300 (council-discipline).

_CHECK_325_RECIPE_GLOB: str = ".omx/operator_authorize_recipes/substrate_*.yaml"
_CHECK_325_SYMPOSIUM_WINDOW_DAYS: int = 14
_CHECK_325_ACCEPTED_VERDICTS: frozenset[str] = frozenset({"PROCEED", "PROCEED_WITH_REVISIONS"})
_CHECK_325_WAIVER_TOKEN: str = "PER_SUBSTRATE_SYMPOSIUM_WAIVED"
_CHECK_325_PLACEHOLDER_RATIONALES: frozenset[str] = frozenset({
    "<rationale>", "<reason>", "", " "
})
# Catalog #325 operator-frontier-override cascade (e) per CLAUDE.md "Mission alignment"
# Consequence #1 + sister Catalog #300 §"Mission alignment" pattern. R11 H1-4 fix
# (2026-05-19): the asymmetry that runtime honors operator-frontier-override but
# Catalog #325 gate did not was the bug class. Acceptance now reads recipe's
# operator_override_rationale + operator_override_memo fields and ratifies the
# dispatch when BOTH are present + non-placeholder + memo path resolves under
# .omx/research/operator_authorizations/.
_CHECK_325_OVERRIDE_RATIONALE_KEY: str = "operator_override_rationale"
_CHECK_325_OVERRIDE_MEMO_KEY: str = "operator_override_memo"
_CHECK_325_OVERRIDE_MEMO_DIR_RELPATH: str = ".omx/research/operator_authorizations"


def _check_325_extract_substrate_id_from_recipe(recipe_path: Path) -> str | None:
    """Derive canonical substrate_id from recipe filename.

    Recipe filename pattern: ``substrate_<substrate_id>_modal_*_dispatch.yaml``
    or ``substrate_<substrate_id>_<provider>_<gpu>_*_dispatch.yaml``.
    Returns the substrate_id token (without the ``substrate_`` prefix) or
    None if filename does not match the canonical pattern.
    """
    stem = recipe_path.stem
    if not stem.startswith("substrate_"):
        return None
    rest = stem[len("substrate_") :]
    # Strip trailing platform/gpu/mode suffix: ``_modal_*_dispatch``,
    # ``_local_*``, etc. Find the first canonical token suffix.
    for suffix_token in (
        "_modal_t4_smoke_dispatch",
        "_modal_a10g_smoke_dispatch",
        "_modal_a100_smoke_dispatch",
        "_modal_t4_dispatch",
        "_modal_a10g_dispatch",
        "_modal_a100_dispatch",
        "_modal_h100_dispatch",
        "_modal_l40s_dispatch",
        "_modal_4090_dispatch",
        "_lightning_dispatch",
        "_vastai_dispatch",
        "_local_apple_silicon",
        "_local_dispatch",
    ):
        if rest.endswith(suffix_token):
            return rest[: -len(suffix_token)]
    return rest  # fall back to full rest


def _check_325_parse_recipe_dispatch_enabled(
    recipe_path: Path,
) -> tuple[bool, bool, str | None, str | None, str | None]:
    """Parse recipe YAML for dispatch_enabled, research_only, waiver, override.

    Returns (dispatch_enabled, research_only, waiver_rationale,
             operator_override_rationale, operator_override_memo).
    Lightweight regex parse to avoid full YAML import cost; only the 2
    top-level flags + same-line waiver on dispatch_enabled line + the 2
    operator-frontier-override fields are needed.

    R11 H1-4 fix (2026-05-19): per Catalog #300 §"Mission alignment"
    Consequence #1 + sister Catalog #325 acceptance cascade (e), recipes
    carrying operator_override_rationale + operator_override_memo per the
    canonical sister pattern are ratified at the gate surface so the gate
    is no longer asymmetric vs runtime behaviour.
    """
    try:
        text = recipe_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return (False, False, None, None, None)

    dispatch_enabled = False
    research_only = False
    waiver_rationale: str | None = None
    override_rationale: str | None = None
    override_memo: str | None = None

    def _strip_inline_yaml_value(raw: str) -> str:
        """Strip surrounding quotes + inline comment from a YAML value."""
        s = raw.strip()
        # Strip surrounding quotes
        if (s.startswith('"') and s.endswith('"')) or (s.startswith("'") and s.endswith("'")):
            s = s[1:-1].strip()
        # Strip inline comment (only if outside quotes; simple heuristic)
        if "#" in s:
            # Conservative: only strip if # appears with leading whitespace
            for marker in (" #", "\t#"):
                idx = s.find(marker)
                if idx >= 0:
                    s = s[:idx].strip()
                    break
        return s

    for line in text.splitlines():
        stripped = line.strip()
        if stripped.startswith("dispatch_enabled:"):
            val = stripped[len("dispatch_enabled:") :].strip().lower()
            if val.startswith("true"):
                dispatch_enabled = True
                # Check same-line waiver
                if _CHECK_325_WAIVER_TOKEN in line:
                    waiver_start = line.find(f"# {_CHECK_325_WAIVER_TOKEN}:")
                    if waiver_start < 0:
                        waiver_start = line.find(f"{_CHECK_325_WAIVER_TOKEN}:")
                    if waiver_start >= 0:
                        after = line[waiver_start:].split(":", 1)
                        if len(after) > 1:
                            rationale = after[1].strip()
                            if rationale and rationale not in _CHECK_325_PLACEHOLDER_RATIONALES and len(rationale) >= 4:
                                waiver_rationale = rationale
        elif stripped.startswith("research_only:"):
            val = stripped[len("research_only:") :].strip().lower()
            if val.startswith("true"):
                research_only = True
        elif stripped.startswith(f"{_CHECK_325_OVERRIDE_RATIONALE_KEY}:"):
            raw = stripped[len(_CHECK_325_OVERRIDE_RATIONALE_KEY) + 1 :]
            val = _strip_inline_yaml_value(raw)
            if val and val not in _CHECK_325_PLACEHOLDER_RATIONALES and len(val) >= 4:
                override_rationale = val
        elif stripped.startswith(f"{_CHECK_325_OVERRIDE_MEMO_KEY}:"):
            raw = stripped[len(_CHECK_325_OVERRIDE_MEMO_KEY) + 1 :]
            val = _strip_inline_yaml_value(raw)
            if val and val not in _CHECK_325_PLACEHOLDER_RATIONALES:
                override_memo = val

    return (dispatch_enabled, research_only, waiver_rationale, override_rationale, override_memo)


def _check_325_operator_frontier_override_active(
    rationale: str | None,
    memo_relpath: str | None,
    repo_root: Path,
) -> tuple[bool, str | None]:
    """Validate operator-frontier-override cascade (e) per Catalog #325.

    Returns (override_active, fail_reason). When override_active is False
    and rationale or memo was provided, fail_reason explains why the
    override was rejected so the violation message is operator-actionable.
    Per Catalog #300 §"Mission alignment" Consequence #1: override REQUIRES
    operator-verbatim rationale + audit-trail memo path. Per the canonical
    location convention, memo MUST resolve under
    ``.omx/research/operator_authorizations/``.
    """
    # Both fields absent => no override claimed; cascade (e) does not apply
    if not rationale and not memo_relpath:
        return (False, None)

    # Partial declaration is a structural error
    if not rationale:
        return (
            False,
            f"operator_override_memo declared without operator_override_rationale "
            f"(Catalog #325 cascade (e) per Catalog #300 §'Mission alignment' "
            f"Consequence #1 requires BOTH fields)",
        )
    if not memo_relpath:
        return (
            False,
            f"operator_override_rationale declared without operator_override_memo "
            f"(Catalog #325 cascade (e) per Catalog #300 §'Mission alignment' "
            f"Consequence #1 requires audit-trail memo path)",
        )

    # Memo path must resolve under canonical location
    memo_path = (repo_root / memo_relpath).resolve()
    canonical_dir = (repo_root / _CHECK_325_OVERRIDE_MEMO_DIR_RELPATH).resolve()
    try:
        memo_path.relative_to(canonical_dir)
    except ValueError:
        return (
            False,
            f"operator_override_memo={memo_relpath!r} not under canonical "
            f"location {_CHECK_325_OVERRIDE_MEMO_DIR_RELPATH}/ "
            f"(Catalog #325 cascade (e))",
        )

    if not memo_path.is_file():
        return (
            False,
            f"operator_override_memo={memo_relpath!r} does not resolve to an "
            f"existing file (Catalog #325 cascade (e))",
        )

    return (True, None)


def _check_325_find_recent_symposium_memo(
    substrate_id: str, repo_root: Path, *, now_utc: str | None = None
) -> tuple[bool, str | None]:
    """Find the most-recent per-substrate symposium memo within window.

    Scans ``.omx/research/council_*_<substrate_id>_*_<YYYYMMDD>.md`` files;
    returns (found_within_window, verdict_token_if_any). The verdict is
    extracted from YAML frontmatter ``council_verdict`` field if present.
    """
    from datetime import datetime, timezone, timedelta
    import re as _re

    research_dir = repo_root / ".omx" / "research"
    if not research_dir.is_dir():
        return (False, None)

    if now_utc:
        try:
            now = datetime.fromisoformat(now_utc.replace("Z", "+00:00"))
        except (ValueError, AttributeError):
            now = datetime.now(timezone.utc)
    else:
        now = datetime.now(timezone.utc)
    cutoff = now - timedelta(days=_CHECK_325_SYMPOSIUM_WINDOW_DAYS)

    # Match council_*_<substrate_id>_*_YYYYMMDD.md (allow either underscore
    # boundary or anywhere in filename for symposium-style memos).
    date_re = _re.compile(r"_(\d{8})\.md$")
    candidates: list[tuple[str, Path]] = []
    for memo in research_dir.glob(f"council_*{substrate_id}*.md"):
        m = date_re.search(memo.name)
        if not m:
            continue
        date_str = m.group(1)
        try:
            memo_date = datetime.strptime(date_str, "%Y%m%d").replace(tzinfo=timezone.utc)
        except ValueError:
            continue
        if memo_date >= cutoff:
            candidates.append((date_str, memo))

    if not candidates:
        return (False, None)

    candidates.sort(reverse=True)  # latest date first
    latest_memo = candidates[0][1]
    try:
        body = latest_memo.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return (True, None)

    # Extract council_verdict from YAML frontmatter (case-insensitive token).
    verdict_re = _re.compile(r"^\s*council_verdict:\s*([A-Z_]+)", _re.MULTILINE)
    m = verdict_re.search(body)
    verdict = m.group(1) if m else None
    return (True, verdict)


def check_substrate_dispatch_has_per_substrate_optimal_form_symposium_anchor(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
    now_utc: str | None = None,
) -> list[str]:
    """STRICT preflight gate Catalog #325 — per-substrate symposium evidence.

    Refuses substrate operator-authorize recipes
    (``.omx/operator_authorize_recipes/substrate_*.yaml``) with
    ``dispatch_enabled: true`` whose substrate lacks a recent (within 14
    days) per-substrate symposium memo at
    ``.omx/research/council_*_<substrate_id>_*_<YYYYMMDD>.md`` with verdict
    in ``{PROCEED, PROCEED_WITH_REVISIONS}``.

    Acceptance cascade:
        (a) per-substrate symposium memo within 14-day window AND verdict
            in {PROCEED, PROCEED_WITH_REVISIONS}
        (b) recipe is ``dispatch_enabled: false`` (out of scope)
        (c) recipe is ``research_only: true`` (transparent non-promotable)
        (d) same-line ``# PER_SUBSTRATE_SYMPOSIUM_WAIVED:<rationale>``
            waiver on the ``dispatch_enabled:`` line (placeholder
            ``<rationale>`` / ``<reason>`` literals rejected;
            rationale must be ≥4 chars)
        (e) operator-frontier-override per Catalog #300 §"Mission alignment"
            Consequence #1: recipe declares BOTH
            ``operator_override_rationale: "<verbatim operator quote>"``
            (>=4 chars, no placeholders) AND
            ``operator_override_memo: .omx/research/operator_authorizations/<memo>.md``
            (memo MUST resolve under canonical audit-trail directory).
            R11 H1-4 fix (2026-05-19): closes asymmetry where runtime
            honored operator-frontier-override but structural gate did not.

    Per CLAUDE.md NON-NEGOTIABLE "PER-SUBSTRATE OPTIMAL FORM via adversarial
    grand council symposium": each ASYMPTOTIC pursuit candidate deserves
    individual cargo-cult audit + 9-dim checklist + observability surface
    + sextet pact deliberation + reactivation criteria + Catalog #324
    post-training Tier-C validation BEFORE paid dispatch. The 6-step
    canonical contract is detailed in the CLAUDE.md section.

    Bug class anchor: 2026-05-17 C6 IBPS 22× miss (smoke 3.04 vs predicted
    [0.113, 0.163]) revealed that META-layer audits at design-memo + recipe-
    emit surfaces CAN surface bug classes but CANNOT adjudicate per-
    substrate cargo-culted assumptions without dedicated council symposium.

    Args:
        strict: If True, raise PreflightError when violations found.
        verbose: If True, print per-violation detail.
        repo_root: Repo root path; defaults to the repo enclosing this file.
        now_utc: Override current UTC for deterministic testing.

    Returns:
        List of violation descriptions (empty if clean).

    Raises:
        PreflightError: if strict and violations non-empty.
    """
    if verbose:
        print("  [check_substrate_dispatch_has_per_substrate_optimal_form_symposium_anchor]")

    root = Path(repo_root) if repo_root else Path(__file__).resolve().parent.parent.parent
    recipe_dir = root / ".omx" / "operator_authorize_recipes"
    if not recipe_dir.is_dir():
        return []

    violations: list[str] = []
    for recipe_path in sorted(recipe_dir.glob("substrate_*.yaml")):
        (
            dispatch_enabled,
            research_only,
            waiver,
            override_rationale,
            override_memo,
        ) = _check_325_parse_recipe_dispatch_enabled(recipe_path)

        # Out-of-scope: recipe not dispatch-enabled
        if not dispatch_enabled:
            continue

        # Opt-out (c): research_only=true
        if research_only:
            continue

        # Opt-out (d): same-line waiver with non-placeholder rationale
        if waiver:
            if verbose:
                print(f"    WAIVED: {recipe_path.name} ({waiver})")
            continue

        # Opt-out (e) R11 H1-4 fix (2026-05-19): operator-frontier-override
        # cascade per CLAUDE.md "Mission alignment" Consequence #1 + Catalog
        # #300 §"Mission alignment". Recipes carrying operator_override_rationale
        # + operator_override_memo (resolving under canonical audit-trail
        # directory) are ratified at this gate so it is no longer asymmetric
        # vs runtime behaviour.
        override_active, override_fail_reason = _check_325_operator_frontier_override_active(
            override_rationale, override_memo, root
        )
        if override_active:
            if verbose:
                print(
                    f"    OPERATOR_FRONTIER_OVERRIDE: {recipe_path.name} "
                    f"(rationale={override_rationale!r}, memo={override_memo})"
                )
            continue
        # If override was claimed but malformed, record violation immediately
        # so the operator gets actionable feedback (rather than the generic
        # missing-symposium message which would mask the cascade-(e) error).
        if override_fail_reason is not None:
            violations.append(
                f"[Catalog #325] {recipe_path.name}: operator-frontier-override "
                f"cascade (e) REJECTED — {override_fail_reason}. "
                f"Per CLAUDE.md 'Mission alignment' Consequence #1, declare "
                f"BOTH operator_override_rationale (verbatim operator quote, "
                f">=4 chars, no placeholders) AND operator_override_memo "
                f"(path under {_CHECK_325_OVERRIDE_MEMO_DIR_RELPATH}/)."
            )
            if verbose:
                print(f"    VIOLATION: {recipe_path.name} (override malformed)")
            continue

        # Now we need symposium evidence
        substrate_id = _check_325_extract_substrate_id_from_recipe(recipe_path)
        if substrate_id is None:
            # Cannot identify substrate; out of scope
            continue

        found, verdict = _check_325_find_recent_symposium_memo(
            substrate_id, root, now_utc=now_utc
        )

        if not found:
            violations.append(
                f"[Catalog #325] {recipe_path.name}: substrate={substrate_id} "
                f"dispatch_enabled=true but NO per-substrate symposium memo at "
                f".omx/research/council_*{substrate_id}*_<YYYYMMDD>.md within "
                f"{_CHECK_325_SYMPOSIUM_WINDOW_DAYS}-day window. Per CLAUDE.md "
                f"NON-NEGOTIABLE 'PER-SUBSTRATE OPTIMAL FORM via adversarial "
                f"grand council symposium': each candidate requires individual "
                f"cargo-cult audit + 9-dim checklist + observability surface + "
                f"sextet pact deliberation + reactivation criteria + Catalog "
                f"#324 post-training Tier-C validation BEFORE paid dispatch."
            )
            if verbose:
                print(f"    VIOLATION: {recipe_path.name} (no symposium)")
            continue

        if verdict is None or verdict not in _CHECK_325_ACCEPTED_VERDICTS:
            violations.append(
                f"[Catalog #325] {recipe_path.name}: substrate={substrate_id} "
                f"symposium found but verdict={verdict!r} not in "
                f"{sorted(_CHECK_325_ACCEPTED_VERDICTS)}. Re-convene symposium "
                f"per CLAUDE.md NON-NEGOTIABLE 'PER-SUBSTRATE OPTIMAL FORM' "
                f"canonical 6-step contract."
            )
            if verbose:
                print(f"    VIOLATION: {recipe_path.name} (verdict={verdict})")

    if violations and strict:
        msg = (
            f"Catalog #325 (per-substrate optimal form symposium): "
            f"{len(violations)} recipe violations. "
            f"Per CLAUDE.md NON-NEGOTIABLE 'PER-SUBSTRATE OPTIMAL FORM via "
            f"adversarial grand council symposium' + operator standing "
            f"directive 2026-05-17/18 'all candidates including c6 ibps may "
            f"need further optimization and iteration and review and audit "
            f"and individual extreme passion and detail and effort and "
            f"adversarial grand council symposiums': every dispatchable "
            f"substrate MUST have a recent per-substrate symposium with "
            f"PROCEED-or-PROCEED_WITH_REVISIONS verdict. "
            f"First violation: {violations[0]}"
        )
        raise PreflightError(msg)

    return violations


# Catalog #326 - check_substrate_driver_consumes_trainer_mode_env_var
# 2026-05-18 lane_driver_fix_smoke_hardcode_plus_new_catalog_gate_cross_substrate_audit_20260518.
