_CHECK_326_DRIVERS_GLOB = "scripts/remote_lane_substrate_*.sh"
_CHECK_326_BUG_CLASS_VERDICTS: frozenset[str] = frozenset({
    "HARDCODES_SMOKE_NO_RECIPE_OPT_OUT",
    "CONSUMES_ENV_DEFAULTS_SMOKE_BUG_CLASS",
    "CONSUMES_ENV_UNKNOWN_DEFAULT_BUG_CLASS",
})
_CHECK_326_LINE_WAIVER_PATTERN = re.compile(
    r"# DRIVER_MODE_HARDCODE_OK:(.+?)(?:$|#)", re.MULTILINE
)
_CHECK_326_FILE_WAIVER_PATTERN = re.compile(
    r"# DRIVER_MODE_HARDCODE_OK_FILE:(.+?)(?:$|#)", re.MULTILINE
)


def _check_326_rationale_is_placeholder(rationale: str) -> bool:
    """True iff the rationale text is a placeholder (rejected per Catalog #326)."""
    low = rationale.strip().rstrip(":").strip().lower()
    return low in ("", "<rationale>", "<reason>")


def _check_326_driver_has_file_waiver(driver_path: Path) -> bool:
    """True iff driver's first 30 lines carry a file-level waiver with non-placeholder rationale."""
    try:
        text = driver_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return False
    head = "\n".join(text.splitlines()[:30])
    for m in _CHECK_326_FILE_WAIVER_PATTERN.finditer(head):
        if not _check_326_rationale_is_placeholder(m.group(1)):
            return True
    return False


def _check_326_driver_has_line_waiver(driver_path: Path) -> bool:
    """True iff driver has a same-line `# DRIVER_MODE_HARDCODE_OK:<rationale>` waiver
    on ANY line containing `--smoke` or `SMOKE_FLAG_ARGS+=(--smoke)`.
    """
    try:
        text = driver_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return False
    for line in text.splitlines():
        if "--smoke" not in line:
            continue
        m = _CHECK_326_LINE_WAIVER_PATTERN.search(line)
        if m and not _check_326_rationale_is_placeholder(m.group(1)):
            return True
    return False


def check_substrate_driver_consumes_trainer_mode_env_var(
    *,
    strict: bool = False,
    verbose: bool = False,
    repo_root: Path | str | None = None,
) -> list[str]:
    """Catalog #326 — refuse substrate drivers that route smoke-vs-full mode in
    a way the matching recipe cannot safely override.

    Delegates verdict classification to the canonical helper
    `tools/audit_substrate_driver_mode_hardcode.py::audit_all_drivers` so the
    operator-facing audit tool + this STRICT preflight gate stay in lock-step.

    Same-line waiver on the `--smoke` line:
    `# DRIVER_MODE_HARDCODE_OK:<rationale>`.
    File-level waiver in the driver's first 30 lines:
    `# DRIVER_MODE_HARDCODE_OK_FILE:<rationale>`.
    Placeholder `<rationale>` / `<reason>` literals rejected.

    Bug-class verdicts refused:
    - `HARDCODES_SMOKE_NO_RECIPE_OPT_OUT`
    - `CONSUMES_ENV_DEFAULTS_SMOKE_BUG_CLASS`

    Per CLAUDE.md "Forbidden substrate driver hardcoding smoke=1 / --smoke
    regardless of dispatch env vars" FORBIDDEN PATTERN + Catalog #270 sister.
    """
    root = Path(repo_root).resolve() if repo_root is not None else REPO_ROOT
    violations: list[str] = []

    # Import the canonical helper lazily so preflight.py itself can be parsed
    # without the tools/ path being on sys.path.
    helper_path = root / "tools" / "audit_substrate_driver_mode_hardcode.py"
    if not helper_path.is_file():
        if verbose:
            print(
                "  [check_substrate_driver_consumes_trainer_mode_env_var] "
                f"SKIP (canonical helper missing at {helper_path})"
            )
        return violations

    import importlib.util as _ilu

    spec = _ilu.spec_from_file_location(
        "tac_check326_audit_helper", str(helper_path)
    )
    if spec is None or spec.loader is None:
        if verbose:
            print(
                "  [check_substrate_driver_consumes_trainer_mode_env_var] "
                "SKIP (canonical helper import failed)"
            )
        return violations
    module = _ilu.module_from_spec(spec)
    try:
        spec.loader.exec_module(module)  # type: ignore[union-attr]
    except Exception as exc:
        if strict:
            raise PreflightError(
                "Catalog #326 audit helper failed to import: "
                f"{type(exc).__name__}: {exc}"
            )
        if verbose:
            print(
                "  [check_substrate_driver_consumes_trainer_mode_env_var] "
                f"SKIP (helper exception: {exc})"
            )
        return violations

    try:
        report = module.audit_all_drivers(root)
    except Exception as exc:
        if strict:
            raise PreflightError(
                "Catalog #326 audit helper raised: "
                f"{type(exc).__name__}: {exc}"
            )
        if verbose:
            print(
                "  [check_substrate_driver_consumes_trainer_mode_env_var] "
                f"SKIP (audit raised: {exc})"
            )
        return violations

    for row in report.get("rows", []):
        verdict = row.get("verdict", "")
        if verdict not in _CHECK_326_BUG_CLASS_VERDICTS:
            continue
        driver_rel = row.get("driver_path", "")
        driver_abs = root / driver_rel
        # Honor file-level + line-level waivers
        if _check_326_driver_has_file_waiver(driver_abs):
            continue
        if _check_326_driver_has_line_waiver(driver_abs):
            continue
        substrate_id = row.get("substrate_id", "?")
        explanation = row.get("explanation", "")
        violations.append(
            f"[Catalog #326] {driver_rel} (substrate={substrate_id}) verdict="
            f"{verdict}: {explanation[:300]}. Per CLAUDE.md 'Bugs must be "
            "permanently fixed AND self-protected against' non-negotiable + "
            "Z6-v2 Wave 2 DEFER 2026-05-18 anchor: fix the driver to consume "
            "Z6_TRAINER_MODE / equivalent env var with full-mode default OR "
            "update the matching recipe `env_overrides` to set the mode-env "
            "var to full OR opt the recipe out via `research_only: true` / "
            "`smoke_only: true` / `dispatch_enabled: false`. OR carry a same-"
            "line `# DRIVER_MODE_HARDCODE_OK:<rationale>` waiver on the "
            "--smoke line (placeholder rationale rejected). Run "
            "`.venv/bin/python tools/audit_substrate_driver_mode_hardcode.py` "
            "for the full per-recipe safety breakdown."
        )

    if verbose:
        if violations:
            print(
                "  [check_substrate_driver_consumes_trainer_mode_env_var] "
                f"{len(violations)} violation(s)"
            )
        else:
            print(
                "  [check_substrate_driver_consumes_trainer_mode_env_var] OK"
            )
    if violations and strict:
        raise PreflightError(
            "check_substrate_driver_consumes_trainer_mode_env_var found "
            f"{len(violations)} violation(s) per Catalog #326.\n  "
            + "\n  ".join(v[:600] for v in violations[:5])
        )
    return violations


# ============================================================================
# Catalog #339 — SILENT-NO-SPAWN-STRUCTURAL-EXTINCTION (2026-05-19)
# ============================================================================
# Bug class anchor: today's 3 consecutive silent-no-spawn incidents (Z6 Wave
# 2 4c / STC v2 / STC sister) all exhibited the same pattern in
# experiments/modal_train_lane.py: `.spawn()` succeeded → paid GPU meter
# started → `register_dispatched_call_id` failed (fcntl lock contention,
# disk full, sister-subagent edit, corruption) → silent
# `try/except Exception: print WARNING + continue` at lines 1921-1960
# swallowed the failure → wrapper exited rc=0 → ledger had no row →
# harvester invisible → operator effort wasted.
#
# Per CLAUDE.md "Modal `.spawn()` HARVEST OR LOSE" non-negotiable + "Bugs
# must be permanently fixed AND self-protected against" non-negotiable.
#
# This gate is the STRUCTURAL protection at the source-text surface that
# refuses any future regression of the silent-swallow pattern around the
# canonical ledger registration call in experiments/modal_train_lane.py.
#
# Gate semantics: AST-scan experiments/modal_train_lane.py for the
# `register_dispatched_call_id_fail_closed(...)` (or
# `register_dispatched_call_id(...)`) call. Refuse if any of:
#   (a) the call appears inside a `try:` body whose handler contains
#       `print(` AND lacks `sys.exit` / `raise SystemExit` / re-raise;
#   (b) the call site uses the legacy non-fail-closed helper
#       `register_dispatched_call_id` directly without an explicit fail-closed
#       handler.
#
# Same-line waiver: `# SILENT_NO_SPAWN_LEDGER_SWALLOW_OK:<rationale>` on
# the function `def main` line OR on the relevant `try:` line. Placeholder
# `<rationale>` / `<reason>` literals rejected per Catalog #287 sister
# discipline.
#
# Sister of Catalog #245 (canonical Modal call_id ledger), Catalog #131
# (fcntl-locked bare-write discipline), Catalog #138 (strict-load), and
# Catalog #143 (paid-job register-before-submit) — together they extinct
# the orphan-paid-Modal-dispatch bug class at FOUR surfaces:
#   (#143) register pending row BEFORE submit
#   (#245) canonical ledger as single source of truth
#   (#131/#138) fcntl-locked / strict-load discipline
#   (#339) fail-closed registration AFTER spawn — THIS gate
# ----------------------------------------------------------------------------


_CHECK_339_TARGET_RELPATH = "experiments/modal_train_lane.py"

_CHECK_339_FAIL_CLOSED_HELPER_NAMES = frozenset(
    {
        "register_dispatched_call_id_fail_closed",
    }
)

_CHECK_339_LEGACY_HELPER_NAMES = frozenset(
    {
        "register_dispatched_call_id",
    }
)

_CHECK_339_WAIVER_RE = re.compile(
    r"#\s*SILENT_NO_SPAWN_LEDGER_SWALLOW_OK\s*:\s*(?P<rationale>[^\n]+)"
)
_CHECK_339_WAIVER_PLACEHOLDERS = frozenset({"<rationale>", "<reason>", ""})


def _check_339_waiver_present(source: str) -> bool:
    """Return True if any line in ``source`` has a valid Catalog #339 waiver."""

    for line in source.splitlines():
        match = _CHECK_339_WAIVER_RE.search(line)
        if not match:
            continue
        rationale = match.group("rationale").strip()
        if rationale in _CHECK_339_WAIVER_PLACEHOLDERS:
            continue
        if len(rationale) < 4:
            continue
        return True
    return False


def _check_339_call_is_in_swallowing_try(
    tree: object, call_node: object
) -> tuple[bool, str | None]:
    """Determine whether ``call_node`` is wrapped in a silent-swallow try.

    Returns ``(is_swallowing, handler_description)`` — handler_description
    is a short string for diagnostic messages (or None).

    A handler is considered "silent-swallowing" when it catches a broad
    exception class (BaseException / Exception / bare except) AND its body
    does NOT contain ``raise`` / ``sys.exit`` / ``SystemExit`` / a re-raise.
    """

    import ast

    # Find the enclosing Try node by walking parents. Use ``object`` rather
    # than ``Any`` so ruff --isolated does not need the `typing` import.
    parent_map: dict[int, object] = {}
    for parent in ast.walk(tree):
        for child in ast.iter_child_nodes(parent):
            parent_map[id(child)] = parent

    current: object = call_node
    while current is not None:
        parent = parent_map.get(id(current))
        if parent is None:
            return False, None
        if isinstance(parent, ast.Try):
            # Check if current is in parent.body (vs handlers / finalbody)
            if any(current is stmt for stmt in parent.body):
                # Inspect handlers — is any of them a silent swallow?
                for handler in parent.handlers:
                    # Broad exception scope: bare except / Exception /
                    # BaseException.
                    is_broad = False
                    if handler.type is None:
                        is_broad = True
                    elif isinstance(handler.type, ast.Name) and handler.type.id in (
                        "Exception",
                        "BaseException",
                    ):
                        is_broad = True
                    if not is_broad:
                        continue
                    # Does the handler re-raise / sys.exit?
                    has_exit_path = False
                    for node in ast.walk(handler):
                        if isinstance(node, ast.Raise):
                            has_exit_path = True
                            break
                        if isinstance(node, ast.Call):
                            func = node.func
                            if (
                                isinstance(func, ast.Attribute)
                                and isinstance(func.value, ast.Name)
                                and func.value.id == "sys"
                                and func.attr == "exit"
                            ):
                                has_exit_path = True
                                break
                            if (
                                isinstance(func, ast.Name)
                                and func.id in ("exit", "quit")
                            ):
                                has_exit_path = True
                                break
                    if not has_exit_path:
                        return True, (
                            f"broad-except handler at line {handler.lineno} "
                            "lacks raise/sys.exit"
                        )
        current = parent

    return False, None


def check_modal_dispatcher_registers_call_id_before_successful_exit(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #339 — refuse silent-no-spawn pattern in modal_train_lane.py.

    Per CLAUDE.md "Modal `.spawn()` HARVEST OR LOSE" + "Bugs must be
    permanently fixed AND self-protected against" non-negotiables.

    The gate AST-scans ``experiments/modal_train_lane.py`` and refuses any
    state where the post-spawn canonical-ledger registration call sits
    inside a silent-swallow ``try/except Exception: print`` handler that
    lacks ``raise`` / ``sys.exit``. The fix is to use
    ``register_dispatched_call_id_fail_closed`` (which raises
    ``LedgerRegistrationFailedError`` on failure) and either let it
    propagate OR catch it explicitly and ``sys.exit(13)`` per the
    Catalog #339 Layer 2 fix.

    Same-line waiver: ``# SILENT_NO_SPAWN_LEDGER_SWALLOW_OK:<rationale>``
    on the ``def main`` line OR on the relevant ``try:`` line (rationale
    >= 4 chars; placeholder ``<rationale>`` / ``<reason>`` rejected so
    the gate's docstring example cannot self-waive).

    Sister of Catalog #245 (canonical Modal call_id ledger), #131
    (fcntl-locked bare-write discipline), #138 (strict-load), #143
    (paid-job register-before-submit).
    """

    import ast

    root = repo_root or REPO_ROOT
    if isinstance(root, str):
        root = Path(root)
    target = root / _CHECK_339_TARGET_RELPATH
    violations: list[str] = []

    if not target.is_file():
        if verbose:
            print(f"  [catalog-339] OK ({_CHECK_339_TARGET_RELPATH} not present)")
        return violations

    try:
        source = target.read_text(encoding="utf-8")
    except Exception as exc:
        violations.append(
            f"[Catalog #339] cannot read {_CHECK_339_TARGET_RELPATH}: {exc}"
        )
        if strict:
            raise PreflightError(violations[0])
        return violations

    # File-level waiver bypasses gate (rare; for the deliberate operator-approved
    # case where the swallow is intentional + documented).
    if _check_339_waiver_present(source):
        if verbose:
            print(
                f"  [catalog-339] OK ({_CHECK_339_TARGET_RELPATH} carries "
                "SILENT_NO_SPAWN_LEDGER_SWALLOW_OK waiver)"
            )
        return violations

    try:
        tree = ast.parse(source, filename=str(target))
    except SyntaxError as exc:
        violations.append(
            f"[Catalog #339] {_CHECK_339_TARGET_RELPATH} SyntaxError: {exc}"
        )
        if strict:
            raise PreflightError(violations[0])
        return violations

    # Find every Call node whose function is one of the registration helpers.
    register_calls: list[tuple[object, str]] = []
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        func = node.func
        name: str | None = None
        if isinstance(func, ast.Name):
            name = func.id
        elif isinstance(func, ast.Attribute):
            name = func.attr
        if name is None:
            continue
        if (
            name in _CHECK_339_FAIL_CLOSED_HELPER_NAMES
            or name in _CHECK_339_LEGACY_HELPER_NAMES
        ):
            register_calls.append((node, name))

    if not register_calls:
        # No registration call found at all — that's a different bug class
        # (the wrapper is not registering AT ALL). Flag it.
        violations.append(
            f"[Catalog #339] {_CHECK_339_TARGET_RELPATH}: no "
            f"register_dispatched_call_id_fail_closed(...) or "
            f"register_dispatched_call_id(...) call found in source. "
            f"Modal dispatcher MUST register the call_id in the canonical "
            f"ledger per CLAUDE.md 'Modal .spawn() HARVEST OR LOSE'."
        )

    for call_node, name in register_calls:
        is_swallowing, handler_desc = _check_339_call_is_in_swallowing_try(
            tree, call_node
        )
        if is_swallowing:
            violations.append(
                f"[Catalog #339] {_CHECK_339_TARGET_RELPATH}:{call_node.lineno}: "
                f"{name}(...) is wrapped in a silent-swallow try ({handler_desc}). "
                f"Use register_dispatched_call_id_fail_closed and let "
                f"LedgerRegistrationFailedError propagate OR catch + "
                f"sys.exit(non-zero). See Catalog #339 fix anchor; today's "
                f"3 silent-no-spawn incidents (Z6 Wave 2 4c / STC v2 / "
                f"STC sister) were caused by this exact pattern. Add "
                f"`# SILENT_NO_SPAWN_LEDGER_SWALLOW_OK:<rationale>` waiver "
                f"only with operator review."
            )

    if verbose:
        if violations:
            print(
                f"  [catalog-339] WARN: {len(violations)} silent-no-spawn "
                f"violation(s) in {_CHECK_339_TARGET_RELPATH} (strict={strict})"
            )
        else:
            print(f"  [catalog-339] OK ({_CHECK_339_TARGET_RELPATH} scanned)")

    if violations and strict:
        raise PreflightError(
            "check_modal_dispatcher_registers_call_id_before_successful_exit: "
            f"{len(violations)} silent-no-spawn violation(s) (Catalog #339 — "
            "SILENT-NO-SPAWN-STRUCTURAL-EXTINCTION; 2026-05-19 anchor); "
            "first 3:\n  " + "\n  ".join(violations[:3])
        )
    return violations


# ============================================================================
# Catalog #344 - check_empirical_finding_memo_references_canonical_equation
#
# CANONICAL-EQUATIONS-AND-MODELS-REGISTRY self-protection 2026-05-19 per
# operator NON-NEGOTIABLE verbatim: *"we need to formalize all of this and
# canonicalize and operationalize because I am afraid we are learning but
# if we don't have systems of equations and models and such we are just
# gaining tribal knowledge"*.
#
# Refuses .omx/research/*.md memos dated >= 2026-05-19 that contain
# empirical-finding tokens without an adjacent canonical-equation reference.
# Same-line waiver `# FORMALIZATION_PENDING:<rationale>` (placeholder
# rejected per Catalog #287 sister discipline).
#
# Initial wire-in is WARN-ONLY per CLAUDE.md "Strict-flip atomicity rule"
# because today's pre-framework memos predate this gate; strict-flip
# planned after the initial 6 equations populate the registry + the
# first wave of memo backfills complete.

_CHECK_344_RESEARCH_RELPATH = ".omx/research"
_CHECK_344_CUTOFF_DATE_SUFFIX_INT = 20260519  # framework's birthday
_CHECK_344_DESIGN_FILENAME_RE = re.compile(r".*_(\d{8})(?:T\d{6}Z)?(?:_codex)?\.md$")

# Empirical-finding tokens that trigger the gate. Case-insensitive substring match.
_CHECK_344_EMPIRICAL_FINDING_TOKENS: tuple[str, ...] = (
    "empirical reduction",
    "empirical anchor",
    "predicted vs measured",
    "predicted vs empirical",
    "falsified",
    "ratified",
    "bayesian update",
    "posterior update",
    "prediction-vs-empirical",
    "empirical residual",
)

# Acceptance tokens that satisfy the gate (case-insensitive substring).
_CHECK_344_CANONICAL_EQUATION_REFERENCE_TOKENS: tuple[str, ...] = (
    "tac.canonical_equations",
    "canonical_equations_registry",
    "canonical_equations.registry",
    "tools/list_canonical_equations.py",
    "tools/recalibrate_equation.py",
    "register_canonical_equation",
    "update_equation_with_empirical_anchor",
    "canonicalequation",  # dataclass mention; case-insensitive
)

# Same-line waiver token (sister of Catalog #303 design).
_CHECK_344_WAIVER_MARKER = "FORMALIZATION_PENDING"
_CHECK_344_WAIVER_RE = re.compile(
    r"#\s*" + re.escape(_CHECK_344_WAIVER_MARKER) + r":\s*(?P<rationale>[^\n]+)"
)

# Placeholder rationales rejected per Catalog #287 sister discipline.
_CHECK_344_PLACEHOLDER_RATIONALES: tuple[str, ...] = ("<rationale>", "<reason>")
_CHECK_344_MIN_RATIONALE_LEN = 4

# Self-exempt: the gate's own definition file plus its dedicated test file.
_CHECK_344_SELF_EXEMPT_PATHS: tuple[str, ...] = (
    "src/tac/preflight.py",
    "src/tac/tests/test_check_344_canonical_equation_referenced.py",
    # The canonical equation registry's landing memo itself REFERENCES
    # tac.canonical_equations heavily but ALSO mentions "ratified"/etc;
    # it satisfies the gate via acceptance tokens, so no exemption needed.
)


def _check_344_text_has_empirical_finding(text: str) -> bool:
    """True iff text contains any empirical-finding trigger token."""
    low = text.lower()
    return any(token in low for token in _CHECK_344_EMPIRICAL_FINDING_TOKENS)


def _check_344_text_has_canonical_equation_reference(text: str) -> bool:
    """True iff text contains any canonical-equation reference token."""
    low = text.lower()
    return any(
        token.lower() in low for token in _CHECK_344_CANONICAL_EQUATION_REFERENCE_TOKENS
    )


def _check_344_text_has_valid_waiver(text: str) -> bool:
    """True iff text carries a well-formed FORMALIZATION_PENDING waiver."""
    for m in _CHECK_344_WAIVER_RE.finditer(text):
        rationale = m.group("rationale").strip()
        if not rationale:
            continue
        if rationale in _CHECK_344_PLACEHOLDER_RATIONALES:
            continue
        if len(rationale) < _CHECK_344_MIN_RATIONALE_LEN:
            continue
        return True
    return False


def check_empirical_finding_memo_references_canonical_equation(
    *,
    repo_root: Path | str | None = None,
    strict: bool = False,
    verbose: bool = False,
) -> list[str]:
    """Catalog #344 — refuse NEW empirical-finding memos without canonical
    equation reference.

    Per CLAUDE.md "Canonical equations + models registry" non-negotiable +
    operator NON-NEGOTIABLE 2026-05-19. Scans repo-local
    ``.omx/research/*.md`` files dated >= 2026-05-19 for empirical-finding
    tokens (``empirical reduction`` / ``predicted vs empirical`` / etc.)
    without an adjacent canonical-equation reference token
    (``tac.canonical_equations`` / ``canonical_equations_registry`` /
    sister names). Accepts same-line waiver
    ``# FORMALIZATION_PENDING:<rationale>`` (placeholder rejected per
    Catalog #287 sister discipline).

    Sister of Catalog #290 + #294 + #296 + #297 + #303 + #305 + #309 +
    #324 (design-memo discipline cluster) and Catalog #287 (empirical-
    claim-evidence-tag at the source-text surface).

    Memory: ``feedback_canonical_equations_and_models_registry_formalization_landed_20260519.md``.
    Lane: ``lane_canonical_equations_and_models_registry_formalization_framework_20260519``.
    """
    root = Path(repo_root or REPO_ROOT)
    research_root = root / _CHECK_344_RESEARCH_RELPATH
    if not research_root.is_dir():
        if verbose:
            print(
                f"  [catalog-344] {_CHECK_344_RESEARCH_RELPATH} not present, skipping"
            )
        return []

    violations: list[str] = []
    try:
        candidates = sorted(research_root.iterdir())
    except OSError:
        return []

    for entry in candidates:
        if not entry.is_file() or not entry.name.endswith(".md"):
            continue
        try:
            rel = entry.relative_to(root)
        except ValueError:
            rel = entry
        rel_str = str(rel)
        if any(exempt in rel_str for exempt in _CHECK_344_SELF_EXEMPT_PATHS):
            continue
        m = _CHECK_344_DESIGN_FILENAME_RE.match(entry.name)
        if not m:
            continue
        try:
            date_int = int(m.group(1))
        except (TypeError, ValueError):
            continue
        if date_int < _CHECK_344_CUTOFF_DATE_SUFFIX_INT:
            continue
        try:
            text = entry.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        if not _check_344_text_has_empirical_finding(text):
            continue
        if _check_344_text_has_canonical_equation_reference(text):
            continue
        if _check_344_text_has_valid_waiver(text):
            continue
        violations.append(
            f"{rel}: memo dated {date_int} contains empirical-finding "
            f"token(s) but does NOT reference any canonical equation. Per "
            f"CLAUDE.md \"Canonical equations + models registry\" non-"
            f"negotiable + operator NON-NEGOTIABLE 2026-05-19, every new "
            f"empirical-finding memo MUST cite the corresponding canonical "
            f"equation via ``tac.canonical_equations`` import / equation_id "
            f"citation, OR carry same-line waiver "
            f"`# FORMALIZATION_PENDING:<rationale>` (placeholder rejected). "
            f"Catalog #344 (sister of #287/#290/#294/#296/#297/#303/#305)."
        )

    if verbose:
        if violations:
            print(
                f"  [catalog-344] {len(violations)} memo(s) missing canonical "
                "equation reference"
            )
        else:
            print("  [catalog-344] OK (no empirical-finding memos lack reference)")
    if violations and strict:
        raise PreflightError(
            "check_empirical_finding_memo_references_canonical_equation found "
            f"{len(violations)} memo(s) missing the required canonical equation "
            "reference. Per CLAUDE.md \"Canonical equations + models registry\" "
            "non-negotiable + operator NON-NEGOTIABLE 2026-05-19. Catalog #344 "
            "(sister of #287 / #290 / #294 / #296 / #297 / #303 / #305).\n  "
            + "\n  ".join(v[:400] for v in violations[:5])
        )
    return violations


